function addPhase(metrics, phase, startMs) {
  const duration = performance.now() - startMs;
  metrics.phaseMs[phase] = (metrics.phaseMs[phase] ?? 0) + duration;
  return duration;
}

function createMovementProfiler(metrics) {
  return {
    measure(phase, operation) {
      const start = performance.now();

      try {
        return operation();
      } finally {
        addPhase(metrics, `movement:${phase}`, start);
      }
    },
    count(name, amount = 1) {
      metrics.movementCounters[name] = (metrics.movementCounters[name] ?? 0) + amount;
    },
  };
}

function createContextProfiler(metrics, prefix) {
  return {
    measure(phase, operation) {
      const start = performance.now();

      try {
        return operation();
      } finally {
        addPhase(metrics, `context:${prefix}:${phase}`, start);
      }
    },
    count(name, amount = 1) {
      const key = `${prefix}:${name}`;
      metrics.contextCounters[key] = (metrics.contextCounters[key] ?? 0) + amount;
    },
  };
}

function createReportedKnowledgeProfiler(metrics) {
  return {
    measure(phase, operation) {
      const start = performance.now();

      try {
        return operation();
      } finally {
        addPhase(metrics, `reportedKnowledge:${phase}`, start);
      }
    },
    count(name, amount = 1) {
      metrics.reportedKnowledgeCounters[name] = (metrics.reportedKnowledgeCounters[name] ?? 0) + amount;
    },
  };
}

// Cumulative, benchmark-only observer for one dry-margin band across a scenario
// window. It reads decisions and post-decision band state (never hidden tile
// truth) so that "behaviour X happened at least once" can be validated even
// though --report-band only shows the latest tick.
function createDryMarginTracker(selector, modules) {
  const normalized = String(selector ?? "Dry Margin").toLowerCase();
  const matches = (band) =>
    String(band.id).toLowerCase().includes(normalized) ||
    band.name.toLowerCase().includes(normalized);
  const actionTypeCounts = {};
  const seasonalModesSeen = new Set();
  const placeAssessmentsSeen = new Set();
  const waterSourceKindsSeen = new Set();
  let ticksObserved = 0;
  let probeBuiltTicks = 0;
  let probeSelectedTicks = 0;
  let probeRejectedTicks = 0;
  let stayTicks = 0;
  let outwardTicks = 0;
  let maxDryRefugePull = 0;
  let maxTemporaryWaterOpportunity = 0;
  let maxDroughtFailureRisk = 0;
  let maxDroughtSeverity = 0;
  let failedWaterObserved = false;
  let firstProbe = undefined;
  let probeRejectionExample = undefined;
  const anchorStatusesSeen = new Set();
  const residenceModesSeen = new Set();
  const residentialActionsSeen = new Set();
  let maxSeasonsAnchored = 0;
  let anchoredHoldTicks = 0;
  let firstAnchorHold = undefined;
  let dispersedWetSeasonRoundTicks = 0;
  let dispersedWhileMovedTicks = 0;
  let maxRememberedAnchorCount = 0;
  let maxAnchorMemoryConfidence = 0;
  let totalSuccessfulHolds = 0;
  let totalFailedHolds = 0;
  let anchorMemoryRevisitTicks = 0;
  let firstWetDispersal = undefined;
  let maxObservedCycleCount = 0;
  let maxRoundConfidence = 0;
  const seasonalPhasesSeen = new Set();
  const seasonalRoundOutcomesSeen = new Set();
  let roundFollowedTicks = 0;
  let dispersedWhileHeldTicksTotal = 0;
  let firstSeasonalCycle = undefined;
  let rotationTicks = 0;
  let maxDepletionAvoidance = 0;
  let maxRotationPressure = 0;
  let stickinessTicks = 0;
  let maxDryRefugeStickiness = 0;
  let maxRefugeDistance = 0;
  const behaviorBasesSeen = new Set();

  return {
    matches,
    observe({ time, world, band, updatedBand, decision }) {
      if (!matches(updatedBand)) {
        return;
      }

      ticksObserved += 1;

      if (modules?.getDryMarginRelevanceBasis !== undefined && world !== undefined) {
        for (const basis of modules.getDryMarginRelevanceBasis(world, updatedBand)) {
          behaviorBasesSeen.add(basis);
        }
      }
      const actionType = decision.action.type;
      actionTypeCounts[actionType] = (actionTypeCounts[actionType] ?? 0) + 1;

      if (actionType === "stay" || actionType === "no_op") {
        stayTicks += 1;
      } else {
        outwardTicks += 1;
      }

      const dry = updatedBand.dryMarginContext;
      if (dry !== undefined) {
        if (dry.seasonalMode !== undefined) {
          seasonalModesSeen.add(dry.seasonalMode.mode);
          maxDryRefugePull = Math.max(maxDryRefugePull, dry.seasonalMode.dryRefugePull);
          maxTemporaryWaterOpportunity = Math.max(maxTemporaryWaterOpportunity, dry.seasonalMode.temporaryWaterOpportunity);
          maxDroughtSeverity = Math.max(maxDroughtSeverity, dry.seasonalMode.droughtSeverity);
        }
        placeAssessmentsSeen.add(dry.currentPlaceAssessment);
        if (dry.currentWaterRefuge !== undefined) {
          waterSourceKindsSeen.add(dry.currentWaterRefuge.sourceKind);
          maxDroughtFailureRisk = Math.max(maxDroughtFailureRisk, dry.currentWaterRefuge.droughtFailureRisk);
          if (dry.currentWaterRefuge.sourceKind === "failed_or_unreliable_water") {
            failedWaterObserved = true;
          }
        }
      }

      // Also detect a failed/unreliable water source the band was standing on
      // BEFORE it decided to leave (post-decision context would already have moved on).
      const startRecord = band.knowledge.observedTiles[band.position];
      const startMemory = band.placeMemory[band.position];
      if (
        (startRecord !== undefined && (startRecord.observedWaterAccess ?? 1) < 0.22) ||
        (startMemory !== undefined &&
          (startMemory.lastKnownWaterStress ?? 0) > 0.6 &&
          (startMemory.valences.includes("depleted") || startMemory.valences.includes("risky")))
      ) {
        failedWaterObserved = true;
      }

      const anchor = updatedBand.residentialAnchor;
      const intra = updatedBand.intraSeasonActivity;
      if (anchor !== undefined) {
        anchorStatusesSeen.add(anchor.anchorStatus);
        maxSeasonsAnchored = Math.max(maxSeasonsAnchored, anchor.seasonsAnchored);
      }
      if (updatedBand.anchorDecision !== undefined) {
        residentialActionsSeen.add(updatedBand.anchorDecision.chosenResidentialAction);
      }
      // Anchor revisitation memory (2I.3, PART 5): the band started this season
      // already holding a memory of its current tile as a prior anchor.
      const priorMemoryHere = band.anchorMemories?.[band.position];
      if (priorMemoryHere !== undefined) {
        anchorMemoryRevisitTicks += 1;
      }
      if (updatedBand.anchorMemories !== undefined) {
        const records = Object.values(updatedBand.anchorMemories);
        maxRememberedAnchorCount = Math.max(maxRememberedAnchorCount, records.length);
        for (const record of records) {
          maxAnchorMemoryConfidence = Math.max(maxAnchorMemoryConfidence, record.confidence);
        }
        totalSuccessfulHolds = records.reduce((sum, record) => sum + record.successfulHoldCount, 0);
        totalFailedHolds = records.reduce((sum, record) => sum + record.failedHoldCount, 0);
      }

      // Seasonal-round memory (2I.4): cycle count, confidence, phases, outcomes.
      const round = updatedBand.seasonalRound;
      if (round !== undefined) {
        maxObservedCycleCount = Math.max(maxObservedCycleCount, round.observedCycleCount);
        maxRoundConfidence = Math.max(maxRoundConfidence, round.confidence);
      }
      const rotation = updatedBand.roundCatchmentRotation;
      if (rotation !== undefined) {
        rotationTicks += 1;
        maxDepletionAvoidance = Math.max(maxDepletionAvoidance, rotation.depletionAvoidance);
        maxRotationPressure = Math.max(maxRotationPressure, rotation.rotationPressure);
      }
      const roundState = updatedBand.seasonalRoundState;
      if (roundState !== undefined) {
        seasonalPhasesSeen.add(roundState.currentPhase);
        seasonalRoundOutcomesSeen.add(roundState.outcome);
        if (roundState.outcome === "followed") {
          roundFollowedTicks += 1;
        }
        if (roundState.dryRefugeStickiness > 0) {
          stickinessTicks += 1;
          maxDryRefugeStickiness = Math.max(maxDryRefugeStickiness, roundState.dryRefugeStickiness);
        }
        if (roundState.currentDistanceFromRememberedRefuge !== undefined) {
          maxRefugeDistance = Math.max(maxRefugeDistance, roundState.currentDistanceFromRememberedRefuge);
        }
        if (firstSeasonalCycle === undefined && round !== undefined && round.observedCycleCount >= 1) {
          firstSeasonalCycle = {
            tick: time.tick,
            season: time.season,
            observedCycleCount: round.observedCycleCount,
            confidence: round.confidence,
            currentPhase: roundState.currentPhase,
            rememberedDryRefugeTileId: roundState.rememberedDryRefugeTileId === undefined
              ? undefined
              : String(roundState.rememberedDryRefugeTileId),
          };
        }
      }

      if (intra !== undefined) {
        residenceModesSeen.add(intra.residenceMode);
        if (intra.residenceMode === "dispersed_wet_season_round") {
          dispersedWetSeasonRoundTicks += 1;
          if (intra.residenceMoved) {
            dispersedWhileMovedTicks += 1;
          } else {
            dispersedWhileHeldTicksTotal += 1;
          }
          if (firstWetDispersal === undefined) {
            firstWetDispersal = {
              tick: time.tick,
              season: time.season,
              residenceMoved: intra.residenceMoved,
              foragingRadius: intra.foragingRadius,
              radiusBasis: updatedBand.foragingRadiusState?.basis,
              seasonalMode: updatedBand.dryMarginContext?.seasonalMode?.mode,
            };
          }
        }
        if (!intra.residenceMoved) {
          anchoredHoldTicks += 1;
          if (firstAnchorHold === undefined && anchor !== undefined) {
            firstAnchorHold = {
              tick: time.tick,
              season: time.season,
              anchorTileId: String(anchor.anchorTileId),
              tetheringWaterTileId: anchor.tetheringWaterTileId === undefined ? undefined : String(anchor.tetheringWaterTileId),
              residenceMode: intra.residenceMode,
              anchorStatus: anchor.anchorStatus,
              foragingRadius: anchor.foragingRadius,
              catchmentTileCount: anchor.catchmentTileIds.length,
              holdValue: anchor.holdValue,
              relocateValue: anchor.relocateValue,
              relocationHysteresis: updatedBand.anchorDecision?.relocationHysteresis,
              anchorWaterSecurity: anchor.anchorWaterSecurity,
              dependencyLoad: anchor.dependencyLoad,
              activityBudget: intra.activityBudget,
            };
          }
        }
      }

      const probeAlternative = decision.alternativesConsidered.find(
        (alternative) => alternative.action.type === "logistical_probe",
      );
      const probeSelected = actionType === "logistical_probe";

      if (probeAlternative !== undefined) {
        probeBuiltTicks += 1;

        if (!probeSelected) {
          probeRejectedTicks += 1;
          if (probeRejectionExample === undefined) {
            probeRejectionExample = {
              tick: time.tick,
              season: time.season,
              rejectionReason: probeAlternative.rejectionReason?.type ?? "unknown",
              probeScore: probeAlternative.score,
              winningAction: formatActionForReport(decision.action),
              winningScore: decision.alternativesConsidered[0]?.score,
            };
          }
        }
      }

      if (probeSelected) {
        probeSelectedTicks += 1;

        if (firstProbe === undefined) {
          const target = decision.action.targetTileId;
          const beforeRecord = band.knowledge.observedTiles[target];
          const afterRecord = updatedBand.knowledge.observedTiles[target];
          const probeBreakdown = decision.alternativesConsidered[0]?.scoreBreakdown;
          const payload = decision.primaryReason;

          firstProbe = {
            tick: time.tick,
            season: time.season,
            targetTileId: String(target),
            residentialTileBefore: String(band.position),
            residentialTileAfter: String(updatedBand.position),
            residentialUnchanged: band.position === updatedBand.position,
            targetConfidenceBefore: beforeRecord?.confidence ?? null,
            targetConfidenceAfter: afterRecord?.confidence ?? null,
            targetKnowledgeSourceBefore: beforeRecord?.knowledgeSource ?? "none",
            targetKnowledgeSourceAfter: afterRecord?.knowledgeSource ?? "none",
            knownTilesBefore: Object.keys(band.knowledge.observedTiles).length,
            knownTilesAfter: Object.keys(updatedBand.knowledge.observedTiles).length,
            scoutValue: payload?.scoutValue,
            moveValue: payload?.moveValue,
            stayValue: payload?.stayValue,
            departureThreshold: payload?.departureThreshold,
            uncertainty: payload?.uncertainty,
            movementCostApplied: probeBreakdown?.movementCost,
            riskCostApplied: probeBreakdown?.riskCost,
            primaryReason: decision.primaryReason.type,
            secondaryReasons: decision.secondaryReasons.map((reason) => reason.type),
          };
        }
      }
    },
    summarize() {
      if (ticksObserved === 0) {
        return undefined;
      }

      return {
        bandSelector: String(selector ?? "Dry Margin"),
        ticksObserved,
        actionTypeCounts,
        logisticalProbe: {
          builtTicks: probeBuiltTicks,
          selectedTicks: probeSelectedTicks,
          rejectedTicks: probeRejectedTicks,
          everSelected: probeSelectedTicks > 0,
          everAvailable: probeBuiltTicks > 0,
          firstSelection: firstProbe,
          rejectionExample: probeRejectionExample,
        },
        stayTicks,
        outwardTicks,
        residentialAnchor: {
          anchorStatusesSeen: [...anchorStatusesSeen].sort(),
          residenceModesSeen: [...residenceModesSeen].sort(),
          residentialActionsSeen: [...residentialActionsSeen].sort(),
          maxSeasonsAnchored,
          anchoredHoldTicks,
          firstAnchorHold,
        },
        wetSeasonDispersal: {
          dispersedWetSeasonRoundTicks,
          dispersedWhileMovedTicks,
          dispersedWhileHeldTicks: dispersedWetSeasonRoundTicks - dispersedWhileMovedTicks,
          firstWetDispersal,
        },
        anchorMemory: {
          maxRememberedAnchorCount,
          maxConfidence: round2(maxAnchorMemoryConfidence),
          totalSuccessfulHolds,
          totalFailedHolds,
          revisitTicks: anchorMemoryRevisitTicks,
        },
        seasonalRound: {
          maxObservedCycleCount,
          maxRoundConfidence: round2(maxRoundConfidence),
          seasonalPhasesSeen: [...seasonalPhasesSeen].sort(),
          outcomesSeen: [...seasonalRoundOutcomesSeen].sort(),
          roundFollowedTicks,
          dispersedWhileHeldTicks: dispersedWhileHeldTicksTotal,
          firstSeasonalCycle,
        },
        catchmentRotation: {
          rotationTicks,
          maxDepletionAvoidance: round2(maxDepletionAvoidance),
          maxRotationPressure: round2(maxRotationPressure),
        },
        dryRefugeStickiness: {
          stickinessTicks,
          maxDryRefugeStickiness: round2(maxDryRefugeStickiness),
          maxRefugeDistance,
        },
        behaviorBasesSeen: [...behaviorBasesSeen].sort(),
        seasonalModesSeen: [...seasonalModesSeen].sort(),
        placeAssessmentsSeen: [...placeAssessmentsSeen].sort(),
        waterSourceKindsSeen: [...waterSourceKindsSeen].sort(),
        failedWaterObserved,
        maxDryRefugePull: round2(maxDryRefugePull),
        maxTemporaryWaterOpportunity: round2(maxTemporaryWaterOpportunity),
        maxDroughtFailureRisk: round2(maxDroughtFailureRisk),
        maxDroughtSeverity: round2(maxDroughtSeverity),
      };
    },
  };
}

