function projectEcologyResearchWorld(modules, world) {
  const withResources = modules.resourceEcology.applyResourceEcologyContext(world);
  const withProto = modules.protoCamps.applyProtoCampContext(withResources);
  const withVisible = modules.visibleNature.applyVisibleNatureContext(withProto);
  return modules.bandEvents.applyBandReadabilityContext(withVisible);
}

function makeEcologyResearchFingerprint(world) {
  const bands = Object.values(world.bands)
    .filter(isActiveBand)
    .sort(compareBands)
    .slice(0, 12)
    .map((band) => ({
      id: String(band.id),
      position: String(band.position),
      nature: {
        fauna: band.visibleNature?.faunaCards.map((card) => `${card.stockId}:${card.knowledgeState}:${card.perceivedAbundance}`).join(",") ?? "",
        aquatic: band.visibleNature?.aquaticCards.map((card) => `${card.stockId}:${card.aquaticEffect}:${card.pressure}`).join(",") ?? "",
        plants: band.visibleNature?.plantCards.map((card) => `${card.patchId}:${card.plantPatchEffect}:${card.pressure}`).join(",") ?? "",
        forests: band.visibleNature?.forestCards.map((card) => `${card.patchId}:${card.growthTrend}:${card.visibilityEffect}`).join(",") ?? "",
      },
      events: (band.eventHistory?.recentEvents ?? []).slice(0, 6).map((event) => `${event.category}:${event.title}:${event.stateKey}`).join(","),
    }));

  return JSON.stringify({
    tick: Number(world.time.tick),
    bands,
    faunaStocks: Object.keys(world.faunaStocks ?? {}).sort().slice(0, 24),
    plantPatchState: Object.keys(world.plantPatchState ?? {}).sort().slice(0, 24),
    forestPatchState: Object.keys(world.forestPatchState ?? {}).sort().slice(0, 24),
  });
}

function finding(kind, summary, impact, recommendation) {
  return { kind, summary, impact, recommendation };
}

function measurePerformanceOperation(name, operation) {
  const memoryBefore = readProcessMemory();
  const start = performance.now();
  const value = operation();
  const wallMs = performance.now() - start;
  const memoryAfter = readProcessMemory();

  return {
    name,
    wallMs: round2(wallMs),
    memoryBefore,
    memoryAfter,
    memoryDelta: diffProcessMemory(memoryBefore, memoryAfter),
    value,
  };
}

function readProcessMemory() {
  if (typeof process.memoryUsage !== "function") {
    return undefined;
  }

  const usage = process.memoryUsage();

  return {
    rssMb: round2(usage.rss / 1024 / 1024),
    heapUsedMb: round2(usage.heapUsed / 1024 / 1024),
    heapTotalMb: round2(usage.heapTotal / 1024 / 1024),
  };
}

function diffProcessMemory(before, after) {
  if (before === undefined || after === undefined) {
    return undefined;
  }

  return {
    rssMb: round2(after.rssMb - before.rssMb),
    heapUsedMb: round2(after.heapUsedMb - before.heapUsedMb),
    heapTotalMb: round2(after.heapTotalMb - before.heapTotalMb),
  };
}

function runFullPipelinePerformanceSample(modules, kind, years) {
  const ticks = years * 4;
  const initialWorld = modules.initSimWorld({ kind });
  const startPopulation = getTotalPopulation(initialWorld);
  const start = performance.now();
  const world = modules.stepSim(initialWorld, ticks, "seasonal");
  const totalRuntimeMs = performance.now() - start;
  const summary = summarizeFullPipelineWorldForPerformance(modules, world, startPopulation, ticks, totalRuntimeMs);

  return {
    kind,
    years,
    ticks,
    startPopulation,
    world,
    summary,
  };
}

function summarizeFullPipelineWorldForPerformance(modules, world, startPopulation, ticks, totalRuntimeMs) {
  const bands = Object.values(world.bands);
  const activeBands = bands.filter(isActiveBand);
  const faunaSummary = modules.faunaStock.summarizeFaunaStocks(world);

  return {
    tick: Number(world.time.tick),
    year: world.time.year,
    ticksRequested: ticks,
    totalRuntimeMs: round2(totalRuntimeMs),
    averageMsPerTick: round4(totalRuntimeMs / Math.max(1, ticks)),
    totalBands: bands.length,
    activeBands: activeBands.length,
    totalPopulation: getTotalPopulation(world),
    startPopulation,
    populationDelta: getTotalPopulation(world) - startPopulation,
    faunaStocks: faunaSummary.stockCount,
    faunaKinds: faunaSummary.byKind,
    eventHistoryTotal: bands.reduce((sum, band) => sum + (band.eventHistory?.recentEvents.length ?? 0), 0),
    visibleNatureBands: bands.filter((band) => band.visibleNature !== undefined).length,
    protoCampBands: bands.filter((band) => band.protoCampMemory !== undefined).length,
    resourceEcologyBands: bands.filter((band) => band.resourceEcology !== undefined).length,
  };
}

function summarizeBenchmarkPerformanceMeasurement(measurement) {
  const summary = measurement.value.summary;

  return {
    name: measurement.name,
    wallMs: measurement.wallMs,
    memoryDelta: measurement.memoryDelta,
    scenario: measurement.value.scenario,
    runtime: summarizeBenchmarkRuntimeForPerformance(summary),
    slowestSubpasses: summary.slowestSubpasses,
  };
}

function summarizeNestedAuditPerformanceMeasurement(measurement) {
  return {
    name: measurement.name,
    wallMs: measurement.wallMs,
    memoryDelta: measurement.memoryDelta,
    verdict: measurement.value.verdict,
    check: measurement.value.check,
    regressions: measurement.value.regressions,
  };
}

function summarizeFullPipelinePerformanceMeasurement(measurement) {
  return {
    name: measurement.name,
    wallMs: measurement.wallMs,
    memoryDelta: measurement.memoryDelta,
    summary: measurement.value.summary,
  };
}

function summarizeBenchmarkRuntimeForPerformance(summary) {
  return {
    completed: summary.completed,
    ticksRequested: summary.ticksRequested,
    ticksSimulated: summary.ticksSimulated,
    totalRuntimeMs: summary.totalRuntimeMs,
    averageMsPerTick: summary.averageMsPerTick,
    maxMsPerTick: summary.maxMsPerTick,
    activeBands: summary.activeBands,
    totalBands: summary.totalBands,
    totalPopulation: summary.totalPopulation,
    cacheBuildsPerTick: summary.cacheBuildsPerTick,
  };
}

function summarizePerformanceHotspots(summary) {
  return {
    topSubpasses: summary.slowestSubpasses,
    movement: summarizeMovementHotspots(summary.phaseSummary).slice(0, 8),
    context: summarizeContextHotspots(summary.phaseSummary).slice(0, 10),
    reportedKnowledge: summarizeReportedKnowledgeHotspots(summary.phaseSummary).slice(0, 8),
    interpretation: [
      "Movement candidate generation is the dominant measured movement hotspot.",
      "Carrying capacity inside range-saturation/context passes is the dominant support hotspot.",
      "Reported-knowledge refresh/evidence scanning is visible but below movement/support in the sampled run.",
      "Fauna and plant seasonal advances are currently modest compared with movement/context.",
      "Full-pipeline stepSim cost includes daily actions and readability contexts not individually separated by the older benchmark profiler.",
    ],
  };
}

function summarizePerformanceMemoryGrowth(worlds) {
  const bands = worlds.flatMap((world) => Object.values(world.bands));
  const activeBands = bands.filter(isActiveBand);
  const eventStats = {
    recentMax: maxPerformanceCount(bands, (band) => band.eventHistory?.recentEvents.length ?? 0),
    last10YearsMax: maxPerformanceCount(bands, (band) => band.eventHistory?.last10Years.length ?? 0),
    last25YearsMax: maxPerformanceCount(bands, (band) => band.eventHistory?.last25Years.length ?? 0),
    droppedRecentTotal: bands.reduce((sum, band) => sum + (band.eventHistory?.droppedRecentEventCount ?? 0), 0),
    cap: { recent: 48, last10Years: 80, last25Years: 120 },
  };
  const resourceKnowledgeMax = maxPerformanceCount(bands, (band) => band.resourceKnowledgeState?.patchMemories.length ?? 0);
  const resourceKnowledgeCapMax = maxPerformanceCount(bands, (band) => band.resourceKnowledgeState?.cap ?? 0);
  const resourcePlaceMax = maxPerformanceCount(bands, (band) => band.resourceEcology?.topResourcePlaceMemories.length ?? 0);
  const resourcePlaceCapMax = maxPerformanceCount(bands, (band) => band.resourceEcology?.placeMemoryCap ?? 0);
  const protoCampMax = maxPerformanceCount(bands, (band) => band.protoCampMemory?.topPlaces.length ?? 0);
  const protoCampCapMax = maxPerformanceCount(bands, (band) => band.protoCampMemory?.memoryCap ?? 0);
  const visibleNature = {
    faunaCardsMax: maxPerformanceCount(bands, (band) => band.visibleNature?.faunaCards.length ?? 0),
    plantCardsMax: maxPerformanceCount(bands, (band) => band.visibleNature?.plantCards.length ?? 0),
    animalKnowledgeMax: maxPerformanceCount(bands, (band) => band.visibleNature?.animalKnowledge.length ?? 0),
    tracksSightingsMax: maxPerformanceCount(bands, (band) => band.visibleNature?.faunaCards.filter((card) =>
      card.knowledgeState === "inferred_from_tracks" ||
      card.knowledgeState === "recent_tracks" ||
      card.knowledgeState === "direct_sighting" ||
      card.knowledgeState === "repeated_sighting" ||
      card.knowledgeState === "reliable_route",
    ).length ?? 0),
    domesticationTrajectoryMax: maxPerformanceCount(bands, (band) => band.visibleNature?.domesticationTrajectories.length ?? 0),
    acuteEpisodeMax: maxPerformanceCount(bands, (band) => band.visibleNature?.acuteEpisodes.length ?? 0),
    capsMax: {
      faunaCards: maxPerformanceCount(bands, (band) => band.visibleNature?.memoryCaps.faunaCardCap ?? 0),
      plantCards: maxPerformanceCount(bands, (band) => band.visibleNature?.memoryCaps.plantCardCap ?? 0),
      animalKnowledge: maxPerformanceCount(bands, (band) => band.visibleNature?.memoryCaps.animalKnowledgeCap ?? 0),
      acuteEpisodes: maxPerformanceCount(bands, (band) => band.visibleNature?.memoryCaps.acuteEpisodeCap ?? 0),
    },
  };
  const debugAndDecision = {
    decisionRecordsMax: Math.max(0, ...worlds.map((world) => Object.keys(world.decisions).length)),
    decisionHistoryMaxBand: maxPerformanceCount(bands, (band) => band.decisionHistory.length),
    causalTraceMaxBand: maxPerformanceCount(bands, (band) => band.causalTraces.length),
    activityTripsMaxBand: maxPerformanceCount(bands, (band) => band.recentIntraSeasonTrips?.length ?? 0),
    residentialMoveEventsMaxBand: maxPerformanceCount(bands, (band) => band.recentResidentialMoveEvents?.length ?? 0),
    placeMemoryMaxBand: maxPerformanceCount(bands, (band) => Object.keys(band.placeMemory ?? {}).length),
    knownTileMaxBand: maxPerformanceCount(bands, (band) => Object.keys(band.knowledge?.observedTiles ?? {}).length),
  };
  const capViolations = {
    eventRecent: eventStats.recentMax > eventStats.cap.recent,
    eventLast10Years: eventStats.last10YearsMax > eventStats.cap.last10Years,
    eventLast25Years: eventStats.last25YearsMax > eventStats.cap.last25Years,
    resourceKnowledge: resourceKnowledgeCapMax > 0 && resourceKnowledgeMax > resourceKnowledgeCapMax,
    resourcePlace: resourcePlaceCapMax > 0 && resourcePlaceMax > resourcePlaceCapMax,
    protoCamp: protoCampCapMax > 0 && protoCampMax > protoCampCapMax,
    visibleFaunaCards: visibleNature.capsMax.faunaCards > 0 && visibleNature.faunaCardsMax > visibleNature.capsMax.faunaCards,
    visiblePlantCards: visibleNature.capsMax.plantCards > 0 && visibleNature.plantCardsMax > visibleNature.capsMax.plantCards,
    visibleAnimalKnowledge: visibleNature.capsMax.animalKnowledge > 0 && visibleNature.animalKnowledgeMax > visibleNature.capsMax.animalKnowledge,
    visibleAcuteEpisodes: visibleNature.capsMax.acuteEpisodes > 0 && visibleNature.acuteEpisodeMax > visibleNature.capsMax.acuteEpisodes,
  };

  return {
    worldsMeasured: worlds.length,
    bandsMeasured: bands.length,
    activeBandSnapshotsMeasured: activeBands.length,
    eventHistory: eventStats,
    resourceKnowledge: {
      patchMemoryMaxBand: resourceKnowledgeMax,
      patchMemoryCapMax: resourceKnowledgeCapMax,
      resourcePlaceMemoryMaxBand: resourcePlaceMax,
      resourcePlaceMemoryCapMax: resourcePlaceCapMax,
      activityResourceTraceMaxBand: maxPerformanceCount(bands, (band) => band.resourceEcology?.activityResourceTraces.length ?? 0),
    },
    protoCamps: {
      topPlacesMaxBand: protoCampMax,
      memoryCapMax: protoCampCapMax,
      currentPlaces: bands.filter((band) => band.protoCampMemory?.currentPlace !== undefined).length,
    },
    visibleNature,
    debugAndDecision,
    capViolations,
    allKnownCapsSatisfied: Object.values(capViolations).every((violation) => violation === false),
    notes: [
      "Known tiles/place memories remain behavior-affecting and grow with exploration; they are not newly capped here.",
      "Recent events, resource ecology projections, proto-camps, visible nature cards, and activity/movement rings are capped.",
      "Long-term history is represented by bounded windows plus compressed lifetime summaries where available.",
    ],
  };
}

function summarizePerformanceUiPayload(modules, world) {
  const snapshotStart = performance.now();
  const footprint = measurePerf4SnapshotFootprint(modules, world);
  const snapshotMeasurementMs = performance.now() - snapshotStart;
  const selectedBand = Object.values(world.bands).filter(isActiveBand).sort(compareBands)[0];
  const selectedBandJson = selectedBand === undefined ? "" : JSON.stringify(selectedBand);
  const selectedEventJson = selectedBand?.eventHistory === undefined ? "" : JSON.stringify(selectedBand.eventHistory);
  const selectedVisibleNatureJson = selectedBand?.visibleNature === undefined ? "" : JSON.stringify(selectedBand.visibleNature);
  const selectedProtoCampJson = selectedBand?.protoCampMemory === undefined ? "" : JSON.stringify(selectedBand.protoCampMemory);
  const selectedResourceJson = selectedBand?.resourceEcology === undefined ? "" : JSON.stringify(selectedBand.resourceEcology);

  return {
    snapshotFootprint: footprint,
    snapshotMeasurementMs: round2(snapshotMeasurementMs),
    selectedBandId: selectedBand === undefined ? undefined : String(selectedBand.id),
    selectedBandBytes: byteLengthUtf8(selectedBandJson),
    selectedEventHistoryBytes: byteLengthUtf8(selectedEventJson),
    selectedVisibleNatureBytes: byteLengthUtf8(selectedVisibleNatureJson),
    selectedProtoCampBytes: byteLengthUtf8(selectedProtoCampJson),
    selectedResourceEcologyBytes: byteLengthUtf8(selectedResourceJson),
    workerArchitectureNotes: [
      "Live overlay posts marker/activity subset every overlay tick.",
      "Full dynamic snapshot carries all bands/debug and is posted rarely or on inspection actions.",
      "Selected-band UI still reads from the full dynamic snapshot once it is present; further lazy projection would need a UI/worker payload pass.",
    ],
    risks: [
      "Dynamic snapshot grows with bands and per-band debug/readability state.",
      "Technical tab can expose large selected-band records, but card/event/resource sections are capped.",
      "Canvas selected overlays scan selected-band known/place/corridor records, not all band debug panels.",
    ],
  };
}

function byteLengthUtf8(value) {
  return Buffer.byteLength(value, "utf8");
}

function maxPerformanceCount(values, selector) {
  if (values.length === 0) {
    return 0;
  }

  return Math.max(...values.map((value) => selector(value)));
}

function makePerformanceWorldFingerprint(world) {
  const bands = Object.values(world.bands)
    .sort(compareBands)
    .map((band) => ({
      id: String(band.id),
      position: String(band.position),
      status: band.status,
      viability: band.viability?.status,
      population: toPopulationCount(band.demography.population),
      recentEvents: band.eventHistory?.recentEvents.map((event) => event.eventId).slice(0, 12) ?? [],
      protoCamp: band.protoCampMemory?.currentPlace?.campLikeState,
      visibleNature: band.visibleNature?.natureHeadline,
    }));

  return JSON.stringify({
    tick: Number(world.time.tick),
    year: world.time.year,
    bands,
    decisionArchive: world.decisionArchive,
    tileDepletionKeys: Object.keys(world.tileDepletion ?? {}).sort().slice(0, 64),
  });
}

