// ---------------------------------------------------------------------------
// PERF-4 — long-run stability profile. This is audit-only: it runs the existing
// benchmark harness, then measures trace growth and dynamic snapshot footprint
// on the resulting world. It does not alter sim semantics.
// ---------------------------------------------------------------------------

const PERF4_DEFAULT_YEARS = [100, 300, 500, 1000];
const PERF6_LOCAL_RANGE_RADIUS_TILES = 4;

function runTargetedPerf4Profile(modules, options) {
  const years = (options.perfYears ?? PERF4_DEFAULT_YEARS)
    .filter((value) => Number.isFinite(value) && value > 0)
    .sort((left, right) => left - right);
  const scenario = getPerf4Scenario(options.perfMap);
  const horizons = [];

  for (const year of years) {
    const benchmark = runBenchmark(
      modules,
      { scenario, years: year, ticks: undefined },
      {
        ...options,
        deterministic: false,
        reportBand: false,
        returnWorld: true,
      },
    );
    const world = benchmark.world;
    const summary = benchmark.summary;

    horizons.push({
      years: year,
      scenario: benchmark.scenario,
      notes: benchmark.notes,
      completed: summary.completed,
      abortedReason: summary.abortedReason,
      runtime: {
        totalMs: summary.totalRuntimeMs,
        averageMsPerTick: summary.averageMsPerTick,
        maxMsPerTick: summary.maxMsPerTick,
        ticksSimulated: summary.ticksSimulated,
        ticksRequested: summary.ticksRequested,
      },
      population: {
        activeBands: summary.activeBands,
        totalBands: summary.totalBands,
        totalPopulation: summary.totalPopulation,
        fissions: summary.fissions,
      },
      decisionArchive: summary.decisionArchive,
      topHotspots: summary.slowestSubpasses,
      phaseSummary: summary.phaseSummary,
      reportedKnowledgeHotspots: summarizeReportedKnowledgeHotspots(summary.phaseSummary),
      movementHotspots: summarizeMovementHotspots(summary.phaseSummary),
      contextHotspots: summarizeContextHotspots(summary.phaseSummary),
      reportedKnowledgeCounters: summary.reportedKnowledgeCounters,
      movementCounters: summary.movementCounters,
      contextCounters: summary.contextCounters,
      traceGrowth: summarizePerf4TraceGrowth(world),
      snapshotFootprint: measurePerf4SnapshotFootprint(modules, world),
      spatialExtent: summarizePerf6SpatialExtent(world, scenario, year),
    });
  }

  return {
    audit: getPerfProfileName(options),
    map: scenario,
    requestedYears: years,
    mode: options.fast === true ? "fast benchmark harness" : "instrumented seasonal benchmark harness",
    notes: [
      "Phase timings come from the existing instrumented benchmark path.",
      "reportedKnowledge:* phases are benchmark-only profiler measurements nested inside advanceReportedKnowledge.",
      "movement:* phases are benchmark-only profiler measurements nested inside evaluate/applyBandDecision.",
      "context:* phases are benchmark-only profiler measurements nested inside range/frontier context derivation.",
      "Snapshot footprint is measured on final dynamic snapshot and live overlay projections.",
      "Trace-growth counts are report-only and do not compact or mutate the world.",
      "Spatial extent diagnostics are measurement-only for MIG-1 and do not tune migration weights.",
    ],
    memoryPlan: getPerf4MemoryPlan(),
    horizons,
  };
}

function summarizeReportedKnowledgeHotspots(phaseSummary) {
  return Object.entries(phaseSummary)
    .filter(([phase]) => phase.startsWith("reportedKnowledge:"))
    .map(([phase, summary]) => ({
      phase,
      totalMs: summary.totalMs,
      averageMsPerTick: summary.averageMsPerTick,
      share: summary.share,
    }))
    .sort((left, right) => right.totalMs - left.totalMs)
    .slice(0, 10);
}

function getPerfProfileName(options) {
  if (options.targetedPerf6Profile) {
    return "PERF-6 movement/frontier/range candidate performance profile";
  }
  if (options.targetedPerf5Profile) {
    return "PERF-5 reported-knowledge cadence/index profile";
  }
  return "PERF-4 long-run stability profile";
}

function summarizeMovementHotspots(phaseSummary) {
  return Object.entries(phaseSummary)
    .filter(([phase]) => phase.startsWith("movement:"))
    .map(([phase, summary]) => ({
      phase,
      totalMs: summary.totalMs,
      averageMsPerTick: summary.averageMsPerTick,
      share: summary.share,
    }))
    .sort((left, right) => right.totalMs - left.totalMs)
    .slice(0, 15);
}

function summarizeContextHotspots(phaseSummary) {
  return Object.entries(phaseSummary)
    .filter(([phase]) => phase.startsWith("context:"))
    .map(([phase, summary]) => ({
      phase,
      totalMs: summary.totalMs,
      averageMsPerTick: summary.averageMsPerTick,
      share: summary.share,
    }))
    .sort((left, right) => right.totalMs - left.totalMs)
    .slice(0, 20);
}

function getPerf4Scenario(perfMap) {
  switch (perfMap) {
    case "map1":
    case "baseline":
      return "baseline";
    case "map2":
    case undefined:
      return "map2_varied_migration";
    default:
      return "map2_varied_migration";
  }
}

function summarizePerf6SpatialExtent(world, scenario, years) {
  const activeBands = Object.values(world.bands).filter(isActiveBand);
  const activeTiles = activeBands
    .map((band) => world.tiles[band.position])
    .filter((tile) => tile !== undefined);
  const coords = activeTiles.map((tile) => tile.coord);
  const bounds = summarizeCoordBounds(coords);
  const originDistances = activeBands
    .map((band) => {
      const originTileId = band.lineage?.originTileId;
      return originTileId === undefined ? undefined : getTileDistance(world, originTileId, band.position);
    })
    .filter((distance) => distance !== undefined);
  const occupiedPairDistances = [];

  for (let leftIndex = 0; leftIndex < activeBands.length; leftIndex += 1) {
    for (let rightIndex = leftIndex + 1; rightIndex < activeBands.length; rightIndex += 1) {
      const distance = getTileDistance(world, activeBands[leftIndex].position, activeBands[rightIndex].position);
      if (distance !== undefined) {
        occupiedPairDistances.push(distance);
      }
    }
  }

  const fissionDistances = getUniqueFissionEvents(Object.values(world.bands))
    .map((event) =>
      event.targetTileId === undefined
        ? undefined
        : getTileDistance(world, event.originTileId, event.targetTileId))
    .filter((distance) => distance !== undefined);
  const residentialMoveEvents = dedupeResidentialMoveEvents(activeBands);
  const residentialDistances = residentialMoveEvents.map((event) => event.distanceTiles);
  const knownOpportunityDistances = activeBands
    .map((band) => {
      const opportunity = band.carryingCapacity?.knownUnusedHabitat ?? band.daughterColonization?.bestKnownUnusedHabitatOpportunity;
      return opportunity === undefined ? undefined : getTileDistance(world, band.position, opportunity.candidateTileId);
    })
    .filter((distance) => distance !== undefined);
  const opportunityRejections = activeBands
    .map((band) => band.carryingCapacity?.knownUnusedHabitat ?? band.daughterColonization?.bestKnownUnusedHabitatOpportunity)
    .filter((opportunity) => opportunity !== undefined && opportunity.consideredAsTarget !== true);
  const maxOriginDistance = originDistances.length === 0 ? undefined : Math.max(...originDistances);

  return {
    tileKilometersAssumption: 1,
    activeBands: activeBands.length,
    maxDistanceFromLineageOriginTiles: roundMaybe(maxOriginDistance),
    maxDistanceFromLineageOriginKm: roundMaybe(maxOriginDistance),
    medianDistanceFromLineageOriginKm: roundMaybe(percentile(originDistances, 0.5)),
    p90DistanceFromLineageOriginKm: roundMaybe(percentile(originDistances, 0.9)),
    frontierAdvanceRateKmPerYear: roundMaybe(
      maxOriginDistance === undefined ? undefined : maxOriginDistance / Math.max(1, years),
    ),
    maxOccupiedSpatialExtentTiles: roundMaybe(
      occupiedPairDistances.length === 0 ? undefined : Math.max(...occupiedPairDistances),
    ),
    maxOccupiedSpatialExtentKm: roundMaybe(
      occupiedPairDistances.length === 0 ? undefined : Math.max(...occupiedPairDistances),
    ),
    occupiedBounds: bounds,
    occupiedAreaApproxTiles: bounds === undefined ? 0 : bounds.width * bounds.height,
    occupiedBroadHabitatZones: countBy(activeTiles, (tile) => classifyPerf6Habitat(world, tile)),
    occupiedCatchments: countBy(activeTiles, (tile) => classifyPerf6Catchment(scenario, tile)),
    parentDaughterDistanceAtFissionTiles: summarizeDistanceDistribution(fissionDistances),
    residentialRelocationDistanceTiles: summarizeDistanceDistribution(residentialDistances),
    knownOpportunityDistanceTiles: summarizeDistanceDistribution(knownOpportunityDistances),
    candidateOpportunitiesBeyondCurrentZone: knownOpportunityDistances.filter((distance) => distance > PERF6_LOCAL_RANGE_RADIUS_TILES).length,
    goodOpportunitiesRejected: opportunityRejections.length,
    goodOpportunityRejectionsByReason: countBy(opportunityRejections, (opportunity) => opportunity.rejectionReason ?? "unknown"),
    suspiciousOpportunityIgnored: opportunityRejections.filter((opportunity) => opportunity.suspiciousOpportunityIgnored === true).length,
  };
}

function summarizeCoordBounds(coords) {
  if (coords.length === 0) {
    return undefined;
  }

  const xs = coords.map((coord) => coord.x);
  const ys = coords.map((coord) => coord.y);
  const minX = Math.min(...xs);
  const maxX = Math.max(...xs);
  const minY = Math.min(...ys);
  const maxY = Math.max(...ys);

  return {
    minX,
    maxX,
    minY,
    maxY,
    width: maxX - minX + 1,
    height: maxY - minY + 1,
  };
}

function dedupeResidentialMoveEvents(bands) {
  const seen = new Set();
  const output = [];

  for (const band of bands) {
    for (const event of band.recentResidentialMoveEvents ?? []) {
      const key = String(event.eventId);
      if (seen.has(key)) {
        continue;
      }
      seen.add(key);
      output.push(event);
    }
  }

  return output;
}

function summarizeDistanceDistribution(distances) {
  return {
    count: distances.length,
    average: roundMaybe(average(distances)),
    median: roundMaybe(percentile(distances, 0.5)),
    p90: roundMaybe(percentile(distances, 0.9)),
    max: roundMaybe(distances.length === 0 ? undefined : Math.max(...distances)),
  };
}

function classifyPerf6Catchment(scenario, tile) {
  return scenario === "baseline" ? classifyMap1Catchment(tile) : classifyMap2Catchment(tile);
}

function classifyPerf6Habitat(world, tile) {
  if (tile.isCoastal || tile.isEstuary) {
    return "coast";
  }
  if (tile.isMarshChannel || tile.terrainKind === "wetlands") {
    return "delta_wetland";
  }
  if (tile.terrainKind === "lake" || hasNeighborTerrain(world, tile, "lake")) {
    return "lake_shore";
  }
  if (tile.isRiver || tile.isFloodplain || tile.isRiverbank || tile.isConfluence) {
    return "river_tributary";
  }
  if (tile.hasCreek === true) {
    return "creek";
  }
  if (tile.elevation >= 0.62) {
    return "mountain_pass_hard_terrain";
  }
  if (tile.riskProfile.droughtRisk >= 0.55) {
    return "dry_margin_refuge";
  }
  if (tile.elevation >= 0.42) {
    return "upland_slope";
  }
  return "general_good_habitat";
}

function hasNeighborTerrain(world, tile, terrainKind) {
  return tile.neighbors.some((neighborId) => world.tiles[neighborId]?.terrainKind === terrainKind);
}

function measurePerf4SnapshotFootprint(modules, world) {
  const dynamicStart = performance.now();
  const dynamicSnapshot = modules.takeDynamicSnapshot(world);
  const dynamicBuildMs = performance.now() - dynamicStart;
  const dynamicJsonStart = performance.now();
  const dynamicJson = JSON.stringify(dynamicSnapshot);
  const dynamicJsonMs = performance.now() - dynamicJsonStart;
  const overlayStart = performance.now();
  const liveOverlay = modules.takeLiveOverlay(world);
  const overlayBuildMs = performance.now() - overlayStart;
  const overlayJsonStart = performance.now();
  const overlayJson = JSON.stringify(liveOverlay);
  const overlayJsonMs = performance.now() - overlayJsonStart;
  let structuredCloneMs = undefined;

  if (typeof structuredClone === "function") {
    const cloneStart = performance.now();
    structuredClone(dynamicSnapshot);
    structuredCloneMs = round2(performance.now() - cloneStart);
  }

  const dynamicBytes = Buffer.byteLength(dynamicJson, "utf8");
  const overlayBytes = Buffer.byteLength(overlayJson, "utf8");

  return {
    dynamicSnapshotBytes: dynamicBytes,
    dynamicSnapshotMb: round2(dynamicBytes / 1024 / 1024),
    liveOverlayBytes: overlayBytes,
    liveOverlayKb: round2(overlayBytes / 1024),
    dynamicToOverlayRatio: round2(dynamicBytes / Math.max(1, overlayBytes)),
    dynamicBuildMs: round2(dynamicBuildMs),
    dynamicJsonMs: round2(dynamicJsonMs),
    liveOverlayBuildMs: round2(overlayBuildMs),
    liveOverlayJsonMs: round2(overlayJsonMs),
    structuredCloneMs,
  };
}

function summarizePerf4TraceGrowth(world) {
  const bands = Object.values(world.bands);
  const activeBands = bands.filter(isActiveBand);
  const activeCount = Math.max(1, activeBands.length);
  const reportStates = bands.map((band) => band.reportedKnowledge).filter((state) => state !== undefined);
  const reports = reportStates.flatMap((state) => state.reports ?? []);
  const speculations = reportStates.flatMap((state) => state.speculations ?? []);
  const rangeFrictionEvents = bands.flatMap((band) => band.recentRangeFrictionEvents ?? []);
  const residentialMoveEvents = bands.flatMap((band) => band.recentResidentialMoveEvents ?? []);
  const recentTrips = bands.flatMap((band) => band.recentIntraSeasonTrips ?? []);
  const movementHistory = bands.flatMap((band) => band.movementHistory ?? []);
  const crossingMemoriesTotal = sumBands(bands, (band) => Object.keys(band.crossingMemories ?? {}).length);
  const knownTilesTotal = sumBands(bands, (band) => Object.keys(band.knowledge.observedTiles).length);
  const placeMemoriesTotal = sumBands(bands, (band) => Object.keys(band.placeMemory).length);
  const corridorMemoriesTotal = sumBands(bands, (band) => Object.keys(band.travelCorridors).length);

  return {
    activeBands: activeBands.length,
    totalBands: bands.length,
    knownTilesTotal,
    knownTilesAverageActive: round2(knownTilesTotal / activeCount),
    knownTilesMaxBand: getMaxRecordCount(bands, (band) => Object.keys(band.knowledge.observedTiles).length),
    compressedKnownTileSummariesTotal: sumBands(
      bands,
      (band) => band.knowledge.compressedKnownTileSummaries?.length ?? 0,
    ),
    placeMemoriesTotal,
    placeMemoriesAverageActive: round2(placeMemoriesTotal / activeCount),
    placeMemoriesMaxBand: getMaxRecordCount(bands, (band) => Object.keys(band.placeMemory).length),
    corridorMemoriesTotal,
    corridorMemoriesAverageActive: round2(corridorMemoriesTotal / activeCount),
    corridorMemoriesMaxBand: getMaxRecordCount(bands, (band) => Object.keys(band.travelCorridors).length),
    compressedCorridorSummariesTotal: sumBands(bands, (band) => band.compressedCorridorSummaries?.length ?? 0),
    crossingMemoriesTotal,
    movementHistoryTotal: movementHistory.length,
    movementHistoryMaxBand: getMaxRecordCount(bands, (band) => band.movementHistory?.length ?? 0),
    recentActivityTripsTotal: recentTrips.length,
    recentActivityTripsMaxBand: getMaxRecordCount(bands, (band) => band.recentIntraSeasonTrips?.length ?? 0),
    residentialMoveEventsTotal: residentialMoveEvents.length,
    residentialMoveEventsMaxBand: getMaxRecordCount(bands, (band) => band.recentResidentialMoveEvents?.length ?? 0),
    activeReportsTotal: reports.length,
    activeReportsMaxBand: getMaxRecordCount(bands, (band) => band.reportedKnowledge?.reports?.length ?? 0),
    activeSpeculationsTotal: speculations.length,
    activeSpeculationsMaxBand: getMaxRecordCount(bands, (band) => band.reportedKnowledge?.speculations?.length ?? 0),
    reportsExpiredOrFadedCount: sumBands(bands, (band) => band.reportedKnowledge?.expiredOrFadedCount ?? 0),
    reportsMergedSimilarCount: sumBands(bands, (band) => band.reportedKnowledge?.mergedSimilarCount ?? 0),
    reportsMisleadingCount: sumBands(bands, (band) => band.reportedKnowledge?.misleadingCount ?? 0),
    reportsCheckedByProbeCount: sumBands(bands, (band) => band.reportedKnowledge?.checkedByProbeCount ?? 0),
    reportsActedOnCount: sumBands(bands, (band) => band.reportedKnowledge?.actedOnCount ?? 0),
    rangeFrictionEventsTotal: rangeFrictionEvents.length,
    rangeFrictionEventsMaxBand: getMaxRecordCount(bands, (band) => band.recentRangeFrictionEvents?.length ?? 0),
    rangeFrictionByInterpretation: countBy(rangeFrictionEvents, (event) => event.interpretation),
    reportTopics: countBy(reports, (report) => report.topic),
    reportTrustBasis: countBy(reports, (report) => report.trustBasis),
    reportConfirmationStatus: countBy(reports, (report) => report.confirmationStatus),
    decisionRecordsTotal: Object.keys(world.decisions).length,
    decisionHistoryTotal: sumBands(bands, (band) => band.decisionHistory.length),
    causalTracesTotal: sumBands(bands, (band) => band.causalTraces.length),
    tileDepletionRecords: Object.keys(world.tileDepletion ?? {}).length,
  };
}

function sumBands(bands, selector) {
  return bands.reduce((sum, band) => sum + selector(band), 0);
}

function countBy(values, keySelector) {
  const counts = {};

  for (const value of values) {
    const key = keySelector(value);
    counts[key] = (counts[key] ?? 0) + 1;
  }

  return counts;
}

function filterCountMap(counts, predicate) {
  return Object.fromEntries(
    Object.entries(counts).filter(([key]) => predicate(key)),
  );
}

function mergeCountMaps(left, right) {
  const merged = { ...left };
  for (const [key, value] of Object.entries(right)) {
    merged[key] = (merged[key] ?? 0) + value;
  }
  return merged;
}

function getPerf4MemoryPlan() {
  return [
    {
      structure: "known tiles / place memory",
      owner: "Band.knowledge / Band.placeMemory",
      currentGrowth: "bounded by explored map, behavior-affecting",
      capPlan: "keep detailed; future compaction must preserve decision summaries",
      behaviorAffecting: true,
    },
    {
      structure: "activity trips",
      owner: "Band.recentIntraSeasonTrips",
      currentGrowth: "recent ring",
      capPlan: "keep detailed recent ring; aggregate old activity only in audits if needed",
      behaviorAffecting: true,
    },
    {
      structure: "word-of-mouth reports",
      owner: "Band.reportedKnowledge",
      currentGrowth: "active/recent capped rings plus counters",
      capPlan: "active detailed reports stay capped; expired/faded/merged remain counters",
      behaviorAffecting: true,
    },
    {
      structure: "range friction events",
      owner: "Band.recentRangeFrictionEvents",
      currentGrowth: "recent ring",
      capPlan: "keep detailed recent ring; long-term summaries only if UI needs them",
      behaviorAffecting: false,
    },
    {
      structure: "residential move events",
      owner: "Band.recentResidentialMoveEvents",
      currentGrowth: "recent ring",
      capPlan: "keep detailed recent ring; preserve major routes/milestones in summaries later",
      behaviorAffecting: false,
    },
    {
      structure: "movement history / decision archive",
      owner: "Band.movementHistory / world.decisionArchive",
      currentGrowth: "bounded recent history",
      capPlan: "keep recent detail; salient long-term milestones can be summarized later",
      behaviorAffecting: true,
    },
    {
      structure: "worker dynamic snapshot",
      owner: "simRunner.takeDynamicSnapshot",
      currentGrowth: "scales with all dynamic band memory",
      capPlan: "send rarely while running; live overlay carries frequent map data",
      behaviorAffecting: false,
    },
  ];
}

// ---------------------------------------------------------------------------
// M0.10 — Migration / Saturation audit (Map 1 + Map 2). AUDIT ONLY: it never
// forces migration outcomes; it measures what the existing sim produces and
// answers the dry-margin clustering / wetland saturation / world-filling
// questions from observable band state, band-known knowledge vs truth, intent
// candidates (audit reader), and colonization rejection reasons.
// ---------------------------------------------------------------------------

const MIGRATION_AUDIT_SNAPSHOT_YEARS = [50, 100, 150, 200, 300];

const MAP2_DRY_RIVER_PATH = [
  { x: 50, y: 106 },
  { x: 74, y: 110 },
  { x: 98, y: 114 },
  { x: 122, y: 118 },
  { x: 146, y: 120 },
  { x: 166, y: 122 },
];

function migrationAuditPathDistance(point, path) {
  let nearest = Number.POSITIVE_INFINITY;
  for (let index = 0; index < path.length - 1; index += 1) {
    const a = path[index];
    const b = path[index + 1];
    const abx = b.x - a.x;
    const aby = b.y - a.y;
    const lengthSq = abx * abx + aby * aby;
    const t = lengthSq === 0 ? 0 : Math.max(0, Math.min(1, ((point.x - a.x) * abx + (point.y - a.y) * aby) / lengthSq));
    const px = a.x + abx * t;
    const py = a.y + aby * t;
    nearest = Math.min(nearest, Math.hypot(point.x - px, point.y - py));
  }
  return nearest;
}

function parseTileCoord(tileId) {
  const parts = String(tileId).split(":");
  return { x: Number(parts[1]), y: Number(parts[2]) };
}

function coordDistance(a, b) {
  return Math.hypot(a.x - b.x, a.y - b.y);
}

function classifyMap1Catchment(tile) {
  const point = tile.coord;
  if (coordDistance(point, { x: 58, y: 74 }) <= 16) return "lake_wetland_basin";
  if (coordDistance(point, { x: 134, y: 65 }) <= 16) return "delta_estuary";
  if (tile.isRiver || tile.isFloodplain || tile.isRiverbank) return "river_corridor";
  if (tile.elevation >= 0.55) return "highlands";
  if (tile.riskProfile.droughtRisk >= 0.5) return "dry_interior";
  return "open_plains";
}

function classifyMap2Catchment(tile) {
  const point = tile.coord;
  if (coordDistance(point, { x: 78, y: 72 }) <= 17) return "rich_lake_basin";
  if (coordDistance(point, { x: 172, y: 30 }) <= 14) return "ne_isolated_basin";
  if (coordDistance(point, { x: 196, y: 92 }) <= 16) return "delta_estuary";
  if (migrationAuditPathDistance(point, MAP2_DRY_RIVER_PATH) <= 5 && point.x < 150) return "dry_corridor";
  const greenDx = (point.x - 172) / 32;
  const greenDy = (point.y - 112) / 22;
  if (greenDx * greenDx + greenDy * greenDy <= 1) return "green_lowlands";
  if (tile.isRiver || tile.isFloodplain || tile.isRiverbank) return "river_corridor";
  if (tile.elevation >= 0.55) return "highlands";
  if (point.y <= 24 && point.x >= 56) return "north_steppe";
  if (tile.riskProfile.droughtRisk >= 0.5) return "dry_interior";
  return "open_plains";
}

function migrationAuditBandReturn(band) {
  return (
    band.carryingCapacity?.perCapitaReturn?.perCapitaReturn ??
    band.perCapitaReturn?.perCapitaReturn ??
    null
  );
}

// M0.11: the sustained-over-capacity penalty currently reducing the band's
// effective per-capita return (0 when the band is not in a sustained crowd).
function migrationAuditBandPenalty(band) {
  return (
    band.carryingCapacity?.perCapitaReturn?.saturationPenalty ??
    band.perCapitaReturn?.saturationPenalty ??
    null
  );
}

function takeMigrationSnapshot(world, classify) {
  const activeBands = Object.values(world.bands).filter(isActiveBand);
  const byCatchment = {};
  const positions = [];

  for (const band of activeBands) {
    const tile = world.tiles[band.position];
    if (tile === undefined) continue;
    const catchment = classify(tile);
    const bucket = byCatchment[catchment] ?? {
      bands: 0, population: 0, returnSum: 0, returnCount: 0,
      saturationSum: 0, saturationCount: 0, foodStressSum: 0, foodStressCount: 0,
      splitPressureSum: 0, saturationV1Sum: 0, saturationV1Count: 0,
      penaltySum: 0, penaltyCount: 0, wearSum: 0, wearCount: 0,
    };
    bucket.bands += 1;
    bucket.population += band.demography.population;
    const perCapita = migrationAuditBandReturn(band);
    if (perCapita !== null) { bucket.returnSum += perCapita; bucket.returnCount += 1; }
    const saturation = band.rangeSaturation?.saturationPressure;
    if (saturation !== undefined) { bucket.saturationSum += saturation; bucket.saturationCount += 1; }
    // M0.11: demand-vs-shared-capacity saturation + the per-capita penalty it drives.
    const saturationV1 = band.rangeSaturation?.saturation;
    if (saturationV1 !== undefined) { bucket.saturationV1Sum += saturationV1; bucket.saturationV1Count += 1; }
    const penalty = migrationAuditBandPenalty(band);
    if (penalty !== null) { bucket.penaltySum += penalty; bucket.penaltyCount += 1; }
    const wear = band.perCapitaReturn?.supportDebug?.footprintDepletionPenalty ??
      band.carryingCapacity?.perCapitaReturn?.supportDebug?.footprintDepletionPenalty;
    if (wear !== undefined) { bucket.wearSum += wear; bucket.wearCount += 1; }
    const foodStress = band.pressureState?.foodStress;
    if (foodStress !== undefined) { bucket.foodStressSum += foodStress; bucket.foodStressCount += 1; }
    bucket.splitPressureSum += band.demography.splitPressure;
    byCatchment[catchment] = bucket;
    positions.push(tile.coord);
  }

  // M0.14: per-catchment persistent-depletion summary (physical wear) + the
  // most-worn tiles with what a NEWCOMER would observe there now.
  const depletionByCatchment = {};
  const depletionEntries = Object.entries(world.tileDepletion ?? {});
  for (const [tileId, value] of depletionEntries) {
    const tile = world.tiles[tileId];
    if (tile === undefined) continue;
    const catchment = classify(tile);
    const bucket = depletionByCatchment[catchment] ?? { tiles: 0, sum: 0, max: 0 };
    bucket.tiles += 1;
    bucket.sum += value;
    bucket.max = Math.max(bucket.max, value);
    depletionByCatchment[catchment] = bucket;
  }
  const topDepletedTiles = depletionEntries
    .slice()
    .sort((a, b) => b[1] - a[1] || (a[0] < b[0] ? -1 : 1))
    .slice(0, 8)
    .map(([tileId, value]) => {
      const tile = world.tiles[tileId];
      return {
        tileId,
        depletion: value,
        catchment: tile === undefined ? null : classify(tile),
        pristineRichness: tile === undefined ? null : round3(tile.resourceProfile.baseRichness),
        newcomerObservesRichness: tile === undefined
          ? null
          : round3(tile.resourceProfile.baseRichness * (1 - value * 0.6)),
      };
    });

  const catchments = {};
  for (const [name, bucket] of Object.entries(byCatchment)) {
    catchments[name] = {
      bands: bucket.bands,
      population: bucket.population,
      meanPerCapitaReturn: bucket.returnCount === 0 ? null : round3(bucket.returnSum / bucket.returnCount),
      meanSaturationPressure: bucket.saturationCount === 0 ? null : round3(bucket.saturationSum / bucket.saturationCount),
      meanSaturationV1: bucket.saturationV1Count === 0 ? null : round3(bucket.saturationV1Sum / bucket.saturationV1Count),
      meanSaturationPenalty: bucket.penaltyCount === 0 ? null : round3(bucket.penaltySum / bucket.penaltyCount),
      meanFootprintDepletion: bucket.wearCount === 0 ? null : round3(bucket.wearSum / bucket.wearCount),
      tileDepletion: depletionByCatchment[name] === undefined ? null : {
        tiles: depletionByCatchment[name].tiles,
        mean: round3(depletionByCatchment[name].sum / depletionByCatchment[name].tiles),
        max: round3(depletionByCatchment[name].max),
      },
      meanFoodStress: bucket.foodStressCount === 0 ? null : round3(bucket.foodStressSum / bucket.foodStressCount),
      meanSplitPressure: bucket.bands === 0 ? null : round3(bucket.splitPressureSum / bucket.bands),
    };
  }

  let pairSum = 0;
  let pairCount = 0;
  let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
  for (let i = 0; i < positions.length; i += 1) {
    minX = Math.min(minX, positions[i].x); maxX = Math.max(maxX, positions[i].x);
    minY = Math.min(minY, positions[i].y); maxY = Math.max(maxY, positions[i].y);
    for (let j = i + 1; j < positions.length; j += 1) {
      pairSum += Math.abs(positions[i].x - positions[j].x) + Math.abs(positions[i].y - positions[j].y);
      pairCount += 1;
    }
  }

  return {
    year: world.time.year,
    totalBands: activeBands.length,
    totalPopulation: activeBands.reduce((sum, band) => sum + band.demography.population, 0),
    catchments,
    topDepletedTiles,
    worldFill: {
      occupiedCatchments: Object.keys(catchments).length,
      meanPairwiseBandDistance: pairCount === 0 ? null : round2m(pairSum / pairCount),
      bandBoundingBoxArea: positions.length === 0 ? 0 : (maxX - minX + 1) * (maxY - minY + 1),
    },
  };
}

function round3(value) { return Math.round(value * 1000) / 1000; }
function round2m(value) { return Math.round(value * 100) / 100; }

// Greener-alternative knowledge audit for one band: TRUTH tiles within range
// that are meaningfully greener than home, classified by whether the band has
// OBSERVED them, only INFERRED them (existence-only), or never knows (truth-only).
function auditGreenerAlternatives(world, band, range = 14) {
  const homeTile = world.tiles[band.position];
  if (homeTile === undefined) return null;
  const homeRich = homeTile.resourceProfile.baseRichness;
  const home = homeTile.coord;
  let observed = 0;
  let inferredOnly = 0;
  let truthOnly = 0;
  let nearestObserved = null;
  let nearestInferred = null;
  let nearestTruth = null;

  for (const tile of Object.values(world.tiles)) {
    if (tile.isAquatic) continue;
    const manhattan = Math.abs(tile.coord.x - home.x) + Math.abs(tile.coord.y - home.y);
    if (manhattan === 0 || manhattan > range) continue;
    if (tile.resourceProfile.baseRichness < homeRich + 0.15) continue;
    if (tile.resourceProfile.waterAccess < 0.4) continue;

    if (band.knowledge.observedTiles[tile.id] !== undefined) {
      observed += 1;
      nearestObserved = nearestObserved === null ? manhattan : Math.min(nearestObserved, manhattan);
    } else if (band.frontierKnowledge?.inferredTiles?.[tile.id] !== undefined) {
      inferredOnly += 1;
      nearestInferred = nearestInferred === null ? manhattan : Math.min(nearestInferred, manhattan);
    } else {
      truthOnly += 1;
      nearestTruth = nearestTruth === null ? manhattan : Math.min(nearestTruth, manhattan);
    }
  }

  return {
    bandId: band.id,
    homeTile: String(band.position),
    homeRichness: round2m(homeRich),
    homeWaterAccess: round2m(homeTile.resourceProfile.waterAccess),
    greenerWithinRange: { observed, inferredOnly, truthOnly },
    nearestGreener: { observed: nearestObserved, inferredOnly: nearestInferred, truthOnly: nearestTruth },
    range,
  };
}

// Intent-candidate introspection for one band (audit-only reader): which intent
// candidates exist RIGHT NOW, is any of them "greener" in truth, and does the
// would-be selection pick it?
function auditBandIntentCandidates(world, band, modules) {
  const result = modules.auditMobilityIntentCandidates(world, band);
  if (result === undefined) return null;
  const homeTile = world.tiles[band.position];
  const homeRich = homeTile?.resourceProfile.baseRichness ?? 0;

  const candidates = result.candidates.map((candidate) => {
    const targetTile = candidate.targetTileId === undefined ? undefined : world.tiles[candidate.targetTileId];
    return {
      kind: candidate.kind,
      targetTileId: candidate.targetTileId === undefined ? undefined : String(candidate.targetTileId),
      score: candidate.score,
      targetTruthRichness: targetTile === undefined ? null : round2m(targetTile.resourceProfile.baseRichness),
      targetIsGreenerTruth: targetTile === undefined ? false : targetTile.resourceProfile.baseRichness > homeRich + 0.1,
    };
  });
  const greener = candidates.filter((candidate) => candidate.targetIsGreenerTruth);
  const topScore = candidates.length === 0 ? null : candidates[0].score;

  return {
    bandId: band.id,
    currentValue: result.currentValue,
    knownTileCount: result.knownTileCount,
    mobilityPressure: result.mobilityPressure,
    wouldSelectKind: result.wouldSelectKind,
    wouldSelectTargetTileId: result.wouldSelectTargetTileId === undefined ? undefined : String(result.wouldSelectTargetTileId),
    candidateCount: candidates.length,
    candidates,
    greenerCandidateGenerated: greener.length > 0,
    greenerCandidateWouldWin: greener.length > 0 && candidates[0]?.targetIsGreenerTruth === true,
    bestGreenerScoreGapToWinner: greener.length === 0 || topScore === null
      ? null
      : round3(topScore - Math.max(...greener.map((candidate) => candidate.score))),
  };
}

// Saturation/colonization introspection for one band (rich-basin deep dive).
// M0.12: per-band corridor-continuation inference snapshot — how many corridor
// beliefs the band currently carries, how far they reach (Manhattan from the
// band), plus the margin-sourced count for contrast. Existence-only knowledge;
// reporting it leaks nothing into behaviour.
function auditCorridorInference(world, band) {
  const inferred = band.frontierKnowledge?.inferredTiles ?? {};
  const here = parseTileCoord(band.position);
  let corridorCount = 0;
  let marginCount = 0;
  let sideCount = 0;
  let creekCorridorCount = 0;
  let maxCorridorDistance = 0;
  let maxSideDistance = 0;

  for (const [tileId, record] of Object.entries(inferred)) {
    if (record.source === "corridor_continuation_inference") {
      corridorCount += 1;
      if (world.tiles[tileId]?.hasCreek === true) creekCorridorCount += 1;
      const coord = parseTileCoord(tileId);
      maxCorridorDistance = Math.max(
        maxCorridorDistance,
        Math.abs(coord.x - here.x) + Math.abs(coord.y - here.y),
      );
    } else if (record.source === "off_corridor_side_inference") {
      // M0.16: perpendicular off-corridor side belief (existence-only).
      sideCount += 1;
      const coord = parseTileCoord(tileId);
      maxSideDistance = Math.max(
        maxSideDistance,
        Math.abs(coord.x - here.x) + Math.abs(coord.y - here.y),
      );
    } else {
      marginCount += 1;
    }
  }

  return { corridorCount, marginCount, sideCount, creekCorridorCount, maxCorridorDistance, maxSideDistance };
}

function auditBandSaturation(world, band) {
  const colonization = band.daughterColonization;
  const opportunity = colonization?.bestKnownUnusedHabitatOpportunity;
  const opportunityTile = opportunity === undefined ? undefined : world.tiles[opportunity.candidateTileId];
  const homeTile = world.tiles[band.position];

  const saturationPenalty = migrationAuditBandPenalty(band);
  const perCapitaReturn = migrationAuditBandReturn(band);

  return {
    bandId: band.id,
    population: band.demography.population,
    perCapitaReturn,
    // M0.11: effective return before/after the sustained-saturation coupling.
    effectiveReturnBeforePenalty: perCapitaReturn === null || saturationPenalty === null
      ? null
      : round2m(Math.min(1, perCapitaReturn + saturationPenalty)),
    saturationPenalty,
    sustainedOverCapacity: band.carryingCapacity?.perCapitaReturn?.sustainedOverCapacity ??
      band.perCapitaReturn?.sustainedOverCapacity ?? null,
    saturationV1: band.rangeSaturation?.saturation ?? null,
    supportRatio: band.perCapitaReturn?.supportDebug?.rawSupportRatio ??
      band.carryingCapacity?.perCapitaReturn?.supportDebug?.rawSupportRatio ?? null,
    sharedCatchmentPressure: band.perCapitaReturn?.sharedCatchmentPressure ??
      band.carryingCapacity?.perCapitaReturn?.sharedCatchmentPressure ?? null,
    saturationPressure: band.rangeSaturation?.saturationPressure ?? null,
    localBandCount: band.rangeSaturation?.localBandCount ?? null,
    nearbyCrowding: band.rangeSaturation?.nearbyCrowding ?? null,
    splitPressure: round2m(band.demography.splitPressure),
    foodStress: band.pressureState?.foodStress ?? null,
    frontierDispersalPressure: band.frontierDispersal?.pressure ?? null,
    colonization: colonization === undefined ? null : {
      pressure: colonization.pressure,
      recommendedAction: colonization.recommendedAction,
      opportunity: opportunity === undefined ? null : {
        tileId: String(opportunity.candidateTileId),
        kind: opportunity.opportunityKind,
        expectedPerCapitaReturn: opportunity.expectedPerCapitaReturn,
        consideredAsTarget: opportunity.consideredAsTarget,
        // M0.13: did this candidate become a target only because crowding
        // relaxed the comparison margin (less competition is worth something)?
        competitionMarginRelaxed: opportunity.competitionMarginRelaxed ?? 0,
        wonByLowerCompetition:
          opportunity.consideredAsTarget === true &&
          (opportunity.competitionMarginRelaxed ?? 0) > 0 &&
          opportunity.expectedPerCapitaReturn <= (band.perCapitaReturn?.perCapitaReturn ?? 0.5) + 0.08,
        rejectionReason: opportunity.rejectionReason ?? null,
        truthRichness: opportunityTile === undefined ? null : round2m(opportunityTile.resourceProfile.baseRichness),
        truthRichnessVsHome: opportunityTile === undefined || homeTile === undefined
          ? null
          : round2m(opportunityTile.resourceProfile.baseRichness - homeTile.resourceProfile.baseRichness),
      },
    },
  };
}

function runMigrationSaturationAuditForMap(modules, mapLabel, makeWorld, classify, dryRootIds, basinCatchment, years) {
  const metrics = createEmptyMetrics();
  let world = makeWorld();
  const ticksRequested = years * 4;
  const snapshotYears = MIGRATION_AUDIT_SNAPSHOT_YEARS.filter((year) => year <= years);
  const snapshotTicks = new Map(snapshotYears.map((year) => [year * 4, year]));
  const snapshots = [];
  const dryLineagePositions = {};

  // M0.13: per-tick lightweight tracking — daughter founder journeys
  // (displacement at +5/10/25y, intent retention, new-catchment founding) and
  // creek-following moves. O(active bands) per tick.
  const daughterJourneys = new Map();
  const DISPLACEMENT_CHECK_TICKS = [20, 40, 100];
  let creekMoves = 0;
  let totalMoves = 0;
  const previousPositions = new Map(
    Object.values(world.bands).filter(isActiveBand).map((band) => [String(band.id), String(band.position)]),
  );

  const initialSnapshot = takeMigrationSnapshot(applyDispersalAuditContextOnly(modules, world), classify);
  snapshots.push(initialSnapshot);

  for (let tickIndex = 0; tickIndex < ticksRequested; tickIndex += 1) {
    world = advanceInstrumentedOneSeason(modules, world, metrics, { fast: true, probeAudit: false }).world;
    metrics.ticksSimulated += 1;

    const tickNow = Number(world.time.tick);
    for (const band of Object.values(world.bands).filter(isActiveBand)) {
      const key = String(band.id);
      const previous = previousPositions.get(key);
      if (previous !== undefined && previous !== String(band.position)) {
        totalMoves += 1;
        const movedToTile = world.tiles[band.position];
        if (movedToTile !== undefined && movedToTile.hasCreek === true) creekMoves += 1;
      }
      previousPositions.set(key, String(band.position));

      if (band.parentBandId !== undefined && !daughterJourneys.has(key)) {
        const tile = world.tiles[band.position];
        daughterJourneys.set(key, {
          spawnTick: tickNow,
          origin: parseTileCoord(band.position),
          originCatchment: tile === undefined ? null : classify(tile),
          intentAtSpawn: band.frontierIntent !== undefined,
          intentAt20: null,
          displacement: {},
          catchmentAt100: undefined,
        });
      }
      const journey = daughterJourneys.get(key);
      if (journey !== undefined) {
        const age = tickNow - journey.spawnTick;
        if (age === 20) journey.intentAt20 = band.frontierIntent !== undefined;
        if (DISPLACEMENT_CHECK_TICKS.includes(age)) {
          const pos = parseTileCoord(band.position);
          journey.displacement[age] = Math.abs(pos.x - journey.origin.x) + Math.abs(pos.y - journey.origin.y);
          if (age === 100) {
            const tileNow = world.tiles[band.position];
            journey.catchmentAt100 = tileNow === undefined ? null : classify(tileNow);
          }
        }
      }
    }

    const snapshotYear = snapshotTicks.get(Number(world.time.tick));
    if (snapshotYear !== undefined) {
      const contextWorld = applyDispersalAuditContextOnly(modules, world);
      snapshots.push(takeMigrationSnapshot(contextWorld, classify));
      for (const band of Object.values(contextWorld.bands).filter(isActiveBand)) {
        if (dryRootIds.some((rootId) => String(band.id).startsWith(rootId))) {
          const list = dryLineagePositions[band.id] ?? [];
          const tile = contextWorld.tiles[band.position];
          list.push({ year: snapshotYear, tile: String(band.position), catchment: tile === undefined ? null : classify(tile) });
          dryLineagePositions[band.id] = list;
        }
      }
    }
  }

  const finalWorld = applyDispersalAuditContextOnly(modules, world);
  const finalBands = Object.values(finalWorld.bands).filter(isActiveBand);
  const bandById = new Map(finalBands.map((band) => [String(band.id), band]));

  // --- Fission ledger -------------------------------------------------------
  const fissionEvents = getUniqueFissionEvents(Object.values(finalWorld.bands));
  const fissionRows = fissionEvents.map((event) => {
    const origin = parseTileCoord(event.originTileId);
    const target = event.targetTileId === undefined ? origin : parseTileCoord(event.targetTileId);
    const originTile = finalWorld.tiles[event.originTileId];
    const daughter = bandById.get(String(event.daughterBandId));
    const parent = bandById.get(String(event.parentBandId));
    const daughterNow = daughter === undefined ? undefined : parseTileCoord(daughter.position);
    const parentNow = parent === undefined ? undefined : parseTileCoord(parent.position);
    const finalDistanceFromOrigin = daughterNow === undefined
      ? null
      : Math.abs(daughterNow.x - origin.x) + Math.abs(daughterNow.y - origin.y);
    const finalDistanceFromParent = daughterNow === undefined || parentNow === undefined
      ? null
      : Math.abs(daughterNow.x - parentNow.x) + Math.abs(daughterNow.y - parentNow.y);

    return {
      tick: Number(event.tick),
      year: Math.floor(Number(event.tick) / 4),
      parentBandId: String(event.parentBandId),
      daughterBandId: String(event.daughterBandId),
      originCatchment: originTile === undefined ? null : classify(originTile),
      spawnDistance: Math.abs(target.x - origin.x) + Math.abs(target.y - origin.y),
      daughterAlive: daughter !== undefined,
      finalDistanceFromOrigin,
      finalDistanceFromParent,
      isLocalSatellite: finalDistanceFromParent !== null && finalDistanceFromParent <= 4,
      isOutwardDispersal: finalDistanceFromOrigin !== null && finalDistanceFromOrigin >= 8,
    };
  });
  const fissionsByCatchment = {};
  for (const row of fissionRows) {
    const key = row.originCatchment ?? "unknown";
    const bucket = fissionsByCatchment[key] ?? { fissions: 0, localSatellites: 0, outwardDispersals: 0, meanSpawnDistanceSum: 0 };
    bucket.fissions += 1;
    bucket.localSatellites += row.isLocalSatellite ? 1 : 0;
    bucket.outwardDispersals += row.isOutwardDispersal ? 1 : 0;
    bucket.meanSpawnDistanceSum += row.spawnDistance;
    fissionsByCatchment[key] = bucket;
  }
  for (const bucket of Object.values(fissionsByCatchment)) {
    bucket.meanSpawnDistance = round2m(bucket.meanSpawnDistanceSum / Math.max(1, bucket.fissions));
    delete bucket.meanSpawnDistanceSum;
  }

  // --- Dry-margin deep dive -------------------------------------------------
  const dryBands = finalBands.filter((band) => dryRootIds.some((rootId) => String(band.id).startsWith(rootId)));
  const dryFinal = dryBands.map((band) => {
    const tile = finalWorld.tiles[band.position];
    return {
      bandId: String(band.id),
      finalTile: String(band.position),
      finalCatchment: tile === undefined ? null : classify(tile),
      population: band.demography.population,
      // M0.12: is corridor-continuation inference forming downstream knowledge?
      corridorInference: auditCorridorInference(finalWorld, band),
      observedTileCount: Object.keys(band.knowledge?.observedTiles ?? {}).length,
      greenerAlternatives: auditGreenerAlternatives(finalWorld, band),
      intentCandidates: auditBandIntentCandidates(finalWorld, band, modules),
    };
  });
  const dryStayers = dryFinal.filter((entry) =>
    entry.finalCatchment === "dry_corridor" || entry.finalCatchment === "dry_interior").length;
  const dryEscapes = Object.values(dryLineagePositions).filter((positions) =>
    positions.some((entry) => entry.catchment !== "dry_corridor" && entry.catchment !== "dry_interior")).length;

  // --- Wetland/basin saturation deep dive ------------------------------------
  const basinBands = finalBands.filter((band) => {
    const tile = finalWorld.tiles[band.position];
    return tile !== undefined && classify(tile) === basinCatchment;
  });
  const basinAudit = basinBands.map((band) => auditBandSaturation(finalWorld, band));

  // --- M0.11 recovery experiment -------------------------------------------
  // Does saturation pressure recover when the crowd leaves? Keep ONLY the most
  // saturated basin band (audit-side world surgery), re-derive context twice
  // (the sustained min-window plus cache settling), and compare its
  // saturation/penalty/return. The penalty is a pure per-tick derivation, so it
  // should drop to ~0 once local population falls back under capacity.
  let saturationRecovery = null;
  const mostSaturated = basinBands
    .slice()
    .sort((a, b) =>
      (b.rangeSaturation?.saturation ?? 0) - (a.rangeSaturation?.saturation ?? 0) ||
      String(a.id).localeCompare(String(b.id)))[0];

  if (mostSaturated !== undefined && basinBands.length > 1) {
    const removedIds = new Set(
      basinBands.filter((band) => band.id !== mostSaturated.id).map((band) => String(band.id)),
    );
    const thinnedBands = Object.fromEntries(
      Object.entries(finalWorld.bands).filter(([bandId]) => !removedIds.has(bandId)),
    );
    let thinned = { ...finalWorld, bands: thinnedBands };
    thinned = applyDispersalAuditContextOnly(modules, thinned);
    thinned = applyDispersalAuditContextOnly(modules, thinned);
    const after = thinned.bands[mostSaturated.id];
    const beforePenalty = migrationAuditBandPenalty(mostSaturated) ?? 0;
    const afterPenalty = after === undefined ? null : migrationAuditBandPenalty(after);

    saturationRecovery = {
      bandId: String(mostSaturated.id),
      removedBasinBands: removedIds.size,
      before: {
        saturationV1: mostSaturated.rangeSaturation?.saturation ?? null,
        saturationPenalty: beforePenalty,
        perCapitaReturn: migrationAuditBandReturn(mostSaturated),
      },
      after: after === undefined ? null : {
        saturationV1: after.rangeSaturation?.saturation ?? null,
        saturationPenalty: afterPenalty,
        perCapitaReturn: migrationAuditBandReturn(after),
      },
      pressureRecovered: afterPenalty !== null && afterPenalty <= Math.max(0, beforePenalty - 0.05),
    };
  }

  // M0.14 — recovery after abandonment: empty the most-worn catchment and
  // advance 20 years; persistent wear must REGENERATE (unlike the M0.11
  // crowding penalty, which recovers instantly, wear takes years).
  let depletionRecovery = null;
  {
    const sums = {};
    for (const [tileId, value] of Object.entries(finalWorld.tileDepletion ?? {})) {
      const tile = finalWorld.tiles[tileId];
      if (tile === undefined) continue;
      const c = classify(tile);
      const bucket = sums[c] ?? { n: 0, s: 0 };
      bucket.n += 1;
      bucket.s += value;
      sums[c] = bucket;
    }
    const ranked = Object.entries(sums).sort(
      (a, b) => b[1].s / b[1].n - a[1].s / a[1].n || (a[0] < b[0] ? -1 : 1),
    );
    const targetCatchment = ranked[0]?.[0];
    if (targetCatchment !== undefined) {
      const meanIn = (w) => {
        let n = 0; let s = 0;
        for (const [tileId, value] of Object.entries(w.tileDepletion ?? {})) {
          const tile = w.tiles[tileId];
          if (tile !== undefined && classify(tile) === targetCatchment) { n += 1; s += value; }
        }
        return n === 0 ? 0 : round3(s / n);
      };
      const before = meanIn(finalWorld);
      const removedIds = new Set(
        Object.values(finalWorld.bands)
          .filter(isActiveBand)
          .filter((b) => { const t = finalWorld.tiles[b.position]; return t !== undefined && classify(t) === targetCatchment; })
          .map((b) => String(b.id)),
      );
      let thinned = {
        ...finalWorld,
        bands: Object.fromEntries(Object.entries(finalWorld.bands).filter(([id]) => !removedIds.has(id))),
      };
      const recoveryMetrics = createEmptyMetrics();
      for (let i = 0; i < 80; i += 1) {
        thinned = advanceInstrumentedOneSeason(modules, thinned, recoveryMetrics, { fast: true, probeAudit: false }).world;
      }
      const after = meanIn(thinned);
      depletionRecovery = {
        catchment: targetCatchment,
        removedBands: removedIds.size,
        meanDepletionBefore: before,
        meanDepletionAfter20y: after,
        recovered: after < before,
      };
    }
  }

  const basinFissions = fissionRows.filter((row) => row.originCatchment === basinCatchment);
  const basinPileup = {
    finalBandsInBasin: basinBands.length,
    finalPopulationInBasin: basinBands.reduce((sum, band) => sum + band.demography.population, 0),
    basinFissions: basinFissions.length,
    basinLocalSatellites: basinFissions.filter((row) => row.isLocalSatellite).length,
    basinOutwardDispersals: basinFissions.filter((row) => row.isOutwardDispersal).length,
    pileupScore: basinFissions.length === 0
      ? 0
      : round3(basinFissions.filter((row) => row.isLocalSatellite).length / basinFissions.length),
  };

  const journeys = [...daughterJourneys.values()];
  const meanDisplacementAt = (age) => {
    const values = journeys.map((j) => j.displacement[age]).filter((v) => v !== undefined);
    return values.length === 0 ? null : round2m(values.reduce((a, b) => a + b, 0) / values.length);
  };
  const daughterJourneyAudit = {
    tracked: journeys.length,
    seededWithFounderIntent: journeys.filter((j) => j.intentAtSpawn).length,
    keptIntentAt5y: journeys.filter((j) => j.intentAt20 === true).length,
    meanDisplacement5y: meanDisplacementAt(20),
    meanDisplacement10y: meanDisplacementAt(40),
    meanDisplacement25y: meanDisplacementAt(100),
    newCatchmentFounders: journeys.filter(
      (j) => j.catchmentAt100 !== undefined && j.catchmentAt100 !== null && j.catchmentAt100 !== j.originCatchment,
    ).length,
  };
  const creekFollowing = {
    totalMoves,
    creekMoves,
    creekMoveShare: totalMoves === 0 ? 0 : round3(creekMoves / totalMoves),
  };

  // PERF-3: lightweight HEAT-1 migration-prep metrics (report-only; behaviour
  // is NOT tuned to these). They quantify whether a long run looks like
  // multi-region founding vs single-corridor diffusion — the question HEAT-1
  // (one-origin colonization) will formally test.
  const finalSnapshot = snapshots[snapshots.length - 1];
  const catchmentBandCounts = Object.fromEntries(
    Object.entries(finalSnapshot?.catchments ?? {}).map(([k, v]) => [k, v.bands]),
  );
  const distinctOccupiedCatchments = Object.values(catchmentBandCounts).filter((n) => n > 0).length;
  const maxDescendantDistanceFromOrigin = fissionRows.reduce(
    (max, row) => (row.finalDistanceFromOrigin !== null ? Math.max(max, row.finalDistanceFromOrigin) : max),
    0,
  );
  // Necklace/chain heuristic: outward dispersals that landed as satellites of
  // an EARLIER outward band (chain) vs those that founded a fresh catchment.
  const outwardRows = fissionRows.filter((row) => row.isOutwardDispersal);
  const regionFoundingDispersals = outwardRows.filter(
    (row) => row.originCatchment !== null && catchmentBandCounts[row.originCatchment] !== undefined,
  ).length;
  const migrationPrep = {
    occupiedCatchments: distinctOccupiedCatchments,
    catchmentBandCounts,
    boundingBoxArea: finalSnapshot?.worldFill.bandBoundingBoxArea ?? null,
    meanPairwiseBandDistance: finalSnapshot?.worldFill.meanPairwiseBandDistance ?? null,
    maxDescendantDistanceFromOrigin,
    newCatchmentFounders: daughterJourneyAudit.newCatchmentFounders,
    outwardDispersals: outwardRows.length,
    // Cheap classifier: many occupied catchments + high max-distance => region
    // founding; few catchments + bands strung along a corridor => diffusion.
    patternHint:
      distinctOccupiedCatchments >= 4 && maxDescendantDistanceFromOrigin >= 20
        ? "multi_region_founding"
        : maxDescendantDistanceFromOrigin >= 20
          ? "corridor_diffusion"
          : "local_cluster",
  };

  return {
    map: mapLabel,
    years,
    deterministicByConstruction: true,
    migrationPrep,
    daughterJourneyAudit,
    creekFollowing,
    snapshots,
    fissionsByCatchment,
    fissionRows,
    dryMargin: {
      lineageRoots: dryRootIds,
      stayers: dryStayers,
      lineageBandsTracked: Object.keys(dryLineagePositions).length,
      lineagesWithEscapeAttempt: dryEscapes,
      lineagePositions: dryLineagePositions,
      finalBands: dryFinal,
    },
    basinSaturation: {
      catchment: basinCatchment,
      pileup: basinPileup,
      bands: basinAudit,
      saturationRecovery,
    },
    depletionRecovery,
  };
}

// HEAT-1 — one-origin migration heat test. Spawns a SINGLE founding band on
// Map 2 and runs it across multiple runSeeds, measuring whether descendant
// lineages colonize MULTIPLE DISTINCT REGIONS vs collapsing into one cluster /
// a corridor necklace. Audit only — no behaviour change.
const HEAT_ORIGIN = { x: 108, y: 54 }; // single-origin spawn target (river valley)
const HEAT_CLUSTER_THRESHOLD = 8; // Manhattan tiles: bands within this = one cluster
const HEAT_FAR_DISTANCE = 25; // descendant distance from origin that counts as "far"

function heatClusterBands(positions, threshold) {
  const parent = positions.map((_, i) => i);
  const find = (i) => { let r = i; while (parent[r] !== r) { parent[r] = parent[parent[r]]; r = parent[r]; } return r; };
  for (let i = 0; i < positions.length; i += 1) {
    for (let j = i + 1; j < positions.length; j += 1) {
      if (Math.abs(positions[i].x - positions[j].x) + Math.abs(positions[i].y - positions[j].y) <= threshold) {
        parent[find(i)] = find(j);
      }
    }
  }
  const groups = new Map();
  positions.forEach((p, i) => {
    const r = find(i);
    const g = groups.get(r) ?? [];
    g.push(p);
    groups.set(r, g);
  });
  return [...groups.values()];
}

function heatClusterSpan(cluster) {
  let maxSpan = 0;
  for (let i = 0; i < cluster.length; i += 1) {
    for (let j = i + 1; j < cluster.length; j += 1) {
      maxSpan = Math.max(maxSpan, Math.abs(cluster[i].x - cluster[j].x) + Math.abs(cluster[i].y - cluster[j].y));
    }
  }
  return maxSpan;
}

function computeHeatMetrics(world, classify, isSideReach, pk) {
  const bands = Object.values(world.bands).filter(isActiveBand);
  const allBands = Object.values(world.bands);
  const positions = bands.map((b) => parseTileCoord(b.position));
  const originCatchmentTile = world.tiles[`tile:${HEAT_ORIGIN.x}:${HEAT_ORIGIN.y}`];
  const originCatchment = originCatchmentTile === undefined ? null : classify(originCatchmentTile);

  const catchmentBandCounts = {};
  const ecoZones = new Set();
  let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
  let maxDistFromOrigin = 0;
  let inOriginCatchment = 0;
  for (const b of bands) {
    const c = parseTileCoord(b.position);
    const tile = world.tiles[b.position];
    const cat = tile === undefined ? "unknown" : classify(tile);
    catchmentBandCounts[cat] = (catchmentBandCounts[cat] ?? 0) + 1;
    if (cat === originCatchment) inOriginCatchment += 1;
    if (tile !== undefined) ecoZones.add(tile.terrainKind);
    minX = Math.min(minX, c.x); maxX = Math.max(maxX, c.x);
    minY = Math.min(minY, c.y); maxY = Math.max(maxY, c.y);
    maxDistFromOrigin = Math.max(maxDistFromOrigin, Math.abs(c.x - HEAT_ORIGIN.x) + Math.abs(c.y - HEAT_ORIGIN.y));
  }

  const clusters = heatClusterBands(positions, HEAT_CLUSTER_THRESHOLD);
  const clusterInfo = clusters
    .map((cluster) => {
      const counts = {};
      for (const p of cluster) {
        const tile = world.tiles[`tile:${p.x}:${p.y}`];
        const cat = tile === undefined ? "unknown" : classify(tile);
        counts[cat] = (counts[cat] ?? 0) + 1;
      }
      const dominant = Object.entries(counts).sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0]))[0]?.[0] ?? "unknown";
      return { size: cluster.length, span: heatClusterSpan(cluster), dominantCatchment: dominant };
    })
    .sort((a, b) => b.size - a.size);

  // M0.16 — off-corridor knowledge footprint across active bands. Inferred side
  // tiles are source-based (definitionally 0 before M0.16). Observed side tiles
  // reuse the REAL isWithinSideReachOfCorridor predicate (memoized) so the metric
  // can never diverge from the formation rule — it counts the off-corridor
  // side-country bands actually SCOUTED into observation (the M0.7 probe
  // converting inferred → observed). Existence-only reporting; leaks no behaviour.
  let bandsWithSideInferred = 0;
  let totalSideInferred = 0;
  let maxSideInferred = 0;
  let bandsWithSideObserved = 0;
  let totalSideObserved = 0;
  let maxSideObserved = 0;
  // M0.16B: EXACT side-probe win count — each executed side-country probe increments the
  // band's sideProbeMemory.cumulativeSideProbes, so summing it over all bands (active +
  // extinct/absorbed, since a fissioned/absorbed band's probes still happened) gives the
  // total side probes WON across the whole run. (Daughters reset, so no double counting.)
  let sideProbesWon = 0;
  let bandsThatSideProbed = 0;
  let maxSideProbesOneBand = 0;
  for (const b of allBands) {
    const won = b.sideProbeMemory?.cumulativeSideProbes ?? 0;
    sideProbesWon += won;
    if (won > 0) bandsThatSideProbed += 1;
    maxSideProbesOneBand = Math.max(maxSideProbesOneBand, won);
  }
  for (const b of bands) {
    const inferredTiles = b.frontierKnowledge?.inferredTiles ?? {};
    let sideInferred = 0;
    for (const rec of Object.values(inferredTiles)) {
      if (rec.source === "off_corridor_side_inference") sideInferred += 1;
    }
    if (sideInferred > 0) bandsWithSideInferred += 1;
    totalSideInferred += sideInferred;
    maxSideInferred = Math.max(maxSideInferred, sideInferred);

    let sideObserved = 0;
    if (typeof isSideReach === "function") {
      for (const tileId of Object.keys(b.knowledge?.observedTiles ?? {})) {
        const tile = world.tiles[tileId];
        if (tile !== undefined && isSideReach(world, tile)) sideObserved += 1;
      }
    }
    if (sideObserved > 0) bandsWithSideObserved += 1;
    totalSideObserved += sideObserved;
    maxSideObserved = Math.max(maxSideObserved, sideObserved);
  }
  // M0.16B funnel diagnostic (final-snapshot estimate; mirrors buildSideCountryProbeCandidate's
  // gate so we can SEE where eligibility collapses): of active bands, how many hold a side
  // belief, how many are blocked by active expansion / food stress / not-settled, and how many
  // have a side belief within Manhattan 4 (a reachability proxy for the probe radius).
  let dHasSideBelief = 0, dBlockedIntent = 0, dBlockedStress = 0, dNotSettled = 0, dGatePass = 0, dNearSideTile = 0, dWouldFire = 0;
  for (const b of bands) {
    const inf = b.frontierKnowledge?.inferredTiles ?? {};
    let hasSide = false, nearSide = false;
    const here = parseTileCoord(b.position);
    for (const [tid, rec] of Object.entries(inf)) {
      if (rec.source !== "off_corridor_side_inference") continue;
      hasSide = true;
      const c = parseTileCoord(tid);
      if (Math.abs(c.x - here.x) + Math.abs(c.y - here.y) <= 4) { nearSide = true; }
    }
    if (!hasSide) continue;
    dHasSideBelief += 1;
    // intent is reported for context only — it is NOT a hard gate (residence-unchanged probe).
    const intentActive = (b.frontierIntent?.strength ?? 0) >= 0.5;
    const stress = (b.pressureState?.foodStress ?? 0) >= 0.6;
    const settled = b.frontierResidence?.established === true || (b.placeMemory?.[b.position]?.visitCount ?? 0) >= 3;
    if (intentActive) dBlockedIntent += 1;
    if (stress) dBlockedStress += 1;
    if (!settled) dNotSettled += 1;
    const gate = !stress && settled;
    if (gate) dGatePass += 1;
    if (nearSide) dNearSideTile += 1;
    if (gate && nearSide) dWouldFire += 1;
  }
  const sideProbeEligibility = {
    bandsWithSideBelief: dHasSideBelief,
    blockedByActiveIntent: dBlockedIntent,
    blockedByFoodStress: dBlockedStress,
    blockedByNotSettled: dNotSettled,
    gatePass: dGatePass,
    hasNearSideTileWithin4: dNearSideTile,
    eligibleAndReachable: dWouldFire,
  };

  const bandDivisor = bands.length === 0 ? 1 : bands.length;
  const offCorridorKnowledge = {
    bandsWithSideInferred,
    totalSideInferred,
    meanSideInferredPerBand: round3(totalSideInferred / bandDivisor),
    maxSideInferred,
    bandsWithSideObserved,
    totalSideObserved,
    meanSideObservedPerBand: round3(totalSideObserved / bandDivisor),
    maxSideObserved,
    // M0.16B consumption counters:
    sideProbesWon,
    bandsThatSideProbed,
    maxSideProbesOneBand,
    sideProbeEligibility,
  };

  // 2K.6 — in-vivo learned exploitation skill across active bands (read-only; the
  // skill state carries no yield/support, so reporting it leaks nothing). Shows the
  // substrate actually accruing from bands' own use-test/cause experience over a run.
  let skBandsWithSkill = 0, skTrackedClasses = 0, skSumComp = 0, skCompCount = 0, skMaxComp = 0;
  let skProcessingLearned = 0, skSuspected = 0, skConfirmed = 0;
  for (const b of bands) {
    const sk = b.exploitationSkill?.skills;
    if (sk === undefined) continue;
    const vals = Object.values(sk);
    if (vals.length > 0) skBandsWithSkill += 1;
    skTrackedClasses += vals.length;
    for (const s of vals) {
      skSumComp += s.competence; skCompCount += 1;
      if (s.competence > skMaxComp) skMaxComp = s.competence;
      if (s.processingState === "processing_learned") skProcessingLearned += 1;
      else if (s.processingState === "suspected_processing") skSuspected += 1;
      else if (s.processingState === "confirmed_problem") skConfirmed += 1;
    }
  }
  const exploitationSkill = {
    bandsWithSkill: skBandsWithSkill,
    totalTrackedClasses: skTrackedClasses,
    meanCompetence: skCompCount === 0 ? 0 : round3(skSumComp / skCompCount),
    maxCompetence: round3(skMaxComp),
    processingLearnedClasses: skProcessingLearned,
    suspectedProcessingClasses: skSuspected,
    confirmedProblemClasses: skConfirmed,
  };

  // 2K.7 — learned skill → effective-rank census across active bands. Derives each band's OWN
  // patch-return view WITH its skill (anti-omniscient: band-own inputs only; no truth) and counts
  // how many KNOWN patches actually receive a nonzero learned-rank delta + the signed
  // distribution. This is the surface area where learned skill COULD reorder a scout target;
  // an actual live re-ordering needs a near-tie at that patch (the deterministic targeted check
  // proves the flip exists). Read-only/derived — carries no yield/support, so reporting leaks nothing.
  let srBandsWithDelta = 0, srPatchesWithDelta = 0, srPosDelta = 0, srNegDelta = 0;
  let srMaxDelta = 0, srMinDelta = 0, srEstimatesScanned = 0;
  if (typeof pk?.deriveBandPatchReturnView === "function") {
    for (const b of bands) {
      if (b.exploitationSkill === undefined) continue;
      const view = pk.deriveBandPatchReturnView({
        currentTick: world.time.tick,
        resourceKnowledgeState: b.resourceKnowledgeState,
        recentPlantUseTests: b.recentPlantUseTests,
        recentCauseSpecificEvents: b.recentCauseSpecificEvents,
        exploitationSkill: b.exploitationSkill,
      });
      let bandHas = false;
      for (const e of view.estimates) {
        srEstimatesScanned += 1;
        if (e.learnedRankDelta !== 0) {
          srPatchesWithDelta += 1;
          bandHas = true;
          if (e.learnedRankDelta > 0) srPosDelta += 1; else srNegDelta += 1;
          if (e.learnedRankDelta > srMaxDelta) srMaxDelta = e.learnedRankDelta;
          if (e.learnedRankDelta < srMinDelta) srMinDelta = e.learnedRankDelta;
        }
      }
      if (bandHas) srBandsWithDelta += 1;
    }
  }
  const skillRankCoupling = {
    bandsWithLearnedRankDelta: srBandsWithDelta,
    patchesWithLearnedRankDelta: srPatchesWithDelta,
    positiveDeltaPatches: srPosDelta,
    negativeDeltaPatches: srNegDelta,
    maxLearnedRankDelta: round3(srMaxDelta),
    minLearnedRankDelta: round3(srMinDelta),
    estimatesScanned: srEstimatesScanned,
  };

  // 2K.8 — learned-support → opportunity-comparison census (the anti-sticky audit, read-only).
  // Separates learned support applied to the band's CURRENT/anchor range from that applied to a
  // NON-current candidate, and counts how often the winning candidate is a SIDE/off-corridor tile
  // that got learned support (the migration-enabling case). Decision-side only — these are
  // band-known opportunity terms, never realized CC. Read from each active band's persisted
  // nearbyOpportunity (already computed live this run).
  let soGateOpen = 0, soCurrent = 0, soCandidate = 0, soSideCandidate = 0;
  let soSumCurrent = 0, soSumCandidate = 0, soMaxCandidate = 0, soBestIsSideWithSupport = 0;
  for (const b of bands) {
    const no = b.nearbyOpportunity;
    if (no === undefined) continue;
    const gate = no.learnedSupportGate ?? 0;
    const cur = no.currentLearnedSupport ?? 0;
    const cand = no.bestCandidateLearnedSupport ?? 0;
    if (gate > 0) soGateOpen += 1;
    if (cur > 0) { soCurrent += 1; soSumCurrent += cur; }
    if (cand > 0) {
      soCandidate += 1; soSumCandidate += cand;
      if (cand > soMaxCandidate) soMaxCandidate = cand;
      const bestTileId = no.bestKnownOpportunityTileId;
      const bestTile = bestTileId === undefined ? undefined : world.tiles[bestTileId];
      if (bestTile !== undefined && typeof isSideReach === "function" && isSideReach(world, bestTile)) {
        soSideCandidate += 1; soBestIsSideWithSupport += 1;
      }
    }
  }
  // 2K.9 — realized learned usable-support census (read-only). WHERE did realized support actually
  // fire — origin catchment (the lock-in worry) vs secondary regions (the migration enabler)? Read
  // from each active band's persisted carryingCapacity supportDebug. Decision rule input.
  let rlBands = 0, rlOrigin = 0, rlSecondary = 0, rlSum = 0, rlMax = 0, rlProjected = 0, rlBlocked = 0;
  for (const b of bands) {
    const sd = b.carryingCapacity?.perCapitaReturn?.supportDebug;
    if (sd === undefined) continue;
    const d = sd.realizedLearnedSupportDelta ?? 0;
    if ((sd.candidateProjectedLearnedSupportDelta ?? 0) > 0) rlProjected += 1;
    if ((sd.realizedLearnedSupportBlockedReasons?.length ?? 0) > 0) rlBlocked += 1;
    if (d <= 0) continue;
    rlBands += 1; rlSum += d; if (d > rlMax) rlMax = d;
    const tile = world.tiles[b.position];
    const cat = tile === undefined ? "unknown" : classify(tile);
    if (cat === originCatchment) rlOrigin += 1; else rlSecondary += 1;
  }
  const realizedLearnedSupport = {
    bandsWithRealizedLearnedSupport: rlBands,
    bandsOriginCatchment: rlOrigin,
    bandsSecondaryRegion: rlSecondary,
    totalRealizedLearnedSupport: round3(rlSum),
    maxRealizedLearnedSupportPerBand: round3(rlMax),
    meanRealizedLearnedSupportPerBand: rlBands === 0 ? 0 : round3(rlSum / rlBands),
    bandsWithProjectedCandidateSupport: rlProjected,
    bandsWithBlockedLearnedSupport: rlBlocked,
  };

  // HEAT-2 (audit-only, read-only): regional economy — per-capita return and fission origin split
  // origin-catchment vs secondary-region, so the audit can tell whether secondary bands are
  // economically viable (not just present) and whether secondary lineages REPRODUCE locally
  // (fission originating in secondary regions = self-sustaining niche, not a transient satellite).
  let reOrigin = 0, reSecondary = 0, reOriginPcr = 0, reSecondaryPcr = 0, reOriginFiss = 0, reSecondaryFiss = 0;
  for (const b of bands) {
    const tile = world.tiles[b.position];
    const cat = tile === undefined ? "unknown" : classify(tile);
    const pcr = b.carryingCapacity?.perCapitaReturn?.perCapitaReturn ?? b.perCapitaReturn?.perCapitaReturn ?? 0;
    const fissioned = (b.fissionEvents?.length ?? 0) > 0;
    if (cat === originCatchment) {
      reOrigin += 1; reOriginPcr += pcr; if (fissioned) reOriginFiss += 1;
    } else {
      reSecondary += 1; reSecondaryPcr += pcr; if (fissioned) reSecondaryFiss += 1;
    }
  }
  const regionEconomy = {
    originBands: reOrigin,
    secondaryBands: reSecondary,
    meanPerCapitaOrigin: reOrigin === 0 ? 0 : round3(reOriginPcr / reOrigin),
    meanPerCapitaSecondary: reSecondary === 0 ? 0 : round3(reSecondaryPcr / reSecondary),
    originFissionBands: reOriginFiss,
    secondaryFissionBands: reSecondaryFiss,
  };

  // 2K.10 — side-country patch-memory census (read-only). Counts patch memories tagged with the
  // side_country_probe source event (formed by an applied side probe), by resource class and by
  // origin-vs-secondary location, plus how many have matching exploitation skill (i.e. can bind to
  // 2K.7/2K.8/2K.9). Shows whether side-country observation is finally producing off-corridor
  // resource substrate. Anti-omniscient: read from the band's own memories' reasonIds.
  let spBands = 0, spMemories = 0, spOrigin = 0, spSecondary = 0, spMatchingSkill = 0;
  const spByClass = {};
  for (const b of bands) {
    const mems = b.resourceKnowledgeState?.patchMemories ?? [];
    const skills = b.exploitationSkill?.skills;
    let bandHas = false;
    for (const m of mems) {
      const isSideFormed = (m.reasonIds ?? []).some((r) => String(r).includes("side_country_probe"));
      if (!isSideFormed) continue;
      bandHas = true; spMemories += 1;
      spByClass[m.resourceClassId] = (spByClass[m.resourceClassId] ?? 0) + 1;
      const tile = world.tiles[m.approximateTile];
      const cat = tile === undefined ? "unknown" : classify(tile);
      if (cat === originCatchment) spOrigin += 1; else spSecondary += 1;
      if (skills !== undefined && skills[m.resourceClassId] !== undefined && (skills[m.resourceClassId].competence ?? 0) > 0) spMatchingSkill += 1;
    }
    if (bandHas) spBands += 1;
  }
  const sidePatchMemory = {
    bandsWithSideFormedMemory: spBands,
    sideFormedMemories: spMemories,
    sideFormedByClass: spByClass,
    sideFormedOriginCatchment: spOrigin,
    sideFormedSecondaryRegion: spSecondary,
    sideFormedWithMatchingSkill: spMatchingSkill,
  };

  const skillOpportunityCoupling = {
    bandsWithGateOpen: soGateOpen,
    // (1) learned support applied to CURRENT/anchor range:
    bandsWithCurrentLearnedSupport: soCurrent,
    meanCurrentLearnedSupport: soCurrent === 0 ? 0 : round3(soSumCurrent / soCurrent),
    // (2) learned support applied to a NON-current candidate:
    bandsWithCandidateLearnedSupport: soCandidate,
    meanCandidateLearnedSupport: soCandidate === 0 ? 0 : round3(soSumCandidate / soCandidate),
    maxCandidateLearnedSupport: round3(soMaxCandidate),
    // (3) winning candidate is a SIDE/off-corridor tile that got learned support (migration enabler):
    bandsBestCandidateSideWithLearnedSupport: soBestIsSideWithSupport,
    sideCandidatesWithLearnedSupport: soSideCandidate,
  };

  // 2K.6B / INFO-1 — proactive information-seeking footprint. cumulativeProactiveInfoActions
  // is the EXACT lifetime count of proactive resource_scouts (summed over all bands, active +
  // gone, since a fissioned/absorbed band's actions still happened). recentPlantUseTests ring
  // entries are a snapshot proxy for current test activity (skill accrual itself is in
  // exploitationSkill above). Read-only; no behaviour leak.
  let piTotalActions = 0, piBands = 0, piRecentTestEntries = 0;
  for (const b of allBands) {
    const c = b.proactiveInfoMemory?.cumulativeProactiveInfoActions ?? 0;
    piTotalActions += c;
    if (c > 0) piBands += 1;
  }
  // Funnel diagnostic (mirrors the proactive GATE on final-snapshot active bands) + a proxy
  // for whether ANY resource_scout ever fired (recentScoutLearning ring non-empty).
  let piGateFood = 0, piGateMobility = 0, piGateLabor = 0, piGateAll = 0, piAnyScoutLearning = 0;
  let piTotalPatchMemories = 0, piBandsWithPatchMemories = 0, piMaxPatchMemories = 0;
  let piPlantBearingPatches = 0;
  for (const b of bands) {
    const mems = b.resourceKnowledgeState?.patchMemories ?? [];
    const pm = mems.length;
    piTotalPatchMemories += pm;
    if (pm > 0) piBandsWithPatchMemories += 1;
    if (pm > piMaxPatchMemories) piMaxPatchMemories = pm;
    for (const mem of mems) { if (mem.plantObservation !== undefined) piPlantBearingPatches += 1; }
    piRecentTestEntries += b.recentPlantUseTests?.length ?? 0;
    const fs = b.pressureState?.foodStress ?? b.hungerPressure ?? 0;
    const mp = b.pressureState?.mobilityPressure ?? 0;
    const lab = b.carryingCapacity?.populationDemand?.laborCapacity ?? b.size ?? 0;
    const foodOk = fs < 0.5, mobOk = mp < 0.6, laborOk = lab >= 6;
    if (foodOk) piGateFood += 1;
    if (mobOk) piGateMobility += 1;
    if (laborOk) piGateLabor += 1;
    if (foodOk && mobOk && laborOk) piGateAll += 1;
    if ((b.recentScoutLearning?.length ?? 0) > 0) piAnyScoutLearning += 1;
  }
  const proactiveInfo = {
    totalProactiveInfoActions: piTotalActions,
    bandsThatProactivelyScouted: piBands,
    recentPlantUseTestRingEntries: piRecentTestEntries,
    gate: {
      foodOk: piGateFood,
      mobilityOk: piGateMobility,
      laborOk: piGateLabor,
      allGateOk: piGateAll,
      bandsWithAnyScoutLearning: piAnyScoutLearning,
      activeBands: bands.length,
      totalPatchMemories: piTotalPatchMemories,
      bandsWithPatchMemories: piBandsWithPatchMemories,
      maxPatchMemories: piMaxPatchMemories,
      plantBearingPatches: piPlantBearingPatches,
    },
  };

  const occupiedCatchments = Object.values(catchmentBandCounts).filter((n) => n > 0).length;
  const regionalClusters = Object.entries(catchmentBandCounts).filter(([, n]) => n >= 2).length;
  const secondaryRegionPockets = clusterInfo.filter(
    (c) => c.size >= 2 && c.dominantCatchment !== originCatchment,
  ).length;
  const largest = clusterInfo[0];

  // Pattern classification (the user's necklace failure mode is explicit):
  let pattern;
  if (regionalClusters >= 2 && secondaryRegionPockets >= 1 && occupiedCatchments >= 3 && maxDistFromOrigin >= HEAT_FAR_DISTANCE) {
    pattern = "multi_region_founding";
  } else if (maxDistFromOrigin >= HEAT_FAR_DISTANCE && clusterInfo.length <= 1 && largest !== undefined && largest.span >= 20) {
    pattern = "necklace_or_single_chain";
  } else if (maxDistFromOrigin >= HEAT_FAR_DISTANCE) {
    pattern = "corridor_diffusion";
  } else {
    pattern = "local_cluster";
  }

  return {
    bands: bands.length,
    population: Math.round(bands.reduce((s, b) => s + b.demography.population, 0)),
    fissions: allBands.reduce((n, b) => n + (b.fissionEvents?.length ?? 0), 0),
    extinctions: allBands.filter((b) => b.viability?.status === "extinct").length,
    absorbed: allBands.filter((b) => b.viability?.status === "absorbed").length,
    originCatchment,
    maxDistFromOrigin,
    boundingBoxArea: bands.length === 0 ? 0 : (maxX - minX + 1) * (maxY - minY + 1),
    occupiedCatchments,
    catchmentBandCounts,
    regionalClusters,
    distinctClusters: clusterInfo.length,
    clusters: clusterInfo,
    secondaryRegionPockets,
    largestClusterSize: largest?.size ?? 0,
    largestClusterSpan: largest?.span ?? 0,
    ecoZonesOccupied: ecoZones.size,
    ecoZones: [...ecoZones].sort(),
    pctInOriginCatchment: bands.length === 0 ? 0 : round3(inOriginCatchment / bands.length),
    pctInSecondaryRegions: bands.length === 0 ? 0 : round3(1 - inOriginCatchment / bands.length),
    offCorridorKnowledge,
    exploitationSkill,
    skillRankCoupling,
    skillOpportunityCoupling,
    realizedLearnedSupport,
    sidePatchMemory,
    regionEconomy,
    proactiveInfo,
    pattern,
  };
}

function heatFingerprint(world) {
  const parts = Object.values(world.bands).filter(isActiveBand)
    .map((b) => `${b.id}@${b.position}#${b.demography.population}`).sort();
  let h = 2166136261;
  const s = parts.join("|");
  for (let i = 0; i < s.length; i += 1) { h ^= s.charCodeAt(i); h = Math.imul(h, 16777619); }
  return (h >>> 0).toString(16);
}

function runOneOriginHeatTest(modules, options) {
  const years = options.heatYears === undefined || Number.isNaN(options.heatYears) ? 500 : Math.max(50, Math.floor(options.heatYears));
  const seeds = (options.heatSeeds ?? "heat-1,heat-2,heat-3,heat-4,heat-5").split(",").map((s) => s.trim()).filter((s) => s.length > 0);
  const classify = classifyMap2Catchment;

  const runOnce = (seed) => {
    const metrics = createEmptyMetrics();
    let world = modules.spawnSingleOriginBand(modules.createVariedMigrationWorld());
    world = { ...world, runSeed: modules.hashSeedString(seed) };
    for (let t = 0; t < years * 4; t += 1) {
      world = advanceInstrumentedOneSeason(modules, world, metrics, { fast: true, probeAudit: false }).world;
    }
    return world;
  };

  // Reproducibility: first seed run twice must match exactly.
  const reproSeed = seeds[0];
  const reproA = heatFingerprint(runOnce(reproSeed));
  const reproB = heatFingerprint(runOnce(reproSeed));

  const perSeed = seeds.map((seed) => {
    const world = runOnce(seed);
    return {
      seed,
      fingerprint: heatFingerprint(world),
      metrics: computeHeatMetrics(world, classify, modules.isWithinSideReachOfCorridor, modules.patchExploitationKnowledge),
    };
  });

  const fingerprints = perSeed.map((s) => s.fingerprint);
  const distinctFingerprints = new Set(fingerprints).size;
  const patterns = perSeed.map((s) => s.metrics.pattern);
  const multiRegionSeeds = perSeed.filter((s) => s.metrics.pattern === "multi_region_founding").length;
  const necklaceSeeds = perSeed.filter((s) => s.metrics.pattern === "necklace_or_single_chain").length;
  const maxDistRange = [Math.min(...perSeed.map((s) => s.metrics.maxDistFromOrigin)), Math.max(...perSeed.map((s) => s.metrics.maxDistFromOrigin))];
  const occupiedRange = [Math.min(...perSeed.map((s) => s.metrics.occupiedCatchments)), Math.max(...perSeed.map((s) => s.metrics.occupiedCatchments))];

  // M0.16 — cross-seed off-corridor knowledge summary (quick read; per-seed
  // detail lives in perSeed[].metrics.offCorridorKnowledge).
  const ock = perSeed.map((s) => s.metrics.offCorridorKnowledge);
  const offCorridorSummary = {
    seedsWithSideInference: ock.filter((o) => o.totalSideInferred > 0).length,
    totalSideInferredRange: [Math.min(...ock.map((o) => o.totalSideInferred)), Math.max(...ock.map((o) => o.totalSideInferred))],
    maxSideInferredAnyBand: Math.max(...ock.map((o) => o.maxSideInferred)),
    totalSideObservedRange: [Math.min(...ock.map((o) => o.totalSideObserved)), Math.max(...ock.map((o) => o.totalSideObserved))],
    bandsWithSideObservedRange: [Math.min(...ock.map((o) => o.bandsWithSideObserved)), Math.max(...ock.map((o) => o.bandsWithSideObserved))],
    // M0.16B consumption: did side probes actually WIN (vs M0.16's zero)?
    seedsWithSideProbeWins: ock.filter((o) => o.sideProbesWon > 0).length,
    sideProbesWonRange: [Math.min(...ock.map((o) => o.sideProbesWon)), Math.max(...ock.map((o) => o.sideProbesWon))],
    bandsThatSideProbedRange: [Math.min(...ock.map((o) => o.bandsThatSideProbed)), Math.max(...ock.map((o) => o.bandsThatSideProbed))],
  };
  const pctSecondaryRange = [
    Math.min(...perSeed.map((s) => s.metrics.pctInSecondaryRegions)),
    Math.max(...perSeed.map((s) => s.metrics.pctInSecondaryRegions)),
  ];

  return {
    suite: "targeted_one_origin_heat",
    map: "map2_single_origin",
    years,
    origin: HEAT_ORIGIN,
    reproducibility: { seed: reproSeed, runA: reproA, runB: reproB, reproducible: reproA === reproB },
    divergence: {
      seedCount: seeds.length,
      distinctFingerprints,
      allDistinct: distinctFingerprints === seeds.length,
      patterns,
      multiRegionSeeds,
      necklaceSeeds,
      maxDistFromOriginRange: maxDistRange,
      occupiedCatchmentsRange: occupiedRange,
      pctInSecondaryRegionsRange: pctSecondaryRange,
    },
    offCorridorSummary,
    acceptance: {
      same_seed_reproducible: reproA === reproB,
      seeds_diverge: distinctFingerprints === seeds.length,
      some_seed_multi_region: multiRegionSeeds > 0,
      not_all_necklace: necklaceSeeds < seeds.length,
      descendants_leave_origin_region: perSeed.some((s) => s.metrics.pctInSecondaryRegions >= 0.34),
      multiple_eco_zones: perSeed.some((s) => s.metrics.ecoZonesOccupied >= 3),
    },
    perSeed,
  };
}

// =====================================================================
// TASK 10 — single-origin spread OFF vs ON the daughter-colonization
// fission-bias lever. Reuses the HEAT-1 single-origin infrastructure
// (spawnSingleOriginBand + classifyMap2Catchment + the cluster/pattern
// notions). Audit-only: the OFF variant uses the default (flag absent/false)
// so it is the real, unmodified sim; the ON variant only toggles
// world.auditOptions.daughterColonizationFissionBiasEnabled before stepping.
// Deterministic: legacy zero-jitter (no runSeed), and we advance one season at
// a time only to track per-tick single-step distances (byte-identical to a
// single stepSim(N) call — verified). No teleport: every active descendant's
// per-season tile move must be a contiguous single-tile (grid-distance 1) step.
// =====================================================================

// Catchments that make up the ORIGIN river corridor (the dense single-corridor
// cluster the origin band starts in). origin {x:108,y:54} is a floodplain tile,
// so classifyMap2Catchment returns "river_corridor"; the dry channel is the
// other corridor catchment. Used for the "founded outside corridor" + riverLocked
// notions.
const SPREAD_ORIGIN_CORRIDOR_CATCHMENTS = new Set(["river_corridor", "dry_corridor"]);
// Max legitimate per-season tile displacement for a surviving band (intra-season
// migration walk is contiguous single-tile breadcrumb steps; a season packs a few
// of them). Anything beyond this would indicate a teleport rather than a walk.
const SPREAD_MAX_SEASON_STEP = 8;
const SPREAD_FOUNDER_PRESSURE_MIN = 0.24;

function gridDistanceFromTileIds(a, b) {
  const ca = parseTileCoord(a);
  const cb = parseTileCoord(b);
  return Math.abs(ca.x - cb.x) + Math.abs(ca.y - cb.y);
}

function summarizeAcceptedFounderPulses(world, fissionEvents, classify) {
  const targetDistances = [];
  let acceptedFounderPulses = 0;
  let outsideOriginCorridor = 0;
  let routeBacked = 0;
  let fordBacked = 0;
  let edgeBacked = 0;
  const reasonTypeCounts = {};

  for (const ev of fissionEvents) {
    if (ev.targetTileId === undefined) continue;

    const distance = gridDistanceFromTileIds(ev.originTileId, ev.targetTileId);
    targetDistances.push(distance);
    const type = String(ev.splitReason?.type ?? "unknown");
    reasonTypeCounts[type] = (reasonTypeCounts[type] ?? 0) + 1;
    const tile = world.tiles[ev.targetTileId];
    const catchment = tile === undefined ? "unknown" : classify(tile);
    const routeEvidence =
      type === "crossing_enabled_split" ||
      type === "river_corridor_split" ||
      type === "coastal_split" ||
      type === "frontier_split" ||
      distance <= 8;
    const fordEvidence = type === "crossing_enabled_split";
    const edgeEvidence =
      tile !== undefined &&
      (tile.isRiverbank === true ||
        tile.isFloodplain === true ||
        tile.isCoastal === true ||
        tile.isEstuary === true ||
        type === "frontier_split");

    if (routeEvidence && distance >= 3) acceptedFounderPulses += 1;
    if (!SPREAD_ORIGIN_CORRIDOR_CATCHMENTS.has(catchment)) outsideOriginCorridor += 1;
    if (routeEvidence) routeBacked += 1;
    if (fordEvidence) fordBacked += 1;
    if (edgeEvidence) edgeBacked += 1;
  }

  const sortedDistances = [...targetDistances].sort((a, b) => a - b);
  const median =
    sortedDistances.length === 0
      ? 0
      : sortedDistances[Math.floor((sortedDistances.length - 1) / 2)];
  const average =
    sortedDistances.length === 0
      ? 0
      : round3(sortedDistances.reduce((sum, value) => sum + value, 0) / sortedDistances.length);

  return {
    acceptedFounderPulses,
    fissionFoundedOutsideOriginCorridor: outsideOriginCorridor,
    acceptedFounderPulseRouteBacked: routeBacked,
    acceptedFounderPulseFordBacked: fordBacked,
    acceptedFounderPulseEdgeBacked: edgeBacked,
    averageDaughterFissionTargetDistance: average,
    medianDaughterFissionTargetDistance: median,
    reasonTypeCounts,
  };
}

function summarizeFounderPulseCandidates(world, bands) {
  const blockedReasonsDistribution = {};
  const candidateRecords = [];
  let candidateCount = 0;
  let causalEvidenceCandidates = 0;

  for (const band of bands) {
    const opportunity = band.daughterColonization?.bestKnownUnusedHabitatOpportunity;
    if (opportunity === undefined) continue;

    candidateCount += 1;
    const tileId = opportunity.candidateTileId;
    const tile = world.tiles[tileId];
    const record = band.knowledge?.observedTiles?.[tileId];
    const evidence = getFounderOpportunityEvidence(world, band, opportunity, tile);
    const blockedReasons = [];

    if ((band.daughterColonization?.pressure ?? 0) < SPREAD_FOUNDER_PRESSURE_MIN) blockedReasons.push("pressure_below_threshold");
    if (opportunity.confidence < 0.34) blockedReasons.push("confidence_too_low");
    if (record === undefined) blockedReasons.push("target_not_in_observed_known_memory");
    if (record !== undefined && record.confidence < 0.34) blockedReasons.push("target_memory_confidence_too_low");
    if ((record?.observedWaterAccess ?? opportunity.waterReliability ?? 0) < 0.32) blockedReasons.push("water_confidence_too_low");
    if ((record?.observedRisk ?? opportunity.riskPenalty ?? 0) > 0.5 || opportunity.riskPenalty > 0.55) blockedReasons.push("risk_too_high");
    if (!opportunity.consideredAsTarget) blockedReasons.push(`opportunity_not_considered:${opportunity.rejectionReason ?? "not_better"}`);
    if (!evidence.routeEvidence) blockedReasons.push("no_known_route_or_edge_evidence");
    if (!evidence.fordEvidence && evidence.crossingLikely) blockedReasons.push("no_known_ford_crossing");
    if ((band.pressureState?.parentCoreOverlap ?? 0) < 0.18) blockedReasons.push("parent_overlap_not_high_enough");
    if (band.parentBandId !== undefined && Number(world.time.tick) - Number(band.lineage?.createdAt?.tick ?? world.time.tick) < 60) {
      blockedReasons.push("daughter_not_mature_enough");
    }
    if ((band.pressureState?.safeFrontierPull ?? 0) < 0.08) blockedReasons.push("no_safe_frontier_pull");
    if (band.daughterColonization?.recommendedAction !== "fission_toward_opportunity") blockedReasons.push("fallback_stayed_local");
    if (evidence.routeEvidence) causalEvidenceCandidates += 1;

    if (blockedReasons.length === 0) {
      blockedReasons.push("available_candidate_not_chosen_yet");
    }

    for (const reason of blockedReasons) {
      blockedReasonsDistribution[reason] = (blockedReasonsDistribution[reason] ?? 0) + 1;
    }

    candidateRecords.push({
      bandId: String(band.id),
      parentBandId: band.parentBandId === undefined ? null : String(band.parentBandId),
      tick: Number(world.time.tick),
      candidateTile: String(tileId),
      pressure: round3(band.daughterColonization?.pressure ?? 0),
      confidence: round3(opportunity.confidence),
      routeEvidence: evidence.routeEvidence,
      fordEvidence: evidence.fordEvidence,
      sideCountryEvidence: evidence.sideCountryEvidence,
      edgeEvidence: evidence.edgeEvidence,
      pressureReasons: band.daughterColonization?.reasonIds?.map(String) ?? [],
      opportunityReasons: opportunity.reasonIds?.map(String) ?? [],
      blockedReasons,
      chosen: false,
      noTeleport: true,
      noOmniscientTarget: record !== undefined,
      noEconomyShortcut: true,
    });
  }

  return {
    founderPulseCandidates: candidateCount,
    founderPulseCandidatesWithRouteEvidence: causalEvidenceCandidates,
    blockedReasonsDistribution,
    sampleFounderPulseCandidates: candidateRecords.slice(0, 8),
  };
}

function getFounderOpportunityEvidence(world, band, opportunity, tile) {
  const basis = opportunity.basis ?? [];
  const hasRouteBasis = basis.some((entry) =>
    [
      "river_corridor_inference",
      "coast_corridor_inference",
      "lake_wetland_chain",
      "pass_corridor",
      "scout_probe_result",
      "seasonal_round_memory",
      "remembered_place",
      "personally_observed",
    ].includes(String(entry)),
  );
  const hasCorridorMemory = Object.values(band.travelCorridors ?? {}).some(
    (corridor) =>
      corridor.confidence > 0.3 &&
      (corridor.fromTileId === opportunity.candidateTileId || corridor.toTileId === opportunity.candidateTileId),
  );
  const hasCrossingMemory = Object.values(band.crossingMemories ?? {}).some(
    (memory) =>
      memory.successConfidence > 0.34 &&
      (memory.crossingTileA === opportunity.candidateTileId || memory.crossingTileB === opportunity.candidateTileId),
  );
  const hasEdge =
    tile !== undefined &&
    (tile.isRiverbank === true ||
      tile.isFloodplain === true ||
      tile.isCoastal === true ||
      tile.isEstuary === true ||
      tile.isMarshChannel === true ||
      tile.terrainKind === "hills");
  const sideCountryEvidence = (band.resourceKnowledgeState?.patchMemories ?? []).some(
    (memory) =>
      (memory.approximateTile === opportunity.candidateTileId || memory.linkedTiles?.includes(opportunity.candidateTileId)) &&
      memory.reasonIds?.some((reasonId) => String(reasonId).includes("side_country")),
  );
  const crossingLikely =
    tile !== undefined &&
    (tile.isRiver === true || tile.isRiverbank === true || tile.isFloodplain === true || tile.isMarshChannel === true);

  return {
    routeEvidence: hasRouteBasis || hasCorridorMemory || hasCrossingMemory || hasEdge || sideCountryEvidence,
    fordEvidence: hasCrossingMemory,
    sideCountryEvidence,
    edgeEvidence: hasEdge,
    crossingLikely,
  };
}

function summarizeLightExplorationAndReports(world, activeBands) {
  const reportsByTopic = {};
  const reportsByTrustBasis = {};
  const reportsByDistortion = {};
  const reportsByDisposition = {};
  const reportsByRegionKind = {};
  const reportsBySourceBasis = {};
  const reportsByConfirmationStatus = {};
  const speculationsByHypothesis = {};
  const reportIds = new Set();
  const speculationIds = new Set();
  let reportsCreated = 0;
  let internalReportsCreated = 0;
  let interBandReportsCreated = 0;
  let checkedByProbe = 0;
  let actedOn = 0;
  let misleadingReports = 0;
  let partiallyConfirmed = 0;
  let contradicted = 0;
  let stale = 0;
  let reportTargetUnknownToReceiver = 0;
  let reportRecordsWithoutRegion = 0;
  let exactTilePrimaryReports = 0;
  let directRelocationWithoutKnownOrRouteEvidence = 0;
  let knownTributaryBands = 0;
  let creekActivityTargets = 0;
  let creekFissionTargets = 0;
  let occupiedCreekCorridors = 0;
  let knownCrossingCount = 0;
  let usedCrossingCount = 0;
  let sideCountryMemoryTiles = 0;
  let reportsWithRouteEvidence = 0;
  let activeReportRecordCount = 0;
  let bandsWithReports = 0;
  let maxActiveReportsPerBand = 0;
  let reportCapViolations = 0;
  let speculationCapViolations = 0;

  for (const band of activeBands) {
    const reports = band.reportedKnowledge?.reports ?? [];
    const speculations = band.reportedKnowledge?.speculations ?? [];
    activeReportRecordCount += reports.length;
    if (reports.length > 0) bandsWithReports += 1;
    if (reports.length > maxActiveReportsPerBand) maxActiveReportsPerBand = reports.length;
    if (reports.length > 16) reportCapViolations += 1;
    if (speculations.length > 8) speculationCapViolations += 1;
    reportsCreated += band.reportedKnowledge?.receivedCount ?? 0;
    internalReportsCreated += band.reportedKnowledge?.internalGeneratedCount ?? 0;
    interBandReportsCreated += band.reportedKnowledge?.interBandGeneratedCount ?? 0;
    checkedByProbe += band.reportedKnowledge?.checkedByProbeCount ?? 0;
    actedOn += band.reportedKnowledge?.actedOnCount ?? 0;
    misleadingReports += band.reportedKnowledge?.misleadingCount ?? 0;
    partiallyConfirmed += band.reportedKnowledge?.partiallyConfirmedCount ?? 0;
    contradicted += band.reportedKnowledge?.contradictedCount ?? 0;
    stale += band.reportedKnowledge?.staleCount ?? 0;

    const positionTile = world.tiles[band.position];
    if (positionTile?.hasCreek === true) occupiedCreekCorridors += 1;

    if (Object.keys(band.knowledge?.observedTiles ?? {}).some((tileId) => world.tiles[tileId]?.hasCreek === true)) {
      knownTributaryBands += 1;
    }

    for (const trip of band.recentIntraSeasonTrips ?? []) {
      if (world.tiles[trip.targetTileId]?.hasCreek === true) {
        creekActivityTargets += 1;
      }
    }

    for (const event of band.fissionEvents ?? []) {
      if (event.targetTileId !== undefined && world.tiles[event.targetTileId]?.hasCreek === true) {
        creekFissionTargets += 1;
      }
    }

    for (const crossing of Object.values(band.crossingMemories ?? {})) {
      knownCrossingCount += 1;
      if ((crossing.useCount ?? 0) > 0) usedCrossingCount += 1;
    }

    const sideTiles = new Set();
    for (const memory of band.resourceKnowledgeState?.patchMemories ?? []) {
      if (memory.reasonIds?.some((reasonId) => String(reasonId).includes("side_country"))) {
        sideTiles.add(String(memory.approximateTile));
      }
    }
    sideCountryMemoryTiles += sideTiles.size;

    for (const report of reports) {
      if (!reportIds.has(report.reportId)) {
        reportIds.add(report.reportId);
        incrementCount(reportsByTopic, report.topic);
        incrementCount(reportsByTrustBasis, report.trustBasis);
        incrementCount(reportsByDistortion, report.distortionLevel);
        incrementCount(reportsByDisposition, report.receiverDisposition);
        incrementCount(reportsByRegionKind, report.regionTarget?.regionKind ?? "missing_region");
        incrementCount(reportsBySourceBasis, report.sourceBasis ?? "missing_source_basis");
        incrementCount(reportsByConfirmationStatus, report.confirmationStatus ?? "missing_confirmation");
      }

      if (report.regionTarget === undefined) {
        reportRecordsWithoutRegion += 1;
      }

      if (report.regionTarget?.precision === "exact_observed_area") {
        exactTilePrimaryReports += 1;
      }

      if (report.targetTileId !== undefined && band.knowledge.observedTiles[report.targetTileId] === undefined) {
        reportTargetUnknownToReceiver += 1;
      }

      if (report.targetTileId !== undefined && hasReportRouteEvidence(band, report.targetTileId)) {
        reportsWithRouteEvidence += 1;
      }

      if (
        report.receiverDisposition === "acted_on" &&
        report.targetTileId !== undefined &&
        band.knowledge.observedTiles[report.targetTileId] === undefined &&
        !hasReportRouteEvidence(band, report.targetTileId)
      ) {
        directRelocationWithoutKnownOrRouteEvidence += 1;
      }
    }

    for (const speculation of speculations) {
      if (!speculationIds.has(speculation.speculationId)) {
        speculationIds.add(speculation.speculationId);
        incrementCount(speculationsByHypothesis, speculation.hypothesis);
      }
    }
  }

  return {
    reportsCreated,
    internalReportsCreated,
    interBandReportsCreated,
    activeReportRecords: reportIds.size,
    activeReportRecordCount,
    averageActiveReportsPerBand: round3(activeBands.length === 0 ? 0 : activeReportRecordCount / activeBands.length),
    maxActiveReportsPerBand,
    bandsWithReports,
    reportsByTopic,
    reportsByRegionKind,
    reportsBySourceBasis,
    reportsByTrustBasis,
    reportsByDistortion,
    reportsByDisposition,
    reportsByConfirmationStatus,
    checkedByProbe,
    actedOn,
    misleadingReports,
    partiallyConfirmed,
    contradicted,
    stale,
    speculations: speculationIds.size,
    speculationsByHypothesis,
    reportTargetUnknownToReceiver,
    reportRecordsWithoutRegion,
    exactTilePrimaryReports,
    reportsWithRouteEvidence,
    directRelocationWithoutKnownOrRouteEvidence,
    knownTributaryBands,
    occupiedCreekCorridors,
    creekActivityTargets,
    creekFissionTargets,
    knownCrossingCount,
    usedCrossingCount,
    sideCountryMemoryTiles,
    noDirectRelocationFromReportAlone: directRelocationWithoutKnownOrRouteEvidence === 0,
    noDirectResourceUnlockFromReports: true,
    noObservedTileCreatedByReport: true,
    reportCapViolations,
    speculationCapViolations,
    capsCompliant: reportCapViolations === 0 && speculationCapViolations === 0,
  };
}

function hasReportRouteEvidence(band, tileId) {
  return (
    band.knowledge?.observedTiles?.[tileId] !== undefined ||
    Object.values(band.travelCorridors ?? {}).some(
      (corridor) => corridor.fromTileId === tileId || corridor.toTileId === tileId,
    ) ||
    Object.values(band.crossingMemories ?? {}).some(
      (crossing) => crossing.crossingTileA === tileId || crossing.crossingTileB === tileId,
    )
  );
}

function computeSingleOriginSpread(modules, { biasOn, years }) {
  const classify = classifyMap2Catchment;
  let world = modules.spawnSingleOriginBand(modules.createVariedMigrationWorld());
  world = {
    ...world,
    auditOptions: { ...(world.auditOptions ?? {}), daughterColonizationFissionBiasEnabled: biasOn },
  };

  // Per-tick breadcrumb no-teleport tracking: each active band's previous tile.
  let prevPositions = new Map(
    Object.values(world.bands).filter(isActiveBand).map((b) => [String(b.id), parseTileCoord(b.position)]),
  );
  let maxSeasonStep = 0;
  let teleportEvents = 0;

  const totalSeasons = years * 4;
  for (let t = 0; t < totalSeasons; t += 1) {
    world = modules.stepSim(world, 1, "seasonal");
    const nextPositions = new Map();
    for (const b of Object.values(world.bands).filter(isActiveBand)) {
      const key = String(b.id);
      const here = parseTileCoord(b.position);
      nextPositions.set(key, here);
      const prev = prevPositions.get(key); // undefined => band born this season (no prior tile)
      if (prev !== undefined) {
        const step = Math.abs(here.x - prev.x) + Math.abs(here.y - prev.y);
        if (step > maxSeasonStep) maxSeasonStep = step;
        if (step > SPREAD_MAX_SEASON_STEP) teleportEvents += 1;
      }
    }
    prevPositions = nextPositions;
  }

  // Context application (range/frontier/disposition/encounter) so daughterColonization
  // + nearbyOpportunity are populated for reporting — mirrors the migration audit.
  const ctxWorld = applyDispersalAuditContextOnly(modules, world);
  const active = Object.values(ctxWorld.bands).filter(isActiveBand);
  const lightExploration = summarizeLightExplorationAndReports(ctxWorld, active);

  // Origin catchment + per-catchment occupancy via the HEAT classifier.
  const originTile = ctxWorld.tiles[`tile:${HEAT_ORIGIN.x}:${HEAT_ORIGIN.y}`];
  const originCatchment = originTile === undefined ? null : classify(originTile);
  const catchmentBandCounts = {};
  let inOriginCatchment = 0;
  let longestLineageDistance = 0;
  for (const b of active) {
    const tile = ctxWorld.tiles[b.position];
    const cat = tile === undefined ? "unknown" : classify(tile);
    catchmentBandCounts[cat] = (catchmentBandCounts[cat] ?? 0) + 1;
    if (cat === originCatchment) inOriginCatchment += 1;
    const c = parseTileCoord(b.position);
    const dist = Math.abs(c.x - HEAT_ORIGIN.x) + Math.abs(c.y - HEAT_ORIGIN.y);
    if (dist > longestLineageDistance) longestLineageDistance = dist;
  }
  const occupiedCatchments = Object.values(catchmentBandCounts).filter((n) => n > 0).length;
  const pctOutsideOriginCatchment = active.length === 0 ? 0 : round3(1 - inOriginCatchment / active.length);

  // Fissions founded OUTSIDE the origin river corridor: a fission event whose
  // founding origin tile does NOT classify as a corridor catchment.
  const fissionEvents = getUniqueFissionEvents(Object.values(ctxWorld.bands));
  let fissionFoundedOutsideOriginCorridor = 0;
  for (const ev of fissionEvents) {
    const foundTileId = ev.targetTileId ?? ev.originTileId;
    const tile = foundTileId === undefined ? undefined : ctxWorld.tiles[foundTileId];
    const cat = tile === undefined ? "unknown" : classify(tile);
    if (!SPREAD_ORIGIN_CORRIDOR_CATCHMENTS.has(cat)) fissionFoundedOutsideOriginCorridor += 1;
  }
  const founderPulseHistory = summarizeAcceptedFounderPulses(ctxWorld, fissionEvents, classify);

  // Known ford crossing-uses across active descendants (evidence of using known
  // routes/fords to cross, NOT teleport): sum of crossingMemories with useCount>0.
  let knownFordCrossingUses = 0;
  for (const b of active) {
    for (const m of Object.values(b.crossingMemories ?? {})) {
      if ((m.useCount ?? 0) > 0) knownFordCrossingUses += 1;
    }
  }
  const founderPulseCandidates = summarizeFounderPulseCandidates(ctxWorld, active);

  // riverLocked: still essentially one dense corridor cluster (reuse HEAT's notion):
  // a single HEAT cluster whose dominant catchment is a corridor catchment, and no
  // secondary (>=2) non-origin-corridor pocket.
  const positions = active.map((b) => parseTileCoord(b.position));
  const clusters = heatClusterBands(positions, HEAT_CLUSTER_THRESHOLD);
  const clusterInfo = clusters
    .map((cluster) => {
      const counts = {};
      for (const p of cluster) {
        const tile = ctxWorld.tiles[`tile:${p.x}:${p.y}`];
        const cat = tile === undefined ? "unknown" : classify(tile);
        counts[cat] = (counts[cat] ?? 0) + 1;
      }
      const dominant = Object.entries(counts).sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0]))[0]?.[0] ?? "unknown";
      return { size: cluster.length, dominantCatchment: dominant };
    })
    .sort((a, b) => b.size - a.size);
  const regionalClusters = Object.entries(catchmentBandCounts).filter(([, n]) => n >= 2).length;
  const secondaryRegionPockets = clusterInfo.filter(
    (c) => c.size >= 2 && !SPREAD_ORIGIN_CORRIDOR_CATCHMENTS.has(c.dominantCatchment),
  ).length;
  // riverLocked: every occupied catchment is a corridor catchment AND there is no
  // secondary (>=2-band) non-corridor pocket — i.e. the population, however far it
  // necklaces along the channel, has NOT broken out of the origin river catchment(s).
  // (Cluster COUNT along a 1D corridor does not disqualify: a corridor necklace is
  // still river-locked.)
  const occupiedCats = Object.entries(catchmentBandCounts).filter(([, n]) => n > 0).map(([c]) => c);
  const allOccupiedAreCorridor = occupiedCats.length > 0 && occupiedCats.every((c) => SPREAD_ORIGIN_CORRIDOR_CATCHMENTS.has(c));
  const riverLocked = allOccupiedAreCorridor && secondaryRegionPockets === 0;

  // pattern (reuse HEAT's classifier through computeHeatMetrics for consistency).
  const heat = computeHeatMetrics(ctxWorld, classify, modules.isWithinSideReachOfCorridor, modules.patchExploitationKnowledge);

  return {
    variant: biasOn ? "ON" : "OFF",
    years,
    activeBands: active.length,
    occupiedCatchments,
    catchmentBandCounts,
    pctOutsideOriginCatchment,
    longestLineageDistanceFromOrigin: longestLineageDistance,
    fissionFoundedOutsideOriginCorridor,
    knownFordCrossingUses,
    lightExploration,
    occupiedTributaryCreekCorridors: lightExploration.occupiedCreekCorridors,
    knownTributaryCreekBands: lightExploration.knownTributaryBands,
    wordOfMouthReportsCreated: lightExploration.reportsCreated,
    wordOfMouthReportsCheckedByProbe: lightExploration.checkedByProbe,
    wordOfMouthReportsActedOn: lightExploration.actedOn,
    wordOfMouthReportsByTopic: lightExploration.reportsByTopic,
    founderPulseCandidates: founderPulseCandidates.founderPulseCandidates,
    founderPulseCandidatesWithRouteEvidence: founderPulseCandidates.founderPulseCandidatesWithRouteEvidence,
    acceptedFounderPulses: founderPulseHistory.acceptedFounderPulses,
    acceptedFounderPulseRouteBacked: founderPulseHistory.acceptedFounderPulseRouteBacked,
    acceptedFounderPulseFordBacked: founderPulseHistory.acceptedFounderPulseFordBacked,
    acceptedFounderPulseEdgeBacked: founderPulseHistory.acceptedFounderPulseEdgeBacked,
    founderPulseBlockedReasonsDistribution: founderPulseCandidates.blockedReasonsDistribution,
    sampleFounderPulseCandidates: founderPulseCandidates.sampleFounderPulseCandidates,
    averageDaughterFissionTargetDistance: founderPulseHistory.averageDaughterFissionTargetDistance,
    medianDaughterFissionTargetDistance: founderPulseHistory.medianDaughterFissionTargetDistance,
    daughterFissionReasonTypeCounts: founderPulseHistory.reasonTypeCounts,
    expansionUsedKnownRoutesFordsOrEdgeMemory:
      founderPulseHistory.acceptedFounderPulseRouteBacked > 0 ||
      founderPulseHistory.acceptedFounderPulseFordBacked > 0 ||
      founderPulseHistory.acceptedFounderPulseEdgeBacked > 0 ||
      knownFordCrossingUses > 0,
    stillTooRiverLocked: years >= 200 && riverLocked,
    tooExplosive: active.length >= 34 && occupiedCatchments >= 5,
    regionalClusters,
    secondaryRegionPockets,
    riverLocked,
    pattern: heat.pattern,
    noTeleport: {
      maxSeasonStepTiles: maxSeasonStep,
      stepBound: SPREAD_MAX_SEASON_STEP,
      teleportEvents,
      noTeleport: teleportEvents === 0,
    },
  };
}

// Compares OFF vs ON at one horizon and returns both metric blocks + a delta.
function compareSpreadAtYears(modules, years) {
  const off = computeSingleOriginSpread(modules, { biasOn: false, years });
  const on = computeSingleOriginSpread(modules, { biasOn: true, years });
  const occupiedDelta = on.occupiedCatchments - off.occupiedCatchments;
  const pctOutsideDelta = round3(on.pctOutsideOriginCatchment - off.pctOutsideOriginCatchment);
  const distDelta = on.longestLineageDistanceFromOrigin - off.longestLineageDistanceFromOrigin;
  return {
    years,
    off,
    on,
    spreadDelta: {
      occupiedCatchmentsOnMinusOff: occupiedDelta,
      pctOutsideDelta,
      longestLineageDistanceDelta: distDelta,
      fissionOutsideCorridorDelta: on.fissionFoundedOutsideOriginCorridor - off.fissionFoundedOutsideOriginCorridor,
      // The lever "increases spread" only if ON measurably exceeds OFF on at
      // least one spread axis (catchments / outside-fraction / reach). Reported
      // truthfully — ON==OFF (inert lever) yields false.
      leverIncreasesSpread: occupiedDelta > 0 || pctOutsideDelta > 0 || distDelta > 0,
    },
    noTeleport: off.noTeleport.noTeleport && on.noTeleport.noTeleport,
  };
}

function runSingleOriginSpreadAudit(modules, options) {
  const horizons = [100, 200, 300];
  if (options.spread500 === true) horizons.push(500);
  const comparisons = horizons.map((years) => compareSpreadAtYears(modules, years));

  const anyHorizonIncreasesSpread = comparisons.some((c) => c.spreadDelta.leverIncreasesSpread);
  const allNoTeleport = comparisons.every((c) => c.noTeleport);
  const allPassability = comparisons.every(
    (c) => c.off.activeBands >= 0 && c.on.activeBands >= 0,
  );

  return {
    check: "TASK-10 single-origin spread OFF vs ON daughter-colonization fission-bias lever",
    verdict: allNoTeleport ? "pass" : "review",
    command: "node scripts/simBenchmark.mjs --targeted-single-origin-spread",
    origin: HEAT_ORIGIN,
    lever: "world.auditOptions.daughterColonizationFissionBiasEnabled (RANGE-3B normal default ON; audit OFF sets false)",
    horizonsYears: horizons,
    noTeleport: allNoTeleport,
    leverIncreasesSpreadAnyHorizon: anyHorizonIncreasesSpread,
    notes: [
      "OFF = explicit auditOptions.daughterColonizationFissionBiasEnabled=false conservative comparison path.",
      "ON = normal RANGE-3B MVP behaviour (the same as leaving the flag undefined in normal worlds).",
      "Spread is a MEASUREMENT, not a pass/fail gate; the verdict only fails on a no-teleport violation.",
      "noTeleport: every active descendant's per-season tile move is a contiguous breadcrumb step (Manhattan <= SPREAD_MAX_SEASON_STEP).",
      anyHorizonIncreasesSpread
        ? "Observed: the lever increases single-origin spread on at least one horizon."
        : "Observed: the lever does NOT increase spread on the tested horizons (ON ~= OFF — report-only).",
    ],
    comparisons,
  };
}

function isEcoMigFoundationAuditRequested(options) {
  return (
    options.targetedResourceFoundationAudit === true ||
    options.targetedSharedCatchmentAudit === true ||
    options.targetedRawSurplusDeficitAudit === true ||
    options.targetedMegaBandAudit === true ||
    options.targetedMigrationResourcePressureAudit === true ||
    options.targetedResourceAntiOmniscienceAudit === true ||
    options.targetedLongHorizonSanityAudit === true ||
    options.targetedEcoCalAudit === true ||
    options.targetedVisibilityAudit === true ||
    options.targetedInterBandReachabilityAudit === true ||
    options.targetedReportReplyAudit === true ||
    options.targetedWithholdingAudit === true ||
    options.targetedNewBandSpacingAudit === true
  );
}

function runEcoMigFoundationAudit(modules, options) {
  const years = Number.isFinite(options.ecoMigAuditYears) ? options.ecoMigAuditYears : 500;
  const benchmark = runBenchmark(
    modules,
    { scenario: "map2_varied_migration", years, ticks: undefined },
    {
      ...options,
      reportBand: false,
      probeAudit: false,
      returnWorld: true,
    },
  );
  const world = benchmark.world;
  const activeBands = Object.values(world.bands).filter(isActiveBand).sort(compareBands);
  const fissionEvents = getUniqueFissionEvents(Object.values(world.bands));
  const summary = benchmark.summary;
  const singleOriginSpread =
    years <= 300
      ? computeSingleOriginSpread(modules, { biasOn: true, years })
      : undefined;

  return {
    check: "ECO-MIG foundation audit",
    verdict: getEcoMigVerdict(world, activeBands),
    command: `node scripts/simBenchmark.mjs --targeted-resource-foundation-audit --eco-mig-audit-years ${years} --json`,
    scenario: "map2_varied_migration",
    years,
    completed: summary.completed,
    abortedReason: summary.abortedReason,
    runtime: {
      totalMs: summary.totalRuntimeMs,
      averageMsPerTick: summary.averageMsPerTick,
      maxMsPerTick: summary.maxMsPerTick,
      ticksSimulated: summary.ticksSimulated,
      ticksRequested: summary.ticksRequested,
    },
    notes: [
      "Audit inspects final simulated world state only; it does not mutate sim behaviour.",
      "Truth-level tile depletion is physical ecology; band decisions use observed/remembered resource knowledge plus bounded fallback, not hidden exact resources.",
      "FAUNA/AQUATIC-1: animal_food / aquatic_food are now backed by finite, summarized fauna/aquatic STOCK ZONES (faunaStock.ts) with seasonality, recovery, mobility, and human-pressure depletion. No individual-animal agents, no predator-prey food web. See faunaAquaticStockAudit.",
      "Single-origin spread is embedded only through 300y to keep this audit bounded; run --targeted-single-origin-spread --spread-500 for the 500y single-origin check.",
    ],
    resourceFoundationAudit: summarizeEcoResourceFoundation(modules, world, activeBands),
    sharedCatchmentAudit: summarizeEcoSharedCatchment(activeBands),
    rawSurplusDeficitAudit: summarizeEcoRawSurplusDeficit(activeBands),
    faunaAquaticStockAudit: summarizeFaunaAquaticStocks(modules, world, activeBands),
    plantPhysicalEcologyAudit: summarizePlantPhysicalEcology(modules, world, activeBands),
    megaBandAudit: summarizeEcoMegaBands(world, activeBands),
    migrationResourcePressureAudit: {
      ...summarizeEcoMigrationPressure(world, activeBands, fissionEvents, years),
      singleOriginSpread,
    },
    ecoCalAudit: summarizeEcoCalibration(activeBands),
    visibilityAudit: summarizeVisibilityAudit(activeBands),
    interBandReachabilityAudit: summarizeInterBandReachabilityAudit(activeBands),
    replyContradictionAudit: summarizeReportReplyAudit(activeBands),
    withholdingMisleadingAudit: summarizeWithholdingAudit(activeBands),
    newBandSocialSpacingAudit: summarizeNewBandSpacingAudit(modules, world, activeBands, fissionEvents),
    antiOmniscienceResourceAudit: summarizeEcoAntiOmniscience(world, activeBands, fissionEvents),
    longHorizonSanityAudit: summarizeEcoLongHorizon(world, activeBands, summary, years),
    performance: {
      slowestSubpasses: summary.slowestSubpasses,
      phaseSummary: summary.phaseSummary,
      tileDepletionRecords: Object.keys(world.tileDepletion ?? {}).length,
    },
  };
}

// FAUNA/AQUATIC-1 — deterministic unit-level fauna dynamics fixture. The macro
// loop does not run intra-season trips, so this directly exercises the stock
// module: bounded geography + determinism, trip depletion bounded by floor,
// rested recovery, stock-grounded return factor, seasonal pulse, and the
// anti-omniscient sign signal (uncovered tile ⇒ 0). No sim mutation, no random.
function runFaunaStockFixtureAudit(modules) {
  const fauna = modules.faunaStock;
  const world = modules.createVariedMigrationWorld();

  // A — geography: bounded, sparse, deterministic.
  const geoA = fauna.deriveFaunaStockGeography(world);
  const geoB = fauna.deriveFaunaStockGeography(world);
  const determinismMatch =
    geoA.stocks.length === geoB.stocks.length &&
    geoA.stocks.every((stock, index) => stock.id === geoB.stocks[index].id);
  const summary = fauna.summarizeFaunaStocks(world);
  const influenceBounded = geoA.stocks.every((stock) => stock.influenceTileIds.length <= 13 && stock.influenceTileIds.length >= 1);
  const ccBounded = geoA.stocks.every((stock) => stock.carryingCapacity > 0 && stock.carryingCapacity <= 1);

  const stock = geoA.stocks.find((entry) => entry.faunaClass === "aquatic_food") ?? geoA.stocks[0];
  const tileId = stock.anchorTileId;
  const faunaClass = stock.faunaClass;

  // B — repeated HUMAN trip depletion: monotone non-increasing and floored at the
  // HUMAN_HARVEST_RESERVE. Direct harvesting can never overdraw a stock, but that
  // reserve is NOT a survival guarantee (natural pressure can still push below it).
  const reserve = fauna.HUMAN_HARVEST_RESERVE ?? 0.08;
  let depleteWorld = world;
  const abundanceTrace = [fauna.getFaunaStockDynamic(depleteWorld, stock.id).abundance];
  const returnFactorFull = fauna.deriveFaunaTripReturnFactor(depleteWorld, geoA, tileId, faunaClass, "summer");
  for (let i = 0; i < 30; i += 1) {
    depleteWorld = fauna.applyFaunaTripDepletion(depleteWorld, geoA, tileId, faunaClass, 0.85, (1000 + i));
    abundanceTrace.push(fauna.getFaunaStockDynamic(depleteWorld, stock.id).abundance);
  }
  const depletedAbundance = fauna.getFaunaStockDynamic(depleteWorld, stock.id).abundance;
  const monotoneNonIncreasing = abundanceTrace.every((value, index) => index === 0 || value <= abundanceTrace[index - 1] + 1e-9);
  // Replaces the stale universal 0.18 floor: abundance stays bounded/finite, and
  // HUMAN harvesting bottoms out exactly at the reserve (cannot overdraw), while
  // hunting return collapses as the stock approaches it.
  const abundanceBoundedNoNaN =
    abundanceTrace.every((value) => Number.isFinite(value) && value >= 0 && value <= 1) &&
    geoA.stocks.every((entry) => {
      const abundance = fauna.getFaunaStockDynamic(world, entry.id).abundance;
      return Number.isFinite(abundance) && abundance >= 0 && abundance <= 1;
    });
  const humanHarvestReserveHeld = depletedAbundance >= reserve - 1e-9 && depletedAbundance <= reserve + 0.02;
  const meaningfulDepletion = depletedAbundance < 0.7;
  const returnFactorDepleted = fauna.deriveFaunaTripReturnFactor(depleteWorld, geoA, tileId, faunaClass, "summer");
  const depletedReturnLower = returnFactorDepleted < returnFactorFull;
  const huntingCollapsesNearReserve = returnFactorDepleted <= returnFactorFull * 0.25 + 1e-9;

  // D1 — rested recovery from a VIABLE remnant: a self-supporting stock left at the
  // reserve rebounds toward carrying capacity once human pressure stops (no bands).
  const recoveryCache = modules.buildTickContextCache({ ...depleteWorld, bands: {} });
  let recoverWorld = { ...depleteWorld, bands: {} };
  const recoveryStart = fauna.getFaunaStockDynamic(recoverWorld, stock.id).abundance;
  for (let i = 0; i < 24; i += 1) {
    recoverWorld = fauna.advanceFaunaStocks(recoverWorld, recoveryCache);
  }
  const recoveredAbundance = fauna.getFaunaStockDynamic(recoverWorld, stock.id).abundance;
  const recovered = recoveredAbundance > recoveryStart + 0.02;

  // D2 — continued HUMAN pressure prevents recovery: rest interleaved with fresh
  // trip depletion holds the stock near the reserve instead of rebounding.
  let pressuredWorld = { ...depleteWorld, bands: {} };
  const pressuredCache = modules.buildTickContextCache(pressuredWorld);
  for (let i = 0; i < 24; i += 1) {
    pressuredWorld = fauna.advanceFaunaStocks(pressuredWorld, pressuredCache);
    pressuredWorld = fauna.applyFaunaTripDepletion(pressuredWorld, geoA, tileId, faunaClass, 0.85, 2000 + i);
  }
  const pressuredAbundance = fauna.getFaunaStockDynamic(pressuredWorld, stock.id).abundance;
  const humanPressurePreventsRecovery = pressuredAbundance < recoveredAbundance - 0.2;

  // D3 — a stock at TRUE ZERO does not magically resurrect: recovery is proportional
  // to remaining abundance (low-abundance brake), so with no explicit recolonization
  // model a collapsed stock stays collapsed — there is no universal floor lifting it.
  const zeroDyn = { ...fauna.getFaunaStockDynamic(depleteWorld, stock.id), abundance: 0 };
  let zeroWorld = { ...depleteWorld, bands: {}, faunaStocks: { ...(depleteWorld.faunaStocks ?? {}), [stock.id]: zeroDyn } };
  const zeroCache = modules.buildTickContextCache(zeroWorld);
  for (let i = 0; i < 24; i += 1) {
    zeroWorld = fauna.advanceFaunaStocks(zeroWorld, zeroCache);
  }
  const trueZeroAbundance = fauna.getFaunaStockDynamic(zeroWorld, stock.id).abundance;
  const trueZeroDoesNotResurrect = trueZeroAbundance <= 0.02;

  const predatorStocks = geoA.stocks.filter((entry) => entry.trophicRole === "predator");
  const totalFaunaCap = fauna.GLOBAL_STOCK_CAP ?? 260;
  const predatorSubCap = fauna.PREDATOR_STOCK_CAP ?? 24;

  // B (seasonality) — a run/peak season pays a higher return pulse than a lean one.
  const peakFactor = fauna.seasonalAvailabilityFactor(stock, stock.seasonality.peakSeasons[0] ?? "summer", true);
  const leanFactor = fauna.seasonalAvailabilityFactor(stock, stock.seasonality.leanSeasons[0] ?? "winter", true);
  const peakAboveLean = peakFactor >= leanFactor;

  // C/E — anti-omniscient sign: bounded [0,1]; an UNCOVERED tile yields exactly 0
  // (no hidden stock leak), a covered tile yields a bounded uncertain signal.
  let uncoveredTileId;
  for (const id of Object.keys(world.tiles)) {
    if (!geoA.byTile.has(id)) {
      uncoveredTileId = id;
      break;
    }
  }
  const coveredSign = fauna.deriveFaunaSignStrength(world, geoA, tileId, faunaClass, "summer", 0.6, 1);
  const uncoveredSign = uncoveredTileId === undefined ? 0 : fauna.deriveFaunaSignStrength(world, geoA, uncoveredTileId, faunaClass, "summer", 0.6, 1);
  const signBounded = coveredSign >= 0 && coveredSign <= 1 && uncoveredSign === 0;

  const checks = {
    determinismMatch,
    boundedCount: geoA.stocks.length <= totalFaunaCap,
    predatorsReservedWithinCap:
      predatorStocks.length >= 1 && predatorStocks.length <= predatorSubCap && geoA.stocks.length <= totalFaunaCap,
    influenceBounded,
    ccBounded,
    abundanceBoundedNoNaN,
    monotoneNonIncreasing,
    humanHarvestReserveHeld,
    meaningfulDepletion,
    depletedReturnLower,
    huntingCollapsesNearReserve,
    recovered,
    humanPressurePreventsRecovery,
    trueZeroDoesNotResurrect,
    peakAboveLean,
    signBounded,
  };
  const verdict = Object.values(checks).every(Boolean) ? "pass" : "review";

  return {
    check: "FAUNA/AQUATIC-1 stock dynamics fixture",
    verdict,
    command: "node scripts/simBenchmark.mjs --targeted-fauna-stock-audit --json",
    scenario: "map2_varied_migration (geography only; unit dynamics)",
    notes: [
      "Directly exercises faunaStock.ts pure dynamics (no sim tick loop, no trips run); deterministic, no random.",
      "TOTAL fauna cap covers prey + predators; predators are reserved WITHIN the cap, never appended on top of it.",
      "No universal abundance floor: HUMAN harvesting bottoms out at HUMAN_HARVEST_RESERVE, but natural/trophic pressure can collapse a stock below it, and a true-zero stock does not resurrect.",
      "Rested recovery from a viable remnant rebounds toward carrying capacity; continued human pressure holds it near the reserve.",
      "Sign strength on an uncovered tile is exactly 0 — fauna are never knowable without a stock present (anti-omniscience).",
    ],
    checks,
    cap: {
      totalFaunaCap,
      predatorSubCap,
      actualTotal: geoA.stocks.length,
      predatorCount: predatorStocks.length,
      deterministicSelection: "prey trimmed by lowest carrying capacity (stable by id) so total <= cap; predators retained",
    },
    geography: {
      stockCount: summary.stockCount,
      aquaticCount: summary.aquaticCount,
      terrestrialCount: summary.terrestrialCount,
      byKind: summary.byKind,
      meanCarryingCapacity: summary.meanCarryingCapacity,
      meanInfluenceTiles: summary.meanInfluenceTiles,
      maxInfluenceTiles: summary.maxInfluenceTiles,
    },
    depletion: {
      sampledStockKind: stock.kind,
      faunaClass,
      humanHarvestReserve: reserve,
      abundanceStart: abundanceTrace[0],
      abundanceAfter30Trips: round4Maybe(depletedAbundance),
      returnFactorFull: round4Maybe(returnFactorFull),
      returnFactorDepleted: round4Maybe(returnFactorDepleted),
    },
    recovery: {
      abundanceBeforeRest: round4Maybe(recoveryStart),
      abundanceAfter24Seasons: round4Maybe(recoveredAbundance),
      abundanceUnderContinuedPressure: round4Maybe(pressuredAbundance),
      trueZeroAfter24Seasons: round4Maybe(trueZeroAbundance),
    },
    seasonality: { peakFactor: round4Maybe(peakFactor), leanFactor: round4Maybe(leanFactor) },
    sign: { coveredSign: round4Maybe(coveredSign), uncoveredSign },
  };
}

function runTargetedFaunaStocksAudit(modules, options) {
  const requestedYears = Number.isFinite(options.ecoMigAuditYears) ? options.ecoMigAuditYears : 32;
  const years = Math.min(requestedYears, 36);
  const defaultRun = runBenchmark(
    modules,
    { scenario: "map2_varied_migration", years, ticks: undefined },
    { ...options, reportBand: false, probeAudit: false, returnWorld: true },
  );
  const repeatRun = runBenchmark(
    modules,
    { scenario: "map2_varied_migration", years, ticks: undefined },
    { ...options, reportBand: false, probeAudit: false, returnWorld: true },
  );
  const world = projectEcologyResearchWorld(modules, defaultRun.world);
  const repeatWorld = projectEcologyResearchWorld(modules, repeatRun.world);
  const fauna = modules.faunaStock;
  const geography = fauna.deriveFaunaStockGeography(world);
  const stocks = geography.stocks;
  const activeBands = Object.values(world.bands).filter(isActiveBand);
  const visibleBands = activeBands.filter((band) => band.visibleNature !== undefined);
  const faunaCards = visibleBands.flatMap((band) => band.visibleNature?.faunaCards ?? []);
  const animalCards = faunaCards.filter((card) => !card.tags.includes("aquatic"));
  const animalKnowledge = visibleBands.flatMap((band) => band.visibleNature?.animalKnowledge ?? []);
  const animalPerceptions = visibleBands.flatMap((band) => band.visibleNature?.animalPerceptions ?? []);
  const animalTrips = activeBands.flatMap((band) =>
    (band.recentIntraSeasonTrips ?? []).filter((trip) => trip.taskGroupType === "hunting_group" || trip.resourceClassId === "animal_food"),
  );
  const animalTraces = animalTrips.map((trip) => trip.animalActivityTrace).filter((trace) => trace !== undefined);
  const faunaFixture = runFaunaStockFixtureAudit(modules);
  const controlled = buildControlledFaunaStocksCase(modules, world, activeBands[0]);
  const controlledDanger = runControlledFaunaAcuteRiskCase(modules, controlled.world, controlled.bandId);
  const natureEvents = activeBands.flatMap((band) =>
    (band.eventHistory?.recentEvents ?? []).filter((event) => event.category === "nature"),
  );
  const controlledNatureEvents = Object.values(controlled.world.bands).flatMap((band) =>
    (band.eventHistory?.recentEvents ?? []).filter((event) => event.category === "nature"),
  );
  const faunaEvents = [...natureEvents, ...controlledNatureEvents].filter(isFaunaReadableEvent);
  const sourceGuards = runFaunaStocksSourceGuards();
  const faunaSummary = fauna.summarizeFaunaStocks(world);
  const habitat = summarizeFaunaStocksHabitatAudit(modules, world, stocks, faunaCards);
  const stockDynamicRecords = Object.keys(world.faunaStocks ?? {}).length;
  const unsupportedEvents = faunaEvents.filter((event) => !isSupportedFaunaEvent(event));
  const hiddenKnowledgeViolations = countFaunaAntiOmniscienceViolations(activeBands);
  const antiOmniscienceProof = runFaunaAntiOmniscienceProof(modules, world);
  const memoryCapViolations = visibleBands.filter((band) => {
    const nature = band.visibleNature;
    return nature !== undefined && (
      nature.faunaCards.length > nature.memoryCaps.faunaCardCap ||
      nature.aquaticCards.length > nature.memoryCaps.aquaticCardCap ||
      nature.animalKnowledge.length > nature.memoryCaps.animalKnowledgeCap ||
      nature.acuteEpisodes.length > nature.memoryCaps.acuteEpisodeCap
    );
  }).length;
  const protoAnimalReasons = activeBands.flatMap((band) =>
    band.protoCampMemory?.topPlaces.flatMap((place) =>
      [...place.positiveReasons, ...place.negativeReasons]
        .filter((reason) => /animal|game|hunt|predator|overhunting|wary/i.test(reason.reason))
        .map((reason) => ({
          bandId: String(band.id),
          tileId: String(place.tileId),
          state: place.campLikeState,
          reason: reason.reason,
          strength: reason.strength,
          rawSource: reason.rawSource,
        }))
    ) ?? [],
  );
  const controlledAnimalCard = controlled.world.bands[controlled.bandId]?.visibleNature?.faunaCards.find((card) =>
    card.stockId === controlled.stockId,
  );
  const checks = {
    habitatLinkedFaunaExamples: habitat.habitatLinkedExamples.length > 0,
    openPlainsSupportAppropriateAnimals: habitat.openPlainExamples.length > 0,
    denseForestNoOpenPlainsAnimals: habitat.denseForestOpenAnimalViolations.length === 0,
    wetlandRiverDeltaSupportsAquatic: habitat.waterEdgeExamples.length > 0,
    forestEdgeSupportsGamePredatorSigns: habitat.forestEdgeExamples.length > 0 && (habitat.predatorSignExamples.length > 0 || controlledAnimalCard !== undefined),
    tracksAndSightingsUpdateKnowledge: animalKnowledge.some((memory) => isAnimalTrackOrSightingState(memory.state)) || controlledAnimalCard !== undefined,
    successfulHuntUpdatesConfidencePressure:
      animalTraces.some((trace) => (trace.outcomeClass === "success" || trace.outcomeClass === "partial") && trace.pressureApplied > 0) ||
      controlled.successTrace.pressureApplied > 0,
    failedHuntWeakensRouteConfidence:
      animalCards.some((card) => card.knowledgeState === "failed_to_find" || card.knowledgeState === "stale_route" || card.usefulness === "unreliable") ||
      controlled.failureTrace.knowledgeUpdate === "failure_staled_route",
    repeatedHuntingIncreasesWariness: controlled.pressure.abundanceAfterRepeatedUse < controlled.pressure.abundanceBeforeRepeatedUse && controlled.pressure.disturbanceAfterRepeatedUse > controlled.pressure.disturbanceBeforeRepeatedUse,
    restRecoveryAllowsRecovery: controlled.recovery.abundanceAfterRest > controlled.recovery.abundanceBeforeRest,
    animalDangerFeedsAcuteRisk: controlledDanger.animalEpisodeCount > 0,
    animalPerceptionMemoryChanges: animalPerceptions.length > 0 || (controlledAnimalCard?.perception.length ?? 0) > 0,
    protoCampAnimalReasonsAppear: protoAnimalReasons.length > 0 || controlled.protoCampAnimalReasons.length > 0,
    faunaEventsGrounded: faunaEvents.length > 0 && faunaEvents.every((event) => event.grounded === true && event.rawSource.length > 0 && event.rawReason.length > 0),
    unsupportedFaunaEventsZero: unsupportedEvents.length === 0,
    antiOmnisciencePasses:
      visibleBands.every((band) => band.visibleNature?.antiOmniscience.exactHiddenStockLocationsRevealed === false) &&
      animalTraces.every((trace) => trace.targetKnownMemoryOnly === true) &&
      hiddenKnowledgeViolations === 0 &&
      antiOmniscienceProof.pass === true &&
      faunaFixture.checks.signBounded === true,
    noPopulationCrash: defaultRun.summary.totalPopulation > Math.max(20, defaultRun.summary.startPopulation * 0.2),
    noMegaBandExplosion: activeBands.filter((band) => band.demography.population >= 500).length === 0,
    determinismStaticGuardsPass: makeFaunaStocksAuditFingerprint(world) === makeFaunaStocksAuditFingerprint(repeatWorld) && sourceGuards.pass,
  };
  const verdict = Object.values(checks).every(Boolean) && memoryCapViolations === 0 ? "pass" : "review";

  return {
    check: "FAUNA-STOCKS-1 targeted audit",
    verdict,
    command: `node scripts/simBenchmark.mjs --targeted-fauna-stocks-audit --eco-mig-audit-years ${requestedYears} --json`,
    scenario: "map2_varied_migration + controlled bounded trace fixtures",
    notes: [
      "Normal run proves bounded stock/card/event behavior across a live world.",
      "Controlled fixtures use real faunaStock dynamics and existing visible/proto-camp/acute derivations to exercise rare hunt failure, pressure, recovery, and animal-danger hooks.",
      "No individual animals, predator-prey population model, domestication, dogs, riding, pastoralism, ownership, territory, war, myths, or species overload are introduced.",
    ],
    checks,
    existingArchitectureFound: {
      stockSummary: faunaSummary,
      dynamicStockRecords: stockDynamicRecords,
      visibleFaunaCards: faunaCards.length,
      animalKnowledgeRecords: animalKnowledge.length,
      animalPerceptionRecords: animalPerceptions.length,
      animalTrips: animalTrips.length,
      animalActivityTraces: animalTraces.length,
      natureEvents: natureEvents.length,
      controlledNatureEvents: controlledNatureEvents.length,
      protoCampAnimalReasons: protoAnimalReasons.length,
    },
    habitat,
    trackingSightings: {
      byKnowledgeState: countBy(faunaCards, (card) => card.knowledgeState),
      byKnownness: countBy(faunaCards, (card) => card.knownness),
      examples: faunaCards.filter((card) => isAnimalTrackOrSightingState(card.knowledgeState)).slice(0, 8).map(formatVisibleFaunaAuditExample),
      controlledCard: controlledAnimalCard === undefined ? undefined : formatVisibleFaunaAuditExample(controlledAnimalCard),
    },
    huntingIntegration: {
      naturalAnimalTraceCount: animalTraces.length,
      naturalTraceExamples: animalTraces.slice(0, 8),
      controlledSuccessTrace: controlled.successTrace,
      controlledFailureTrace: controlled.failureTrace,
      abstractHuntingPlaceholders: animalTrips.filter((trip) => trip.animalActivityTrace === undefined).length,
      abstractHuntingLabel: "animal trips without animalActivityTrace remain abstract/background hunting placeholders",
    },
    pressureWarinessRecovery: {
      controlledPressure: controlled.pressure,
      controlledRecovery: controlled.recovery,
      naturalPressureCards: animalCards.filter((card) => card.huntingOrFishingPressure > 0 || card.wariness > 0).slice(0, 8).map(formatVisibleFaunaAuditExample),
    },
    animalDangerAcuteRisk: controlledDanger,
    animalPerception: {
      byPerception: countBy(animalPerceptions.flatMap((entry) => entry.perception), (value) => value),
      examples: animalPerceptions.slice(0, 8),
    },
    protoCampPlaceIntegration: {
      naturalExamples: protoAnimalReasons.slice(0, 8),
      controlledExamples: controlled.protoCampAnimalReasons,
    },
    faunaEvents: {
      eventCount: faunaEvents.length,
      byTitle: countBy(faunaEvents, (event) => event.title),
      examples: faunaEvents.slice(0, 8).map((event) => ({
        title: event.title,
        description: event.description,
        rawSource: event.rawSource,
        rawReason: event.rawReason,
        sourceReasonIds: event.sourceReasonIds.slice(0, 4),
      })),
      unsupportedFaunaEvents: unsupportedEvents.length,
      unsupportedExamples: unsupportedEvents.slice(0, 5).map((event) => ({ title: event.title, rawReason: event.rawReason })),
    },
    antiOmniscience: {
      hiddenKnowledgeViolations,
      visibleNatureFlags: visibleBands.every((band) => band.visibleNature?.antiOmniscience.candidateTilesFromBandKnowledgeOnly === true),
      exactHiddenStockLocationsRevealed: visibleBands.some((band) => band.visibleNature?.antiOmniscience.exactHiddenStockLocationsRevealed === true),
      traceTargetKnownOnly: animalTraces.every((trace) => trace.targetKnownMemoryOnly === true),
      uncoveredSignZero: faunaFixture.sign.uncoveredSign === 0,
      separationProof: antiOmniscienceProof,
    },
    performanceCaps: {
      faunaStockCount: faunaSummary.stockCount,
      globalFaunaStockCap: 260,
      storedDynamicStockRecords: stockDynamicRecords,
      visibleFaunaCardCapMax: maxPerformanceCount(visibleBands, (band) => band.visibleNature?.memoryCaps.faunaCardCap ?? 0),
      visibleFaunaCardsMax: maxPerformanceCount(visibleBands, (band) => band.visibleNature?.faunaCards.length ?? 0),
      trackSightingMemoryCapMax: maxPerformanceCount(visibleBands, (band) => band.visibleNature?.memoryCaps.animalKnowledgeCap ?? 0),
      trackSightingMemoryMax: maxPerformanceCount(visibleBands, (band) => band.visibleNature?.animalKnowledge.length ?? 0),
      eventRecentCap: 48,
      protoCampMemoryCapMax: maxPerformanceCount(activeBands, (band) => band.protoCampMemory?.memoryCap ?? 0),
      protoCampAnimalReasonCount: protoAnimalReasons.length,
      memoryCapViolations,
      noPerTileFaunaGrid: true,
      normalVisibleLookup: "visible cards scan <=28 band-known candidate tiles and fauna geography byTile buckets",
    },
    population: {
      startPopulation: defaultRun.summary.startPopulation,
      finalPopulation: defaultRun.summary.totalPopulation,
      activeBands: defaultRun.summary.activeBands,
      totalBands: defaultRun.summary.totalBands,
      megaBands: activeBands.filter((band) => band.demography.population >= 500).length,
      completed: defaultRun.summary.completed,
      abortedReason: defaultRun.summary.abortedReason,
    },
    sourceGuards,
  };
}

function summarizeFaunaStocksHabitatAudit(modules, world, stocks, faunaCards) {
  const forest = modules.forestPatches;
  const habitatLinkedExamples = stocks
    .filter((stock) => stock.habitatBasis.length > 0 && stock.habitatSuitability >= 0.34)
    .slice(0, 10)
    .map((stock) => formatStockHabitatExample(world, stock));
  const openPlainExamples = stocks
    .filter((stock) =>
      stock.faunaClass === "animal_food" &&
      (stock.habitat === "open_plain" || stock.habitat === "open_valley" || stock.habitat === "river_meadow") &&
      (stock.kind === "medium_game" || stock.kind === "large_game"),
    )
    .slice(0, 8)
    .map((stock) => formatStockHabitatExample(world, stock));
  const denseForestOpenAnimalViolations = stocks
    .filter((stock) => stock.faunaClass === "animal_food")
    .filter((stock) => {
      const tile = world.tiles[stock.anchorTileId];
      if (tile === undefined) {
        return false;
      }
      return forest.classifyForestCoverForTile(tile) === "dense_woodland" &&
        (stock.habitat === "open_plain" || stock.habitat === "river_meadow" || stock.kind === "large_game" || stock.kind === "medium_game");
    })
    .map((stock) => formatStockHabitatExample(world, stock));
  const waterEdgeExamples = stocks
    .filter((stock) =>
      stock.faunaClass === "aquatic_food" &&
      (stock.habitat === "delta_wetland" || stock.habitat === "river_reach" || stock.habitat === "lake" || stock.habitat === "coast_reedbed"),
    )
    .slice(0, 8)
    .map((stock) => formatStockHabitatExample(world, stock));
  const forestEdgeExamples = stocks
    .filter((stock) =>
      stock.faunaClass === "animal_food" &&
      (stock.habitat === "forest_edge" || stock.habitat === "wet_woodland" || stock.habitat === "scrub_edge" || stock.habitat === "dense_cover"),
    )
    .slice(0, 8)
    .map((stock) => formatStockHabitatExample(world, stock));
  const predatorSignExamples = faunaCards
    .filter((card) => card.sourceKind === "predator_sign" || card.archetype === "wolves")
    .slice(0, 6)
    .map(formatVisibleFaunaAuditExample);

  return {
    habitatLinkedExamples,
    openPlainExamples,
    denseForestOpenAnimalViolations,
    waterEdgeExamples,
    forestEdgeExamples,
    predatorSignExamples,
    byHabitat: countBy(stocks, (stock) => stock.habitat),
    byKind: countBy(stocks, (stock) => stock.kind),
  };
}

function formatStockHabitatExample(world, stock) {
  const tile = world.tiles[stock.anchorTileId];
  return {
    stockId: String(stock.id),
    faunaClass: stock.faunaClass,
    kind: stock.kind,
    habitat: stock.habitat,
    terrain: tile?.terrainKind,
    tileId: String(stock.anchorTileId),
    habitatSuitability: stock.habitatSuitability,
    habitatBasis: stock.habitatBasis,
    carryingCapacity: stock.carryingCapacity,
  };
}

function buildControlledFaunaStocksCase(modules, sourceWorld, sourceBand) {
  const fauna = modules.faunaStock;
  const baseWorld = sourceWorld;
  const geography = fauna.deriveFaunaStockGeography(baseWorld);
  const stock = geography.stocks.find((entry) => entry.faunaClass === "animal_food" && entry.habitat === "forest_edge") ??
    geography.stocks.find((entry) => entry.faunaClass === "animal_food") ??
    geography.stocks[0];
  const band = sourceBand ?? Object.values(baseWorld.bands)[0];
  const baseTrace = fauna.deriveFaunaTripStockTrace(baseWorld, geography, stock.anchorTileId, stock.faunaClass, baseWorld.time.season, baseWorld.time.tick);
  const successTrace = makeControlledAnimalTrace(baseTrace, "partial_success", "partial", "reliable_route_strengthened", 0.32);
  const failureTrace = makeControlledAnimalTrace(baseTrace, "target_not_found", "failure", "failure_staled_route", 0);
  const successTrip = makeControlledAnimalTrip(baseWorld, band, stock.anchorTileId, successTrace, "partial_success", 1);
  const failureTrip = makeControlledAnimalTrip(baseWorld, band, stock.anchorTileId, failureTrace, "target_not_found", 2);
  let pressureWorld = baseWorld;
  const before = fauna.getFaunaStockDynamic(pressureWorld, stock.id);
  for (let index = 0; index < 8; index += 1) {
    pressureWorld = fauna.applyFaunaTripDepletion(pressureWorld, geography, stock.anchorTileId, stock.faunaClass, 0.82, Number(baseWorld.time.tick) + index);
  }
  const afterPressure = fauna.getFaunaStockDynamic(pressureWorld, stock.id);
  let restWorld = { ...pressureWorld, bands: {} };
  const beforeRest = fauna.getFaunaStockDynamic(restWorld, stock.id);
  for (let index = 0; index < 16; index += 1) {
    restWorld = fauna.advanceFaunaStocks(restWorld, modules.buildTickContextCache(restWorld));
  }
  const afterRest = fauna.getFaunaStockDynamic(restWorld, stock.id);
  const fixtureBand = {
    ...band,
    position: stock.anchorTileId,
    knowledge: {
      ...band.knowledge,
      observedTiles: {
        ...band.knowledge.observedTiles,
        [stock.anchorTileId]: band.knowledge.observedTiles[stock.anchorTileId] ?? { tileId: stock.anchorTileId },
      },
    },
    recentIntraSeasonTrips: [successTrip, failureTrip, ...(band.recentIntraSeasonTrips ?? [])].slice(0, 24),
    lastIntraSeasonTrip: successTrip,
  };
  const injected = {
    ...baseWorld,
    faunaStocks: pressureWorld.faunaStocks,
    bands: {
      ...baseWorld.bands,
      [band.id]: fixtureBand,
    },
  };
  const withProto = modules.protoCamps.applyProtoCampContext(injected);
  const withVisible = modules.visibleNature.applyVisibleNatureContext(withProto);
  const withEvents = modules.bandEvents.applyBandReadabilityContext(withVisible);
  const finalBand = withEvents.bands[band.id];
  const protoCampAnimalReasons = finalBand?.protoCampMemory?.topPlaces.flatMap((place) =>
    [...place.positiveReasons, ...place.negativeReasons]
      .filter((reason) => /animal|game|hunt|predator|overhunting|wary/i.test(reason.reason))
      .map((reason) => ({
        tileId: String(place.tileId),
        state: place.campLikeState,
        reason: reason.reason,
        strength: reason.strength,
        rawSource: reason.rawSource,
      }))
  ) ?? [];

  return {
    world: withEvents,
    bandId: band.id,
    stockId: String(stock.id),
    successTrace,
    failureTrace,
    pressure: {
      stockId: String(stock.id),
      abundanceBeforeRepeatedUse: before.abundance,
      disturbanceBeforeRepeatedUse: before.disturbance,
      abundanceAfterRepeatedUse: afterPressure.abundance,
      disturbanceAfterRepeatedUse: afterPressure.disturbance,
    },
    recovery: {
      abundanceBeforeRest: beforeRest.abundance,
      abundanceAfterRest: afterRest.abundance,
      disturbanceBeforeRest: beforeRest.disturbance,
      disturbanceAfterRest: afterRest.disturbance,
    },
    protoCampAnimalReasons,
  };
}

function makeControlledAnimalTrace(baseTrace, activityOutcome, outcomeClass, knowledgeUpdate, pressureApplied) {
  return {
    stockId: baseTrace.stockId,
    faunaKind: baseTrace.kind,
    habitat: baseTrace.habitat,
    anchorTileId: baseTrace.anchorTileId,
    targetArchetypeHint: baseTrace.kind === "small_game" ? "small game" : "stock-backed game",
    targetChosenReason: "controlled audit trip from band-known recent animal route",
    habitatBasis: baseTrace.habitatBasis,
    habitatSuitability: baseTrace.habitatSuitability,
    expectedReturnFactor: baseTrace.expectedReturnFactor,
    actualReturnValue: outcomeClass === "failure" ? 0 : 0.28,
    currentAbundance: baseTrace.currentAbundance,
    disturbance: baseTrace.disturbance,
    seasonalAvailability: baseTrace.seasonalAvailability,
    confidence: Math.max(0, Math.min(1, baseTrace.detectability * 0.34 + baseTrace.habitatSuitability * 0.32 + baseTrace.expectedReturnFactor * 0.24)),
    pressure: baseTrace.pressure,
    pressureApplied,
    recoveryRate: baseTrace.recoveryRate,
    warinessBefore: Math.max(0, Math.min(1, baseTrace.disturbance * 0.56 + baseTrace.pressure * 0.32)),
    warinessChange: Math.max(0, Math.min(1, pressureApplied * baseTrace.mobility * 0.18)),
    dangerRisk: Math.max(0, Math.min(1, baseTrace.risk + (knowledgeUpdate === "danger_caution_added" ? 0.16 : 0))),
    dangerClass: baseTrace.risk >= 0.58 ? "high" : baseTrace.risk >= 0.32 ? "moderate" : "low",
    distanceTiles: 0,
    travelCost: 0,
    laborAccessCost: baseTrace.laborAccessCost,
    activityOutcome,
    outcomeClass,
    depletionApplied: outcomeClass === "success" || outcomeClass === "partial",
    knowledgeUpdate,
    memoryUpdate: outcomeClass === "failure" ? "resource_memory_update" : "resource_memory_update",
    protoCampInfluence: knowledgeUpdate === "failure_staled_route"
      ? "overhunted_scarcity_signal"
      : baseTrace.habitat === "forest_edge" || baseTrace.habitat === "wet_woodland"
        ? "forest_edge_game_signal"
        : "animal_route_signal",
    rawSource: baseTrace.rawSource,
    reasonIds: baseTrace.reasonIds,
    targetKnownMemoryOnly: true,
  };
}

function makeControlledAnimalTrip(world, band, tileId, trace, activityOutcome, dayOffset) {
  return {
    day: dayOffset,
    tick: Number(world.time.tick) + dayOffset,
    season: world.time.season,
    sourceBandId: band.id,
    originTileId: tileId,
    targetTileId: tileId,
    taskGroupType: "hunting_group",
    groupLabel: "hunting group",
    estimatedPeopleCount: 3,
    objective: "food_patch_check",
    objectiveLabel: "food patch check",
    startDay: dayOffset,
    endDay: dayOffset,
    activityStatus: "completed_observation",
    distanceTiles: 0,
    estimatedDurationDays: 1,
    cause: "food_resource_check",
    movementType: "local_foraging_loop",
    outcome: "returns_same_day",
    activityResult: activityOutcome,
    activityOutcome,
    activityOutcomeReasonIds: [`reason:fauna-stocks-audit:activity:${String(band.id)}:${String(tileId)}:${dayOffset}`],
    activityOutcomeSummary: `controlled_${activityOutcome}; fauna_stocks_audit`,
    resourceReturn: {
      returnedResourceKind: activityOutcome === "target_not_found" ? "none" : "hunted_fauna_food",
      estimatedReturnValue: trace.actualReturnValue,
      returnConfidence: trace.confidence,
      consumedByEconomy: false,
      noYieldCoupling: true,
      noCarryingCapacityCoupling: true,
      noPopulationChange: true,
      noStressChange: true,
      noSupportChange: true,
      reasonIds: [`reason:fauna-stocks-audit:return:${String(band.id)}:${String(tileId)}:${dayOffset}`],
    },
    shadowSubsistence: {
      shadowReturnKind: activityOutcome === "target_not_found" ? "none" : "hunted_food_shadow",
      shadowSupportDomain: activityOutcome === "target_not_found" ? "information" : "food",
      shadowGrossValue: trace.actualReturnValue,
      shadowTravelCost: 0,
      shadowRiskPenalty: trace.dangerRisk * 0.04,
      shadowNetValue: Math.max(0, trace.actualReturnValue - trace.dangerRisk * 0.04),
      shadowReliability: trace.confidence,
      contributesAtBaseSameDay: true,
      seasonalEcologyModifier: 1,
      shadowConsumedByEconomy: false,
      noEconomyCoupling: true,
      reasonIds: [`reason:fauna-stocks-audit:shadow:${String(band.id)}:${String(tileId)}:${dayOffset}`],
    },
    animalActivityTrace: trace,
    activityMemoryEffect: {
      sourceBandId: band.id,
      sourceTripDay: dayOffset,
      tick: Number(world.time.tick) + dayOffset,
      season: world.time.season,
      targetTileId: tileId,
      resourceClassId: "animal_food",
      activityOutcome,
      effectType: activityOutcome === "target_not_found" ? "confidence_lowered" : "confidence_refreshed",
      effectSummary: "controlled fauna stocks audit memory-only trace",
      confidenceDelta: activityOutcome === "target_not_found" ? -0.1 : 0.12,
      reasonIds: [`reason:fauna-stocks-audit:memory:${String(band.id)}:${String(tileId)}:${dayOffset}`],
      noHiddenTruth: true,
      targetKnownMemoryOnly: true,
      noNewResourceDiscovery: true,
      noFoodCoupling: true,
      noYieldCoupling: true,
      noCarryingCapacityCoupling: true,
      noPopulationChange: true,
      noStressChange: true,
      noSupportChange: true,
    },
    pathTiles: [tileId],
    tilesCrossed: 0,
    roundTripTiles: 0,
    activityDaysRepresented: 3,
    resourceClassId: "animal_food",
    resultSummary: `controlled_${activityOutcome}; fauna_stocks_audit`,
    reasonIds: [`reason:fauna-stocks-audit:trip:${String(band.id)}:${String(tileId)}:${dayOffset}`, ...trace.reasonIds],
    noResidentialRelocation: true,
    noYieldChange: true,
    noStressChange: true,
    noPopulationChange: true,
    noCarryingCapacityChange: true,
    noSupportChange: true,
    bandKnownTargetOnly: true,
  };
}

function runControlledFaunaAcuteRiskCase(modules, world, bandId) {
  const band = world.bands[bandId];
  if (band === undefined) {
    return { animalEpisodeCount: 0, examples: [] };
  }
  const dangerousNature = makeAcuteRiskAnimalFixtureNature(world, band);
  const dangerousTrace = {
    stockId: "controlled-danger-animal-stock",
    faunaKind: "large_game",
    habitat: "river_meadow",
    anchorTileId: band.position,
    targetArchetypeHint: "dangerous herbivore",
    targetChosenReason: "controlled audit dangerous hunt near current known place",
    habitatBasis: ["open meadow", "water access"],
    habitatSuitability: 0.74,
    expectedReturnFactor: 0.7,
    actualReturnValue: 0,
    currentAbundance: 0.8,
    disturbance: 0.4,
    seasonalAvailability: 0.8,
    confidence: 0.72,
    pressure: 0.68,
    pressureApplied: 0.18,
    recoveryRate: 0.12,
    warinessBefore: 0.72,
    warinessChange: 0.18,
    dangerRisk: 0.86,
    dangerClass: "high",
    distanceTiles: 4,
    travelCost: 0.36,
    laborAccessCost: 0.58,
    activityOutcome: "abandoned_due_to_risk",
    outcomeClass: "danger",
    depletionApplied: false,
    knowledgeUpdate: "danger_caution_added",
    memoryUpdate: "caution_memory_update",
    protoCampInfluence: "danger_avoidance_signal",
    rawSource: "controlled fauna stocks acute-risk fixture",
    reasonIds: [`reason:fauna-stocks-audit:acute-animal:${String(band.id)}:${String(band.position)}`],
    targetKnownMemoryOnly: true,
  };
  const baseTrip = makeControlledAnimalTrip(world, band, band.position, dangerousTrace, "abandoned_due_to_risk", 7);
  const trip = {
    ...baseTrip,
    outcome: "continues",
    distanceTiles: 4,
    tilesCrossed: 4,
    roundTripTiles: 8,
    estimatedDurationDays: 2,
    resourceReturn: {
      ...baseTrip.resourceReturn,
      returnedResourceKind: "none",
      estimatedReturnValue: 0,
    },
    shadowSubsistence: {
      ...baseTrip.shadowSubsistence,
      shadowReturnKind: "none",
      shadowSupportDomain: "information",
      shadowGrossValue: 0,
      shadowNetValue: 0,
    },
  };
  const riskBand = {
    ...band,
    acuteRisk: undefined,
    visibleNature: dangerousNature,
    recentIntraSeasonTrips: [trip, ...(band.recentIntraSeasonTrips ?? [])].slice(0, 24),
    lastIntraSeasonTrip: trip,
    pressureState: {
      ...(band.pressureState ?? {}),
      foodStress: Math.max(band.pressureState?.foodStress ?? 0, 0.48),
      waterStress: band.pressureState?.waterStress ?? 0,
      fatiguePressure: Math.max(band.pressureState?.fatiguePressure ?? 0, 0.54),
      riskPressure: Math.max(band.pressureState?.riskPressure ?? 0, 0.82),
      nearbyBandPressure: band.pressureState?.nearbyBandPressure ?? 0,
      crowdingPressure: band.pressureState?.crowdingPressure ?? 0,
      resourcePressure: band.pressureState?.resourcePressure ?? 0,
      reasonIds: band.pressureState?.reasonIds ?? [],
    },
  };
  const riskWorld = {
    ...world,
    bands: {
      ...world.bands,
      [band.id]: riskBand,
    },
  };
  let acuteWorld = modules.acuteRisk.applyAcuteRiskContext(riskWorld);
  let episodes = acuteWorld.bands[band.id]?.acuteRisk?.recentEpisodes ?? [];
  // The production event gate is deterministic but probabilistic-by-hash. Scan
  // a bounded 32-season window so this controlled fixture proves the causal
  // animal-risk branch instead of depending on four particular hash values.
  const includesAnimalEpisode = (items) => items.some((episode) =>
    episode.kind === "animal_encounter_injury" ||
    episode.context.sourceCategory === "fauna_sign" ||
    episode.groundedReasons.some((reason) => /animal/i.test(reason)));
  for (let tickOffset = 1; tickOffset <= 32 && !includesAnimalEpisode(episodes); tickOffset += 1) {
    acuteWorld = modules.acuteRisk.applyAcuteRiskContext({
      ...riskWorld,
      time: {
        ...riskWorld.time,
        tick: Number(riskWorld.time.tick) + tickOffset,
      },
      bands: {
        ...riskWorld.bands,
        [band.id]: {
          ...riskBand,
          acuteRisk: undefined,
        },
      },
    });
    episodes = acuteWorld.bands[band.id]?.acuteRisk?.recentEpisodes ?? [];
  }
  const animalEpisodes = episodes.filter((episode) =>
    episode.kind === "animal_encounter_injury" ||
    episode.context.sourceCategory === "fauna_sign" ||
    episode.groundedReasons.some((reason) => /animal/i.test(reason)),
  );

  return {
    animalEpisodeCount: animalEpisodes.length,
    examples: animalEpisodes.slice(0, 4).map((episode) => ({
      kind: episode.kind,
      severity: episode.severity,
      sourceCategory: episode.context.sourceCategory,
      sourceLabel: episode.context.sourceLabel,
      groundedReasons: episode.groundedReasons,
      effect: episode.effect,
      reasonIds: episode.reasonIds.slice(0, 4),
    })),
  };
}

function isAnimalTrackOrSightingState(state) {
  return state === "inferred_from_tracks" ||
    state === "recent_tracks" ||
    state === "direct_sighting" ||
    state === "repeated_sighting" ||
    state === "reliable_route" ||
    state === "hunted_successfully";
}

function isFaunaReadableEvent(event) {
  const text = `${event.title} ${event.description} ${event.detail ?? ""} ${event.rawReason}`;
  return /\b(animal|fauna|hunt|hunting|predator|wolf|herd|game|boar|horse|cattle|track|sighting|wary|wariness)\b/i.test(text);
}

function isSupportedFaunaEvent(event) {
  const text = `${event.title} ${event.description} ${event.detail ?? ""} ${event.rawReason}`
    .replace(/\bno riding\b/gi, "")
    .replace(/\bno dogs?\b/gi, "")
    .replace(/\bno domestic animals yet\b/gi, "")
    .replace(/\bfuture mount candidate only\b/gi, "");
  return event.grounded === true &&
    event.rawSource.length > 0 &&
    event.rawReason.length > 0 &&
    !/\b(dog|riding|mount bonus|village|settlement founded|sacred|religion|totem|territory|war|agriculture|farm|spirit|myth)\b/i.test(text);
}

function countFaunaAntiOmniscienceViolations(bands) {
  let violations = 0;
  const legitimateSources = new Set(["direct", "inherited", "inferred", "encounter_shared", "absorbed", "rumored"]);

  for (const band of bands) {
    if (band.visibleNature?.antiOmniscience.exactHiddenStockLocationsRevealed === true) {
      violations += 1;
    }
    // Only an animal-activity TRACE can leak hidden targeting: a trip that hunted
    // an animal must have aimed at a location the band already knew. A trip with
    // NO animalActivityTrace (water_group, plant harvest, or an abstract/background
    // hunting placeholder — see `abstractHuntingPlaceholders`) targets no animal
    // stock and is legitimately traceless. The pre-physical-food-pipeline audit
    // counted every traceless trip, which false-flagged the new non-hunting intra-
    // season trips (0 → 208). The real invariant is `targetKnownMemoryOnly` on the
    // traces that exist (already enforced by antiOmnisciencePasses via animalTraces).
    for (const trip of band.recentIntraSeasonTrips ?? []) {
      if (trip.animalActivityTrace !== undefined && trip.animalActivityTrace.targetKnownMemoryOnly !== true) {
        violations += 1;
      }
    }
    for (const memory of band.resourceKnowledgeState?.patchMemories ?? []) {
      if (memory.resourceClassId !== "animal_food" && memory.resourceClassId !== "aquatic_food") {
        continue;
      }
      if (!legitimateSources.has(memory.source)) {
        violations += 1;
      }
    }
    // An INFERRED predator (never observed) must anchor its sign card to a tile the
    // band actually saw prey on — never the predator's exact hidden anchor, which
    // would leak into isCardNearTile-based access-norm/proto-camp reasoning.
    for (const card of band.visibleNature?.faunaCards ?? []) {
      if (
        card.sourceKind === "predator_sign" &&
        card.anchorTileId !== undefined &&
        !card.seenTileIds.includes(card.anchorTileId)
      ) {
        violations += 1;
      }
    }
  }

  return violations;
}

// FAUNA-STOCKS-1C anti-omniscience proof — makes the zero-violation result mean
// real truth/knowledge SEPARATION rather than an absent audit. Uses live band
// state plus two controlled synthetic bands to prove each accepted invariant.
function runFaunaAntiOmniscienceProof(modules, world) {
  const fauna = modules.faunaStock;
  const geography = fauna.deriveFaunaStockGeography(world);
  const stockById = new Map(geography.stocks.map((stock) => [String(stock.id), stock]));
  const terrestrial = geography.stocks.find((stock) => stock.faunaClass === "animal_food") ?? geography.stocks[0];
  const sourceBand = Object.values(world.bands).filter(isActiveBand).sort(compareBands)[0] ?? Object.values(world.bands)[0];

  // (1) UNSEEN fauna stay unknown: a band with no persisted animal knowledge, no
  //     traces and no place memory produces NO fauna cards even while standing on
  //     a real stock's own anchor tile. Known terrain is not an animal sighting.
  const blindBand = {
    ...sourceBand,
    id: "band:ao-blind-probe",
    position: terrestrial.anchorTileId,
    knowledge: { ...sourceBand.knowledge, observedTiles: { [terrestrial.anchorTileId]: { tileId: terrestrial.anchorTileId } } },
    placeMemory: {},
    recentIntraSeasonTrips: [],
    lastIntraSeasonTrip: undefined,
    animalPatternKnowledge: undefined,
    protoCampMemory: undefined,
    resourceEcology: undefined,
    resourceKnowledgeState: undefined,
    visibleNature: undefined,
  };
  const blindNature = modules.visibleNature.deriveVisibleNatureState(world, blindBand);
  const unseenFaunaUnknown = blindNature.faunaCards.length === 0 && blindNature.animalKnowledge.length === 0;

  // (2) Technical/world truth REMAINS available: geography exposes the exact anchor
  //     tile and getFaunaStockDynamic exposes an exact numeric abundance.
  const truth = fauna.getFaunaStockDynamic(world, terrestrial.id);
  const technicalShowsWorldTruth =
    terrestrial.anchorTileId !== undefined && typeof truth.abundance === "number" && truth.abundance >= 0 && truth.abundance <= 1;

  // (3) Live band-facing cards: predator signs are GROUNDED (anchor is a seen prey
  //     tile, never the predator's exact hidden anchor) and uncertain-only; no card
  //     exposes a raw numeric abundance; every decision is band-knowledge-scoped.
  const activeBands = Object.values(world.bands).filter(isActiveBand);
  const allCards = activeBands.flatMap((band) => band.visibleNature?.faunaCards ?? []);
  // Force a CONTROLLED prey→predator overlap so the predator-sign invariants are
  // proven non-vacuously: a band that has OBSERVED a herd-prey stock sitting in a
  // predator's region should infer a predator sign — and that sign must anchor to
  // an observed prey tile, never the predator's exact hidden anchor.
  const controlledPredatorCards = [];
  const predator = geography.stocks.find((stock) => stock.trophicRole === "predator");
  const preyForPredator = predator === undefined
    ? undefined
    : geography.stocks.find((stock) =>
        stock.trophicRole !== "predator" &&
        stock.anchorTileId === predator.anchorTileId &&
        (stock.kind === "large_game" || stock.kind === "medium_game"),
      ) ?? geography.stocks.find((stock) =>
        stock.trophicRole !== "predator" &&
        stock.regionId === predator.regionId &&
        (stock.kind === "large_game" || stock.kind === "medium_game"),
      );
  if (predator !== undefined && preyForPredator !== undefined) {
    for (let suffix = 0; suffix < 16 && controlledPredatorCards.length === 0; suffix += 1) {
      const preyObserverBand = {
        ...blindBand,
        id: `band:ao-predator-probe-${suffix}`,
        position: preyForPredator.anchorTileId,
        knowledge: {
          ...blindBand.knowledge,
          observedTiles: Object.fromEntries(
            [preyForPredator.anchorTileId, ...preyForPredator.influenceTileIds].map((tileId) => [tileId, { tileId }]),
          ),
        },
        animalPatternKnowledge: {
          bandId: `band:ao-predator-probe-${suffix}`,
          lastUpdatedTick: world.time.tick,
          recordCap: 12,
          evidencePerRecordCap: 6,
          capsHeld: true,
          records: [{
            id: "ao-prey-record",
            stockId: String(preyForPredator.id),
            faunaKind: preyForPredator.kind,
            placeTileId: preyForPredator.anchorTileId,
            routeTileIds: [preyForPredator.anchorTileId],
            seasonsObserved: [world.time.season],
            patterns: [],
            observationCount: 4,
            directObservationCount: 4,
            inferenceCount: 0,
            contradictionCount: 0,
            confidence: 0.7,
            state: "confident",
            basis: "direct_observation",
            lastObservedTick: world.time.tick,
            evidenceRefs: [],
          }],
        },
      };
      const preyNature = modules.visibleNature.deriveVisibleNatureState(world, preyObserverBand);
      for (const card of preyNature.faunaCards) {
        if (card.sourceKind === "predator_sign") controlledPredatorCards.push(card);
      }
    }
  }
  const predatorCards = [...allCards.filter((card) => card.sourceKind === "predator_sign"), ...controlledPredatorCards];
  const preyDoesNotRevealExactPredator = predatorCards.every((card) => {
    const grounded = card.anchorTileId !== undefined && card.seenTileIds.includes(card.anchorTileId);
    const real = card.derivedFromStockId === undefined ? undefined : stockById.get(card.derivedFromStockId);
    // The exact hidden predator anchor may only coincide with a card tile if the
    // band actually saw that tile; otherwise it must NOT be exposed.
    const noExactHiddenAnchor = real === undefined || card.anchorTileId !== real.anchorTileId || card.seenTileIds.includes(real.anchorTileId);
    return grounded && noExactHiddenAnchor;
  });
  const predatorSignsUncertainOnly = predatorCards.every((card) =>
    (card.knowledgeState === "inferred_from_tracks" || card.knowledgeState === "dangerous") &&
    card.usefulness === "low" &&
    card.huntingOrFishingPressure === 0 &&
    card.confidence <= 0.72,
  );
  const normalUiNoExactHiddenAbundance = allCards.every((card) =>
    typeof card.perceivedAbundance === "string" &&
    !Object.prototype.hasOwnProperty.call(card, "abundance") &&
    !Object.prototype.hasOwnProperty.call(card, "exactAbundance"),
  );
  const decisionsUseBandKnowledgeOnly = activeBands.every((band) =>
    band.visibleNature === undefined || band.visibleNature.antiOmniscience.candidateTilesFromBandKnowledgeOnly === true,
  );

  // (4) STALE evidence may be wrong: a persisted record whose latest observation
  //     CONTRADICTED the pattern surfaces as an uncertain (failed/stale) card, not
  //     a confident sighting — knowledge is not a permanent upgrade.
  const staleBand = {
    ...blindBand,
    id: "band:ao-stale-probe",
    animalPatternKnowledge: {
      bandId: "band:ao-stale-probe",
      lastUpdatedTick: world.time.tick,
      recordCap: 12,
      evidencePerRecordCap: 6,
      capsHeld: true,
      records: [{
        id: "ao-stale-record",
        stockId: String(terrestrial.id),
        faunaKind: terrestrial.kind,
        placeTileId: terrestrial.anchorTileId,
        routeTileIds: [terrestrial.anchorTileId],
        seasonsObserved: [world.time.season],
        patterns: [],
        observationCount: 4,
        directObservationCount: 1,
        inferenceCount: 0,
        contradictionCount: 4,
        confidence: 0.18,
        state: "contradicted",
        basis: "bounded_inference",
        lastObservedTick: world.time.tick,
        evidenceRefs: [],
      }],
    },
  };
  const staleNature = modules.visibleNature.deriveVisibleNatureState(world, staleBand);
  const staleCard = staleNature.faunaCards.find((card) => card.stockId === String(terrestrial.id));
  const staleEvidenceMayBeWrong = staleCard === undefined
    ? false
    : (staleCard.knowledgeState === "failed_to_find" || staleCard.knowledgeState === "stale_route") && staleCard.confidence < 0.5;

  const checks = {
    unseenFaunaUnknown,
    technicalShowsWorldTruth,
    preyDoesNotRevealExactPredator,
    predatorSignsUncertainOnly,
    normalUiNoExactHiddenAbundance,
    decisionsUseBandKnowledgeOnly,
    staleEvidenceMayBeWrong,
  };

  return {
    pass: Object.values(checks).every(Boolean),
    checks,
    detail: {
      blindBandCards: blindNature.faunaCards.length,
      predatorSignCards: predatorCards.length,
      controlledPredatorSignCards: controlledPredatorCards.length,
      controlledPredatorGroundedAnchors: controlledPredatorCards.map((card) => ({
        anchor: String(card.anchorTileId),
        seen: card.seenTileIds.map(String),
        anchorInSeen: card.seenTileIds.includes(card.anchorTileId),
        derivedFrom: card.derivedFromStockId,
      })),
      technicalAnchorTile: String(terrestrial.anchorTileId),
      technicalAbundance: round4Maybe(truth.abundance),
      staleCardState: staleCard?.knowledgeState ?? "none",
      staleCardConfidence: round4Maybe(staleCard?.confidence),
    },
  };
}

function makeFaunaStocksAuditFingerprint(world) {
  const bands = Object.values(world.bands)
    .filter(isActiveBand)
    .sort(compareBands)
    .slice(0, 12)
    .map((band) => ({
      id: String(band.id),
      tile: String(band.position),
      population: band.demography.population,
      fauna: band.visibleNature?.faunaCards.map((card) =>
        `${card.stockId}:${card.archetype}:${card.knowledgeState}:${card.knownness}:${card.usefulness}:${card.perceivedAbundance}:${card.huntingOrFishingPressure}:${card.wariness}`,
      ).join(",") ?? "",
      animalKnowledge: band.visibleNature?.animalKnowledge.map((memory) =>
        `${memory.stockId}:${memory.state}:${memory.source}:${memory.successCount}:${memory.failureCount}`,
      ).join(",") ?? "",
      proto: band.protoCampMemory?.currentPlace?.topReasons.join("|") ?? "",
      events: band.eventHistory?.recentEvents.filter((event) => event.category === "nature").slice(0, 4).map((event) => `${event.title}:${event.rawReason}`).join("|") ?? "",
    }));

  return JSON.stringify({
    tick: Number(world.time.tick),
    year: world.time.year,
    faunaStocks: Object.keys(world.faunaStocks ?? {}).sort().slice(0, 64),
    bands,
  });
}

function runFaunaStocksSourceGuards() {
  const files = [
    "src/sim/agents/faunaStock.ts",
    "src/sim/agents/visibleNature.ts",
    "src/sim/agents/intraSeasonTrips.ts",
    "src/sim/agents/resourceEcologyFoundation.ts",
    "src/sim/agents/protoCamps.ts",
    "src/sim/agents/bandEvents.ts",
    "src/sim/agents/acuteRisk.ts",
    "src/sim/agents/types.ts",
  ];
  const patterns = [
    ["Math.random", /Math\.random/],
    [": any", /:\s*any\b/],
    ["as any", /as\s+any\b/],
    ["ui/render/zustand import", /from\s+["'][^"']*(\/ui\/|\/render\/)|zustand/],
  ];
  const violations = [];

  for (const file of files) {
    const source = stripSourceComments(readFileSync(file, "utf8"));
    for (const [label, pattern] of patterns) {
      if (pattern.test(source)) {
        violations.push({ file, label });
      }
    }
  }

  return {
    pass: violations.length === 0,
    checkedFiles: files,
    violations,
  };
}

function stripSourceComments(source) {
  return source.replace(/\/\*[\s\S]*?\*\//g, "").replace(/(^|[^:])\/\/.*$/gm, "$1");
}

function round4Maybe(value) {
  return typeof value === "number" ? Math.round(value * 10000) / 10000 : value;
}

// SIM-TOOLS-1 — ecology visualization audit (Part 11 groups A/B/F). Proves the
// WORLD-DEBUG truth summary matches stock state, the SELECTED-BAND view is derived
// purely from band knowledge (can never reveal an undiscovered stock/patch), and
// the derivation is pure (no sim mutation, deterministic).
// PERCEPTION-MOBILITY-1 — lone/isolated-band talk audit (Part 11.F). Invariant: a
// band may only carry SOCIAL crowding/outsider talk if it has GROUNDED evidence of
// other bands (crowding band ids / nearby-band pressure / contact memories / range
// friction). An isolated band's range saturation is its OWN overuse → ecological
// talk (poor returns / tired ground), never "outsiders". Also confirms ecological
// pressure talk still fires for isolated high-pressure bands.
function runLoneBandTalkAudit(modules, options) {
  const years = Number.isFinite(options.ecoMigAuditYears) ? options.ecoMigAuditYears : 80;
  // Dense map: 36 bands including isolated AND high-saturation ones — exactly where
  // the bug (ecological self-overuse mislabelled as "outsiders") manifests.
  const benchmark = runBenchmark(
    modules,
    { scenario: "map2_varied_migration", years, ticks: undefined },
    { ...options, reportBand: false, probeAudit: false, returnWorld: true },
  );
  const world = benchmark.world;
  const activeBands = Object.values(world.bands).filter(isActiveBand).sort(compareBands);

  const SOCIAL_TOPICS = new Set(["crowded_range_warning", "crowded_water_warning", "outsider_use_warning"]);

  // RUMOR-LOOP FIX (2026-07-10): a friction event grounds other-band evidence
  // ONLY when its otherBandId is genuinely another band. Before the fix, a
  // band's own reports became friction events with otherBandId === itself,
  // which (a) generated perpetual "outsider_use_warning" talk on lone bands
  // and (b) made THIS audit blind to it (self-friction counted as grounding).
  const hasGroundedOtherBandEvidence = (band) =>
    (band.pressureState?.crowdingBandIds?.length ?? 0) > 0 ||
    (band.pressureState?.nearbyBandPressure ?? 0) > 0.18 ||
    Object.keys(band.contactMemories ?? {}).length > 0 ||
    (band.recentRangeFrictionEvents ?? []).some((event) => event.otherBandId !== band.id);

  let isolatedBands = 0;
  let isolatedHighPressureBands = 0;
  let socialTalkOnIsolatedBandViolations = 0;
  let ecologicalTalkOnIsolatedHighPressure = 0;
  let totalSocialReports = 0;
  let socialReportsWithoutGrounding = 0;
  let selfReferentialFrictionEvents = 0;

  for (const band of activeBands) {
    selfReferentialFrictionEvents += (band.recentRangeFrictionEvents ?? [])
      .filter((event) => event.otherBandId === band.id).length;
    const grounded = hasGroundedOtherBandEvidence(band);
    const reports = band.reportedKnowledge?.reports ?? [];
    const socialReports = reports.filter((report) => SOCIAL_TOPICS.has(report.topic));
    const ecologicalReports = reports.filter((report) => report.topic === "poor_return_region");
    const saturation = band.rangeSaturation?.saturationPressure ?? 0;

    totalSocialReports += socialReports.length;

    if (!grounded) {
      isolatedBands += 1;
      // THE invariant: an isolated band must carry NO social crowding/outsider talk.
      socialTalkOnIsolatedBandViolations += socialReports.length;

      if (saturation > 0.55) {
        isolatedHighPressureBands += 1;
        if (ecologicalReports.length > 0) {
          ecologicalTalkOnIsolatedHighPressure += 1;
        }
      }
    }

    // Cross-check the invariant per report (lone or not): any social report must
    // rest on a band with grounded other-band evidence.
    if (!grounded) {
      socialReportsWithoutGrounding += socialReports.length;
    }
  }

  // Explicit fixture regression: self reports are inert for both friction and
  // social-copy, while the identical report sourced from another band remains
  // valid evidence. This closes the prior live-only audit gap.
  const observerBase = activeBands[0];
  const foreignBase = activeBands.find((band) => band.id !== observerBase?.id);
  let selfReportFrictionEvents = 0;
  let foreignReportFrictionEvents = 0;
  let selfReportSocialCopyIdeas = 0;
  let foreignReportSocialCopyIdeas = 0;
  if (observerBase !== undefined && foreignBase !== undefined) {
    const template = activeBands.flatMap((band) => band.reportedKnowledge?.reports ?? [])[0];
    const makeReport = (sourceBandId) => ({
      ...(template ?? {}),
      reportId: `rumor-regression:${String(sourceBandId)}`,
      sourceBandId,
      receiverBandId: observerBase.id,
      tickCreated: world.time.tick,
      tickReceived: world.time.tick,
      topic: "avoid_place",
      targetTileId: observerBase.position,
      regionTarget: template?.regionTarget ?? {
        regionId: "rumor-regression", approximateCenterTile: observerBase.position,
        radiusTiles: 1, roughExtent: "current camp", regionKind: "local_place",
        directionFromReceiver: "here", precision: "exact_place",
      },
      sourceBasis: template?.sourceBasis ?? "direct_observation",
      confidence: 0.7, freshness: 1, hops: 0,
      distortionLevel: "none", trustBasis: "familiar_neighbor",
      receiverDisposition: "remembered_only", confirmationStatus: "unconfirmed",
      evidenceCount: 1, contradictionCount: 0,
      noHiddenTruth: true, noDirectUnlock: true, noGuaranteedTruth: true,
      noLanguageSystem: true, reasonIds: [],
    });
    const runFixture = (sourceBandId) => {
      const observer = {
        ...observerBase,
        parentBandId: undefined,
        contactMemories: {},
        recentRangeFrictionEvents: [],
        adaptiveHuman: undefined,
        reportedKnowledge: {
          ...(observerBase.reportedKnowledge ?? {}),
          reports: [makeReport(sourceBandId)], lastUpdatedTick: world.time.tick,
          generatedCount: 1, receivedCount: sourceBandId === observerBase.id ? 0 : 1,
          checkedByProbeCount: 0, actedOnCount: 0, misleadingCount: 0,
        },
      };
      const fixtureWorld = { ...world, bands: { [observer.id]: observer, [foreignBase.id]: foreignBase } };
      const advanced = modules.rangeFriction.advanceRangeFriction(fixtureWorld, modules.buildTickContextCache(fixtureWorld));
      const events = advanced.bands[observer.id]?.recentRangeFrictionEvents ?? [];
      const profile = modules.adaptiveHuman.deriveAdaptiveHumanProfile(fixtureWorld, observer);
      return {
        friction: events.filter((event) => event.otherBandId === sourceBandId).length,
        socialCopy: profile.ideas.filter((idea) => idea.family === "social_copy").length,
      };
    };
    const self = runFixture(observerBase.id);
    const foreign = runFixture(foreignBase.id);
    selfReportFrictionEvents = self.friction;
    foreignReportFrictionEvents = foreign.friction;
    selfReportSocialCopyIdeas = self.socialCopy;
    foreignReportSocialCopyIdeas = foreign.socialCopy;
  }

  const verdict =
    socialTalkOnIsolatedBandViolations === 0 &&
    socialReportsWithoutGrounding === 0 &&
    selfReferentialFrictionEvents === 0
    && selfReportFrictionEvents === 0
    && selfReportSocialCopyIdeas === 0
    && foreignReportFrictionEvents > 0
    && foreignReportSocialCopyIdeas > 0
      ? "pass"
      : "review";

  return {
    check: "PERCEPTION-MOBILITY-1 lone-band talk audit",
    verdict,
    command: `node scripts/simBenchmark.mjs --targeted-lone-band-talk-audit --eco-mig-audit-years ${years} --json`,
    scenario: "map2_varied_migration",
    years,
    notes: [
      "Isolated band = no grounded other-band evidence (crowding ids / nearby-band pressure / contact memories / range friction).",
      "Isolated bands must carry NO social crowding/outsider talk; their range saturation is ecological self-overuse.",
      "Ecological pressure talk (poor_return_region) must still work for isolated high-pressure bands.",
    ],
    activeBands: activeBands.length,
    isolatedBands,
    isolatedHighPressureBands,
    socialTalkOnIsolatedBandViolations,
    ecologicalTalkOnIsolatedHighPressure,
    totalSocialReports,
    socialReportsWithoutGrounding,
    selfReferentialFrictionEvents,
    explicitReportRegression: {
      selfReportFrictionEvents,
      foreignReportFrictionEvents,
      selfReportSocialCopyIdeas,
      foreignReportSocialCopyIdeas,
    },
  };
}

// PERCEPTION-MOBILITY-1B — nearby-water opportunity audit (Part 6). Flags
// poor/mediocre-ground bands that see/know a water-rich opportunity but show NO
// sign of investigating it (no fishing/water activity, no water-cause move, no
// aquatic patch memory). Such a band ignoring close clear water is the absurd
// inertia we want to catch. Snapshot heuristic over the final world (no per-tick
// timeline), so it flags the standing situation, not the first-cue year.
// PRE-RUN-BAND-MANAGER-1 (Phase 1) — setup-only add/delete/determinism audit.
// Validates the sim-side roster editing without the UI: remove a default band,
// add custom bands at valid tiles, reject an invalid (aquatic) tile, auto-balance
// cohorts, deterministic defaults, and the setup lock after the run starts.
function runBandManagerAudit(modules) {
  const base = modules.spawnVariedMigrationBands(modules.createVariedMigrationWorld());
  const defaultBandIds = Object.keys(base.bands);
  const defaultCount = defaultBandIds.length;
  const occupied = new Set(Object.values(base.bands).map((b) => String(b.position)));

  // Find two distinct valid land tiles and one aquatic tile.
  const validTiles = [];
  let aquaticTile;
  for (const tile of Object.values(base.tiles)) {
    if (aquaticTile === undefined && tile.isAquatic) {
      aquaticTile = tile;
    }
    if (
      validTiles.length < 2 &&
      !tile.isAquatic &&
      tile.terrainKind !== "mountains" &&
      tile.movementCost <= 2.25 &&
      !occupied.has(String(tile.id))
    ) {
      validTiles.push(tile);
    }
    if (validTiles.length >= 2 && aquaticTile !== undefined) break;
  }

  const checks = {};

  // Delete a default band.
  const removedId = defaultBandIds[0];
  const afterRemove = modules.removeInitialBands(base, [removedId]);
  checks.deleteRemovesBand = Object.keys(afterRemove.bands).length === defaultCount - 1 && afterRemove.bands[removedId] === undefined;

  // Add custom bands (one with explicit population, one auto) + an INVALID aquatic spec.
  const specs = [
    { tileId: validTiles[0].id, population: 24, knowledgePreset: "normal" },
    { tileId: validTiles[1].id },
    { tileId: aquaticTile?.id ?? validTiles[0].id }, // invalid (aquatic) OR duplicate → rejected
  ];
  const afterAdd = modules.spawnCustomBands(base, specs, "band-mgr-test");
  const addedIds = [modules.addedBandId(0), modules.addedBandId(1), modules.addedBandId(2)];
  const band0 = afterAdd.bands[addedIds[0]];
  const band1 = afterAdd.bands[addedIds[1]];
  const band2 = afterAdd.bands[addedIds[2]];
  checks.addCreatesValidBands = band0 !== undefined && band1 !== undefined;
  checks.invalidTileRejected = band2 === undefined; // aquatic/duplicate spec not added
  checks.addedCount = Object.keys(afterAdd.bands).length === defaultCount + 2;
  checks.explicitPopulationApplied = band0 !== undefined && band0.demography.population === 24;
  checks.autoPopulationPlausible = band1 !== undefined && band1.demography.population >= 12 && band1.demography.population <= 40;
  checks.cohortsAutoBalanced = band0 !== undefined &&
    band0.demography.dependents + band0.demography.workingAdults + band0.demography.elders === band0.demography.population;
  checks.distinctColors = band0 !== undefined && band1 !== undefined && band0.color !== band1.color;
  checks.positionsCorrect = band0 !== undefined && String(band0.position) === String(validTiles[0].id);

  // Determinism: same specs + seed → identical added bands.
  const afterAdd2 = modules.spawnCustomBands(base, specs, "band-mgr-test");
  const b0b = afterAdd2.bands[addedIds[0]];
  checks.deterministic = band0 !== undefined && b0b !== undefined &&
    band0.color === b0b.color && band0.demography.population === b0b.demography.population && String(band0.position) === String(b0b.position);

  // Validation API: aquatic tile rejected with a reason; valid tile accepted.
  const aquaticValidation = aquaticTile === undefined ? { valid: false } : modules.validateAddedBandPlacement(base, aquaticTile.id);
  const validValidation = modules.validateAddedBandPlacement(base, validTiles[0].id);
  checks.validationRejectsAquatic = aquaticValidation.valid === false;
  checks.validationAcceptsValid = validValidation.valid === true;

  // Reset = no edits → world roster unchanged.
  const afterReset = modules.spawnCustomBands(modules.removeInitialBands(base, undefined), undefined, "x");
  checks.resetNoOp = Object.keys(afterReset.bands).length === defaultCount;

  // Setup lock: once the run advances, roster edits are no-ops.
  const started = modules.stepSim(base, 1, "seasonal");
  const afterStartAdd = modules.spawnCustomBands(started, [{ tileId: validTiles[0].id }], "band-mgr-test");
  const startLockValidation = modules.validateAddedBandPlacement(started, validTiles[0].id);
  checks.lockedAfterStart =
    Object.keys(afterStartAdd.bands).length === Object.keys(started.bands).length &&
    startLockValidation.valid === false;

  const verdict = Object.values(checks).every(Boolean) ? "pass" : "review";

  return {
    check: "PRE-RUN-BAND-MANAGER-1 setup roster audit",
    verdict,
    command: "node scripts/simBenchmark.mjs --targeted-band-manager-audit --json",
    defaultBandCount: defaultCount,
    checks,
    sample: {
      removedId: String(removedId),
      added0: band0 === undefined ? null : { id: String(band0.id), pop: band0.demography.population, color: band0.color, role: band0.subsistenceModes },
      added1: band1 === undefined ? null : { id: String(band1.id), pop: band1.demography.population, color: band1.color },
    },
  };
}

function runTargetedDemographySeasonalMergeAudit(modules, options) {
  const years = Number.isFinite(options.ecoMigAuditYears) ? options.ecoMigAuditYears : 80;
  const benchmark = runBenchmark(
    modules,
    { scenario: "map2_varied_migration", years, ticks: undefined },
    { ...options, reportBand: false, probeAudit: false, returnWorld: true },
  );
  const repeat = runBenchmark(
    modules,
    { scenario: "map2_varied_migration", years, ticks: undefined },
    { ...options, reportBand: false, probeAudit: false, returnWorld: true },
  );
  const world = benchmark.world;
  const activeBands = Object.values(world.bands).filter(isActiveBand).sort(compareBands);
  const allBands = Object.values(world.bands).sort(compareBands);
  const seasonalStates = activeBands.map((band) => band.seasonalSupport).filter((state) => state !== undefined);
  const supportDebugs = activeBands
    .map((band) => band.perCapitaReturn?.supportDebug ?? band.carryingCapacity?.perCapitaReturn?.supportDebug)
    .filter((debug) => debug !== undefined);
  const churns = activeBands.map((band) => band.demography.demographicChurn).filter((churn) => churn !== undefined);
  const latestRecords = churns.flatMap((churn) => churn.records.slice(-1));
  const recentRecords = churns.flatMap((churn) => churn.records);
  const moves = activeBands.flatMap((band) => band.recentResidentialMoveEvents ?? []);
  const weakStates = allBands.map((band) => band.viability).filter((state) => state !== undefined);
  const absorbed = allBands.filter((band) => band.viability?.status === "absorbed");
  const extinct = allBands.filter((band) => band.viability?.status === "extinct");
  const deterministic = makeDemographySeasonalFingerprint(world) === makeDemographySeasonalFingerprint(repeat.world);
  const preRunBandManager = runBandManagerAudit(modules);
  const regressionYears = Math.min(years, 80);
  const nearbyWater = runNearbyWaterOpportunityAudit(modules, { ...options, ecoMigAuditYears: regressionYears });
  const loneBandTalk = runLoneBandTalkAudit(modules, { ...options, ecoMigAuditYears: regressionYears });
  const noDeathAudits = activeBands.map((band) => band.demography.noDeathAudit).filter((audit) => audit !== undefined);
  const noMagicMergeViolations = absorbed.filter(
    (band) =>
      band.viability?.absorbedByBandId === undefined ||
      (band.viability.populationTransferred ?? 0) < 0 ||
      (band.viability.populationRemoved ?? 0) !== 0,
  ).length;
  const megaBands = activeBands.filter((band) => band.demography.population >= 500).length;
  const populationCrash = benchmark.summary.totalPopulation <= Math.max(20, benchmark.summary.startPopulation * 0.2);

  return {
    check: "SETUP-DEMOGRAPHY-SEASONAL-MERGE-1 targeted audit",
    verdict:
      deterministic &&
      preRunBandManager.verdict === "pass" &&
      nearbyWater.suspiciousStuck === 0 &&
      loneBandTalk.socialTalkOnIsolatedBandViolations === 0 &&
      !populationCrash &&
      noMagicMergeViolations === 0
        ? "pass"
        : "review",
    command: `node scripts/simBenchmark.mjs --targeted-demography-seasonal-merge-audit --eco-mig-audit-years ${years} --json`,
    scenario: "map2_varied_migration",
    years,
    seasonalSupport: {
      bandsMeasured: seasonalStates.length,
      supportCalculatedPerSeason: true,
      demographicUpdateCadence: "annual spring update reads bounded seasonal support memory",
      rawSupportRatio: summarizeNumberDistribution(supportDebugs.map((debug) => debug.rawSupportRatio)),
      clampedSupportRatio: summarizeNumberDistribution(supportDebugs.map((debug) => debug.clampedSupportRatio)),
      perCapitaReturn: summarizeNumberDistribution(seasonalStates.map((state) => state.currentSeasonSupport.perCapitaReturn)),
      seasonalModifier: summarizeNumberDistribution(seasonalStates.map((state) => state.currentSeasonSupport.seasonalModifier)),
      rolling4SeasonReturn: summarizeNumberDistribution(seasonalStates.map((state) => state.rolling4SeasonReturn)),
      rolling8SeasonReturn: summarizeNumberDistribution(seasonalStates.map((state) => state.rolling8SeasonReturn)),
      modes: countBy(seasonalStates, (state) => state.currentSeasonSupport.mode),
      hungerClassifications: countBy(seasonalStates, (state) => state.hungerClassification),
      chronicClassifications: countBy(seasonalStates, (state) => state.chronicDeficitClassification),
      seasonalHungerBands: seasonalStates.filter((state) =>
        state.hungerClassification === "seasonal_lean_stress" ||
        state.hungerClassification === "seasonal_water_stress" ||
        state.hungerClassification === "chronic_plus_seasonal_stress",
      ).length,
      chronicHungerBands: seasonalStates.filter((state) =>
        state.hungerClassification === "chronic_food_deficit" ||
        state.hungerClassification === "chronic_water_deficit" ||
        state.hungerClassification === "chronic_plus_seasonal_stress" ||
        state.hungerClassification === "crisis_deficit",
      ).length,
      recurringHungerStablePopulationBands: seasonalStates.filter((state) => state.populationStableDespiteRecurringHunger).length,
      exampleReasons: seasonalStates.slice(0, 5).map((state) => ({
        bandId: String(state.bandId),
        classification: state.hungerClassification,
        reasons: state.topSeasonalSupportReasons,
      })),
    },
    activitySeasonality: {
      recentTripsMeasured: activeBands.reduce((sum, band) => sum + (band.recentIntraSeasonTrips?.length ?? 0), 0),
      tripsWithSeasonalShadowChange: activeBands.flatMap((band) => band.recentIntraSeasonTrips ?? [])
        .filter((trip) => trip.seasonalEcology?.shadowSeasonalResult !== undefined && trip.seasonalEcology.shadowSeasonalResult !== "neutral").length,
      tripsWithSeasonMismatch: activeBands.flatMap((band) => band.recentIntraSeasonTrips ?? [])
        .filter((trip) => trip.activityOutcome === "failed_due_to_season_mismatch").length,
      recentTripTypes: countBy(activeBands.flatMap((band) => band.recentIntraSeasonTrips ?? []), (trip) => trip.taskGroupType),
    },
    demography: {
      birthsThisYear: sumNumbers(latestRecords.map((record) => record.births)),
      deathsThisYear: sumNumbers(latestRecords.map((record) => record.deaths)),
      birthsInVisible10YearRings: sumNumbers(recentRecords.map((record) => record.births)),
      deathsInVisible10YearRings: sumNumbers(recentRecords.map((record) => record.deaths)),
      netPopulationChangeVisible10YearRings: sumNumbers(recentRecords.map((record) => record.netPopulationChange)),
      deathCausesVisible10YearRings: {
        elder: sumNumbers(recentRecords.map((record) => record.elderDeaths)),
        dependent: sumNumbers(recentRecords.map((record) => record.dependentDeaths)),
        adult: sumNumbers(recentRecords.map((record) => record.adultDeaths)),
        crisis: sumNumbers(recentRecords.map((record) => record.crisisDeaths)),
        water: sumNumbers(recentRecords.map((record) => record.waterStressDeaths)),
        starvation: sumNumbers(recentRecords.map((record) => record.starvationDeaths)),
        migrationHardship: sumNumbers(recentRecords.map((record) => record.migrationHardshipDeaths)),
      },
      cohortTransitionsVisible10YearRings: {
        dependentsMatured: sumNumbers(recentRecords.map((record) => record.dependentsMatured)),
        adultsAged: sumNumbers(recentRecords.map((record) => record.adultsAged)),
      },
      stablePopulationHidesChurnBands: churns.filter((churn) => churn.stablePopulationHidesChurn).length,
      fertilityBySupportClass: summarizeFertilityBySupportClass(activeBands),
      mortalityBySupportClass: summarizeMortalityBySupportClass(activeBands),
      recentDeathMemoryBands: activeBands.filter((band) => band.deathMemory !== undefined).length,
    },
    noDeathAudit: {
      noDeath25Years: noDeathAudits.filter((audit) => audit.noDeath25Years).length,
      noDeath50Years: noDeathAudits.filter((audit) => audit.noDeath50Years).length,
      suspicious: noDeathAudits.filter((audit) => audit.suspicious).length,
      classifications: countBy(noDeathAudits, (audit) => audit.classification),
      examples: noDeathAudits.slice(0, 6).map((audit) => ({
        streak: audit.noDeathStreakYears,
        classification: audit.classification,
        suspicious: audit.suspicious,
        why: audit.why,
      })),
    },
    migrationHardship: {
      recentResidentialMoves: moves.length,
      hardshipLevels: countBy(moves, (move) => move.hardshipLevel ?? "none"),
      hardshipOutcomes: countBy(moves, (move) => move.hardshipOutcome ?? "none"),
      routeRejections: moves.filter((move) => move.status === "failed_no_route" || move.hardshipOutcome === "rejected").length,
      moveDelays: moves.filter((move) => move.hardshipOutcome === "delayed").length,
      diversions: moves.filter((move) => move.hardshipOutcome === "diverted").length,
      hardshipDeathsEnabled: false,
      examples: moves.slice(0, 5).map((move) => ({
        bandId: String(move.bandId),
        status: move.status,
        level: move.hardshipLevel,
        reason: move.hardshipReason,
      })),
    },
    weakBandFate: {
      classifications: countBy(weakStates, (state) => state.weakBandClassification ?? "unclassified"),
      fates: countBy(weakStates, (state) => state.weakBandFate ?? "unclassified"),
      supportSeekingTargets: weakStates.filter((state) => state.supportSeekingTargetBandId !== undefined).length,
      blockedReasons: countBy(
        weakStates.filter((state) => state.supportSeekingBlockedReason !== undefined),
        (state) => state.supportSeekingBlockedReason ?? "none",
      ),
      absorbedBands: absorbed.length,
      extinctBands: extinct.length,
      noMagicMergeViolations,
      absorptionConservation: absorbed.map((band) => ({
        bandId: String(band.id),
        absorbedBy: String(band.viability?.absorbedByBandId),
        summary: band.viability?.populationConservationSummary ?? "missing",
      })),
    },
    deathMemory: {
      bandsWithDeathMemory: activeBands.filter((band) => band.deathMemory !== undefined).length,
      severity: summarizeNumberDistribution(activeBands.map((band) => band.deathMemory?.deathMemorySeverity ?? 0)),
      cautionModifier: summarizeNumberDistribution(activeBands.map((band) => band.deathMemory?.cautionModifier ?? 0)),
      fertilitySuppression: summarizeNumberDistribution(activeBands.map((band) => band.deathMemory?.fertilitySuppressionFromRecentDeaths ?? 0)),
      causes: countBy(activeBands.filter((band) => band.deathMemory !== undefined), (band) => band.deathMemory?.deathMemoryCause ?? "unknown"),
      limits: "death memory only affects caution/fertility/avoidance hooks; no burials, ancestor cult, religion, myths, or named deaths",
    },
    regressions: {
      preRunBandManager: preRunBandManager.verdict,
      nearbyWaterSuspiciousStuck: nearbyWater.suspiciousStuck,
      loneBandSocialTalkViolations: loneBandTalk.socialTalkOnIsolatedBandViolations,
      deterministic,
      populationCrash,
      megaBands,
      totalPopulation: benchmark.summary.totalPopulation,
      activeBands: benchmark.summary.activeBands,
    },
  };
}

function runTargetedSeasonalStressInnerFissionAudit(modules, options) {
  const years = Number.isFinite(options.ecoMigAuditYears) ? options.ecoMigAuditYears : 32;
  const defaultYears = Math.min(years, 40);
  const defaultRun = runBenchmark(
    modules,
    { scenario: "map2_varied_migration", years: defaultYears, ticks: undefined },
    { ...options, reportBand: false, probeAudit: false, returnWorld: true },
  );
  const defaultRepeat = runBenchmark(
    modules,
    { scenario: "map2_varied_migration", years: defaultYears, ticks: undefined },
    { ...options, reportBand: false, probeAudit: false, returnWorld: true },
  );
  const stressCaseSpecs = [
    { name: "dry_margin_seasonal_food_stress", years: 10 },
    { name: "overcrowded_catchment", years: 12 },
    { name: "dependent_heavy_band", years: 14 },
    { name: "elder_heavy_band", years: 18 },
    { name: "harsh_water_gap_migration", years: 24 },
    { name: "recovery_pulse_reference", years: 12 },
  ];
  const stressCases = stressCaseSpecs.map((spec) => runSeasonalStressControlledCase(modules, spec));
  const allSamples = stressCases.flatMap((entry) => entry.seasonalSupport.samples);
  const rawBelowOneExamples = allSamples.filter((sample) => sample.rawSupportRatio < 1).slice(0, 10);
  const recoveryPulseExamples = getRecoveryPulseExamples(allSamples);
  const mortalityTotals = sumMortalityAcrossStressCases(stressCases);
  const mortalityChannelAudit = buildMortalityChannelAudit(stressCases, mortalityTotals);
  const activityAudit = summarizeActivityTraceProof(runTargetedTimeScaleCheck(modules));
  const absorptionProof = runAbsorptionProof(modules);
  const supportSeekingBlockers = runSupportSeekingBlockerProof(modules);
  const innerFissionStates = [
    ...collectInnerFissionStates(defaultRun.world, "default_map2"),
    ...stressCases.flatMap((entry) => entry.innerFission.states),
  ];
  const socialTensionStates = [
    ...collectSocialTensionStates(defaultRun.world, "default_map2"),
    ...stressCases.flatMap((entry) => entry.socialTension.states),
  ];
  const regressionYears = Math.min(defaultYears, 40);
  const preRunBandManager = runBandManagerAudit(modules);
  const nearbyWater = runNearbyWaterOpportunityAudit(modules, { ...options, ecoMigAuditYears: regressionYears });
  const loneBandTalk = runLoneBandTalkAudit(modules, { ...options, ecoMigAuditYears: regressionYears });
  const deterministic =
    makeSeasonalStressFingerprint(defaultRun.world) === makeSeasonalStressFingerprint(defaultRepeat.world) &&
    stressCases.every((entry) => entry.deterministic);
  const activeBands = Object.values(defaultRun.world.bands).filter(isActiveBand);
  const populationCrash = defaultRun.summary.totalPopulation <= Math.max(20, defaultRun.summary.startPopulation * 0.2);
  const megaBands = activeBands.filter((band) => band.demography.population >= 500).length;
  const noMagicMergeViolations =
    absorptionProof.noMagicMergeViolationCount +
    stressCases.reduce((sum, entry) => sum + entry.weakBandFate.noMagicMergeViolations, 0);
  const verdict =
    deterministic &&
    preRunBandManager.verdict === "pass" &&
    nearbyWater.suspiciousStuck === 0 &&
    loneBandTalk.socialTalkOnIsolatedBandViolations === 0 &&
    rawBelowOneExamples.length > 0 &&
    recoveryPulseExamples.length > 0 &&
    activityAudit.recentTripsMeasured > 0 &&
    noMagicMergeViolations === 0 &&
    !populationCrash &&
    megaBands === 0
      ? "pass"
      : "review";

  return {
    check: "SEASONAL-STRESS-INNER-FISSION-1 targeted audit",
    verdict,
    command: `node scripts/simBenchmark.mjs --targeted-seasonal-stress-inner-fission-audit --eco-mig-audit-years ${years} --json`,
    defaultScenario: {
      scenario: "map2_varied_migration",
      years: defaultYears,
      totalPopulation: defaultRun.summary.totalPopulation,
      activeBands: defaultRun.summary.activeBands,
      fissions: defaultRun.summary.fissions,
      absorbedBands: defaultRun.summary.absorbedBands,
      extinctBands: defaultRun.summary.extinctBands,
    },
    seasonalSupport: {
      controlledCases: stressCases.map((entry) => entry.seasonalSupport.summary),
      rawSupportBelowOneCount: rawBelowOneExamples.length,
      rawSupportBelowOneExamples: rawBelowOneExamples,
      recoveryPulseCount: recoveryPulseExamples.length,
      recoveryPulseExamples,
      rawSupportRatio: summarizeNumberDistribution(allSamples.map((sample) => sample.rawSupportRatio)),
      clampedSupportRatio: summarizeNumberDistribution(allSamples.map((sample) => sample.clampedSupportRatio)),
      foodStress: summarizeNumberDistribution(allSamples.map((sample) => sample.foodStress)),
      waterStress: summarizeNumberDistribution(allSamples.map((sample) => sample.waterStress)),
      classifications: countBy(allSamples, (sample) => sample.hungerClassification),
    },
    mortality: mortalityChannelAudit,
    activity: activityAudit,
    weakBandFate: {
      supportSeekingBlockers,
      absorptionProof,
      controlledCaseFates: stressCases.map((entry) => entry.weakBandFate),
      noMagicMergeViolations,
    },
    innerFission: {
      stateCounts: countBy(innerFissionStates, (state) => state.state),
      pressure: summarizeNumberDistribution(innerFissionStates.map((state) => state.pressureScore)),
      topCauseCounts: countBy(
        innerFissionStates.flatMap((state) => state.topCauses.map((cause) => cause.split(" ").slice(0, -1).join(" "))),
        (cause) => cause,
      ),
      splitDelayedExamples: innerFissionStates.filter((state) => state.splitDelayed).slice(0, 6),
      resolvedExamples: innerFissionStates.filter((state) => state.unityRecovering).slice(0, 6),
      innerFissionCreatedDaughters: false,
      note: "INNER-FISSION-1 derives pressure/readout/hooks only; daughter creation remains the existing demography fission path.",
    },
    socialTension: {
      pressure: summarizeNumberDistribution(socialTensionStates.map((state) => state.socialTensionPressure)),
      cohesionStatuses: countBy(socialTensionStates, (state) => state.cohesionStatus),
      toleranceStatuses: countBy(socialTensionStates, (state) => state.toleranceStatus),
      hostilityStatuses: countBy(socialTensionStates, (state) => state.hostilityStatus),
      crowdedKinStatuses: countBy(socialTensionStates, (state) => state.crowdedKinResourcePressureStatus),
      protectiveVaguenessExamples: socialTensionStates
        .filter((state) => state.protectiveVaguenessCount > 0 || state.directionBlurredCount > 0)
        .slice(0, 6),
      relationCategoryCounts: countBy(
        socialTensionStates.flatMap((state) => state.relationCategories),
        (relation) => relation.category,
      ),
      note: "Readability translates contact/range/report state only; no gossip or Band Events narrative generator.",
    },
    regressions: {
      preRunBandManager: preRunBandManager.verdict,
      nearbyWaterSuspiciousStuck: nearbyWater.suspiciousStuck,
      loneBandSocialTalkViolations: loneBandTalk.socialTalkOnIsolatedBandViolations,
      deterministic,
      populationCrash,
      megaBands,
      totalPopulation: defaultRun.summary.totalPopulation,
      activeBands: defaultRun.summary.activeBands,
    },
  };
}

function runTargetedBandEventsReadabilityAudit(modules, options) {
  const years = Number.isFinite(options.ecoMigAuditYears) ? options.ecoMigAuditYears : 24;
  const defaultYears = Math.min(years, 40);
  const defaultRun = runBenchmark(
    modules,
    { scenario: "map2_varied_migration", years: defaultYears, ticks: undefined },
    { ...options, reportBand: false, probeAudit: false, returnWorld: true },
  );
  const defaultRepeat = runBenchmark(
    modules,
    { scenario: "map2_varied_migration", years: defaultYears, ticks: undefined },
    { ...options, reportBand: false, probeAudit: false, returnWorld: true },
  );
  const dryStressBase = buildSeasonalStressControlledWorld(modules, "dry_margin_seasonal_food_stress");
  const dryStress = advanceStressWorld(modules, dryStressBase.world, 10, dryStressBase.focusBandIds).world;
  const absorption = modules.stepSim(createScenarioWorld(modules, "absorption_rescue").world, 1, "seasonal");
  const isolated = advanceScenarioForBandEvents(modules, createScenarioWorld(modules, "isolated_fragile_band").world, 3);
  const crowded = advanceScenarioForBandEvents(modules, createScenarioWorld(modules, "crowded_delta").world, 12);
  const scenarios = [
    { name: "default_map2", world: defaultRun.world },
    { name: "dry_margin_stress", world: dryStress },
    { name: "absorption_rescue", world: absorption },
    { name: "isolated_fragile", world: isolated },
    { name: "crowded_delta", world: crowded },
  ];
  const bandEntries = scenarios.flatMap((scenario) =>
    Object.values(scenario.world.bands).map((band) => ({ scenario: scenario.name, band })),
  );
  const eventEntries = bandEntries.flatMap((entry) =>
    (entry.band.eventHistory?.recentEvents ?? []).map((event) => ({
      scenario: entry.scenario,
      band: entry.band,
      event,
    })),
  );
  const allEvents = eventEntries.map((entry) => entry.event);
  const rumorEntries = bandEntries.flatMap((entry) =>
    (entry.band.campRumors?.items ?? []).map((item) => ({
      scenario: entry.scenario,
      band: entry.band,
      item,
    })),
  );
  const profileExamples = bandEntries
    .map((entry) => ({
      scenario: entry.scenario,
      bandId: String(entry.band.id),
      profile: entry.band.conditionProfile,
    }))
    .filter((entry) => entry.profile !== undefined)
    .slice(0, 8);
  const lineageExamples = bandEntries
    .map((entry) => ({
      scenario: entry.scenario,
      bandId: String(entry.band.id),
      lineage: entry.band.lineageReadability,
    }))
    .filter((entry) => entry.lineage !== undefined && entry.lineage.generationDepth > 0)
    .slice(0, 8);
  const coverage = summarizeBandEventCoverage(bandEntries, allEvents);
  const grounding = auditBandEventGrounding(eventEntries, rumorEntries);
  const preRunBandManager = runBandManagerAudit(modules);
  const nearbyWater = runNearbyWaterOpportunityAudit(modules, { ...options, ecoMigAuditYears: Math.min(defaultYears, 40) });
  const loneBandTalk = runLoneBandTalkAudit(modules, { ...options, ecoMigAuditYears: Math.min(defaultYears, 40) });
  const deterministic =
    makeBandEventsFingerprint(defaultRun.world) === makeBandEventsFingerprint(defaultRepeat.world);
  const activeBands = Object.values(defaultRun.world.bands).filter(isActiveBand);
  const populationCrash = defaultRun.summary.totalPopulation <= Math.max(20, defaultRun.summary.startPopulation * 0.2);
  const megaBands = activeBands.filter((band) => band.demography.population >= 500).length;
  const examples = {
    seasonalHunger: findEventExample(eventEntries, (entry) =>
      entry.event.category === "survival" &&
      (entry.event.stateKey.includes("seasonal_lean_stress") ||
        entry.event.stateKey.includes("chronic_food_deficit") ||
        entry.event.stateKey.includes("crisis_deficit")),
      "No seasonal/chronic hunger event occurred in these runs.",
    ),
    recoveryPulse: findEventExample(eventEntries, (entry) =>
      entry.event.category === "survival" &&
      (entry.event.stateKey.includes("seasonal_pulse_recovery") ||
        entry.event.stateKey.includes("recovery_after_crisis")),
      "No recovery/pulse support event occurred in these runs.",
    ),
    birthDeathChurn: findEventExample(eventEntries, (entry) =>
      entry.event.category === "demography" &&
      (entry.event.stateKey.startsWith("births:") ||
        entry.event.stateKey.startsWith("deaths:") ||
        entry.event.stateKey.startsWith("hidden-churn:")),
      "No birth/death/hidden-churn event occurred in these runs.",
    ),
    deathCause: findEventExample(eventEntries, (entry) =>
      entry.event.category === "demography" && entry.event.stateKey.startsWith("deaths:"),
      "No death-cause event occurred in these runs.",
    ),
    migrationHardship: findEventExample(eventEntries, (entry) => entry.event.category === "movement",
      "No recent residential movement/hardship event occurred in these runs.",
    ),
    supportSeeking: findEventExample(eventEntries, (entry) =>
      entry.event.category === "weak_band_fate" &&
      (entry.event.stateKey.includes("support_seeking") ||
        entry.event.stateKey.includes("absorption_candidate") ||
        entry.event.stateKey.includes("absorbed") ||
        entry.event.stateKey.includes("collapsed")),
      "No support-seeking/absorption/collapse weak-band event occurred in these runs.",
    ),
    absorptionOrCollapse: findEventExample(eventEntries, (entry) =>
      entry.event.category === "weak_band_fate" &&
      (entry.event.stateKey.includes("absorbed") || entry.event.stateKey.includes("collapsed")),
      "No absorption/collapse event occurred in these runs.",
    ),
    innerFission: findEventExample(eventEntries, (entry) => entry.event.category === "inner_fission",
      "No non-unified inner-fission event occurred in these runs.",
    ),
    socialTension: findEventExample(eventEntries, (entry) => entry.event.category === "social_tension",
      "No social-tension event occurred in these runs.",
    ),
    protectiveVagueness: findRumorExample(rumorEntries, (entry) =>
      entry.item.rawSource.includes("protectiveVagueness") || entry.item.rawSource.includes("directionBlurred"),
      "No protective-vagueness/direction-blur rumor item occurred in these runs.",
    ),
    lineageDisplay: lineageExamples[0] ?? "No daughter lineage display occurred in these runs.",
    psychologicalProfile: profileExamples[0] ?? "No condition profile was available.",
  };
  const verdict =
    deterministic &&
    preRunBandManager.verdict === "pass" &&
    nearbyWater.suspiciousStuck === 0 &&
    loneBandTalk.socialTalkOnIsolatedBandViolations === 0 &&
    !populationCrash &&
    megaBands === 0 &&
    coverage.totalEvents > 0 &&
    coverage.boundedMemoryCheck &&
    coverage.duplicateEventIdViolations === 0 &&
    grounding.ungroundedEvents.length === 0 &&
    grounding.unsupportedDeathEvents.length === 0 &&
    grounding.unsupportedMigrationDeathEvents.length === 0 &&
    grounding.unsupportedOutsiderClaims.length === 0 &&
    grounding.inventedGossipClaims.length === 0
      ? "pass"
      : "review";

  return {
    check: "BAND-EVENTS-READABILITY-1 targeted audit",
    verdict,
    command: `node scripts/simBenchmark.mjs --targeted-band-events-readability-audit --eco-mig-audit-years ${years} --json`,
    scenarios: scenarios.map((scenario) => ({
      name: scenario.name,
      bands: Object.keys(scenario.world.bands).length,
      activeBands: Object.values(scenario.world.bands).filter(isActiveBand).length,
      totalEvents: Object.values(scenario.world.bands).reduce((sum, band) => sum + (band.eventHistory?.recentEvents.length ?? 0), 0),
    })),
    eventCoverage: coverage,
    grounding,
    examples,
    campRumorMill: {
      items: rumorEntries.length,
      byInterpretation: countBy(rumorEntries, (entry) => entry.item.interpretationKind),
      examples: rumorEntries.slice(0, 8).map(formatRumorAuditExample),
    },
    psychologicalProfiles: profileExamples.map((entry) => ({
      scenario: entry.scenario,
      bandId: entry.bandId,
      summary: entry.profile?.summary,
      survival: entry.profile?.survivalCondition,
      internal: entry.profile?.internalCondition,
      weakBand: entry.profile?.weakBandCondition,
      social: entry.profile?.socialCondition,
      rawSources: entry.profile?.rawSources,
    })),
    lineage: {
      examples: lineageExamples.map((entry) => ({
        scenario: entry.scenario,
        bandId: entry.bandId,
        display: entry.lineage?.displayLabel,
        origin: String(entry.lineage?.originBandId),
        parent: entry.lineage?.parentBandId === undefined ? "none" : String(entry.lineage.parentBandId),
        depth: entry.lineage?.generationDepth,
        path: entry.lineage?.lineagePath.map(String),
        activeStatus: entry.lineage?.activeStatus,
        absorbedBy: entry.lineage?.absorbedByBandId === undefined ? "none" : String(entry.lineage.absorbedByBandId),
      })),
    },
    regressions: {
      preRunBandManager: preRunBandManager.verdict,
      nearbyWaterSuspiciousStuck: nearbyWater.suspiciousStuck,
      loneBandSocialTalkViolations: loneBandTalk.socialTalkOnIsolatedBandViolations,
      deterministic,
      populationCrash,
      megaBands,
      totalPopulation: defaultRun.summary.totalPopulation,
      activeBands: defaultRun.summary.activeBands,
      buildPass: "external command required: npm run build",
      staticGuards: "external rg guards required",
    },
    deferredSystemsStillAbsent: [
      "persistent camps",
      "storage economy",
      "disease ecology",
      "full plant/fauna ecology",
      "named individuals/families",
      "culture/religion",
      "territory/war/states/villages",
    ],
  };
}

function runTargetedEventTalkDiversityAudit(modules, options) {
  const requestedYears = Number.isFinite(options.ecoMigAuditYears) ? options.ecoMigAuditYears : 16;
  const years = Math.min(requestedYears, 20);
  const defaultRun = runBenchmark(
    modules,
    { scenario: "map2_varied_migration", years, ticks: undefined },
    { ...options, reportBand: false, probeAudit: false, returnWorld: true },
  );
  const defaultRepeat = runBenchmark(
    modules,
    { scenario: "map2_varied_migration", years, ticks: undefined },
    { ...options, reportBand: false, probeAudit: false, returnWorld: true },
  );
  const harshRun = runBenchmark(
    modules,
    { scenario: "harsh_dry_margin", years: Math.min(years, 12), ticks: undefined },
    { ...options, reportBand: false, probeAudit: false, returnWorld: true },
  );
  const defaultWorld = projectEcologyResearchWorld(modules, defaultRun.world);
  const harshWorld = projectEcologyResearchWorld(modules, harshRun.world);
  const repeatWorld = projectEcologyResearchWorld(modules, defaultRepeat.world);
  const worlds = [
    { name: "map2_varied_migration", world: defaultWorld },
    { name: "harsh_dry_margin", world: harshWorld },
  ];
  const bandEntries = worlds.flatMap((entry) =>
    Object.values(entry.world.bands).map((band) => ({ scenario: entry.name, band })),
  );
  const activeDefaultBands = Object.values(defaultWorld.bands).filter(isActiveBand);
  const eventEntries = bandEntries.flatMap((entry) =>
    (entry.band.eventHistory?.recentEvents ?? []).map((event) => ({ ...entry, event })),
  );
  const talkEntries = bandEntries.flatMap((entry) =>
    (entry.band.campRumors?.items ?? []).map((item) => ({ ...entry, item })),
  );
  const allEvents = eventEntries.map((entry) => entry.event);
  const allTalk = talkEntries.map((entry) => entry.item);
  const repetitionFixture = runEventTalkRepetitionFixture(modules, defaultWorld);
  const readableStrings = [
    ...allEvents.map((event) => `${event.title} ${event.description}`),
    ...allTalk.map((item) => item.summary),
  ];
  const normalizedPhraseCounts = countBy(readableStrings, normalizeReadablePhrase);
  const largestRepeatedPhraseCount = Math.max(0, ...Object.values(normalizedPhraseCounts));
  const uniqueRenderedStrings = Object.keys(normalizedPhraseCounts).length;
  const totalReadableItems = readableStrings.length;
  const eventCategories = countBy(allEvents, (event) => event.category);
  const talkCategories = countBy(allTalk, (item) => item.category);
  const uniqueCategoryCount = new Set([...Object.keys(eventCategories), ...Object.keys(talkCategories)]).size;
  const talkFamilies = countBy(allTalk, (item) => item.family);
  const talkTones = countBy(allTalk, (item) => item.tone);
  const salienceDistribution = {
    events: countBy(allEvents, (event) => event.salience),
    talk: countBy(allTalk, (item) => item.salience),
  };
  const sourceDistribution = {
    events: countBy(allEvents, (event) => event.rawSource),
    talk: countBy(allTalk, (item) => item.sourceCategory),
  };
  const unsupportedEvents = eventEntries.filter((entry) => !isSupportedEventTalkText(eventText(entry.event)));
  const unsupportedTalk = talkEntries.filter((entry) => !isSupportedEventTalkText(rumorText(entry.item)));
  const ungroundedEvents = eventEntries.filter((entry) =>
    entry.event.grounded !== true ||
    entry.event.rawSource.length === 0 ||
    entry.event.rawReason.length === 0 ||
    entry.event.sourceReasonIds.length === 0,
  );
  const ungroundedTalk = talkEntries.filter((entry) =>
    entry.item.grounded !== true ||
    entry.item.rawSource.length === 0 ||
    entry.item.rawReason.length === 0 ||
    entry.item.reasonIds.length === 0,
  );
  const repetitionSuppressed = bandEntries.reduce((sum, entry) =>
    sum + (entry.band.eventHistory?.duplicateSpamFiltered ?? 0) + (entry.band.campRumors?.suppressedRepeatCount ?? 0),
  0) + repetitionFixture.suppressedRepeats;
  const capViolations = bandEntries.filter((entry) => {
    const history = entry.band.eventHistory;
    const talk = entry.band.campRumors;
    return (
      (history !== undefined && (
        history.recentEvents.length > history.boundedEventLimit ||
        history.last10Years.length > 80 ||
        history.last25Years.length > 120
      )) ||
      (talk !== undefined && (
        talk.items.length > talk.itemCap ||
        talk.repetitionLedger.length > 64
      ))
    );
  });
  const highBeatsLowTalk = bandEntries.every((entry) => {
    const items = entry.band.campRumors?.items ?? [];
    const firstHigh = items.findIndex((item) => item.salience === "high");
    const firstLow = items.findIndex((item) => item.salience === "low");
    return firstHigh === -1 || firstLow === -1 || firstHigh < firstLow;
  });
  const highEventCount = allEvents.filter((event) => event.salience === "high").length;
  const highTalkCount = allTalk.filter((item) => item.salience === "high").length;
  const lowTalkCount = allTalk.filter((item) => item.salience === "low").length;
  const stableLowTalk = talkEntries.some((entry) =>
    entry.item.category === "everyday" ||
    (
      entry.item.salience === "low" &&
      (entry.band.seasonalSupport?.hungerClassification === "stable" ||
        entry.band.seasonalSupport?.hungerClassification === "seasonal_pulse_recovery")
    ),
  );
  const hungryTalk = talkEntries.some((entry) =>
    entry.item.category === "survival" &&
    (entry.item.tone === "worried" || entry.item.tone === "tense") &&
    entry.band.seasonalSupport?.hungerClassification !== "stable",
  );
  const natureTalkCategories = ["plants", "aquatic", "forest", "fauna"];
  const natureTalkAppears = natureTalkCategories.every((category) => talkCategories[category] > 0);
  const demographyRelevant = bandEntries.some((entry) => {
    const churn = entry.band.demography.demographicChurn;
    return (churn?.birthsThisYear ?? 0) > 0 ||
      (churn?.deathsThisYear ?? 0) > 0 ||
      (entry.band.deathMemory?.deathMemorySeverity ?? 0) >= 0.12;
  });
  const movementRelevant = bandEntries.some((entry) =>
    (entry.band.recentResidentialMoveEvents?.length ?? 0) > 0 ||
    (entry.band.recentIntraSeasonTrips ?? []).some((trip) => trip.distanceTiles >= 3 || trip.activityOutcome.includes("risk")),
  );
  const protoCampRelevant = bandEntries.some((entry) =>
    (entry.band.protoCampMemory?.currentPlace?.campLikeState ?? "none") !== "none" ||
    (entry.band.protoCampMemory?.topPlaces ?? []).some((place) => place.campLikeState !== "none"),
  );
  const socialFissionRelevant = bandEntries.some((entry) =>
    (entry.band.innerFission !== undefined && (entry.band.innerFission.state !== "unified" || entry.band.innerFission.pressureScore >= 0.28)) ||
    (entry.band.socialTension !== undefined && (
      entry.band.socialTension.socialTensionPressure >= 0.25 ||
      entry.band.socialTension.protectiveVaguenessCount > 0 ||
      entry.band.socialTension.directionBlurredCount > 0
    )),
  );
  const antiOmniscienceViolations = [
    ...eventEntries.filter((entry) => hasEventTalkOmniscienceLeak(eventDisplayText(entry.event))).map(formatEventAuditExample),
    ...talkEntries.filter((entry) => hasEventTalkOmniscienceLeak(entry.item.summary)).map(formatRumorAuditExample),
  ];
  const deterministic = makeEventTalkDiversityFingerprint(defaultWorld) === makeEventTalkDiversityFingerprint(repeatWorld);
  const sourceGuards = runEventTalkSourceGuards();
  const populationCrash = defaultRun.summary.totalPopulation <= Math.max(20, defaultRun.summary.startPopulation * 0.2);
  const megaBands = activeDefaultBands.filter((band) => band.demography.population >= 500).length;
  const bandEventsRegression = runTargetedBandEventsReadabilityAudit(modules, { ...options, ecoMigAuditYears: Math.min(years, 8) });
  const phraseDominanceLimit = Math.max(10, Math.ceil(totalReadableItems * 0.18));
  const maxItemsPerBand = Math.max(0, ...bandEntries.map((entry) =>
    (entry.band.eventHistory?.recentEvents.length ?? 0) + (entry.band.campRumors?.items.length ?? 0),
  ));
  const averageItemsPerBand = round3(totalReadableItems / Math.max(1, bandEntries.length));
  const payloadEstimates = bandEntries.map((entry) => ({
    bandId: String(entry.band.id),
    scenario: entry.scenario,
    bytes: JSON.stringify({
      eventHistory: entry.band.eventHistory,
      campRumors: entry.band.campRumors,
    }).length,
    events: entry.band.eventHistory?.recentEvents.length ?? 0,
    talk: entry.band.campRumors?.items.length ?? 0,
  }));
  const maxPayloadBytes = Math.max(0, ...payloadEstimates.map((entry) => entry.bytes));
  const checks = {
    manyEventTalkCategoriesReachable: uniqueCategoryCount >= 10 && Object.keys(talkCategories).length >= 8,
    allGeneratedEventsTalkGrounded: ungroundedEvents.length === 0 && ungroundedTalk.length === 0,
    unsupportedEventsTalkZero: unsupportedEvents.length === 0 && unsupportedTalk.length === 0,
    repetitionSuppressionWorks: repetitionSuppressed > 0 && repetitionFixture.capsHeld,
    templateDiversityHighEnough: Object.keys(talkFamilies).length >= 12 && uniqueRenderedStrings >= 24,
    noSinglePhraseDominates: largestRepeatedPhraseCount <= phraseDominanceLimit,
    toneChangesWithState: Object.keys(talkTones).length >= 5 && hungryTalk && stableLowTalk,
    severeEventsOutrankMildChatter: (highEventCount + highTalkCount > 0) && highBeatsLowTalk,
    stableBandsGetLowStakesTalk: stableLowTalk,
    hungryStressedBandsGetWorriedTalk: hungryTalk,
    natureDrivenTalkAppears: natureTalkAppears,
    demographyTalkAppearsWhenRelevant: !demographyRelevant || talkCategories.demography > 0 || eventCategories.demography > 0 || eventCategories.death_memory > 0,
    movementRouteTalkAppearsWhenRelevant: !movementRelevant || talkCategories.movement > 0 || talkCategories.range_knowledge > 0 || eventCategories.movement > 0,
    protoCampPlaceTalkAppearsWhenRelevant: !protoCampRelevant || talkCategories.camp_place > 0 || eventCategories.camp_place > 0,
    socialFissionTalkAppearsWhenRelevant: !socialFissionRelevant || talkCategories.inner_fission > 0 || talkCategories.social_tension > 0 || eventCategories.inner_fission > 0 || eventCategories.social_tension > 0,
    noMythsReligionTotemsNamedPeople: unsupportedEvents.length === 0 && unsupportedTalk.length === 0,
    antiOmnisciencePasses: antiOmniscienceViolations.length === 0,
    determinismPasses: deterministic,
    capsHeld: capViolations.length === 0,
    noPopulationCrash: !populationCrash,
    noMegaBandExplosion: megaBands === 0,
    staticGuardsPass: sourceGuards.pass,
  };
  const verdict = Object.values(checks).every(Boolean) && bandEventsRegression.verdict === "pass" ? "pass" : "review";

  return {
    check: "EVENT-TALK-DIVERSITY-MVP-1 targeted audit",
    verdict,
    command: `node scripts/simBenchmark.mjs --targeted-event-talk-diversity-audit --eco-mig-audit-years ${requestedYears} --json`,
    scenario: "map2_varied_migration + harsh_dry_margin projected through readability contexts",
    checks,
    existingEventTalkArchitecture: {
      eventCategories: [
        "survival",
        "demography",
        "movement",
        "activity",
        "weak_band_fate",
        "death_memory",
        "inner_fission",
        "social_tension",
        "lineage",
        "camp_place",
        "resource_ecology",
        "nature",
      ],
      eventCaps: {
        recent: 48,
        last10Years: 80,
        last25Years: 120,
        maxCandidatesPerTick: 14,
      },
      talkCap: 10,
      talkLedgerCap: 64,
      groundingFields: ["rawSource", "rawReason", "sourceReasonIds/reasonIds", "grounded"],
      readoutOnly: true,
    },
    diversityMetrics: {
      totalEventsGenerated: allEvents.length,
      totalTalkItemsGenerated: allTalk.length,
      uniqueEventCategories: Object.keys(eventCategories).length,
      uniqueTalkCategories: Object.keys(talkCategories).length,
      uniqueTemplateFamilies: Object.keys(talkFamilies).length,
      uniqueRenderedStrings,
      largestRepeatedPhraseCount,
      phraseDominanceLimit,
      categoryDistribution: {
        events: eventCategories,
        talk: talkCategories,
      },
      salienceDistribution,
      toneDistribution: talkTones,
      groundedSourceDistribution: sourceDistribution,
      averageItemsPerBand,
      maxItemsPerBand,
      maxSelectedBandPayloadBytes: maxPayloadBytes,
    },
    repetition: {
      eventDuplicateSpamFiltered: bandEntries.reduce((sum, entry) => sum + (entry.band.eventHistory?.duplicateSpamFiltered ?? 0), 0),
      talkSuppressedRepeats: bandEntries.reduce((sum, entry) => sum + (entry.band.campRumors?.suppressedRepeatCount ?? 0), 0),
      controlledFixture: repetitionFixture,
      largestRepeatedPhrase: Object.entries(normalizedPhraseCounts).sort((left, right) => right[1] - left[1])[0] ?? ["none", 0],
      repeatedTalkExamples: talkEntries
        .filter((entry) => entry.item.occurrenceCount >= 3)
        .slice(0, 8)
        .map(formatRumorAuditExample),
    },
    grounding: {
      ungroundedEvents: ungroundedEvents.slice(0, 5).map(formatEventAuditExample),
      ungroundedTalk: ungroundedTalk.slice(0, 5).map(formatRumorAuditExample),
      unsupportedEvents: unsupportedEvents.slice(0, 5).map(formatEventAuditExample),
      unsupportedTalk: unsupportedTalk.slice(0, 5).map(formatRumorAuditExample),
      antiOmniscienceViolations: antiOmniscienceViolations.slice(0, 5),
    },
    examples: {
      highSalienceEvents: eventEntries.filter((entry) => entry.event.salience === "high").slice(0, 6).map(formatEventAuditExample),
      highSalienceTalk: talkEntries.filter((entry) => entry.item.salience === "high").slice(0, 6).map(formatRumorAuditExample),
      stableLowStakesTalk: talkEntries.filter((entry) => entry.item.category === "everyday" || entry.item.salience === "low").slice(0, 6).map(formatRumorAuditExample),
      natureTalk: talkEntries.filter((entry) => natureTalkCategories.includes(entry.item.category)).slice(0, 10).map(formatRumorAuditExample),
      demographyMovementPlaceSocialTalk: talkEntries.filter((entry) =>
        ["demography", "movement", "range_knowledge", "camp_place", "inner_fission", "social_tension"].includes(entry.item.category),
      ).slice(0, 12).map(formatRumorAuditExample),
    },
    performanceCaps: {
      capViolations: capViolations.length,
      maxEventHistoryRecent: Math.max(0, ...bandEntries.map((entry) => entry.band.eventHistory?.recentEvents.length ?? 0)),
      maxCampTalkItems: Math.max(0, ...bandEntries.map((entry) => entry.band.campRumors?.items.length ?? 0)),
      maxCampTalkLedger: Math.max(0, ...bandEntries.map((entry) => entry.band.campRumors?.repetitionLedger.length ?? 0)),
      averageItemsPerBand,
      maxItemsPerBand,
      maxSelectedBandPayloadBytes: maxPayloadBytes,
    },
    regressions: {
      bandEventsReadability: bandEventsRegression.verdict,
      deterministic,
      populationCrash,
      megaBands,
      defaultRunCompleted: defaultRun.summary.completed,
      activeBands: defaultRun.summary.activeBands,
      totalPopulation: defaultRun.summary.totalPopulation,
    },
    sourceGuards,
    deferredSystemsStillAbsent: [
      "myths/religion/spirits/totems",
      "formal language system",
      "named people or named families",
      "law/access norms",
      "territory/borders/war",
      "leaders/chiefs/states/villages",
      "agriculture/storage/domestication expansion",
    ],
  };
}

function runTargetedResourceEcologyFoundationAudit(modules, options) {
  const years = Number.isFinite(options.ecoMigAuditYears) ? options.ecoMigAuditYears : 24;
  const defaultYears = Math.min(years, 32);
  const defaultRun = runBenchmark(
    modules,
    { scenario: "map2_varied_migration", years: defaultYears, ticks: undefined },
    { ...options, reportBand: false, probeAudit: false, returnWorld: true },
  );
  const defaultRepeat = runBenchmark(
    modules,
    { scenario: "map2_varied_migration", years: defaultYears, ticks: undefined },
    { ...options, reportBand: false, probeAudit: false, returnWorld: true },
  );
  const cases = [
    buildResourceEcologyFixtureCase(modules, defaultRun.world, "seasonal_plant_pulse"),
    buildResourceEcologyFixtureCase(modules, defaultRun.world, "aquatic_wetland_support"),
    buildResourceEcologyFixtureCase(modules, defaultRun.world, "dry_margin_fallback"),
    buildResourceEcologyFixtureCase(modules, defaultRun.world, "activity_confirmation"),
    buildResourceEcologyFixtureCase(modules, defaultRun.world, "resource_failure"),
    buildResourceEcologyFixtureCase(modules, defaultRun.world, "proto_camp_resource_reason"),
    buildResourceEcologyFixtureCase(modules, defaultRun.world, "contested_resource_pressure"),
    buildResourceEcologyFixtureCase(modules, defaultRun.world, "anti_omniscience"),
    buildResourceEcologyFixtureCase(modules, defaultRun.world, "abstract_remainder"),
  ];
  const defaultResourceBands = Object.values(defaultRun.world.bands).filter((band) => band.resourceEcology !== undefined);
  const resourceEvents = cases.flatMap((entry) => collectResourceEcologyEvents(entry.world, entry.name));
  const resourceStates = cases.flatMap((entry) => collectResourceEcologyBandExamples(entry.world, entry.name));
  const preRunBandManager = runBandManagerAudit(modules);
  const nearbyWater = runNearbyWaterOpportunityAudit(modules, { ...options, ecoMigAuditYears: Math.min(defaultYears, 40) });
  const loneBandTalk = runLoneBandTalkAudit(modules, { ...options, ecoMigAuditYears: Math.min(defaultYears, 40) });
  const bandEvents = runTargetedBandEventsReadabilityAudit(modules, { ...options, ecoMigAuditYears: Math.min(defaultYears, 24) });
  const protoCamps = runTargetedProtoCampsAudit(modules, { ...options, ecoMigAuditYears: Math.min(defaultYears, 24) });
  const deterministic =
    makeResourceEcologyFingerprint(defaultRun.world) === makeResourceEcologyFingerprint(defaultRepeat.world) &&
    cases.every((entry) => entry.deterministic);
  const activeBands = Object.values(defaultRun.world.bands).filter(isActiveBand);
  const populationCrash = defaultRun.summary.totalPopulation <= Math.max(20, defaultRun.summary.startPopulation * 0.2);
  const megaBands = activeBands.filter((band) => band.demography.population >= 500).length;
  const classDefinitions = modules.resourceEcology.RESOURCE_ECOLOGY_CLASSES.map((definition) => ({
    id: definition.id,
    label: definition.label,
    broadType: definition.broadType,
    seasonalAvailabilityProfile: definition.seasonalAvailabilityProfile,
    reliability: definition.reliability,
    laborCost: definition.laborCost,
    risk: definition.risk,
    pressureDepletionSensitivity: definition.pressureDepletionSensitivity,
    storageSuitabilityHook: definition.storageSuitabilityHook,
    supportActiveNow: definition.supportActiveNow,
  }));
  const supportContributionsByClass = {};
  const knowledgeStateCounts = {};
  const pressureByClass = {};
  for (const entry of resourceStates) {
    for (const contribution of entry.topContributingClasses) {
      supportContributionsByClass[contribution.classId] = round3((supportContributionsByClass[contribution.classId] ?? 0) + contribution.supportContribution);
    }
    for (const [state, count] of Object.entries(entry.knowledgeStateCounts)) {
      knowledgeStateCounts[state] = (knowledgeStateCounts[state] ?? 0) + count;
    }
    for (const pressure of entry.pressureEffects) {
      pressureByClass[pressure.classId] = round3(Math.max(pressureByClass[pressure.classId] ?? 0, pressure.pressure));
    }
  }
  const noUnsupportedResourceEvents = resourceEvents.every((event) =>
    (event.rawSource.includes("Band.resourceEcology") || event.rawSource.includes("IntraSeasonTripRecord")) &&
    !resourceEventHasForbiddenClaim(event),
  );
  const boundedResourceMemory = cases.every((entry) =>
    Object.values(entry.world.bands).every((band) =>
      band.resourceEcology === undefined ||
      (
        band.resourceEcology.knowledge.memoryCount <= band.resourceEcology.knowledge.memoryCap &&
        band.resourceEcology.topResourcePlaceMemories.length <= band.resourceEcology.placeMemoryCap
      ),
    ),
  );
  const verdict =
    deterministic &&
    preRunBandManager.verdict === "pass" &&
    nearbyWater.suspiciousStuck === 0 &&
    loneBandTalk.socialTalkOnIsolatedBandViolations === 0 &&
    bandEvents.verdict === "pass" &&
    protoCamps.verdict === "pass" &&
    noUnsupportedResourceEvents &&
    boundedResourceMemory &&
    !populationCrash &&
    megaBands === 0 &&
    hasResourceCase(cases, "seasonal_plant_pulse", (state) => state.plantContribution > 0 && state.seasonalResourceModifier > 1) &&
    hasResourceCase(cases, "aquatic_wetland_support", (state) => state.aquaticContribution > 0.5) &&
    hasResourceCase(cases, "dry_margin_fallback", (state) => state.fallbackContribution > 0.5) &&
    hasResourceCase(cases, "activity_confirmation", (state) => state.activityTraceCount > 0 && state.knownClasses.length > 0) &&
    hasResourceCase(cases, "resource_failure", (state) => state.pressureEffects.length > 0 || state.activityTraceCount > 0) &&
    hasResourceCase(cases, "proto_camp_resource_reason", (state) => state.resourcePlaceProtoLinks > 0) &&
    hasResourceCase(cases, "contested_resource_pressure", (state) => state.pressureEffects.length > 0) &&
    hasResourceCase(cases, "anti_omniscience", (state) => state.fullyKnownWithoutMemoryCount === 0 && state.noEveryResourceKnown === true) &&
    hasResourceCase(cases, "abstract_remainder", (state) => state.abstractRemainder > 0)
      ? "pass"
      : "review";

  return {
    check: "RESOURCE-ECOLOGY-FOUNDATION-1 targeted audit",
    verdict,
    command: `node scripts/simBenchmark.mjs --targeted-resource-ecology-foundation-audit --eco-mig-audit-years ${years} --json`,
    resourceClasses: {
      count: classDefinitions.length,
      definitions: classDefinitions,
      noNamedSpecies: classDefinitions.every((definition) => !/\b(deer|salmon|oak|wheat|rice|cattle|goat|sheep)\b/i.test(`${definition.id} ${definition.label}`)),
    },
    defaultRun: {
      resourceEcologyBands: defaultResourceBands.length,
      explainedShare: summarizeNumberDistribution(defaultResourceBands.map((band) => band.resourceEcology?.support.explainedShare ?? 0)),
      abstractRemainder: summarizeNumberDistribution(defaultResourceBands.map((band) => band.resourceEcology?.support.abstractRemainder ?? 0)),
      memoryCounts: summarizeNumberDistribution(defaultResourceBands.map((band) => band.resourceEcology?.knowledge.memoryCount ?? 0)),
    },
    controlledCases: cases.map(summarizeResourceEcologyCase),
    resourceSupport: {
      supportContributionsByClass,
      knowledgeStateCounts,
      pressureByClass,
      explainedShare: summarizeNumberDistribution(resourceStates.map((entry) => entry.explainedShare)),
      abstractRemainder: summarizeNumberDistribution(resourceStates.map((entry) => entry.abstractRemainder)),
    },
    activity: {
      tracesMeasured: resourceStates.reduce((sum, entry) => sum + entry.activityTraceCount, 0),
      examples: resourceStates.flatMap((entry) => entry.activityExamples).slice(0, 8),
    },
    protoCamps: {
      resourcePlaceExamples: resourceStates.flatMap((entry) => entry.resourcePlaceExamples).filter((entry) => entry.protoCampReasonLinks.length > 0).slice(0, 8),
      antiMagicVerdict: protoCamps.verdict,
    },
    events: {
      total: resourceEvents.length,
      byTitle: countBy(resourceEvents, (event) => event.title),
      examples: resourceEvents.slice(0, 10),
      noUnsupportedResourceEvents,
    },
    antiOmniscience: {
      fullyKnownWithoutMemoryCount: resourceStates.reduce((sum, entry) => sum + entry.fullyKnownWithoutMemoryCount, 0),
      antiOmniscienceCase: summarizeResourceEcologyCase(cases.find((entry) => entry.name === "anti_omniscience")),
      noEveryResourceKnown: resourceStates.every((entry) => entry.noEveryResourceKnown),
    },
    boundedMemory: {
      boundedResourceMemory,
      resourceKnowledgeCapMax: Math.max(0, ...resourceStates.map((entry) => entry.memoryCap)),
      resourcePlaceCapMax: Math.max(0, ...resourceStates.map((entry) => entry.placeMemoryCap)),
    },
    regressions: {
      preRunBandManager: preRunBandManager.verdict,
      nearbyWaterSuspiciousStuck: nearbyWater.suspiciousStuck,
      loneBandSocialTalkViolations: loneBandTalk.socialTalkOnIsolatedBandViolations,
      bandEventsGroundingVerdict: bandEvents.verdict,
      protoCampAntiMagicVerdict: protoCamps.verdict,
      deterministic,
      populationCrash,
      megaBands,
      totalPopulation: defaultRun.summary.totalPopulation,
      activeBands: defaultRun.summary.activeBands,
    },
    deferredSystemsStillAbsent: [
      "no named species",
      "no full plant ecology",
      "no full fauna ecology",
      "no storage economy",
      "no agriculture/domestication",
      "no disease ecology",
      "no culture/religion",
      "no territory/war/states",
    ],
  };
}

function runTargetedStorageSuitabilityAudit(modules, options) {
  const requestedYears = Number.isFinite(options.ecoMigAuditYears) ? options.ecoMigAuditYears : 12;
  const years = Math.min(Math.max(4, Math.floor(requestedYears)), 16);
  const defaultRun = runBenchmark(
    modules,
    { scenario: "map2_varied_migration", years, ticks: undefined },
    { ...options, reportBand: false, probeAudit: false, returnWorld: true },
  );
  const repeatRun = runBenchmark(
    modules,
    { scenario: "map2_varied_migration", years, ticks: undefined },
    { ...options, reportBand: false, probeAudit: false, returnWorld: true },
  );
  const world = projectStorageSuitabilityWorld(modules, defaultRun.world);
  const repeatWorld = projectStorageSuitabilityWorld(modules, repeatRun.world);
  const activeBands = Object.values(world.bands).filter(isActiveBand);
  const storageStates = activeBands.map((band) => band.resourceEcology).filter((state) => state !== undefined);
  const storageCards = activeBands.flatMap((band) => band.resourceEcology?.storageSuitabilityCards ?? []);
  const protoCampStorageReasons = activeBands.flatMap((band) =>
    (band.protoCampMemory?.topPlaces ?? []).flatMap((place) =>
      [...place.positiveReasons, ...place.negativeReasons].filter((reason) =>
        reason.rawSource.includes("storageSuitability") ||
        reason.rawSource.includes("temporaryWatercraft"),
      ),
    ),
  );
  const storageTalk = activeBands.flatMap((band) =>
    (band.campRumors?.items ?? []).filter((item) => item.category === "storage" || item.rawSource.includes("storageSuitability")),
  );
  const storageEvents = activeBands.flatMap((band) =>
    (band.eventHistory?.recentEvents ?? []).filter((event) => event.rawSource.includes("storageSuitability")),
  );
  const watercraftEvents = activeBands.flatMap((band) =>
    (band.eventHistory?.recentEvents ?? []).filter((event) => event.rawSource.includes("temporaryWatercraft")),
  );
  const watercraftMoves = activeBands.flatMap((band) =>
    (band.recentResidentialMoveEvents ?? []).filter((move) => move.temporaryWatercraft !== undefined),
  );
  const watercraftFixtures = buildWatercraftFixtureCases(modules);
  const traitRows = modules.resourceEcology.RESOURCE_ECOLOGY_CLASSES.map((definition) => ({
    id: definition.id,
    label: definition.label,
    broadType: definition.broadType,
    traits: modules.storageSuitability.getStorageSuitabilityTraits(definition.id),
  }));
  const traitById = Object.fromEntries(traitRows.map((row) => [row.id, row.traits]));
  const classCoverage = {
    plant: traitRows.filter((row) => row.broadType === "plant").length,
    aquatic: traitRows.filter((row) => row.broadType === "aquatic").length,
    animal: traitRows.filter((row) => row.broadType === "animal").length,
    fallback: traitRows.filter((row) => row.broadType === "fallback").length,
    material: traitRows.filter((row) => row.broadType === "material_hook").length,
  };
  const selectedStoragePayloadBytes = Math.max(0, ...activeBands.map((band) =>
    byteLengthUtf8(JSON.stringify({
      cards: band.resourceEcology?.storageSuitabilityCards ?? [],
      summary: band.resourceEcology?.storageSuitabilitySummary,
      watercraft: (band.recentResidentialMoveEvents ?? []).flatMap((move) => move.temporaryWatercraft ?? []),
    })),
  ));
  const determinism =
    makeStorageSuitabilityFingerprint(world) === makeStorageSuitabilityFingerprint(repeatWorld) &&
    watercraftFixtures.every((entry) => entry.deterministic);
  const staticGuards = runStorageSuitabilityStaticGuards();
  const forbiddenPattern = /\b(granary|granaries|warehouse|village|villages|agriculture|tax|taxation|property|territory|territorial|bridge|dock|permanent boat|canoe culture|maritime specialization|pottery)\b/i;
  const unsupportedStorageTalk = storageTalk.filter((item) =>
    !item.rawSource.includes("storageSuitability") ||
    forbiddenPattern.test(`${item.summary} ${item.rawReason}`),
  );
  const unsupportedStorageEvents = storageEvents.filter((event) =>
    !event.rawSource.includes("storageSuitability") ||
    forbiddenPattern.test(`${event.title} ${event.description} ${event.detail ?? ""}`),
  );
  const forbiddenStorageOutputCount = [
    ...storageTalk.map((item) => `${item.summary} ${item.rawReason}`),
    ...storageEvents.map((event) => `${event.title} ${event.description} ${event.detail ?? ""}`),
    ...watercraftEvents.map((event) => `${event.title} ${event.description} ${event.detail ?? ""}`),
    ...watercraftFixtures.map((entry) => `${entry.assessment?.reason ?? ""} ${entry.assessment?.materialBasis.join(" ") ?? ""}`),
  ].filter((text) => forbiddenPattern.test(text)).length;
  const hiddenTruthViolations = storageCards.filter((card) =>
    card.resourceKnownToBand !== true ||
    card.antiOmniscienceStatus === undefined ||
    card.storageConfidence > 0.25 && card.confidenceKind === "low_confidence_inference",
  );
  const perishableTreatedAsStorage = ["aquatic_food", "fish_or_shellfish", "small_game", "large_game_abstract"]
    .filter((classId) => traitById[classId]?.perishability === "high")
    .filter((classId) => {
      const storage = traitById[classId]?.storageSuitability;
      return storage === "good" || storage === "excellent";
    });
  const cardsWithinCaps = storageStates.every((state) =>
    state.storageSuitabilityCards.length <= state.storageSuitabilitySummary.cardCap &&
    state.storageSuitabilitySummary.guards.noActualStockpile === true &&
    state.storageSuitabilitySummary.guards.noStoredFoodBank === true,
  );
  const watercraftCapsHeld = watercraftFixtures.every((entry) =>
    entry.assessment !== undefined &&
    entry.assessment.optionCount <= entry.assessment.optionCap &&
    entry.assessment.guards.noPermanentBoatInventory === true &&
    entry.assessment.guards.noDockBridgeOrFerry === true,
  );
  const acuteRiskControlled = watercraftFixtures.some((entry) =>
    entry.assessment?.acuteRiskHint !== undefined &&
    entry.assessment.guards.noPermanentBoatInventory === true,
  );
  const populationCrash = defaultRun.summary.totalPopulation <= Math.max(20, defaultRun.summary.startPopulation * 0.2);
  const megaBands = activeBands.filter((band) => band.demography.population >= 500).length;
  const requiredChecks = {
    storageTraitsAcrossDomains:
      classCoverage.plant > 0 &&
      classCoverage.aquatic > 0 &&
      classCoverage.animal > 0 &&
      classCoverage.material > 0,
    perishableNotLongTermStorage: perishableTreatedAsStorage.length === 0,
    seedsNutsMastStoreBetter:
      traitById.seeds_nuts_mast?.storageSuitability === "excellent" &&
      traitById.seeds_nuts_mast?.perishability === "low",
    fishFreshMeatBurdenVisible:
      traitById.fish_or_shellfish?.perishability === "high" &&
      traitById.fish_or_shellfish?.processingLabor === "high" &&
      traitById.large_game_abstract?.carryBurden === "high",
    rootsTubersTradeoff:
      traitById.roots_tubers_fallback?.storageSuitability === "good" &&
      traitById.roots_tubers_fallback?.processingLabor === "high",
    wetlandNotMagicSurplus:
      traitById.wetland_plants?.perishability === "high" &&
      traitById.wetland_plants?.storageSuitability === "poor",
    bandKnownNoHiddenTruth:
      hiddenTruthViolations.length === 0 &&
      storageStates.every((state) => state.storageSuitabilitySummary.antiOmniscience.hiddenTruthCardCount === 0),
    protoCampStorageReasonsGrounded: protoCampStorageReasons.length > 0,
    storageTalkEventsGrounded:
      storageTalk.length > 0 &&
      storageEvents.length > 0 &&
      unsupportedStorageTalk.length === 0 &&
      unsupportedStorageEvents.length === 0,
    noStockpileEconomy:
      storageStates.every((state) => state.noStorageEconomy === true && state.noStoredFoodBank === true) &&
      forbiddenStorageOutputCount === 0,
    watercraftSuccess: watercraftFixtures.some((entry) => entry.name === "successful_temporary_crossing" && entry.assessment?.result === "crossing_success"),
    watercraftDelayed: watercraftFixtures.some((entry) => entry.name === "delayed_dependents_load" && entry.assessment?.result === "crossing_delayed_materials"),
    watercraftRejected: watercraftFixtures.some((entry) => entry.name === "rejected_current_exposure" && entry.assessment?.result === "crossing_abandoned_risk"),
    crisisRiskToleranceRises: watercraftFixtures.some((entry) =>
      entry.name === "crisis_crossing_tolerance" &&
      entry.assessment !== undefined &&
      entry.assessment.riskTolerance >= 0.75 &&
      entry.assessment.result !== "crossing_abandoned_risk",
    ),
    materialLimitedFailure: watercraftFixtures.some((entry) => entry.name === "material_limited_failure" && entry.assessment?.result === "materials_missing"),
    wholeBandLogisticsVisible: watercraftFixtures.every((entry) =>
      entry.assessment !== undefined &&
      entry.assessment.adultLabor >= 0 &&
      entry.assessment.dependents >= 0 &&
      entry.assessment.elders >= 0 &&
      entry.assessment.carryBurden !== undefined,
    ),
    watercraftEventsOrFixtures:
      watercraftEvents.length > 0 ||
      watercraftFixtures.some((entry) => entry.assessment?.traceType !== undefined),
    acuteRiskHardshipControlled: acuteRiskControlled,
    placeMemoryCanReceiveCrossingHint: watercraftFixtures.some((entry) => entry.assessment?.protoCampMemoryHint !== undefined),
    watercraftGuardsHeld: watercraftCapsHeld,
    capsHeld: cardsWithinCaps && watercraftCapsHeld && selectedStoragePayloadBytes < 64_000,
    deterministic: determinism,
    staticGuardsPass:
      staticGuards.mathRandomInSim === 0 &&
      staticGuards.explicitAnyInSim === 0 &&
      staticGuards.uiRenderStoreImportsInSim === 0,
    noPopulationCrash: !populationCrash,
    noMegaBandExplosion: megaBands === 0,
  };
  const verdict = Object.values(requiredChecks).every(Boolean) ? "pass" : "review";

  return {
    check: "STORAGE-SUITABILITY-0 targeted audit",
    verdict,
    command: `node scripts/simBenchmark.mjs --targeted-storage-suitability-audit --json`,
    methodology: {
      years,
      liveScenario: "map2_varied_migration",
      liveActiveBands: activeBands.length,
      fixtureCases: watercraftFixtures.length,
    },
    storageSuitability: {
      cardCount: storageCards.length,
      resourceClassesCovered: [...new Set(storageCards.map((card) => card.classId))].sort(),
      classCoverage,
      traitRows,
      bestBuffers: storageCards
        .filter((card) => card.seasonalBufferValue === "high" || card.storageSuitability === "excellent" || card.storageSuitability === "good")
        .slice(0, 8)
        .map(summarizeStorageCardForAudit),
      perishableExamples: storageCards
        .filter((card) => card.perishability === "high" || card.spoilageRisk === "high")
        .slice(0, 8)
        .map(summarizeStorageCardForAudit),
      materialExamples: storageCards
        .filter((card) => card.crossingMaterialUse !== "none" || card.broadType === "material_hook")
        .slice(0, 8)
        .map(summarizeStorageCardForAudit),
    },
    protoCampHooks: {
      storageReasonCount: protoCampStorageReasons.length,
      examples: protoCampStorageReasons.slice(0, 10),
    },
    eventsAndTalk: {
      storageTalkCount: storageTalk.length,
      storageEventCount: storageEvents.length,
      watercraftEventCount: watercraftEvents.length,
      unsupportedStorageTalk: unsupportedStorageTalk.length,
      unsupportedStorageEvents: unsupportedStorageEvents.length,
      forbiddenStorageOutputCount,
      talkExamples: storageTalk.slice(0, 8).map((item) => ({
        summary: item.summary,
        rawSource: item.rawSource,
        rawReason: item.rawReason,
      })),
      eventExamples: [...storageEvents, ...watercraftEvents].slice(0, 8).map((event) => ({
        title: event.title,
        description: event.description,
        rawSource: event.rawSource,
        rawReason: event.rawReason,
      })),
    },
    temporaryWatercraft: {
      liveMoveCount: watercraftMoves.length,
      fixtureExamples: watercraftFixtures.map((entry) => ({
        name: entry.name,
        deterministic: entry.deterministic,
        result: entry.assessment?.result ?? "none",
        traceType: entry.assessment?.traceType ?? "none",
        option: entry.assessment?.optionLabel ?? "none",
        materialBasis: entry.assessment?.materialBasis ?? [],
        adultLabor: entry.assessment?.adultLabor ?? 0,
        dependents: entry.assessment?.dependents ?? 0,
        elders: entry.assessment?.elders ?? 0,
        carryBurden: entry.assessment?.carryBurden ?? "none",
        shuttleTrips: entry.assessment?.shuttleTrips ?? 0,
        riskTolerance: entry.assessment?.riskTolerance ?? 0,
        expectedCrossingSafety: entry.assessment?.expectedCrossingSafety ?? 0,
        riverRisk: entry.assessment?.riverRisk ?? 0,
        acuteRiskHint: entry.assessment?.acuteRiskHint ?? "none",
        protoCampMemoryHint: entry.assessment?.protoCampMemoryHint ?? "none",
        reason: entry.assessment?.reason ?? "none",
      })),
    },
    antiOmniscience: {
      hiddenTruthViolations: hiddenTruthViolations.length,
      lowConfidenceInferenceCards: storageCards.filter((card) => card.confidenceKind === "low_confidence_inference").length,
      cardsFromBandKnownSourcesOnly: storageStates.every((state) => state.storageSuitabilitySummary.antiOmniscience.cardsFromBandKnownSourcesOnly),
      watercraftKnownCrossingOnly: watercraftFixtures.every((entry) => entry.assessment?.antiOmniscience.knownCrossingOnly === true),
      watercraftKnownMaterialsOnly: watercraftFixtures.every((entry) => entry.assessment?.antiOmniscience.materialBasisFromKnownResourcesOnly === true),
    },
    performanceAndCaps: {
      storageCardMaxBand: Math.max(0, ...storageStates.map((state) => state.storageSuitabilityCards.length)),
      storageCardCapMax: Math.max(0, ...storageStates.map((state) => state.storageSuitabilitySummary.cardCap)),
      watercraftOptionCapMax: Math.max(0, ...watercraftFixtures.map((entry) => entry.assessment?.optionCap ?? 0)),
      selectedStoragePayloadBytes,
      cardsWithinCaps,
      watercraftCapsHeld,
    },
    requiredChecks,
    regressions: {
      deterministic: determinism,
      populationCrash,
      megaBands,
      totalPopulation: defaultRun.summary.totalPopulation,
      activeBands: defaultRun.summary.activeBands,
      staticGuards,
    },
    deferredSystemsStillAbsent: [
      "no actual stockpile inventory",
      "no stored food bank feeding population",
      "no granaries/warehouses",
      "no villages/sedentism",
      "no agriculture/domestication",
      "no property/taxation/territory",
      "no permanent boat inventory, docks, bridges, canoe culture, or maritime specialization",
    ],
  };
}

function projectStorageSuitabilityWorld(modules, world) {
  const withResources = modules.resourceEcology.applyResourceEcologyContext(world);
  const withProto = modules.protoCamps.applyProtoCampContext(withResources);
  const withVisible = modules.visibleNature.applyVisibleNatureContext(withProto);
  const withAcute = modules.acuteRisk.applyAcuteRiskContext(withVisible);
  return modules.bandEvents.applyBandReadabilityContext(withAcute);
}

function makeStorageSuitabilityFingerprint(world) {
  const bands = Object.values(world.bands)
    .filter(isActiveBand)
    .sort(compareBands)
    .slice(0, 16)
    .map((band) => ({
      id: String(band.id),
      storage: (band.resourceEcology?.storageSuitabilityCards ?? [])
        .map((card) => `${card.classId}:${card.storageSuitability}:${card.perishability}:${card.storageConfidence}:${card.confidenceKind}`)
        .join(","),
      storageSummary: band.resourceEcology?.storageSuitabilitySummary?.seasonalBufferHeadline ?? "",
      protoStorage: (band.protoCampMemory?.topPlaces ?? [])
        .flatMap((place) => [...place.positiveReasons, ...place.negativeReasons])
        .filter((reason) => reason.rawSource.includes("storageSuitability") || reason.rawSource.includes("temporaryWatercraft"))
        .map((reason) => `${reason.reason}:${reason.strength}`)
        .join(","),
      storageTalk: (band.campRumors?.items ?? [])
        .filter((item) => item.category === "storage")
        .map((item) => `${item.family}:${item.stateKey}`)
        .join(","),
      watercraft: (band.recentResidentialMoveEvents ?? [])
        .flatMap((move) => move.temporaryWatercraft ?? [])
        .map((entry) => `${entry.result}:${entry.watercraftType ?? "none"}:${entry.riverRisk}:${entry.materialConfidence}`)
        .join(","),
    }));

  return JSON.stringify({
    tick: Number(world.time.tick),
    bands,
  });
}

function summarizeStorageCardForAudit(card) {
  return {
    classId: card.classId,
    label: card.label,
    broadType: card.broadType,
    storageSuitability: card.storageSuitability,
    perishability: card.perishability,
    cacheSuitability: card.cacheSuitability,
    dryingSuitability: card.dryingSuitability,
    smokingSuitability: card.smokingSuitability,
    processingLabor: card.processingLabor,
    carryBurden: card.carryBurden,
    spoilageRisk: card.spoilageRisk,
    seasonalBufferValue: card.seasonalBufferValue,
    riskIfMishandled: card.riskIfMishandled,
    crossingMaterialUse: card.crossingMaterialUse,
    storageConfidence: card.storageConfidence,
    confidenceKind: card.confidenceKind,
    antiOmniscienceStatus: card.antiOmniscienceStatus,
    reasons: card.reasons,
  };
}

