function makeStaleRelationshipBodyState(state) {
  return {
    ...state,
    weatherMemories: state.weatherMemories.map((memory) => ({
      ...memory,
      strength: Math.max(0.18, memory.strength * 0.45),
      staleness: 0.82,
      trend: "recovered",
      routeCaution: Math.max(0.12, memory.routeCaution * 0.5),
    })),
    sickness: {
      ...state.sickness,
      active: false,
      severity: 0.08,
      recoverySignal: 0.8,
    },
    campCleanliness: {
      ...state.campCleanliness,
      pressure: 0.12,
      recovery: 0.72,
      scavengerPressure: 0.04,
      state: "recovering",
    },
  };
}

function makeRelationshipMemoryFingerprint(world) {
  return JSON.stringify(
    Object.values(world.bands)
      .filter(isActiveBand)
      .map((band) => band.relationshipMemory)
      .filter((state) => state !== undefined)
      .map(makeRelationshipMemoryStateFingerprint)
      .sort(),
  );
}

function makeRelationshipMemoryStateFingerprint(state) {
  return JSON.stringify({
    mode: state.mode,
    practice: state.practiceSkills.map((record) => [record.skill, record.status, record.practice, record.effect]),
    animal: state.animalFamiliarity.map((record) => [record.stockId, record.kind, record.humanLearning, record.animalWariness, record.campFollowing]),
    scavengers: state.scavengerPatterns.map((record) => [record.kind, record.pressure, record.risk]),
    gatherings: state.seasonalAggregations.map((record) => [record.tileId, record.trigger, record.intensity, record.dispersalSignal]),
    failures: state.failureStories.map((record) => [record.kind, record.strength, record.staleness, record.trend]),
    places: state.placeCharacters.map((record) => [record.tileId, record.kind, record.salience]),
    reputations: state.reputations.map((record) => [record.otherBandId, record.kind, record.familiarity, record.tension]),
    absorption: state.absorptionDetails.map((record) => [record.kind, record.targetBandId, record.absorbedByBandId, record.pressure]),
    routes: state.routeFamiliarity.map((record) => [record.fromTileId, record.toTileId, record.kind, record.status, record.ease, record.risk]),
    behavior: state.behavior,
    capsHeld: state.capsHeld,
  });
}

function relationshipMemoryUiReadoutChecks() {
  // READABILITY-UI-ORGANIZATION-1 — relationship memory now surfaces in the
  // People tab (reputations, gatherings, joinings by band NAME) and the Nature
  // tab (animal familiarity); raw proof stays Technical.
  const people = readFileSync(join(process.cwd(), "src/ui/band/People.tsx"), "utf8");
  const nature = readFileSync(join(process.cwd(), "src/ui/band/Nature.tsx"), "utf8");
  const technical = readFileSync(join(process.cwd(), "src/ui/band/Technical.tsx"), "utf8");
  const sections = readFileSync(join(process.cwd(), "src/ui/band/sections.tsx"), "utf8");
  const history = readFileSync(join(process.cwd(), "src/ui/band/History.tsx"), "utf8");
  return {
    overview: people.includes("Bands they remember") && people.includes("band.relationshipMemory"),
    nature: nature.includes("animalFamiliarity") && nature.includes("Animals they have come to know"),
    technical: technical.includes("RelationshipMemoryDetails") && sections.includes("RelationshipMemoryDetails"),
    historyFilter: history.includes("relationship_memory"),
  };
}

function runTargetedPerformancePlayabilityAudit(modules, options) {
  const requestedYears = Number.isFinite(options.ecoMigAuditYears) ? options.ecoMigAuditYears : 8;
  const years = Math.min(Math.max(4, Math.floor(requestedYears)), 16);
  const defaultRun = runBenchmark(
    modules,
    { scenario: "map2_varied_migration", years, ticks: undefined },
    { ...options, reportBand: false, probeAudit: false, returnWorld: true },
  );
  const repeatRun = runBenchmark(
    modules,
    { scenario: "map2_varied_migration", years, ticks: undefined },
    { ...options, reportBand: false, probeAudit: false, returnWorld: true },
  );
  const projectedWorld = projectPerformancePlayabilityWorld(modules, defaultRun.world);
  const projectedRepeatWorld = projectPerformancePlayabilityWorld(modules, repeatRun.world);
  const activeBands = Object.values(projectedWorld.bands).filter(isActiveBand).sort(compareBands);
  const selectedBand = pickHeaviestPerformanceBand(activeBands);
  const staticGuards = runStorageSuitabilityStaticGuards();
  const snapshotFootprint = measurePerf4SnapshotFootprint(modules, projectedWorld);
  const selectedPayload = selectedBand === undefined
    ? emptyPerformanceSelectedPayload()
    : measurePerformanceSelectedBandPayload(selectedBand);
  const panelCosts = selectedBand === undefined
    ? emptyPerformancePanelCosts()
    : measurePerformancePanelPayloads(selectedBand, projectedWorld, modules);
  const mapOverlay = measurePerformanceMapOverlayPayload(modules, projectedWorld);
  const counts = summarizePerformancePlayabilityCounts(projectedWorld, activeBands);
  const sourceChecks = performancePlayabilitySourceChecks();
  const memoryShort = summarizePerformanceMemoryGrowth([defaultRun.world, projectedWorld]);
  const deterministic =
    makePerformancePlayabilityFingerprint(projectedWorld) === makePerformancePlayabilityFingerprint(projectedRepeatWorld);
  const noBehaviorChange =
    makePerformanceWorldFingerprint(defaultRun.world) === makePerformanceWorldFingerprint(repeatRun.world);
  const populationCrash = defaultRun.summary.totalPopulation <= Math.max(20, defaultRun.summary.startPopulation * 0.2);
  const megaBands = activeBands.filter((band) => band.demography.population >= 500).length;
  const capViolations = summarizePerformancePlayabilityCapViolations(activeBands);
  const requiredChecks = {
    stepSimTimingReported:
      Number.isFinite(defaultRun.summary.averageMsPerTick) &&
      Number.isFinite(defaultRun.summary.maxMsPerTick) &&
      defaultRun.summary.ticksSimulated > 0,
    snapshotProjectionTimingReported:
      Number.isFinite(snapshotFootprint.dynamicBuildMs) &&
      Number.isFinite(snapshotFootprint.dynamicJsonMs) &&
      Number.isFinite(panelCosts.totalProjectionMs),
    fullSnapshotSizeEstimated:
      snapshotFootprint.dynamicSnapshotBytes > 0 &&
      snapshotFootprint.dynamicSnapshotBytes < 90_000_000,
    selectedBandPayloadBounded:
      selectedPayload.bytes > 0 &&
      selectedPayload.bytes < 1_500_000,
    overviewPayloadBounded:
      panelCosts.overview.bytes < 350_000,
    naturePayloadBounded:
      panelCosts.nature.bytes < 450_000,
    historyPayloadBounded:
      panelCosts.history.bytes < 450_000,
    technicalRawPayloadBounded:
      panelCosts.technicalRaw.bytes < 1_500_000,
    mapOverlayPayloadBounded:
      mapOverlay.liveOverlayBytes > 0 &&
      mapOverlay.liveOverlayBytes < 1_500_000,
    eventTalkCountsBounded:
      counts.maxRecentEvents <= 48 &&
      counts.maxCampTalkItems <= 24,
    natureCardCountsBounded:
      counts.maxFaunaCards <= 10 &&
      counts.maxPlantCards <= 10 &&
      counts.maxAquaticCards <= 8 &&
      counts.maxForestCards <= 8,
    recentSubstrateCountsBounded:
      counts.maxStorageCards <= 16 &&
      counts.maxBodyRecords <= 32 &&
      counts.maxRelationshipRecords <= 48 &&
      counts.maxProtoCampPlaces <= 12 &&
      counts.maxAccessPlaces <= 12,
    rawReasonCountsBounded:
      counts.maxSourceReasonIds <= 32 &&
      counts.maxRawReasonTextBytes < 16_000,
    capsHeld:
      Object.values(capViolations).every((violation) => violation === false),
    deterministic:
      deterministic && noBehaviorChange,
    lazyHiddenTabsSource:
      sourceChecks.bandDetailsActiveTabOnly === true,
    lazyTechnicalSource:
      sourceChecks.collapsibleLazyMount === true &&
      sourceChecks.technicalDefaultOpenHeavyGroups === 0 &&
      sourceChecks.performanceDiagnosticsLazy === true,
    canvasCachingSource:
      sourceChecks.liveOverlayImperativeCanvas === true &&
      sourceChecks.tileFillColorCache === true &&
      sourceChecks.staticCanvasLayerCache === true,
    staticGuardsPass:
      staticGuards.mathRandomInSim === 0 &&
      staticGuards.explicitAnyInSim === 0 &&
      staticGuards.uiRenderStoreImportsInSim === 0,
    noPopulationCrash:
      !populationCrash,
    noMegaBandExplosion:
      megaBands === 0,
  };
  const verdict = Object.values(requiredChecks).every(Boolean) ? "pass" : "review";

  return {
    check: "PERFORMANCE-PLAYABILITY-TRIAGE/FIX targeted audit",
    verdict,
    command: "node scripts/simBenchmark.mjs --targeted-performance-playability-audit --json",
    methodology: {
      years,
      scenario: "map2_varied_migration",
      activeBands: activeBands.length,
      selectedBandId: selectedBand === undefined ? undefined : String(selectedBand.id),
      selectedBandChoice: "heaviest active selected-band JSON payload in sampled projected world",
      browserFpsMeasured: false,
      browserFpsNote: "Node audit cannot measure real browser FPS/frame pacing. The app now exposes lazy Technical payload diagnostics for manual profiling, and canvas source guards prove the rAF/live-overlay/cache path is present.",
    },
    runtime: {
      ticksSimulated: defaultRun.summary.ticksSimulated,
      totalRuntimeMs: round2(defaultRun.summary.totalRuntimeMs),
      averageMsPerTick: round2(defaultRun.summary.averageMsPerTick),
      maxMsPerTick: round2(defaultRun.summary.maxMsPerTick),
      slowestSubpasses: defaultRun.summary.slowestSubpasses?.slice(0, 8) ?? [],
      phaseSummary: defaultRun.summary.phaseSummary,
    },
    payloads: {
      snapshotFootprint,
      selectedBand: selectedPayload,
      panels: panelCosts,
      mapOverlay,
    },
    counts,
    capViolations,
    sourceChecks,
    fixesImplemented: [
      {
        name: "lazy CollapsibleGroup content",
        files: ["src/ui/band/parts.tsx"],
        effect: "collapsed Technical/History raw proof sections no longer mount their child detail components until expanded",
      },
      {
        name: "Technical raw proof closed by default",
        files: ["src/ui/band/Technical.tsx"],
        effect: "opening Technical no longer immediately renders recent heavy substrate debug blocks",
      },
      {
        name: "selected-band payload diagnostics",
        files: ["src/ui/band/Technical.tsx"],
        effect: "Technical-only expandable diagnostics estimate selected-band/panel payloads without cluttering normal UI",
      },
      {
        name: "memoized active-panel projections",
        files: ["src/ui/band/Nature.tsx", "src/ui/band/History.tsx"],
        effect: "pure filtered/sorted selected-band lists are not rebuilt on unrelated rerenders",
      },
    ],
    existingArchitectureFound: {
      simToUi: "worker posts compact live overlays every tick and throttled dynamic snapshots for inspection panels",
      fullSnapshotContents: "time, bands, decisions, decision archive, climate stress, tile depletion, ecology summary",
      frequentPayload: "live overlay with markers, clock/counts, and capped activity traces",
      selectedBandProjection: "normal UI reads one selected band from the latest dynamic snapshot; no separate selected-band RPC yet",
      hiddenTabs: "BandDetails mounts only the active tab",
      canvas: "WorldCanvas subscribes imperatively to the store and paints via rAF; renderer uses static layers and tile-fill caching",
      technicalProof: "raw proof remains available, now lazy-mounted behind collapsible sections",
    },
    manualPlayabilityPath: [
      "Start the app and load Map 2 / varied migration.",
      "Run at Fast or Ultra Fast for several years.",
      "Select a band, switch Overview -> Nature -> History -> Technical.",
      "Expand selected Technical groups and Performance / payload diagnostics only as needed.",
      "Toggle Activity and Range overlays, then pan/zoom the map.",
      "Watch for delayed input, snapshot stalls, and map frame pacing; browser FPS is not measured by this Node audit.",
    ],
    memory: memoryShort,
    determinism: {
      projectedFingerprintStable: deterministic,
      unprojectedBenchmarkFingerprintStable: noBehaviorChange,
    },
    staticGuards,
    requiredChecks,
  };
}

function projectPerformancePlayabilityWorld(modules, world) {
  return modules.bandEvents.applyBandReadabilityContext(
    modules.relationshipMemory.applyRelationshipMemorySocialEcologyContext(
      modules.bodyCampLogistics.applyBodyCampSurvivalLogisticsContext(
        modules.foragingAdaptation.applyForagingLearningAdaptationContext(
          modules.accessNorms.applyProtoAccessContext(
            modules.visibleNature.applyVisibleNatureContext(
              modules.resourceEcology.applyResourceEcologyContext(
                modules.protoCamps.applyProtoCampContext(world),
              ),
            ),
          ),
        ),
      ),
    ),
  );
}

// ---------------------------------------------------------------------------
// DEEP-TIME-HISTORY-TECH-1 targeted audit.
// Verifies the observe-only durable history substrate: founding snapshots,
// bounded era/episode history, daughter inheritance, terminal records, payload
// caps, deterministic ids, and no behavior-path reads.
// ---------------------------------------------------------------------------

function runTargetedDeepTimeHistoryAudit(modules, options) {
  const years = 100;
  const command = "node scripts/simBenchmark.mjs --targeted-deep-time-history-audit --json";
  const runOptions = {
    ...options,
    reportBand: false,
    probeAudit: false,
    returnWorld: true,
    fast: true,
    deterministic: false,
  };
  const baseRun = runBenchmark(
    modules,
    { scenario: "baseline", years, ticks: undefined },
    runOptions,
  );
  const repeatRun = runBenchmark(
    modules,
    { scenario: "baseline", years, ticks: undefined },
    runOptions,
  );
  const world = baseRun.world;
  const repeatWorld = repeatRun.world;
  const constants = modules.bandHistory.DEEP_HISTORY_CONSTANTS;
  const bands = Object.values(world.bands).sort(compareBands);
  const histories = bands
    .map((band) => ({ band, history: band.deepHistory }))
    .filter((entry) => entry.history !== undefined);
  const repeatHistories = Object.values(repeatWorld.bands)
    .sort(compareBands)
    .map((band) => ({ band, history: band.deepHistory }))
    .filter((entry) => entry.history !== undefined);
  const originEntries = histories.filter((entry) => entry.history.founding.kind === "origin_spawn");
  const daughterEntries = histories.filter((entry) => entry.history.founding.kind === "fission_daughter");
  const eraRecords = histories.flatMap((entry) => entry.history.eras.map((era) => ({ band: entry.band, era })));
  const livedEpisodes = histories.flatMap((entry) => entry.history.episodes.map((episode) => ({ band: entry.band, episode })));
  const inheritedEpisodes = histories.flatMap((entry) => entry.history.inheritedEpisodes.map((episode) => ({ band: entry.band, episode })));
  const allEpisodes = [...livedEpisodes, ...inheritedEpisodes];
  const capFixture = runDeepHistoryEraCapFixture(modules, world, histories[0]?.band, constants);
  const terminalFixture = runDeepHistoryTerminalFixture(modules, world, histories, constants);
  const deepHistoryStaticGuards = runDeepHistoryStaticGuards();
  const staticGuards = runStorageSuitabilityStaticGuards();
  const historyFingerprint = makeDeepHistoryFingerprint(histories);
  const repeatHistoryFingerprint = makeDeepHistoryFingerprint(repeatHistories);
  const episodeIds = allEpisodes.map((entry) => entry.episode.id).sort();
  const repeatEpisodeIds = repeatHistories
    .flatMap((entry) => [
      ...entry.history.episodes.map((episode) => episode.id),
      ...entry.history.inheritedEpisodes.map((episode) => episode.id),
    ])
    .sort();
  const evidenceKindCounts = summarizeDeepHistoryEvidenceKinds(histories);
  const maxPayloadEstimate = Math.max(0, ...histories.map((entry) => entry.history.payloadBytesEstimate));
  const maxOpenEraYears = Math.max(0, ...histories.map((entry) => entry.history.openEra?.yearsAccumulated ?? 0));
  const capHeldViolations = histories.filter((entry) => entry.history.caps.capsHeld !== true).map((entry) => String(entry.band.id));
  const behaviorFingerprint = makeDeterminismFingerprint(baseRun.summary);
  const repeatBehaviorFingerprint = makeDeterminismFingerprint(repeatRun.summary);

  const requiredChecks = {
    originBandsReceiveFoundingSnapshots:
      originEntries.length > 0 &&
      originEntries.every((entry) =>
        entry.history.founding.bandId === entry.band.id &&
        entry.history.founding.foundedAt !== undefined &&
        entry.history.founding.startingPopulation > 0 &&
        hasEvidenceKind(entry.history.founding.evidence, "creation_record")),
    daughterFissionBandsReceiveOwnSnapshotsNotCloneCopies:
      daughterEntries.length > 0 &&
      daughterEntries.every((entry) => {
        const parent = world.bands[entry.history.founding.parentBandId];
        return (
          parent?.deepHistory !== undefined &&
          entry.history.bandId === entry.band.id &&
          entry.history.founding.bandId === entry.band.id &&
          entry.history.founding.kind === "fission_daughter" &&
          entry.history.founding.parentBandId === parent.id &&
          entry.history !== parent.deepHistory &&
          entry.history.eras !== parent.deepHistory.eras &&
          entry.history.episodes !== parent.deepHistory.episodes &&
          hasEvidenceKind(entry.history.founding.evidence, "fission_event")
        );
      }) &&
      deepHistoryStaticGuards.cloneGuardHasDeepHistory === true,
    foundingSnapshotsAreHonestAboutUnknowns:
      histories.every((entry) => foundingSnapshotIsHonest(entry.history.founding)),
    eraRecordsCloseOnScheduleOrSignificance:
      eraRecords.length > 0 &&
      eraRecords.every((entry) => eraRecordHasValidClose(entry.era, constants)),
    eraRecordsContainRealDemographicChurnEvidence:
      eraRecords.length > 0 &&
      eraRecords.every((entry) => hasNonEmptyEvidence(entry.era.evidence)) &&
      eraRecords.some((entry) =>
        entry.era.births + entry.era.deaths > 0 &&
        hasEvidenceKind(entry.era.evidence, "demographic_churn") &&
        entry.era.evidence.some((ref) => ref.ids.some((id) => String(id).startsWith(`churn:${String(entry.band.id)}:`)))),
    openEraAccumulatorAdvancesWithoutUnboundedGrowth:
      histories.every((entry) =>
        entry.history.openEra === undefined ||
        (
          entry.history.openEra.yearsAccumulated <= constants.ERA_TARGET_YEARS &&
          entry.history.openEra.daughterBandIds.length <= constants.MAX_DAUGHTER_IDS_PER_ERA &&
          entry.history.lastAdvancedYear >= entry.history.openEra.startYear
        )),
    historicalEpisodesFireOnlyFromGroundedEvidence:
      allEpisodes.length > 0 &&
      allEpisodes.every((entry) =>
        hasNonEmptyEvidence(entry.episode.evidence) &&
        episodeHasGroundedDetail(entry.episode, constants)),
    episodeIdsAreStableAndDeterministic:
      episodeIds.length > 0 &&
      JSON.stringify(episodeIds) === JSON.stringify(repeatEpisodeIds) &&
      historyFingerprint === repeatHistoryFingerprint,
    eraAndEpisodeCapsCompressOldHistory:
      histories.every((entry) =>
        entry.history.eras.length <= entry.history.caps.maxEraRecords &&
        entry.history.episodes.length <= entry.history.caps.maxEpisodes) &&
      capFixture.passed,
    fissionInheritanceIsBounded:
      daughterEntries.length > 0 &&
      daughterEntries.every((entry) => daughterInheritanceIsBounded(world, entry, constants)),
    terminalRecordsExistForDeadBandsOrFixture:
      terminalFixture.passed,
    payloadEstimateAndCapStatusStayBounded:
      maxPayloadEstimate > 0 &&
      maxPayloadEstimate <= constants.PAYLOAD_SOFT_CAP_BYTES &&
      capHeldViolations.length === 0 &&
      histories.every((entry) =>
        entry.history.payloadBytesEstimate > 0 &&
        entry.history.payloadBytesEstimate <= constants.PAYLOAD_SOFT_CAP_BYTES),
    observeOnlyDoesNotAlterBehaviorSummary:
      behaviorFingerprint === repeatBehaviorFingerprint &&
      deepHistoryStaticGuards.deepHistoryRefsOutsideAllowed.length === 0 &&
      deepHistoryStaticGuards.decisionPathDeepHistoryRefs.length === 0 &&
      deepHistoryStaticGuards.advancePhaseWired === true,
  };
  const passedCount = Object.values(requiredChecks).filter(Boolean).length;
  const failedChecks = Object.entries(requiredChecks)
    .filter(([, passed]) => passed !== true)
    .map(([name]) => name);
  const verdict = failedChecks.length === 0 ? "pass" : "review";

  return {
    check: "DEEP-TIME-HISTORY-TECH-1 targeted audit",
    verdict,
    command,
    methodology: {
      scenario: "baseline",
      years,
      liveRun: "100-year baseline run exercises origin bands, era closure, grounded episodes, and fission daughters.",
      capFixture: "Audit-only band clone feeds max-era records plus one public observer advance to prove oldest-pair era merging.",
      terminalFixture: "Audit-only band clone marks one band absorbed and advances through applyBandDeepHistoryContext to prove terminal records.",
      observeOnly: "Behavior summary fingerprint is compared across deterministic repeats; static guard requires deepHistory references only in allowed observer/construction/type files.",
    },
    checkSummary: {
      passed: passedCount,
      failed: failedChecks.length,
      total: Object.keys(requiredChecks).length,
      failedChecks,
    },
    requiredChecks,
    metrics: {
      bandsSampled: bands.length,
      historyBandsSampled: histories.length,
      foundingSnapshotsFound: histories.filter((entry) => entry.history.founding !== undefined).length,
      originSnapshotsFound: originEntries.length,
      daughterRecordsInspected: daughterEntries.length,
      eraRecordsFound: eraRecords.length,
      episodesFound: livedEpisodes.length,
      inheritedEpisodesFound: inheritedEpisodes.length,
      inheritedSummariesInspected: histories.reduce((sum, entry) => sum + entry.history.inheritedEraSummaries.length, 0),
      ancestryEntriesInspected: histories.reduce((sum, entry) => sum + entry.history.ancestryLine.length, 0),
      maxPayloadEstimate,
      maxOpenEraYears,
      capHeldViolations,
      capMergeEvidence: capFixture.evidence,
      deterministicIdsChecked: episodeIds.length,
      behaviorSummaryFingerprint: behaviorFingerprint,
      repeatBehaviorSummaryFingerprint: repeatBehaviorFingerprint,
    },
    evidenceKindCounts,
    capFixture,
    terminalFixture,
    staticGuards: {
      ...staticGuards,
      deepHistoryRefsOutsideAllowed: deepHistoryStaticGuards.deepHistoryRefsOutsideAllowed,
      decisionPathDeepHistoryRefs: deepHistoryStaticGuards.decisionPathDeepHistoryRefs,
      cloneGuardHasDeepHistory: deepHistoryStaticGuards.cloneGuardHasDeepHistory,
      advancePhaseWired: deepHistoryStaticGuards.advancePhaseWired,
    },
    samples: {
      founding: histories.slice(0, 4).map((entry) => ({
        bandId: String(entry.band.id),
        kind: entry.history.founding.kind,
        foundedYear: entry.history.founding.foundedAt.year,
        foundingTileId: String(entry.history.founding.foundingTileId),
        unknownAtFounding: entry.history.founding.unknownAtFounding,
      })),
      eras: eraRecords.slice(0, 5).map((entry) => ({
        bandId: String(entry.band.id),
        id: entry.era.id,
        years: `${entry.era.startYear}-${entry.era.endYear}`,
        closeTrigger: entry.era.closeTrigger,
        headline: entry.era.headline,
        population: `${entry.era.populationStart}->${entry.era.populationEnd}`,
        births: entry.era.births,
        deaths: entry.era.deaths,
        evidence: entry.era.evidence,
        merged: entry.era.merged,
      })),
      episodes: allEpisodes.slice(0, 8).map((entry) => ({
        bandId: String(entry.band.id),
        id: entry.episode.id,
        type: entry.episode.type,
        years: `${entry.episode.startYear}-${entry.episode.endYear ?? "open"}`,
        provenance: entry.episode.provenance,
        evidence: entry.episode.evidence,
        detail: entry.episode.detail,
      })),
      daughters: daughterEntries.slice(0, 6).map((entry) => ({
        bandId: String(entry.band.id),
        parentBandId: String(entry.history.founding.parentBandId),
        inheritedEraSummaries: entry.history.inheritedEraSummaries.length,
        inheritedEpisodes: entry.history.inheritedEpisodes.length,
        ancestryDepth: entry.history.ancestryLine.length,
        ownClosedEras: entry.history.eras.length,
        ownEpisodes: entry.history.episodes.length,
      })),
    },
  };
}

function runDeepHistoryEraCapFixture(modules, world, sourceBand, constants) {
  if (sourceBand?.deepHistory === undefined) {
    return {
      passed: false,
      reason: "no source band with deep history",
      evidence: {},
    };
  }

  const targetYear = 261;
  const targetTick = 1044;
  const eras = Array.from({ length: constants.MAX_ERA_RECORDS }, (_entry, index) =>
    makeDeepHistoryFixtureEra(sourceBand, index));
  const openEra = {
    ...sourceBand.deepHistory.openEra,
    startYear: 240,
    startTileId: sourceBand.position,
    populationStart: sourceBand.demography.population,
    populationMin: sourceBand.demography.population,
    populationMax: sourceBand.demography.population + 3,
    births: 2,
    deaths: 1,
    crisisDeaths: 0,
    hungerYears: 0,
    waterStressYears: 0,
    recoveryYears: 0,
    fissionCount: 0,
    daughterBandIds: [],
    movesCount: 0,
    yearsAccumulated: constants.ERA_TARGET_YEARS,
    awayFromStartYears: 0,
  };
  const capBand = {
    ...sourceBand,
    deepHistory: {
      ...sourceBand.deepHistory,
      eras,
      openEra,
      episodes: [],
      tracking: {
        ...sourceBand.deepHistory.tracking,
        lastObservedTick: targetTick - 1,
        lastObservedYear: targetYear - 1,
      },
      caps: {
        ...sourceBand.deepHistory.caps,
        erasMergedCount: 0,
        episodesDroppedCount: 0,
        capsHeld: true,
      },
      lastAdvancedYear: targetYear - 1,
      payloadBytesEstimate: sourceBand.deepHistory.payloadBytesEstimate,
    },
  };
  const fixtureWorld = {
    ...world,
    time: {
      ...world.time,
      tick: targetTick,
      year: targetYear,
      season: "spring",
    },
    bands: {
      [capBand.id]: capBand,
    },
  };
  const advanced = modules.bandHistory.applyBandDeepHistoryContext(fixtureWorld);
  const advancedBand = advanced.bands[capBand.id];
  const history = advancedBand?.deepHistory;
  const mergedEras = history?.eras.filter((era) => era.merged) ?? [];
  const passed =
    history !== undefined &&
    history.eras.length <= constants.MAX_ERA_RECORDS &&
    history.caps.erasMergedCount >= 1 &&
    mergedEras.length >= 1 &&
    history.payloadBytesEstimate > 0 &&
    history.payloadBytesEstimate <= constants.PAYLOAD_SOFT_CAP_BYTES &&
    history.caps.capsHeld === true;

  return {
    passed,
    evidence: {
      beforeEraCount: eras.length,
      afterEraCount: history?.eras.length ?? 0,
      mergedEraCount: mergedEras.length,
      erasMergedCount: history?.caps.erasMergedCount ?? 0,
      oldestEra: history?.eras[0] === undefined ? undefined : {
        id: history.eras[0].id,
        startYear: history.eras[0].startYear,
        endYear: history.eras[0].endYear,
        merged: history.eras[0].merged,
        mergedSpanCount: history.eras[0].mergedSpanCount,
      },
      payloadBytesEstimate: history?.payloadBytesEstimate ?? 0,
      capsHeld: history?.caps.capsHeld ?? false,
    },
  };
}

function makeDeepHistoryFixtureEra(band, index) {
  const startYear = index * 20;
  const endYear = startYear + 20;
  const populationStart = Math.max(1, band.demography.population + (index % 3) - 1);
  const births = 2 + (index % 4);
  const deaths = 1 + (index % 3);

  return {
    id: `era:${String(band.id)}:${startYear}`,
    startYear,
    endYear,
    closeTrigger: "interval_elapsed",
    headline: births > deaths ? "growth_years" : "steady_years",
    populationStart,
    populationEnd: populationStart + births - deaths,
    populationMin: Math.min(populationStart, populationStart + births - deaths),
    populationMax: Math.max(populationStart, populationStart + births - deaths),
    births,
    deaths,
    crisisDeaths: 0,
    hungerYears: index % 5 === 0 ? 1 : 0,
    waterStressYears: index % 6 === 0 ? 1 : 0,
    recoveryYears: 0,
    fissionCount: 0,
    daughterBandIds: [],
    movesCount: index % 2,
    startTileId: band.position,
    endTileId: band.position,
    evidence: [
      { kind: "demographic_churn", ids: [`churn:${String(band.id)}:${startYear}-${endYear}`] },
    ],
    recordKind: "compressed_pattern",
    confidence: 0.9,
    merged: false,
    mergedSpanCount: 1,
  };
}

function runDeepHistoryTerminalFixture(modules, world, histories, constants) {
  const targetEntry = histories.find((entry) => entry.history.terminalRecord === undefined);
  const absorber = histories.find((entry) => entry.band.id !== targetEntry?.band.id)?.band;

  if (targetEntry === undefined || absorber === undefined) {
    return {
      passed: false,
      reason: "not enough bands for terminal fixture",
      evidence: {},
    };
  }

  const target = targetEntry.band;
  const terminalBand = {
    ...target,
    status: "dispersed",
    viability: {
      ...(target.viability ?? {}),
      status: "absorbed",
      absorbedByBandId: absorber.id,
      populationTransferred: target.demography.population,
      reasonIds: [`reason:deep_history_terminal_fixture:${String(target.id)}`],
    },
    causalTraces: [
      ...target.causalTraces,
      {
        id: `trace:deep-history-terminal-fixture:${String(target.id)}`,
        kind: "band_absorbed",
        time: world.time,
        reasonIds: [`reason:deep_history_terminal_fixture:${String(target.id)}`],
      },
    ].slice(-80),
  };
  const fixtureWorld = {
    ...world,
    time: {
      ...world.time,
      season: "spring",
    },
    bands: {
      [terminalBand.id]: terminalBand,
      [absorber.id]: absorber,
    },
  };
  const advanced = modules.bandHistory.applyBandDeepHistoryContext(fixtureWorld);
  const advancedBand = advanced.bands[terminalBand.id];
  const history = advancedBand?.deepHistory;
  const terminalEpisode = history?.episodes.find((episode) =>
    episode.type === "band_absorbed_end" || episode.type === "band_collapsed_end");
  const passed =
    history?.terminalRecord !== undefined &&
    history.terminalRecord.cause === "absorbed" &&
    history.terminalRecord.absorbedByBandId === absorber.id &&
    hasNonEmptyEvidence(history.terminalRecord.evidence) &&
    terminalEpisode !== undefined &&
    hasNonEmptyEvidence(terminalEpisode.evidence) &&
    history.openEra === undefined &&
    history.payloadBytesEstimate <= constants.PAYLOAD_SOFT_CAP_BYTES;

  return {
    passed,
    evidence: {
      bandId: String(terminalBand.id),
      absorbedByBandId: String(absorber.id),
      terminalRecord: history?.terminalRecord,
      terminalEpisodeId: terminalEpisode?.id,
      closedEraCount: history?.eras.length ?? 0,
      openEraCleared: history?.openEra === undefined,
      payloadBytesEstimate: history?.payloadBytesEstimate ?? 0,
    },
  };
}

function foundingSnapshotIsHonest(founding) {
  if (founding.kind === "origin_spawn") {
    return (
      founding.parentBandId === undefined &&
      founding.parentOriginTileId === undefined &&
      founding.relation === undefined &&
      founding.parentPopulationBefore === undefined &&
      founding.parentFoodStressAtSplit === undefined &&
      founding.parentWaterStressAtSplit === undefined &&
      founding.parentHungerClassificationAtSplit === undefined &&
      founding.parentExtinctionRiskAtSplit === undefined &&
      founding.unknownAtFounding.includes("parentContext_notApplicable_originBand")
    );
  }

  const unknownFieldNames = [
    "parentFoodStressAtSplit",
    "parentWaterStressAtSplit",
    "parentHungerClassificationAtSplit",
    "parentExtinctionRiskAtSplit",
  ];

  return (
    founding.parentBandId !== undefined &&
    founding.parentPopulationBefore !== undefined &&
    unknownFieldNames.every((field) =>
      !founding.unknownAtFounding.includes(field) || founding[field] === undefined)
  );
}

function eraRecordHasValidClose(era, constants) {
  const span = era.endYear - era.startYear;

  if (era.merged) {
    return span >= constants.ERA_TARGET_YEARS && era.mergedSpanCount >= 2 && hasNonEmptyEvidence(era.evidence);
  }

  if (era.closeTrigger === "interval_elapsed") {
    return span >= constants.ERA_TARGET_YEARS && span <= constants.ERA_TARGET_YEARS + 1 && hasNonEmptyEvidence(era.evidence);
  }

  if (era.closeTrigger === "relocation_shift") {
    return span >= constants.RELOCATION_HOLD_YEARS && hasNonEmptyEvidence(era.evidence);
  }

  if (era.closeTrigger === "terminal") {
    return span >= 0 && hasNonEmptyEvidence(era.evidence);
  }

  return span >= constants.ERA_MIN_YEARS_FOR_EVENT_CLOSE && hasNonEmptyEvidence(era.evidence);
}

function episodeHasGroundedDetail(episode, constants) {
  if (!hasNonEmptyEvidence(episode.evidence) || episode.confidence <= 0) {
    return false;
  }

  switch (episode.type) {
    case "daughter_branch_formed":
      return episode.relatedBandId !== undefined && (episode.detail.daughterPopulation ?? 0) > 0;
    case "population_thinned":
      return (episode.detail.netChange ?? 0) < 0 && (episode.detail.basePopulation ?? 0) > 0;
    case "population_recovered":
      return (episode.detail.netChange ?? 0) > 0 && (episode.detail.basePopulation ?? 0) > 0;
    case "long_hunger_period":
      return (episode.detail.streakSeasons ?? 0) >= constants.LONG_HUNGER_MIN_STREAK_SEASONS;
    case "water_caution_period":
      return (episode.detail.waterStressSeasonsLast8 ?? 0) >= constants.WATER_CAUTION_MIN_SEASONS_LAST8;
    case "route_became_memory":
      return episode.relatedRouteId !== undefined && (episode.detail.useCount ?? 0) >= constants.ROUTE_MEMORY_USE_THRESHOLD;
    case "country_expanded":
      return (episode.detail.toBreadth ?? 0) >= (episode.detail.fromBreadth ?? 0) + constants.COUNTRY_EXPANDED_TILE_STEP;
    case "camp_became_home":
      return episode.relatedTileId !== undefined && (episode.detail.repeatedReturnCount ?? 0) >= constants.CAMP_HOME_RETURN_THRESHOLD;
    case "hard_crossing_remembered":
      return (episode.detail.useCount ?? 0) >= constants.HARD_CROSSING_MIN_USES &&
        (episode.detail.riskMemory ?? 0) >= constants.HARD_CROSSING_RISK_THRESHOLD;
    case "fallback_reliance_period":
      return (episode.detail.years ?? 0) >= constants.FALLBACK_RELIANCE_MIN_YEARS;
    case "near_collapse":
      return (episode.detail.extinctionRisk ?? 0) >= constants.NEAR_COLLAPSE_RISK_THRESHOLD;
    case "band_absorbed_end":
    case "band_collapsed_end":
      return episode.detail.populationAtEnd !== undefined;
    default:
      return false;
  }
}

function daughterInheritanceIsBounded(world, entry, constants) {
  const parent = world.bands[entry.history.founding.parentBandId];

  if (parent?.deepHistory === undefined) {
    return false;
  }

  const history = entry.history;

  return (
    history.inheritedEraSummaries.length <= constants.MAX_INHERITED_ERA_SUMMARIES &&
    history.inheritedEpisodes.length <= constants.MAX_INHERITED_EPISODES &&
    history.ancestryLine.length <= constants.MAX_ANCESTRY_ENTRIES &&
    history.inheritedEraSummaries.length <= parent.deepHistory.eras.length &&
    history.inheritedEpisodes.length <= parent.deepHistory.episodes.length &&
    (parent.deepHistory.eras.length <= constants.MAX_INHERITED_ERA_SUMMARIES ||
      history.inheritedEraSummaries.length < parent.deepHistory.eras.length) &&
    (parent.deepHistory.episodes.length <= constants.MAX_INHERITED_EPISODES ||
      history.inheritedEpisodes.length < parent.deepHistory.episodes.length) &&
    history.eras !== parent.deepHistory.eras &&
    history.episodes !== parent.deepHistory.episodes
  );
}

function hasEvidenceKind(evidence, kind) {
  return evidence.some((ref) => ref.kind === kind && ref.ids.length > 0);
}

function hasNonEmptyEvidence(evidence) {
  return (
    Array.isArray(evidence) &&
    evidence.length > 0 &&
    evidence.every((ref) =>
      ref !== undefined &&
      typeof ref.kind === "string" &&
      ref.kind.length > 0 &&
      Array.isArray(ref.ids) &&
      ref.ids.length > 0 &&
      ref.ids.every((id) => String(id).length > 0 && !String(id).includes("undefined")))
  );
}

function makeDeepHistoryFingerprint(entries) {
  return JSON.stringify(entries.map((entry) => ({
    bandId: String(entry.band.id),
    history: entry.history,
  })));
}

function summarizeDeepHistoryEvidenceKinds(entries) {
  const counts = {};
  const add = (ref) => {
    counts[ref.kind] = (counts[ref.kind] ?? 0) + ref.ids.length;
  };

  for (const entry of entries) {
    for (const ref of entry.history.founding.evidence) add(ref);
    for (const era of entry.history.eras) {
      for (const ref of era.evidence) add(ref);
    }
    for (const episode of entry.history.episodes) {
      for (const ref of episode.evidence) add(ref);
    }
    for (const episode of entry.history.inheritedEpisodes) {
      for (const ref of episode.evidence) add(ref);
    }
    if (entry.history.terminalRecord !== undefined) {
      for (const ref of entry.history.terminalRecord.evidence) add(ref);
    }
  }

  return Object.fromEntries(Object.entries(counts).sort(([left], [right]) => left.localeCompare(right)));
}

function runDeepHistoryStaticGuards() {
  const simRoot = join(process.cwd(), "src/sim");
  const simFiles = collectSourceFiles(simRoot);
  const allowedDeepHistoryFiles = new Set([
    join(simRoot, "agents/types.ts"),
    join(simRoot, "agents/bandHistory.ts"),
    join(simRoot, "agents/bandChronicle.ts"),
    join(simRoot, "agents/eventSystem.ts"),
    join(simRoot, "agents/bandIdentity.ts"),
    join(simRoot, "agents/knowledgeEcology.ts"),
    join(simRoot, "agents/socialEcologicalDiffusion.ts"),
    join(simRoot, "agents/spawn.ts"),
    join(simRoot, "agents/demography.ts"),
    join(simRoot, "tick/advance.ts"),
  ]);
  const deepHistoryRefsOutsideAllowed = [];

  for (const file of simFiles) {
    const text = readFileSync(file, "utf8");

    if (text.includes("deepHistory") && !allowedDeepHistoryFiles.has(file)) {
      deepHistoryRefsOutsideAllowed.push(file.replace(`${process.cwd()}/`, ""));
    }
  }

  const decisionPathDeepHistoryRefs = collectSourceFiles(join(simRoot, "rules"))
    .filter((file) => readFileSync(file, "utf8").includes("deepHistory"))
    .map((file) => file.replace(`${process.cwd()}/`, ""));
  const demographyText = readFileSync(join(simRoot, "agents/demography.ts"), "utf8");
  const advanceText = readFileSync(join(simRoot, "tick/advance.ts"), "utf8");
  const benchmarkText = readFileSync(join(process.cwd(), "scripts/simBenchmark.mjs"), "utf8");

  return {
    deepHistoryRefsOutsideAllowed,
    decisionPathDeepHistoryRefs,
    cloneGuardHasDeepHistory: /DAUGHTER_NON_CLONEABLE_FIELDS[\s\S]*"deepHistory"/.test(demographyText),
    advancePhaseWired:
      advanceText.includes("applyBandDeepHistoryContext") &&
      benchmarkText.includes('addPhase(metrics, "deepHistoryAdvance"'),
  };
}

// ---------------------------------------------------------------------------
// DEEP-TIME-CHRONICLE-UI-1 targeted audit.
// Verifies the player-facing Chronicle layer over the accepted deep-history
// substrate: founded/current comparison, compact eras/episodes, inherited vs
// lived memory labels, recent-vs-durable framing, no raw debug dumps, caps,
// deterministic derivation, and 1C readability regression.
// ---------------------------------------------------------------------------

function runTargetedDeepTimeChronicleUiAudit(modules, options) {
  const years = 100;
  const command = "node scripts/simBenchmark.mjs --targeted-deep-time-chronicle-ui-audit --json";
  const runOptions = {
    ...options,
    reportBand: false,
    probeAudit: false,
    returnWorld: true,
    fast: true,
    deterministic: false,
  };
  const baseRun = runBenchmark(
    modules,
    { scenario: "baseline", years, ticks: undefined },
    runOptions,
  );
  const repeatRun = runBenchmark(
    modules,
    { scenario: "baseline", years, ticks: undefined },
    runOptions,
  );
  const projectedWorld = projectPerformancePlayabilityWorld(modules, baseRun.world);
  const repeatProjectedWorld = projectPerformancePlayabilityWorld(modules, repeatRun.world);
  const historyBands = Object.values(projectedWorld.bands)
    .filter((band) => band.deepHistory !== undefined)
    .sort(compareBands);
  const activeHistoryBands = historyBands.filter(isActiveBand);
  const selectedBands = selectDeepTimeChronicleUiBands(activeHistoryBands);
  const chronicleEntries = selectedBands.map((band) => ({
    band,
    chronicle: modules.bandChronicle.deriveBandChronicle(projectedWorld, band),
  }));
  const repeatChronicleEntries = selectedBands
    .map((band) => repeatProjectedWorld.bands[band.id])
    .filter((band) => band !== undefined)
    .map((band) => ({
      band,
      chronicle: modules.bandChronicle.deriveBandChronicle(repeatProjectedWorld, band),
    }));
  const fixture = buildDeepTimeChronicleUiFixtures(modules, projectedWorld, historyBands[0]);
  const fixtureEntries = [fixture.unknownEntry, fixture.daughterEntry].filter((entry) => entry !== undefined);
  const allEntries = [...chronicleEntries, ...fixtureEntries];
  const allChronicles = allEntries.map((entry) => entry.chronicle);
  const deepEntries = allEntries.filter((entry) => entry.chronicle.article.deepHistory !== undefined);
  const oldDeepEntries = deepEntries.filter((entry) =>
    entry.band.deepHistory !== undefined &&
    projectedWorld.time.year - entry.band.deepHistory.founding.foundedAt.year >= 40);
  const daughterDeepEntries = deepEntries.filter((entry) =>
    entry.band.deepHistory?.founding.kind === "fission_daughter");
  const eraRows = deepEntries.flatMap((entry) =>
    entry.chronicle.article.deepHistory.eras.map((era) => ({ band: entry.band, era })));
  const episodeRows = deepEntries.flatMap((entry) =>
    entry.chronicle.article.deepHistory.episodes.map((episode) => ({ band: entry.band, episode })));
  const inheritedRows = deepEntries.flatMap((entry) =>
    entry.chronicle.article.deepHistory.inherited.map((episode) => ({ band: entry.band, episode })));
  const normalTextSamples = allChronicles.flatMap(collectChronicleWikiNormalText);
  const deepTextSamples = allChronicles.flatMap((chronicle) =>
    collectChronicleDeepHistoryNormalText(chronicle.article.deepHistory));
  const codeLikeHits = [];
  scanReadabilityStrings(normalTextSamples, codeLikeHits, "deepTimeChronicle.normal");
  const rawDebugHits = findDeepTimeChronicleRawDebugHits(deepTextSamples);
  const forbiddenHits = normalTextSamples.filter((sample) => WIKI_FORBIDDEN_CONTENT.test(sample)).slice(0, 8);
  const duplicateProse = findDeepTimeChronicleDuplicateProse(deepEntries);
  const artifactHits = scanPolish1cArtifacts(normalTextSamples);
  const unknownFoundingLine = fixture.unknownEntry?.chronicle.article.deepHistory?.comparison.foundedLine ?? "";
  const fakeUnknownFoundingHits = findDeepTimeChronicleFakeUnknownFoundingHits(deepEntries, unknownFoundingLine);
  const evidenceDumpHits = findDeepTimeChronicleEvidenceDumpHits(deepEntries);
  const maxPayloadBytes = Math.max(0, ...allChronicles.map((chronicle) => chronicle.technicalProof.payloadBytesEstimate));
  const maxPayloadKb = round2(maxPayloadBytes / 1024);
  const maxDisplayedRows = Math.max(0, ...deepEntries.map((entry) => {
    const deep = entry.chronicle.article.deepHistory;
    return deep.eras.length + deep.episodes.length + deep.inherited.length;
  }));
  const sourceChecks = deepTimeChronicleUiSourceChecks();
  const staticGuards = runStorageSuitabilityStaticGuards();
  const polishRegression = runTargetedUiReadabilityPolish1cAudit(
    modules,
    { ...options, ecoMigAuditYears: 8, reportBand: false, probeAudit: false },
  );

  const requiredChecks = {
    olderBandsUseDeepHistorySubstrate:
      oldDeepEntries.length > 0 &&
      oldDeepEntries.every((entry) =>
        entry.chronicle.article.deepHistory !== undefined &&
        entry.chronicle.article.longStory.some((paragraph) =>
          collectParagraphText([paragraph]).some((text) =>
            /compressed eras|durable episodes|long record|founding records/i.test(text)))),
    foundingSnapshotAppearsReadableWhenKnown:
      deepEntries.length > 0 &&
      deepEntries.every((entry) =>
        entry.chronicle.article.deepHistory.comparison.foundedLine.includes("Founded in Year") &&
        /with \d+ people/.test(entry.chronicle.article.deepHistory.comparison.foundedLine) &&
        entry.chronicle.article.infobox.some((fact) => fact.label === "Founded")),
    foundingCurrentComparisonAppearsForOldBands:
      oldDeepEntries.length > 0 &&
      oldDeepEntries.every((entry) => {
        const deep = entry.chronicle.article.deepHistory;
        return (
          deep.comparison.foundedLine.length > 0 &&
          deep.comparison.nowLine.includes("Now it has") &&
          deep.comparison.changeLine.length > 0
        );
      }),
    eraRecordsAppearCompactlyWithYearRanges:
      eraRows.length > 0 &&
      eraRows.every(({ era }) =>
        /^Year \d+$|^Years \d+-\d+$/.test(era.yearRange) &&
        era.summary.length > 0 &&
        era.summary.length <= 240 &&
        era.evidenceChips.length > 0 &&
        era.evidenceChips.length <= 3),
    durableEpisodesAppearCompactly:
      episodeRows.length > 0 &&
      episodeRows.every(({ episode }) =>
        /^Year \d+$|^Years \d+-\d+$/.test(episode.yearRange) &&
        episode.title.length > 0 &&
        episode.summary.length > 0 &&
        episode.summary.length <= 220 &&
        episode.evidenceChips.length > 0 &&
        episode.evidenceChips.length <= 3),
    inheritedHistoryLabeledAsInheritedNotPersonallyLived:
      daughterDeepEntries.length > 0 &&
      daughterDeepEntries.every((entry) => {
        const deep = entry.chronicle.article.deepHistory;
        const text = collectChronicleDeepHistoryNormalText(deep).join(" ");
        return /inherited|lineage memory|not personally lived|own lived story begins/i.test(text);
      }),
    recentMemoryAndDurableHistoryAreDistinguished:
      deepEntries.length > 0 &&
      deepEntries.every((entry) => /Durable history covers/i.test(entry.chronicle.article.deepHistory.memoryBoundaryLine)) &&
      deepEntries.some((entry) => /recent record|closer detail|no detailed recent event window/i.test(entry.chronicle.article.deepHistory.memoryBoundaryLine)),
    normalUiDoesNotExposeRawDebug:
      rawDebugHits.length === 0 &&
      codeLikeHits.length === 0 &&
      forbiddenHits.length === 0 &&
      sourceChecks.noRawDeepHistoryDump,
    noRepeatedDuplicateEraEpisodeProse:
      duplicateProse.duplicateCount === 0,
    noSameYearRangeWordingRegression:
      artifactHits.every((hit) => hit.id !== "same-year-range" && hit.id !== "same-year-dash"),
    noFakeFoundingClaimsWhenFieldsUnknown:
      unknownFoundingLine.length > 0 &&
      fakeUnknownFoundingHits.length === 0,
    evidenceAvailableAsChipsOrTechnicalNotDumped:
      evidenceDumpHits.length === 0 &&
      deepEntries.every((entry) =>
        entry.chronicle.article.deepHistory.countsLine.includes("Technical")) &&
      sourceChecks.technicalProofStillAvailable,
    payloadAndEntryCountsRemainBounded:
      maxPayloadBytes > 0 &&
      maxPayloadBytes < 90_000 &&
      maxDisplayedRows <= 15 &&
      allChronicles.every(wikiCapsHeld),
    existing1CReadabilityAuditStillPasses:
      polishRegression.verdict === "pass",
    deterministicChronicleDerivation:
      makeDeepTimeChronicleUiFingerprint(chronicleEntries) === makeDeepTimeChronicleUiFingerprint(repeatChronicleEntries),
  };
  const passedCount = Object.values(requiredChecks).filter(Boolean).length;
  const failedChecks = Object.entries(requiredChecks)
    .filter(([, passed]) => passed !== true)
    .map(([name]) => name);
  const verdict = failedChecks.length === 0 ? "pass" : "review";

  return {
    check: "DEEP-TIME-CHRONICLE-UI-1 targeted audit",
    verdict,
    command,
    methodology: {
      scenario: "baseline",
      years,
      selectedBandRule: "active bands with deepHistory, scored for age, era records, episodes, and daughter inheritance",
      fixtureNote: "Projection-only fixtures exercise unknown founding context and inherited daughter wording when live samples do not cover them; no sim state or decisions are changed.",
      uiLayer: "Chronicle article projection and History.tsx source structure; raw proof remains in Technical.",
    },
    checkSummary: {
      passed: passedCount,
      failed: failedChecks.length,
      total: Object.keys(requiredChecks).length,
      failedChecks,
    },
    metrics: {
      bandsSampled: selectedBands.length,
      historyBandsFound: historyBands.length,
      activeHistoryBandsFound: activeHistoryBands.length,
      oldBandsSampled: oldDeepEntries.length,
      deepHistoryPanelsFound: deepEntries.length,
      foundingComparisonsFound: deepEntries.filter((entry) =>
        entry.chronicle.article.deepHistory?.comparison.foundedLine.length > 0).length,
      eraRowsFound: eraRows.length,
      episodeRowsFound: episodeRows.length,
      daughterRecordsInspected: daughterDeepEntries.length,
      inheritedRowsFound: inheritedRows.length,
      unknownFoundingFixtureUsed: fixture.unknownEntry !== undefined,
      daughterFixtureUsed: fixture.daughterEntry !== undefined,
      normalTextSamples: normalTextSamples.length,
      rawDebugHits: rawDebugHits.length,
      codeTokenHits: codeLikeHits.length,
      duplicateEraEpisodeProseCount: duplicateProse.duplicateCount,
      maxDisplayedDeepHistoryRows: maxDisplayedRows,
      maxPayloadBytes,
      maxPayloadKb,
      deterministicChroniclesChecked: Math.min(chronicleEntries.length, repeatChronicleEntries.length),
      oneCRegressionVerdict: polishRegression.verdict,
    },
    samples: {
      longMemory: deepEntries.slice(0, 3).map((entry) => ({
        bandId: String(entry.band.id),
        founding: entry.chronicle.article.deepHistory.comparison.foundedLine,
        now: entry.chronicle.article.deepHistory.comparison.nowLine,
        memoryBoundary: entry.chronicle.article.deepHistory.memoryBoundaryLine,
        eras: entry.chronicle.article.deepHistory.eras.map((era) => `${era.yearRange}: ${era.title}`),
        episodes: entry.chronicle.article.deepHistory.episodes.map((episode) => `${episode.yearRange}: ${episode.title}`),
        inherited: entry.chronicle.article.deepHistory.inherited.map((episode) => `${episode.yearRange}: ${episode.title}`),
      })),
      unknownFoundingLine,
      rawDebugHits,
      codeLikeHits: codeLikeHits.slice(0, 8),
      forbiddenHits,
      duplicateProseSamples: duplicateProse.samples,
      evidenceDumpHits,
      sameYearArtifactHits: artifactHits.filter((hit) => hit.id === "same-year-range" || hit.id === "same-year-dash").slice(0, 6),
    },
    sourceChecks,
    regressions: {
      uiReadabilityPolish1c: {
        verdict: polishRegression.verdict,
        checkSummary: polishRegression.checkSummary,
      },
      wholeUi: polishRegression.regressions?.wholeUi,
      chronicleWiki: polishRegression.regressions?.chronicleWiki,
      foundation: polishRegression.regressions?.foundation,
      specificMemoryReferents: polishRegression.regressions?.specificMemoryReferents,
    },
    staticGuards,
    requiredChecks,
  };
}

function selectDeepTimeChronicleUiBands(bands) {
  const selected = [];
  const add = (band) => {
    if (band !== undefined && !selected.some((entry) => entry.id === band.id)) {
      selected.push(band);
    }
  };
  const scored = [...bands].sort((left, right) =>
    scoreDeepTimeChronicleUiBand(right) - scoreDeepTimeChronicleUiBand(left) ||
    compareBands(left, right));

  for (const band of scored.filter((entry) => entry.deepHistory?.founding.kind === "origin_spawn").slice(0, 4)) {
    add(band);
  }
  for (const band of scored.filter((entry) => entry.deepHistory?.founding.kind === "fission_daughter").slice(0, 4)) {
    add(band);
  }
  for (const band of scored) {
    add(band);
    if (selected.length >= 12) {
      break;
    }
  }

  return selected;
}

function scoreDeepTimeChronicleUiBand(band) {
  const history = band.deepHistory;
  if (history === undefined) {
    return 0;
  }

  return (
    Math.max(0, history.lastAdvancedYear - history.founding.foundedAt.year) * 0.25 +
    history.eras.length * 5 +
    history.episodes.length * 4 +
    history.inheritedEraSummaries.length * 3 +
    history.inheritedEpisodes.length * 3 +
    (history.founding.kind === "fission_daughter" ? 12 : 0)
  );
}

function buildDeepTimeChronicleUiFixtures(modules, world, sourceBand) {
  if (sourceBand?.deepHistory === undefined) {
    return { unknownEntry: undefined, daughterEntry: undefined };
  }

  const unknownBandId = `${String(sourceBand.id)}:deep-time-chronicle-ui-unknown`;
  const unknownBand = {
    ...sourceBand,
    id: unknownBandId,
    lineage: undefined,
    lineageReadability: undefined,
    deepHistory: {
      ...sourceBand.deepHistory,
      bandId: unknownBandId,
      founding: {
        ...sourceBand.deepHistory.founding,
        bandId: unknownBandId,
        kind: "origin_spawn",
        parentBandId: undefined,
        parentOriginTileId: undefined,
        relation: undefined,
        parentPopulationBefore: undefined,
        parentFoodStressAtSplit: undefined,
        parentWaterStressAtSplit: undefined,
        parentHungerClassificationAtSplit: undefined,
        parentExtinctionRiskAtSplit: undefined,
        foundingTileIsRiverbank: undefined,
        foundingTileIsCoastal: undefined,
        foundingTileIsFloodplain: undefined,
        unknownAtFounding: [
          ...new Set([
            ...sourceBand.deepHistory.founding.unknownAtFounding,
            "parentContext_notApplicable_originBand",
            "foundingTileContext_unknown",
          ]),
        ],
      },
    },
  };
  const unknownWorld = {
    ...world,
    bands: {
      ...world.bands,
      [unknownBandId]: unknownBand,
    },
  };
  const unknownEntry = {
    band: unknownBand,
    chronicle: modules.bandChronicle.deriveBandChronicle(unknownWorld, unknownBand),
  };

  const parentEras = sourceBand.deepHistory.eras.slice(-2);
  const daughterBandId = `${String(sourceBand.id)}:deep-time-chronicle-ui-daughter`;
  const inheritedEraSummaries = parentEras.map((era) => ({
    sourceBandId: sourceBand.id,
    startYear: era.startYear,
    endYear: era.endYear,
    headline: era.headline,
    populationEnd: era.populationEnd,
  }));
  const inheritedEpisodes = sourceBand.deepHistory.episodes.slice(0, 2).map((episode) => ({
    ...episode,
    id: `inherited:${episode.id}`,
    provenance: "inherited",
    inheritedFromBandId: sourceBand.id,
  }));
  const daughterEntry = inheritedEraSummaries.length + inheritedEpisodes.length === 0
    ? undefined
    : (() => {
      const daughterBand = {
        ...sourceBand,
        id: daughterBandId,
        lineageReadability: {
          ...(sourceBand.lineageReadability ?? {}),
          parentBandId: sourceBand.id,
          generationLabel: "daughter",
          daughterBandIds: [],
        },
        deepHistory: {
          ...sourceBand.deepHistory,
          bandId: daughterBandId,
          founding: {
            ...sourceBand.deepHistory.founding,
            bandId: daughterBandId,
            kind: "fission_daughter",
            parentBandId: sourceBand.id,
            parentPopulationBefore: sourceBand.demography.population,
            unknownAtFounding: [
              ...new Set([
                ...sourceBand.deepHistory.founding.unknownAtFounding,
                "parentFoodStressAtSplit",
                "parentWaterStressAtSplit",
              ]),
            ],
          },
          eras: [],
          episodes: [],
          inheritedEraSummaries,
          inheritedEpisodes,
          ancestryLine: [{
            bandId: sourceBand.id,
            foundedYear: sourceBand.deepHistory.founding.foundedAt.year,
            kind: sourceBand.deepHistory.founding.kind,
          }],
        },
      };
      const daughterWorld = {
        ...world,
        bands: {
          ...world.bands,
          [daughterBandId]: daughterBand,
        },
      };

      return {
        band: daughterBand,
        chronicle: modules.bandChronicle.deriveBandChronicle(daughterWorld, daughterBand),
      };
    })();

  return { unknownEntry, daughterEntry };
}

function findDeepTimeChronicleRawDebugHits(samples) {
  const rawPattern = /\b(?:band|tile|reason|decision|stock|patch|event|route|churn|era):[a-z0-9]/i;
  const jsonPattern = /(?:^\s*[\[{]|["'][a-zA-Z0-9_]+["']\s*:)/;

  return samples
    .filter((sample) => rawPattern.test(sample) || jsonPattern.test(sample))
    .slice(0, 8);
}

function findDeepTimeChronicleDuplicateProse(entries) {
  let duplicateCount = 0;
  const samples = [];

  for (const entry of entries) {
    const deep = entry.chronicle.article.deepHistory;
    const lines = [
      ...deep.eras.map((era) => era.summary),
      ...deep.episodes.map((episode) => episode.summary),
      ...deep.inherited.map((episode) => episode.summary),
    ].map((line) => line.trim()).filter((line) => line.length > 0);
    const seen = new Set();

    for (const line of lines) {
      if (seen.has(line)) {
        duplicateCount += 1;
        if (samples.length < 6) {
          samples.push({ bandId: String(entry.band.id), sample: line.slice(0, 160) });
        }
      }
      seen.add(line);
    }
  }

  return { duplicateCount, samples };
}

function findDeepTimeChronicleFakeUnknownFoundingHits(entries, unknownFoundingLine) {
  const hits = [];
  const sourceClaimPattern = /\b(riverbank|coastal|floodplain|parent|food-stressed|water-stressed|hunger|sacred|culture|myth|territory)\b/i;

  if (sourceClaimPattern.test(unknownFoundingLine)) {
    hits.push({ kind: "unknown-fixture", sample: unknownFoundingLine });
  }

  for (const entry of entries) {
    const founding = entry.band.deepHistory?.founding;
    const line = entry.chronicle.article.deepHistory?.comparison.foundedLine;
    if (founding === undefined || line === undefined) {
      continue;
    }
    if (founding.foundingTileIsRiverbank !== true && /\briverbank\b/i.test(line)) {
      hits.push({ kind: "riverbank-overclaim", bandId: String(entry.band.id), sample: line });
    }
    if (founding.foundingTileIsCoastal !== true && /\bcoastal\b/i.test(line)) {
      hits.push({ kind: "coastal-overclaim", bandId: String(entry.band.id), sample: line });
    }
    if (founding.foundingTileIsFloodplain !== true && /\bfloodplain\b/i.test(line)) {
      hits.push({ kind: "floodplain-overclaim", bandId: String(entry.band.id), sample: line });
    }
    if (/food-stressed|water-stressed|hunger|sacred|culture|myth|territory/i.test(line)) {
      hits.push({ kind: "unsupported-founding-claim", bandId: String(entry.band.id), sample: line });
    }
  }

  return hits.slice(0, 8);
}

function findDeepTimeChronicleEvidenceDumpHits(entries) {
  const hits = [];
  for (const entry of entries) {
    const deep = entry.chronicle.article.deepHistory;
    const rows = [...deep.eras, ...deep.episodes, ...deep.inherited];
    for (const row of rows) {
      for (const chip of row.evidenceChips) {
        if (chip.label.length > 34 || /[:{}[\]_]/.test(chip.label)) {
          hits.push({ bandId: String(entry.band.id), label: chip.label });
        }
      }
    }
  }
  return hits.slice(0, 8);
}

function makeDeepTimeChronicleUiFingerprint(entries) {
  return JSON.stringify(
    entries
      .slice()
      .sort((left, right) => String(left.band.id).localeCompare(String(right.band.id)))
      .map((entry) => ({
        bandId: String(entry.band.id),
        deepHistory: entry.chronicle.article.deepHistory,
        longStory: collectParagraphText(entry.chronicle.article.longStory),
        infobox: entry.chronicle.article.infobox,
      })),
  );
}

function deepTimeChronicleUiSourceChecks() {
  const chronicle = readFileSync(join(process.cwd(), "src/sim/agents/bandChronicle.ts"), "utf8");
  const history = readFileSync(join(process.cwd(), "src/ui/band/History.tsx"), "utf8");
  const technical = readFileSync(join(process.cwd(), "src/ui/band/Technical.tsx"), "utf8");
  const css = readFileSync(join(process.cwd(), "src/index.css"), "utf8");

  return {
    projectionExists:
      chronicle.includes("BandChronicleDeepHistorySummary") &&
      chronicle.includes("buildDeepHistorySummary") &&
      chronicle.includes("buildDeepHistoryComparison"),
    longMemoryPanelExists:
      history.includes("ChronicleDeepHistoryPanel") &&
      history.includes("Long memory") &&
      history.includes("Founded") &&
      history.includes("Durable eras") &&
      history.includes("Durable episodes"),
    inheritedLabelExists:
      history.includes("Inherited, not personally lived") &&
      chronicle.includes("not personally lived years"),
    evidenceChipsBounded:
      chronicle.includes("DEEP_HISTORY_EVIDENCE_CHIP_CAP") &&
      history.includes("ChronicleEvidenceChips") &&
      css.includes("chronicle-evidence-chip"),
    noRawDeepHistoryDump:
      !history.includes("JSON.stringify(deepHistory") &&
      !history.includes("JSON.stringify(article.deepHistory") &&
      !history.includes("Object.entries(deepHistory"),
    technicalProofStillAvailable:
      technical.includes("Deep history substrate") &&
      technical.includes("payload / caps") &&
      technical.includes("evidence kinds"),
    responsiveLongMemoryLayout:
      css.includes("chronicle-deep-history") &&
      css.includes("repeat(auto-fit, minmax(180px, 1fr))"),
  };
}

// ---------------------------------------------------------------------------
// EVENT-SYSTEM-TECH+UI-1 targeted audit.
// Verifies the canonical selected-band event projection and Events UI surface:
// grounded provenance/evidence, stable ids, grouping/caps, recent/durable/
// inherited distinction, Chronicle/talk/referent hooks, no fake lore/debug
// dumps, deterministic derivation, and observe-only guard.
// ---------------------------------------------------------------------------

function runTargetedEventSystemUiAudit(modules, options) {
  const years = 100;
  const command = "node scripts/simBenchmark.mjs --targeted-event-system-ui-audit --json";
  const runOptions = {
    ...options,
    reportBand: false,
    probeAudit: false,
    returnWorld: true,
    fast: true,
    deterministic: false,
  };
  const baseRun = runBenchmark(
    modules,
    { scenario: "baseline", years, ticks: undefined },
    runOptions,
  );
  const repeatRun = runBenchmark(
    modules,
    { scenario: "baseline", years, ticks: undefined },
    runOptions,
  );
  const projectedWorld = projectPerformancePlayabilityWorld(modules, baseRun.world);
  const repeatProjectedWorld = projectPerformancePlayabilityWorld(modules, repeatRun.world);
  const activeBands = Object.values(projectedWorld.bands).filter(isActiveBand).sort(compareBands);
  const selectedBands = selectEventSystemUiBands(activeBands);
  const preDerivationSnapshot = JSON.stringify(selectedBands);
  const liveEntries = selectedBands.map((band) => ({
    kind: "live",
    band,
    state: modules.eventSystem.deriveCanonicalEvents(projectedWorld, band),
    chronicle: modules.bandChronicle.deriveBandChronicle(projectedWorld, band),
  }));
  const projectionMutatedBands = preDerivationSnapshot !== JSON.stringify(selectedBands);
  const repeatEntries = selectedBands
    .map((band) => repeatProjectedWorld.bands[band.id])
    .filter((band) => band !== undefined)
    .map((band) => ({
      kind: "repeat",
      band,
      state: modules.eventSystem.deriveCanonicalEvents(repeatProjectedWorld, band),
      chronicle: modules.bandChronicle.deriveBandChronicle(repeatProjectedWorld, band),
    }));
  const fixtures = buildEventSystemUiFixtures(modules, projectedWorld, selectedBands[0]);
  const allEntries = [...liveEntries, ...fixtures];
  const eventRows = allEntries.flatMap((entry) => entry.state.events.map((event) => ({ entry, event })));
  const liveEventRows = liveEntries.flatMap((entry) => entry.state.events.map((event) => ({ entry, event })));
  const normalTextSamples = allEntries.flatMap((entry) => collectEventSystemNormalText(entry.state));
  const codeLikeHits = [];
  scanReadabilityStrings(normalTextSamples, codeLikeHits, "eventSystem.normal");
  const rawDebugHits = findEventSystemRawDebugHits(normalTextSamples);
  const fakeLanguageHits = normalTextSamples.filter((sample) => WIKI_FORBIDDEN_CONTENT.test(sample)).slice(0, 8);
  const duplicateProse = findEventSystemDuplicateProse(allEntries);
  const sameYearArtifacts = scanPolish1cArtifacts(normalTextSamples)
    .filter((hit) => hit.id === "same-year-range" || hit.id === "same-year-dash")
    .slice(0, 8);
  const linkAudit = auditEventChronicleLinks(allEntries);
  const sourceChecks = eventSystemUiSourceChecks();
  const staticGuards = runEventSystemStaticGuards();
  const deepTimeChronicleRegression = runTargetedDeepTimeChronicleUiAudit(
    modules,
    { ...options, reportBand: false, probeAudit: false },
  );
  const maxPayloadBytes = Math.max(0, ...allEntries.map((entry) => entry.state.technicalProof.payloadBytesEstimate));
  const maxListSize = Math.max(0, ...allEntries.map((entry) => entry.state.events.length));
  const maxEventPayloadBytes = Math.max(0, ...allEntries.map((entry) => entry.state.technicalProof.maxEventPayloadBytes));
  const families = [...new Set(eventRows.map(({ event }) => event.family))].sort();
  const inheritedEvents = eventRows.filter(({ event }) => event.memoryScope === "inherited");
  const durableEvents = eventRows.filter(({ event }) => event.memoryScope === "durable");
  const recentEvents = eventRows.filter(({ event }) => event.memoryScope === "recent");
  const groupedEvents = eventRows.filter(({ event }) => event.grouped);
  const referentHookEvents = eventRows.filter(({ event }) => event.relatedReferentIds.length > 0);
  const talkHookEvents = eventRows.filter(({ event }) => event.relatedTalkIds.length > 0);
  const eventLinks = eventRows.filter(({ event }) =>
    event.involvedBandIds.length > 0 ||
    event.involvedTileIds.length > 0 ||
    event.involvedRouteIds.length > 0);
  const eventIdSetSizes = allEntries.map((entry) => new Set(entry.state.events.map((event) => event.id)).size);

  const requiredChecks = {
    canonicalEventObjectsExist:
      liveEntries.length > 0 &&
      liveEntries.every((entry) => entry.state.events.length > 0) &&
      eventRows.every(({ event }) => event.id.startsWith("canonical-event:") && event.title.length > 0 && event.summary.length > 0),
    eventsHaveStableDeterministicIds:
      makeEventSystemFingerprint(liveEntries) === makeEventSystemFingerprint(repeatEntries) &&
      allEntries.every((entry, index) => eventIdSetSizes[index] === entry.state.events.length),
    eventsHaveGroundedProvenanceEvidence:
      eventRows.length > 0 &&
      eventRows.every(({ event }) =>
        event.sourceSystem.length > 0 &&
        event.provenance.length > 0 &&
        event.evidenceChips.length > 0 &&
        (event.sourceEventIds.length + event.sourceReasonIds.length + event.sourceHistoryIds.length > 0)),
    eventFamiliesCategoriesValid:
      eventRows.length > 0 &&
      eventRows.every(({ event }) => EVENT_SYSTEM_VALID_FAMILIES.has(event.family) && EVENT_SYSTEM_VALID_TYPES.has(event.type)) &&
      families.length >= 4,
    eventsIncludeYearOrRange:
      eventRows.every(({ event }) =>
        Number.isFinite(event.startYear) &&
        Number.isFinite(event.endYear) &&
        event.startYear <= event.endYear &&
        /^Year \d+$|^Years \d+-\d+$/.test(formatEventAuditYearRange(event.startYear, event.endYear))),
    eventGroupingPreventsSpam:
      groupedEvents.length > 0 &&
      allEntries.every((entry) =>
        entry.state.events.length <= entry.state.caps.totalEventCap &&
        entry.state.caps.capsHeld === true &&
        entry.state.events.every((event) => event.evidenceChips.length <= entry.state.caps.evidenceChipCap)),
    recentDurableEventsDistinguished:
      recentEvents.length > 0 &&
      durableEvents.length > 0 &&
      allEntries.some((entry) => entry.state.recentEventCount > 0 && entry.state.durableEventCount > 0),
    inheritedEventsLabeledNotPersonallyLived:
      inheritedEvents.length > 0 &&
      inheritedEvents.every(({ event }) =>
        event.livedStatus === "inherited_not_personally_lived" &&
        /inherited|not personally lived/i.test(`${event.summary} ${event.consequence}`)),
    involvedEntityLinksPresentWhereAvailable:
      eventLinks.length > 0 &&
      eventLinks.every(({ event }) =>
        event.involvedBandIds.length > 0 ||
        event.involvedTileIds.length > 0 ||
        event.involvedRouteIds.length > 0),
    chronicleLinksSupportedAndNotBroken:
      linkAudit.renderedLinksChecked > 0 &&
      linkAudit.brokenRenderedLinks.length === 0 &&
      allEntries.some((entry) => entry.state.events.some((event) => event.chronicleSectionIds.includes("article-long-memory"))),
    talkReferentHooksExistWithoutFakeTalk:
      referentHookEvents.length > 0 &&
      talkHookEvents.length > 0 &&
      eventRows.every(({ event }) => event.sourceSystem !== "readable_event_history" || event.provenance !== "inherited_history") &&
      eventRows.every(({ event }) => event.sourceSystem !== "deep_history_inheritance" || event.livedStatus === "inherited_not_personally_lived"),
    eventDetailNoRawJsonDebugArrays:
      rawDebugHits.length === 0 &&
      codeLikeHits.length === 0 &&
      sourceChecks.eventsUiNoRawDump,
    noRepeatedDuplicateEventProse:
      duplicateProse.duplicateCount === 0,
    noSameYearRangeWordingRegression:
      sameYearArtifacts.length === 0,
    noFakeCultureReligionMythCivilizationLanguage:
      fakeLanguageHits.length === 0 &&
      sourceChecks.noFakeLoreInEventsUi,
    eventPayloadAndListLengthsBounded:
      maxPayloadBytes > 0 &&
      maxPayloadBytes < 70_000 &&
      maxListSize <= 48 &&
      maxEventPayloadBytes < 5_000 &&
      allEntries.every((entry) => entry.state.caps.capsHeld === true),
    deterministicEventOutput:
      makeEventSystemFingerprint(liveEntries) === makeEventSystemFingerprint(repeatEntries),
    existingChronicleDeepHistoryReadabilityAuditsPass:
      deepTimeChronicleRegression.verdict === "pass",
    observeOnlyNoBehaviorOrEconomyChange:
      makeDeterminismFingerprint(baseRun.summary) === makeDeterminismFingerprint(repeatRun.summary) &&
      projectionMutatedBands === false &&
      staticGuards.eventSystemRefsInDecisionPaths === 0 &&
      sourceChecks.eventSystemPureProjection,
  };
  const passedCount = Object.values(requiredChecks).filter(Boolean).length;
  const failedChecks = Object.entries(requiredChecks)
    .filter(([, passed]) => passed !== true)
    .map(([name]) => name);
  const verdict = failedChecks.length === 0 ? "pass" : "review";

  return {
    check: "EVENT-SYSTEM-TECH+UI-1 targeted audit",
    verdict,
    command,
    methodology: {
      scenario: "baseline",
      years,
      selectedBandRule: "active bands scored for deep history, recent events, fission, movement records, talk, and memory referents",
      fixtureNote: "Projection-only fixtures exercise grouped recent events, inherited-not-personally-lived records, and talk/referent hooks. They do not mutate live sim state or affect decisions.",
      uiLayer: "src/ui/band/Events.tsx selected-band tab plus Technical compact substrate group.",
    },
    checkSummary: {
      passed: passedCount,
      failed: failedChecks.length,
      total: Object.keys(requiredChecks).length,
      failedChecks,
    },
    metrics: {
      bandsSampled: selectedBands.length,
      fixtureStates: fixtures.length,
      eventsGenerated: eventRows.length,
      liveEventsGenerated: liveEventRows.length,
      groupedEvents: groupedEvents.length,
      eventFamilies: families,
      inheritedEvents: inheritedEvents.length,
      durableEvents: durableEvents.length,
      recentEvents: recentEvents.length,
      eventLinksChecked: eventLinks.length,
      chronicleRenderedLinksChecked: linkAudit.renderedLinksChecked,
      chroniclePotentialUnresolvedTargets: linkAudit.potentialUnresolvedTargets,
      brokenLinks: linkAudit.brokenRenderedLinks.length,
      referentHookEvents: referentHookEvents.length,
      talkHookEvents: talkHookEvents.length,
      rawDebugHits: rawDebugHits.length,
      fakeLanguageHits: fakeLanguageHits.length,
      duplicateProseCount: duplicateProse.duplicateCount,
      sameYearArtifactHits: sameYearArtifacts.length,
      maxEventPayloadBytes,
      maxEventPayloadKb: round2(maxEventPayloadBytes / 1024),
      maxEventStatePayloadBytes: maxPayloadBytes,
      maxEventStatePayloadKb: round2(maxPayloadBytes / 1024),
      maxEventListSize: maxListSize,
      deterministicStatesChecked: Math.min(liveEntries.length, repeatEntries.length),
      projectionMutatedBands,
      deepTimeChronicleRegressionVerdict: deepTimeChronicleRegression.verdict,
    },
    samples: {
      events: allEntries.slice(0, 4).map((entry) => ({
        kind: entry.kind,
        bandId: String(entry.band.id),
        eventCount: entry.state.events.length,
        firstEvents: entry.state.events.slice(0, 4).map((event) => ({
          title: event.title,
          family: event.family,
          scope: event.memoryScope,
          livedStatus: event.livedStatus,
          yearRange: formatEventAuditYearRange(event.startYear, event.endYear),
          evidence: event.evidenceChips.map((chip) => chip.label),
          hooks: {
            chronicle: event.chronicleLinkIds.length,
            referents: event.relatedReferentIds.length,
            talk: event.relatedTalkIds.length,
          },
        })),
      })),
      rawDebugHits,
      codeLikeHits: codeLikeHits.slice(0, 8),
      fakeLanguageHits,
      duplicateProseSamples: duplicateProse.samples,
      sameYearArtifacts,
      brokenRenderedLinks: linkAudit.brokenRenderedLinks,
    },
    sourceChecks,
    staticGuards,
    regressions: {
      deepTimeChronicleUi: {
        verdict: deepTimeChronicleRegression.verdict,
        checkSummary: deepTimeChronicleRegression.checkSummary,
      },
      uiReadabilityPolish1c: deepTimeChronicleRegression.regressions?.uiReadabilityPolish1c,
      wholeUi: deepTimeChronicleRegression.regressions?.wholeUi,
      chronicleWiki: deepTimeChronicleRegression.regressions?.chronicleWiki,
      foundation: deepTimeChronicleRegression.regressions?.foundation,
      specificMemoryReferents: deepTimeChronicleRegression.regressions?.specificMemoryReferents,
    },
    requiredChecks,
  };
}

const EVENT_SYSTEM_VALID_FAMILIES = new Set([
  "origin_lineage",
  "demography",
  "movement_place",
  "route_crossing",
  "knowledge_memory",
  "food_water_pressure",
  "contact_social",
  "historical_compression",
]);

const EVENT_SYSTEM_VALID_TYPES = new Set([
  "founding",
  "daughter_fission",
  "terminal_absorbed",
  "terminal_collapsed",
  "durable_era_closed",
  "durable_episode",
  "inherited_episode",
  "inherited_era_summary",
  "recent_event",
  "recent_pattern",
  "residential_move",
  "fission_split",
]);

function selectEventSystemUiBands(bands) {
  const selected = [];
  const add = (band) => {
    if (band !== undefined && !selected.some((entry) => entry.id === band.id)) {
      selected.push(band);
    }
  };
  const scored = [...bands].sort((left, right) =>
    scoreEventSystemBand(right) - scoreEventSystemBand(left) || compareBands(left, right));

  for (const band of scored.filter((entry) => (entry.deepHistory?.episodes.length ?? 0) > 0).slice(0, 4)) add(band);
  for (const band of scored.filter((entry) => entry.deepHistory?.founding.kind === "fission_daughter").slice(0, 3)) add(band);
  for (const band of scored.filter((entry) => (entry.eventHistory?.recentEvents.length ?? 0) > 0).slice(0, 4)) add(band);
  for (const band of scored.filter((entry) => (entry.campRumors?.items.length ?? 0) > 0).slice(0, 2)) add(band);
  for (const band of scored) {
    add(band);
    if (selected.length >= 10) {
      break;
    }
  }

  return selected;
}

function scoreEventSystemBand(band) {
  return (
    (band.deepHistory === undefined ? 0 : 20) +
    (band.deepHistory?.eras.length ?? 0) * 5 +
    (band.deepHistory?.episodes.length ?? 0) * 6 +
    (band.deepHistory?.inheritedEraSummaries.length ?? 0) * 7 +
    (band.deepHistory?.inheritedEpisodes.length ?? 0) * 7 +
    (band.eventHistory?.recentEvents.length ?? 0) * 4 +
    (band.campRumors?.items.length ?? 0) * 3 +
    (band.recentResidentialMoveEvents?.length ?? 0) * 3 +
    band.fissionEvents.length * 5 +
    (band.deepHistory?.founding.kind === "fission_daughter" ? 15 : 0)
  );
}

function buildEventSystemUiFixtures(modules, world, sourceBand) {
  if (sourceBand === undefined) {
    return [];
  }

  const fixtures = [];
  const groupedFixture = buildEventSystemGroupedTalkFixture(modules, world, sourceBand);
  if (groupedFixture !== undefined) {
    fixtures.push(groupedFixture);
  }
  const inheritedFixture = buildEventSystemInheritedFixture(modules, world, sourceBand);
  if (inheritedFixture !== undefined) {
    fixtures.push(inheritedFixture);
  }
  return fixtures;
}

function buildEventSystemGroupedTalkFixture(modules, world, sourceBand) {
  const fixtureBandId = `${String(sourceBand.id)}:event-system-ui-grouped`;
  const baseEvent = sourceBand.eventHistory?.recentEvents[0] ?? {
    eventId: `event-system-ui-fixture:${String(sourceBand.id)}:0`,
    bandId: sourceBand.id,
    tick: world.time.tick,
    year: world.time.year,
    season: world.time.season,
    category: "movement",
    salience: "medium",
    title: "Repeated camp record",
    description: "A grounded camp-place record repeated closely enough to group.",
    detail: "Audit fixture proves grouped events without changing the sim.",
    stateKey: "event-system-ui-grouped-state",
    rawSource: "audit_projection_fixture",
    rawReason: "grouped event fixture",
    sourceReasonIds: [],
    relatedTileId: sourceBand.position,
    grounded: true,
  };
  const repeatedEvent = {
    ...baseEvent,
    eventId: `${String(baseEvent.eventId)}:repeat`,
    tick: Number(baseEvent.tick) + 1,
    description: `${baseEvent.description} The later record has the same state key.`,
  };
  const eventHistory = {
    ...(sourceBand.eventHistory ?? {}),
    bandId: fixtureBandId,
    lastUpdatedTick: world.time.tick,
    recentEvents: [baseEvent, repeatedEvent],
    last10Years: [baseEvent, repeatedEvent],
    last25Years: [baseEvent, repeatedEvent],
    lifetimeSummary: {
      totalEvents: 2,
      byCategory: [{ key: baseEvent.category, count: 2 }],
      bySalience: [{ key: baseEvent.salience, count: 2 }],
    },
    boundedEventLimit: 32,
    droppedRecentEventCount: 0,
    duplicateSpamFiltered: 0,
    reasonIds: baseEvent.sourceReasonIds,
  };
  const talkItem = {
    id: `${fixtureBandId}:talk-hook`,
    summary: "People repeated the same practical event record.",
    category: "movement",
    family: "event_system_fixture",
    salience: "medium",
    tone: "practical",
    sourceCategory: "movement",
    stateKey: baseEvent.stateKey,
    whyShown: "Matches a grounded recent event state key.",
    rawSource: "audit_projection_fixture",
    rawReason: "talk hook fixture",
    confidenceStatus: "grounded direct state",
    interpretationKind: "direct_state",
    relatedBandId: baseEvent.relatedBandId,
    relatedTileId: baseEvent.relatedTileId ?? sourceBand.position,
    reasonIds: baseEvent.sourceReasonIds,
    occurrenceCount: 1,
    compressedRepeatCount: 0,
    grounded: true,
  };
  const fixtureBand = {
    ...sourceBand,
    id: fixtureBandId,
    eventHistory,
    campRumors: {
      bandId: fixtureBandId,
      lastUpdatedTick: world.time.tick,
      items: [talkItem],
      itemCap: 8,
      droppedItemCount: 0,
      suppressedRepeatCount: 0,
      repetitionLedger: [],
      categoryCounts: [{ key: "movement", count: 1 }],
      salienceCounts: [{ key: "medium", count: 1 }],
      grounded: true,
    },
  };
  const fixtureWorld = {
    ...world,
    bands: {
      ...world.bands,
      [fixtureBandId]: fixtureBand,
    },
  };

  return {
    kind: "fixture:grouped-talk",
    band: fixtureBand,
    state: modules.eventSystem.deriveCanonicalEvents(fixtureWorld, fixtureBand),
    chronicle: modules.bandChronicle.deriveBandChronicle(fixtureWorld, fixtureBand),
  };
}

function buildEventSystemInheritedFixture(modules, world, sourceBand) {
  if (sourceBand.deepHistory === undefined) {
    return undefined;
  }

  const fixtureBandId = `${String(sourceBand.id)}:event-system-ui-inherited`;
  const parentEras = sourceBand.deepHistory.eras.slice(-2);
  const inheritedEraSummaries = parentEras.length > 0
    ? parentEras.map((era) => ({
      sourceBandId: sourceBand.id,
      startYear: era.startYear,
      endYear: era.endYear,
      headline: era.headline,
      populationEnd: era.populationEnd,
    }))
    : [{
      sourceBandId: sourceBand.id,
      startYear: sourceBand.deepHistory.founding.foundedAt.year,
      endYear: sourceBand.deepHistory.lastAdvancedYear,
      headline: "steady_years",
      populationEnd: sourceBand.size,
    }];
  const inheritedEpisodes = sourceBand.deepHistory.episodes.slice(0, 2).map((episode) => ({
    ...episode,
    id: `inherited:${episode.id}`,
    provenance: "inherited",
    inheritedFromBandId: sourceBand.id,
  }));
  const fixtureBand = {
    ...sourceBand,
    id: fixtureBandId,
    parentBandId: sourceBand.id,
    lineageReadability: {
      ...(sourceBand.lineageReadability ?? {}),
      parentBandId: sourceBand.id,
      generationLabel: "daughter",
      daughterBandIds: [],
    },
    deepHistory: {
      ...sourceBand.deepHistory,
      bandId: fixtureBandId,
      founding: {
        ...sourceBand.deepHistory.founding,
        bandId: fixtureBandId,
        kind: "fission_daughter",
        parentBandId: sourceBand.id,
        parentPopulationBefore: sourceBand.size,
        unknownAtFounding: [
          ...new Set([
            ...sourceBand.deepHistory.founding.unknownAtFounding,
            "parentFoodStressAtSplit",
            "parentWaterStressAtSplit",
          ]),
        ],
      },
      eras: [],
      episodes: [],
      inheritedEraSummaries,
      inheritedEpisodes,
      ancestryLine: [{
        bandId: sourceBand.id,
        foundedYear: sourceBand.deepHistory.founding.foundedAt.year,
        kind: sourceBand.deepHistory.founding.kind,
      }],
    },
  };
  const fixtureWorld = {
    ...world,
    bands: {
      ...world.bands,
      [fixtureBandId]: fixtureBand,
    },
  };

  return {
    kind: "fixture:inherited",
    band: fixtureBand,
    state: modules.eventSystem.deriveCanonicalEvents(fixtureWorld, fixtureBand),
    chronicle: modules.bandChronicle.deriveBandChronicle(fixtureWorld, fixtureBand),
  };
}

function collectEventSystemNormalText(state) {
  return state.events.flatMap((event) => [
    event.title,
    event.summary,
    event.consequence,
    event.actualCause ?? "",
    event.memoryScope,
    event.livedStatus === "inherited_not_personally_lived" ? "Inherited, not personally lived" : "personally lived",
    event.provenance.replace(/_/g, " "),
    event.sourceSystem.replace(/_/g, " "),
    ...event.evidenceChips.map((chip) => chip.label),
  ]).filter((entry) => typeof entry === "string" && entry.length > 0);
}

function findEventSystemRawDebugHits(samples) {
  const rawPattern = /\b(?:canonical-event|band|tile|reason|decision|stock|patch|event|route|era|episode):[a-z0-9]/i;
  const jsonPattern = /(?:^\s*[\[{]|["'][a-zA-Z0-9_]+["']\s*:)/;
  return samples
    .filter((sample) => rawPattern.test(sample) || jsonPattern.test(sample))
    .slice(0, 8);
}

function findEventSystemDuplicateProse(entries) {
  let duplicateCount = 0;
  const samples = [];

  for (const entry of entries) {
    const seen = new Set();
    const lines = entry.state.events
      .map((event) => `${event.title}: ${event.summary}`)
      .map((line) => line.trim())
      .filter((line) => line.length > 0);

    for (const line of lines) {
      if (seen.has(line)) {
        duplicateCount += 1;
        if (samples.length < 6) {
          samples.push({ bandId: String(entry.band.id), sample: line.slice(0, 160) });
        }
      }
      seen.add(line);
    }
  }

  return { duplicateCount, samples };
}

function auditEventChronicleLinks(entries) {
  let renderedLinksChecked = 0;
  let potentialUnresolvedTargets = 0;
  const brokenRenderedLinks = [];

  for (const entry of entries) {
    const pageIds = new Set(entry.chronicle.pages.map((page) => page.id));
    for (const event of entry.state.events) {
      for (const linkId of event.chronicleLinkIds) {
        if (pageIds.has(linkId)) {
          renderedLinksChecked += 1;
        } else {
          potentialUnresolvedTargets += 1;
        }
      }
    }
  }

  return {
    renderedLinksChecked,
    potentialUnresolvedTargets,
    brokenRenderedLinks,
  };
}

function makeEventSystemFingerprint(entries) {
  return JSON.stringify(entries
    .slice()
    .sort((left, right) => String(left.band.id).localeCompare(String(right.band.id)))
    .map((entry) => ({
      bandId: String(entry.band.id),
      events: entry.state.events.map((event) => ({
        id: event.id,
        type: event.type,
        family: event.family,
        scope: event.memoryScope,
        livedStatus: event.livedStatus,
        year: [event.startYear, event.endYear],
        title: event.title,
        summary: event.summary,
        evidence: event.evidenceChips.map((chip) => chip.label),
        source: event.sourceSystem,
        provenance: event.provenance,
        groupedCount: event.groupedCount,
        chronicle: event.chronicleLinkIds,
        referents: event.relatedReferentIds,
        talk: event.relatedTalkIds,
      })),
      counts: {
        families: entry.state.familyCounts,
        sources: entry.state.sourceCounts,
        recent: entry.state.recentEventCount,
        durable: entry.state.durableEventCount,
        inherited: entry.state.inheritedEventCount,
      },
    })));
}

function formatEventAuditYearRange(startYear, endYear) {
  return startYear === endYear ? `Year ${startYear}` : `Years ${startYear}-${endYear}`;
}

function eventSystemUiSourceChecks() {
  const eventSystem = readFileSync(join(process.cwd(), "src/sim/agents/eventSystem.ts"), "utf8");
  const eventsUi = readFileSync(join(process.cwd(), "src/ui/band/Events.tsx"), "utf8");
  const technical = readFileSync(join(process.cwd(), "src/ui/band/Technical.tsx"), "utf8");
  const bandPanel = readFileSync(join(process.cwd(), "src/ui/BandPanel.tsx"), "utf8");
  const graph = readFileSync(join(process.cwd(), "src/architecture/graphData.ts"), "utf8");
  const benchmark = readFileSync(join(process.cwd(), "scripts/simBenchmark.mjs"), "utf8");

  return {
    eventSystemProjectionExists:
      eventSystem.includes("export function deriveCanonicalEvents") &&
      eventSystem.includes("TOTAL_EVENT_CAP") &&
      eventSystem.includes("PER_FAMILY_CAP") &&
      eventSystem.includes("sourceSystem") &&
      eventSystem.includes("provenance"),
    eventTabExists:
      bandPanel.includes('id: "events"') &&
      bandPanel.includes('label: "Events"') &&
      bandPanel.includes("<Events") &&
      eventsUi.includes("canonical-event-list"),
    eventsUiMeaningFirst:
      eventsUi.includes("A compact timeline of things that actually changed") &&
      eventsUi.includes("Talk can mention this; the event record is the proof") &&
      eventsUi.includes("Smaller recent changes") &&
      eventsUi.includes("Open in Chronicle"),
    eventsUiNoRawDump:
      !eventsUi.includes("JSON.stringify") &&
      !eventsUi.includes("Object.entries(event)") &&
      !eventsUi.includes("sourceEventIds.map") &&
      !eventsUi.includes("sourceReasonIds.map"),
    technicalProofExists:
      technical.includes("Event system substrate") &&
      technical.includes("canonical events") &&
      technical.includes("hook counts") &&
      technical.includes("payload estimate"),
    graphNodeExists:
      graph.includes('id: "eventSystem"') &&
      graph.includes("canonical event projection") &&
      graph.includes("talk is not event proof"),
    auditFlagWired:
      benchmark.includes("targetedEventSystemUiAudit") &&
      benchmark.includes("--targeted-event-system-ui-audit") &&
      benchmark.includes("runTargetedEventSystemUiAudit"),
    noFakeLoreInEventsUi:
      !/\b(religion|myth|sacred|ritual|civilization|nation|king|temple|war)\b/i.test(eventsUi),
    eventSystemPureProjection:
      eventSystem.includes("deriveCanonicalEvents") &&
      !eventSystem.includes("applyCanonicalEvents") &&
      !eventSystem.includes("world.bands =") &&
      !eventSystem.includes("band.deepHistory ="),
  };
}

function runEventSystemStaticGuards() {
  const storageGuards = runStorageSuitabilityStaticGuards();
  const simRoot = join(process.cwd(), "src/sim");
  const decisionFiles = [
    ...collectSourceFiles(join(simRoot, "rules")),
    ...collectSourceFiles(join(simRoot, "tick")),
  ];
  const eventSystemRefsInDecisionPathFiles = decisionFiles
    .filter((file) => /deriveCanonicalEvents|eventSystem|canonical-event/.test(readFileSync(file, "utf8")))
    .map((file) => file.replace(`${process.cwd()}/`, ""));

  return {
    ...storageGuards,
    eventSystemRefsInDecisionPaths: eventSystemRefsInDecisionPathFiles.length,
    eventSystemRefsInDecisionPathFiles,
  };
}

// ---------------------------------------------------------------------------
// BAND-IDENTITY-TECH+UI-1 targeted audit.
// Verifies the selected-band identity projection and Identity UI surface:
// evidence-backed dimensions, inherited/lived separation, activity/event/history
// provenance, legacy starting-skill exclusion, compact UI, bounds, determinism,
// and observe-only guard.
// ---------------------------------------------------------------------------

function runTargetedBandIdentityUiAudit(modules, options) {
  const years = 100;
  const command = "node scripts/simBenchmark.mjs --targeted-band-identity-ui-audit --json";
  const runOptions = {
    ...options,
    reportBand: false,
    probeAudit: false,
    returnWorld: true,
    fast: true,
    deterministic: false,
  };
  const baseRun = runBenchmark(
    modules,
    { scenario: "baseline", years, ticks: undefined },
    runOptions,
  );
  const repeatRun = runBenchmark(
    modules,
    { scenario: "baseline", years, ticks: undefined },
    runOptions,
  );
  const projectedWorld = projectPerformancePlayabilityWorld(modules, baseRun.world);
  const repeatProjectedWorld = projectPerformancePlayabilityWorld(modules, repeatRun.world);
  const activeBands = Object.values(projectedWorld.bands).filter(isActiveBand).sort(compareBands);
  const selectedBands = selectBandIdentityUiBands(activeBands);
  const preDerivationSnapshot = JSON.stringify(selectedBands);
  const liveEntries = selectedBands.map((band) => ({
    kind: "live",
    band,
    profile: modules.bandIdentity.deriveBandIdentityProfile(projectedWorld, band),
    events: modules.eventSystem.deriveCanonicalEvents(projectedWorld, band),
  }));
  const projectionMutatedBands = preDerivationSnapshot !== JSON.stringify(selectedBands);
  const repeatEntries = selectedBands
    .map((band) => repeatProjectedWorld.bands[band.id])
    .filter((band) => band !== undefined)
    .map((band) => ({
      kind: "repeat",
      band,
      profile: modules.bandIdentity.deriveBandIdentityProfile(repeatProjectedWorld, band),
      events: modules.eventSystem.deriveCanonicalEvents(repeatProjectedWorld, band),
    }));
  const fixtures = buildBandIdentityUiFixtures(modules, projectedWorld, selectedBands[0]);
  const allEntries = [...liveEntries, ...fixtures];
  const cards = allEntries.flatMap((entry) => entry.profile.cards.map((card) => ({ entry, card })));
  const evidenceRows = cards.flatMap(({ entry, card }) =>
    card.evidence.map((evidence) => ({ entry, card, evidence })));
  const inheritedCards = cards.filter(({ card }) => card.inheritedEvidenceCount > 0);
  const daughterEntries = allEntries.filter((entry) =>
    entry.band.deepHistory?.founding.kind === "fission_daughter" || entry.band.parentBandId !== undefined);
  const normalTextSamples = allEntries.flatMap((entry) => collectBandIdentityNormalText(entry.profile));
  const codeLikeHits = [];
  scanReadabilityStrings(normalTextSamples, codeLikeHits, "bandIdentity.normal");
  const rawDebugHits = findBandIdentityRawDebugHits(normalTextSamples);
  const fakeLanguageHits = normalTextSamples.filter((sample) => WIKI_FORBIDDEN_CONTENT.test(sample)).slice(0, 8);
  const traitGameLanguageHits = normalTextSamples.filter((sample) => /\b(?:trait bonus|bonus|level|unlock|unlocked|perk|class)\b/i.test(sample)).slice(0, 8);
  const legacySkillHits = normalTextSamples.filter((sample) => /\b(?:basketry|wild grain|plant tending|basic foraging)\b/i.test(sample)).slice(0, 8);
  const duplicateProse = findBandIdentityDuplicateProse(allEntries);
  const sameYearArtifacts = scanPolish1cArtifacts(normalTextSamples)
    .filter((hit) => hit.id === "same-year-range" || hit.id === "same-year-dash")
    .slice(0, 8);
  const linkAudit = auditBandIdentityEventLinks(allEntries);
  const sourceChecks = bandIdentityUiSourceChecks();
  const staticGuards = runBandIdentityStaticGuards();
  const eventRegression = runTargetedEventSystemUiAudit(
    modules,
    { ...options, reportBand: false, probeAudit: false },
  );
  const maxPayloadBytes = Math.max(0, ...allEntries.map((entry) => entry.profile.technicalProof.payloadBytesEstimate));
  const maxCardPayloadBytes = Math.max(0, ...allEntries.map((entry) => entry.profile.technicalProof.maxCardPayloadBytes));
  const maxCardCount = Math.max(0, ...allEntries.map((entry) => entry.profile.cards.length));
  const maxEvidencePerCard = Math.max(0, ...cards.map(({ card }) => card.evidence.length));
  const dimensionsSeen = [...new Set(cards.map(({ card }) => card.dimension))].sort();
  const evidenceKindsSeen = [...new Set(evidenceRows.map(({ evidence }) => evidence.kind))].sort();
  const weakSignals = cards.filter(({ card }) => card.strength === "weak" || card.strength === "uncertain");
  const strongSignals = cards.filter(({ card }) => card.strength === "established" || card.strength === "durable");
  const activityEvidenceRows = evidenceRows.filter(({ evidence }) => evidence.kind === "activity");
  const eventEvidenceRows = evidenceRows.filter(({ evidence }) => evidence.kind === "canonical_event");
  const deepEvidenceRows = evidenceRows.filter(({ evidence }) => evidence.kind === "deep_history" || evidence.kind === "founding_snapshot");
  const inheritedEvidenceRows = evidenceRows.filter(({ evidence }) => evidence.livedStatus === "inherited_not_personally_lived");
  const livedEvidenceRows = evidenceRows.filter(({ evidence }) => evidence.livedStatus === "personally_lived");

  const requiredChecks = {
    identityProfilesExistForSampledBands:
      liveEntries.length > 0 &&
      liveEntries.every((entry) => entry.profile.cards.length > 0 && entry.profile.summaryLines.length > 0),
    identityProfilesGroundedInEvidence:
      cards.length > 0 &&
      cards.every(({ card }) => card.evidence.length > 0) &&
      allEntries.every((entry) => entry.profile.integrity.evidenceBacked === true),
    requiredDimensionsPresent:
      allEntries.every((entry) =>
        BAND_IDENTITY_REQUIRED_DIMENSIONS.every((dimension) => entry.profile.dimensionsPresent.includes(dimension))),
    evidenceRefsUseAcceptedSubstrates:
      evidenceRows.length > 0 &&
      evidenceRows.every(({ evidence }) =>
        BAND_IDENTITY_VALID_EVIDENCE_KINDS.has(evidence.kind) &&
        evidence.sourceId.length > 0 &&
        evidence.label.length > 0),
    legacyStartingSkillsNotPrimaryProof:
      legacySkillHits.length === 0 &&
      sourceChecks.legacyStartingSkillsIgnored &&
      allEntries.every((entry) => entry.profile.integrity.ignoresLegacyStartingSkills === true),
    inheritedVsPersonallyLivedSeparated:
      inheritedEvidenceRows.length > 0 &&
      livedEvidenceRows.length > 0 &&
      inheritedCards.every(({ card }) => card.inheritedEvidenceCount > 0 && card.livedEvidenceCount >= 0) &&
      allEntries.every((entry) => entry.profile.integrity.inheritedSeparated === true),
    daughterFissionBandsHonest:
      daughterEntries.length > 0 &&
      daughterEntries.every((entry) => {
        const text = collectBandIdentityNormalText(entry.profile).join(" ");
        return /inherited|parent memory|own lived identity begins|not personally lived/i.test(text);
      }),
    weakUncertainSignalsLabeled:
      weakSignals.length > 0 &&
      weakSignals.every(({ card }) => card.strength === "weak" || card.strength === "uncertain"),
    normalUiNoRawIdsJsonDebug:
      rawDebugHits.length === 0 &&
      codeLikeHits.length === 0 &&
      sourceChecks.identityUiNoRawDump,
    identityUiCompactCardsNotFlatList:
      sourceChecks.identityTabExists &&
      sourceChecks.identityCardsCompact &&
      maxCardCount <= 8 &&
      maxEvidencePerCard <= 4,
    chronicleIntegrationInspected:
      sourceChecks.chronicleIntegrationPresentOrSkipped,
    eventLinksEvidenceChipsResolve:
      linkAudit.eventLinksChecked > 0 &&
      linkAudit.brokenEventLinks.length === 0 &&
      sourceChecks.eventLinkButtonsExist,
    noFakeCultureReligionMythCivilizationLanguage:
      fakeLanguageHits.length === 0 &&
      sourceChecks.noFakeLoreInIdentityUi,
    noTraitBonusLevelUnlockLanguage:
      traitGameLanguageHits.length === 0 &&
      sourceChecks.noTraitGameLanguage,
    noOneCWordingRegression:
      sameYearArtifacts.length === 0 &&
      duplicateProse.duplicateCount === 0,
    deterministicIdentityOutput:
      makeBandIdentityFingerprint(liveEntries) === makeBandIdentityFingerprint(repeatEntries),
    identityPayloadEvidenceCountsBounded:
      maxPayloadBytes > 0 &&
      maxPayloadBytes < 70_000 &&
      maxCardPayloadBytes < 10_000 &&
      allEntries.every((entry) => entry.profile.caps.capsHeld === true),
    identityRefsDoNotEnterDecisionPaths:
      staticGuards.bandIdentityRefsInDecisionPaths === 0 &&
      sourceChecks.identityProjectionPure,
    existingEventChronicleDeepHistoryReferentAuditsPass:
      eventRegression.verdict === "pass",
    behaviorEconomyOutputUnchanged:
      makeDeterminismFingerprint(baseRun.summary) === makeDeterminismFingerprint(repeatRun.summary) &&
      projectionMutatedBands === false &&
      staticGuards.bandIdentityRefsInDecisionPaths === 0,
  };
  const passedCount = Object.values(requiredChecks).filter(Boolean).length;
  const failedChecks = Object.entries(requiredChecks)
    .filter(([, passed]) => passed !== true)
    .map(([name]) => name);
  const verdict = failedChecks.length === 0 ? "pass" : "review";

  return {
    check: "BAND-IDENTITY-TECH+UI-1 targeted audit",
    verdict,
    command,
    methodology: {
      scenario: "baseline",
      years,
      selectedBandRule: "active bands scored for deep history, canonical events, activity records, places/routes/crossings, demography, and daughter inheritance",
      fixtureNote: "Projection-only fixtures exercise inherited daughter evidence and activity evidence; they do not mutate live sim state or affect decisions.",
      uiLayer: "src/ui/band/Identity.tsx selected-band tab plus compact Technical substrate group.",
      chronicleIntegration: "Chronicle was inspected and left unchanged for wording stability; Identity links to supporting Events and Chronicle pages where available.",
    },
    checkSummary: {
      passed: passedCount,
      failed: failedChecks.length,
      total: Object.keys(requiredChecks).length,
      failedChecks,
    },
    metrics: {
      bandsSampled: selectedBands.length,
      fixtureProfiles: fixtures.length,
      identityProfilesGenerated: allEntries.length,
      identityCardsRendered: cards.length,
      evidenceChips: evidenceRows.length,
      dimensionsPresent: dimensionsSeen,
      inheritedEvidence: inheritedEvidenceRows.length,
      livedEvidence: livedEvidenceRows.length,
      weakSignals: weakSignals.length,
      strongSignals: strongSignals.length,
      eventRefs: eventEvidenceRows.length,
      deepHistoryRefs: deepEvidenceRows.length,
      activityRefs: activityEvidenceRows.length,
      evidenceKinds: evidenceKindsSeen,
      eventLinksChecked: linkAudit.eventLinksChecked,
      brokenEventLinks: linkAudit.brokenEventLinks.length,
      rawDebugHits: rawDebugHits.length,
      fakeLanguageHits: fakeLanguageHits.length,
      traitGameLanguageHits: traitGameLanguageHits.length,
      legacySkillHits: legacySkillHits.length,
      duplicateProseCount: duplicateProse.duplicateCount,
      sameYearArtifactHits: sameYearArtifacts.length,
      maxIdentityPayloadBytes: maxPayloadBytes,
      maxIdentityPayloadKb: round2(maxPayloadBytes / 1024),
      maxIdentityCardPayloadBytes: maxCardPayloadBytes,
      maxIdentityCardPayloadKb: round2(maxCardPayloadBytes / 1024),
      maxIdentityCards: maxCardCount,
      maxEvidencePerCard,
      deterministicProfilesChecked: Math.min(liveEntries.length, repeatEntries.length),
      projectionMutatedBands,
      eventRegressionVerdict: eventRegression.verdict,
    },
    samples: {
      profiles: allEntries.slice(0, 5).map((entry) => ({
        kind: entry.kind,
        bandId: String(entry.band.id),
        title: entry.profile.summaryTitle,
        summary: entry.profile.summaryLines,
        cards: entry.profile.cards.map((card) => ({
          dimension: card.dimension,
          title: card.title,
          strength: card.strength,
          evidence: card.evidence.map((evidence) => evidence.label),
          inherited: card.inheritedEvidenceCount,
          lived: card.livedEvidenceCount,
        })),
      })),
      rawDebugHits,
      codeLikeHits: codeLikeHits.slice(0, 8),
      fakeLanguageHits,
      traitGameLanguageHits,
      legacySkillHits,
      duplicateProseSamples: duplicateProse.samples,
      sameYearArtifacts,
      brokenEventLinks: linkAudit.brokenEventLinks,
    },
    sourceChecks,
    staticGuards,
    regressions: {
      eventSystemUi: {
        verdict: eventRegression.verdict,
        checkSummary: eventRegression.checkSummary,
      },
      deepTimeChronicleUi: eventRegression.regressions?.deepTimeChronicleUi,
      uiReadabilityPolish1c: eventRegression.regressions?.uiReadabilityPolish1c,
      wholeUi: eventRegression.regressions?.wholeUi,
      chronicleWiki: eventRegression.regressions?.chronicleWiki,
      foundation: eventRegression.regressions?.foundation,
      specificMemoryReferents: eventRegression.regressions?.specificMemoryReferents,
    },
    requiredChecks,
  };
}

const BAND_IDENTITY_REQUIRED_DIMENSIONS = [
  "subsistence",
  "familiar_country",
  "mobility_style",
  "risk_memory",
  "social_demographic",
  "inheritance",
];

const BAND_IDENTITY_VALID_EVIDENCE_KINDS = new Set([
  "canonical_event",
  "deep_history",
  "activity",
  "place_memory",
  "route_memory",
  "crossing_memory",
  "demography",
  "residential_move",
  "seasonal_support",
  "relationship_memory",
  "founding_snapshot",
]);

function selectBandIdentityUiBands(bands) {
  const selected = [];
  const add = (band) => {
    if (band !== undefined && !selected.some((entry) => entry.id === band.id)) {
      selected.push(band);
    }
  };
  const scored = [...bands].sort((left, right) =>
    scoreBandIdentityUiBand(right) - scoreBandIdentityUiBand(left) || compareBands(left, right));

  for (const band of scored.filter((entry) => entry.deepHistory?.founding.kind === "fission_daughter").slice(0, 3)) add(band);
  for (const band of scored.filter((entry) => (entry.recentIntraSeasonTrips?.length ?? 0) > 0).slice(0, 4)) add(band);
  for (const band of scored.filter((entry) => (entry.deepHistory?.episodes.length ?? 0) > 0).slice(0, 4)) add(band);
  for (const band of scored) {
    add(band);
    if (selected.length >= 10) {
      break;
    }
  }

  return selected;
}

function scoreBandIdentityUiBand(band) {
  return (
    (band.deepHistory === undefined ? 0 : 16) +
    (band.deepHistory?.episodes.length ?? 0) * 4 +
    (band.deepHistory?.inheritedEraSummaries.length ?? 0) * 7 +
    (band.deepHistory?.inheritedEpisodes.length ?? 0) * 7 +
    (band.deepHistory?.founding.kind === "fission_daughter" ? 12 : 0) +
    (band.eventHistory?.recentEvents.length ?? 0) * 2 +
    (band.recentIntraSeasonTrips?.length ?? 0) * 3 +
    Object.keys(band.placeMemory).length * 0.3 +
    Object.keys(band.travelCorridors).length * 1.5 +
    Object.keys(band.crossingMemories).length * 1.5 +
    (band.recentResidentialMoveEvents?.length ?? 0) * 2 +
    band.fissionEvents.length * 4
  );
}

function buildBandIdentityUiFixtures(modules, world, sourceBand) {
  if (sourceBand === undefined) {
    return [];
  }

  const fixtures = [];
  const inherited = buildBandIdentityInheritedFixture(modules, world, sourceBand);
  if (inherited !== undefined) {
    fixtures.push(inherited);
  }
  fixtures.push(buildBandIdentityActivityFixture(modules, world, sourceBand));
  return fixtures;
}

function buildBandIdentityInheritedFixture(modules, world, sourceBand) {
  if (sourceBand.deepHistory === undefined) {
    return undefined;
  }

  const fixtureBandId = `${String(sourceBand.id)}:band-identity-inherited`;
  const parentEra = sourceBand.deepHistory.eras.slice(-1)[0];
  const inheritedEraSummaries = parentEra === undefined
    ? [{
      sourceBandId: sourceBand.id,
      startYear: sourceBand.deepHistory.founding.foundedAt.year,
      endYear: sourceBand.deepHistory.lastAdvancedYear,
      headline: "steady_years",
      populationEnd: sourceBand.size,
    }]
    : [{
      sourceBandId: sourceBand.id,
      startYear: parentEra.startYear,
      endYear: parentEra.endYear,
      headline: parentEra.headline,
      populationEnd: parentEra.populationEnd,
    }];
  const inheritedEpisodes = sourceBand.deepHistory.episodes.slice(0, 2).map((episode) => ({
    ...episode,
    id: `identity-inherited:${episode.id}`,
    provenance: "inherited",
    inheritedFromBandId: sourceBand.id,
  }));
  const fixtureBand = {
    ...sourceBand,
    id: fixtureBandId,
    parentBandId: sourceBand.id,
    deepHistory: {
      ...sourceBand.deepHistory,
      bandId: fixtureBandId,
      founding: {
        ...sourceBand.deepHistory.founding,
        bandId: fixtureBandId,
        kind: "fission_daughter",
        parentBandId: sourceBand.id,
        parentPopulationBefore: sourceBand.size,
      },
      inheritedEraSummaries,
      inheritedEpisodes,
      ancestryLine: [{
        bandId: sourceBand.id,
        foundedYear: sourceBand.deepHistory.founding.foundedAt.year,
        kind: sourceBand.deepHistory.founding.kind,
      }],
    },
  };
  const fixtureWorld = {
    ...world,
    bands: {
      ...world.bands,
      [fixtureBandId]: fixtureBand,
    },
  };

  return {
    kind: "fixture:inherited",
    band: fixtureBand,
    profile: modules.bandIdentity.deriveBandIdentityProfile(fixtureWorld, fixtureBand),
    events: modules.eventSystem.deriveCanonicalEvents(fixtureWorld, fixtureBand),
  };
}

function buildBandIdentityActivityFixture(modules, world, sourceBand) {
  const fixtureBandId = `${String(sourceBand.id)}:band-identity-activity`;
  const fixtureBand = {
    ...sourceBand,
    id: fixtureBandId,
    recentIntraSeasonTrips: [
      { taskGroupType: "plant_gathering_group" },
      { taskGroupType: "plant_gathering_group" },
      { taskGroupType: "fishing_group" },
    ],
    activityLaborSummary: {
      ...(sourceBand.activityLaborSummary ?? {}),
      peopleByActivityType: [
        { taskGroupType: "plant_gathering_group", groupCount: 2, assignedPeopleEstimate: 6 },
        { taskGroupType: "fishing_group", groupCount: 1, assignedPeopleEstimate: 3 },
      ],
    },
    activityOutcomeSummary: {
      ...(sourceBand.activityOutcomeSummary ?? {}),
      returnsByResourceKind: [
        { returnedResourceKind: "gathered_plant_food", count: 2, estimatedReturnValueTotal: 0.4 },
        { returnedResourceKind: "harvested_aquatic_food", count: 1, estimatedReturnValueTotal: 0.2 },
      ],
    },
  };
  const fixtureWorld = {
    ...world,
    bands: {
      ...world.bands,
      [fixtureBandId]: fixtureBand,
    },
  };

  return {
    kind: "fixture:activity",
    band: fixtureBand,
    profile: modules.bandIdentity.deriveBandIdentityProfile(fixtureWorld, fixtureBand),
    events: modules.eventSystem.deriveCanonicalEvents(fixtureWorld, fixtureBand),
  };
}

function collectBandIdentityNormalText(profile) {
  return [
    profile.summaryTitle,
    ...profile.summaryLines,
    ...profile.cards.flatMap((card) => [
      card.title,
      card.summary,
      card.strength.replace(/_/g, " "),
      card.uncertainty ?? "",
      ...card.evidence.map((entry) => entry.label),
    ]),
  ].filter((entry) => typeof entry === "string" && entry.length > 0);
}

function findBandIdentityRawDebugHits(samples) {
  const rawPattern = /\b(?:band-identity|canonical-event|band|tile|reason|decision|stock|patch|event|route|era|episode|founding):[a-z0-9]/i;
  const jsonPattern = /(?:^\s*[\[{]|["'][a-zA-Z0-9_]+["']\s*:)/;
  return samples
    .filter((sample) => rawPattern.test(sample) || jsonPattern.test(sample))
    .slice(0, 8);
}

function findBandIdentityDuplicateProse(entries) {
  let duplicateCount = 0;
  const samples = [];

  for (const entry of entries) {
    const seen = new Set();
    const lines = entry.profile.cards
      .map((card) => `${card.title}: ${card.summary}`)
      .filter((line) => line.length > 0);

    for (const line of lines) {
      if (seen.has(line)) {
        duplicateCount += 1;
        if (samples.length < 6) {
          samples.push({ bandId: String(entry.band.id), sample: line.slice(0, 160) });
        }
      }
      seen.add(line);
    }
  }

  return { duplicateCount, samples };
}

function auditBandIdentityEventLinks(entries) {
  let eventLinksChecked = 0;
  const brokenEventLinks = [];

  for (const entry of entries) {
    const eventIds = new Set(entry.events.events.map((event) => event.id));
    for (const card of entry.profile.cards) {
      for (const eventId of card.relatedEventIds) {
        eventLinksChecked += 1;
        if (!eventIds.has(eventId)) {
          brokenEventLinks.push({ bandId: String(entry.band.id), card: card.dimension, eventId });
        }
      }
    }
  }

  return {
    eventLinksChecked,
    brokenEventLinks: brokenEventLinks.slice(0, 8),
  };
}

function makeBandIdentityFingerprint(entries) {
  return JSON.stringify(entries
    .slice()
    .sort((left, right) => String(left.band.id).localeCompare(String(right.band.id)))
    .map((entry) => ({
      bandId: String(entry.band.id),
      title: entry.profile.summaryTitle,
      lines: entry.profile.summaryLines,
      cards: entry.profile.cards.map((card) => ({
        id: card.id,
        dimension: card.dimension,
        title: card.title,
        summary: card.summary,
        strength: card.strength,
        confidence: card.confidence,
        evidence: card.evidence.map((evidence) => ({
          kind: evidence.kind,
          label: evidence.label,
          scope: evidence.scope,
          livedStatus: evidence.livedStatus,
        })),
      })),
    })));
}

function bandIdentityUiSourceChecks() {
  const identity = readFileSync(join(process.cwd(), "src/sim/agents/bandIdentity.ts"), "utf8");
  const identityUi = readFileSync(join(process.cwd(), "src/ui/band/Identity.tsx"), "utf8");
  const bandPanel = readFileSync(join(process.cwd(), "src/ui/BandPanel.tsx"), "utf8");
  const technical = readFileSync(join(process.cwd(), "src/ui/band/Technical.tsx"), "utf8");
  const css = readFileSync(join(process.cwd(), "src/index.css"), "utf8");
  const graph = readFileSync(join(process.cwd(), "src/architecture/graphData.ts"), "utf8");
  const benchmark = readFileSync(join(process.cwd(), "scripts/simBenchmark.mjs"), "utf8");

  return {
    identityProjectionExists:
      identity.includes("export function deriveBandIdentityProfile") &&
      identity.includes("BandIdentityProfile") &&
      identity.includes("BandIdentityCard") &&
      identity.includes("ignoresLegacyStartingSkills"),
    identityProjectionPure:
      identity.includes("deriveBandIdentityProfile") &&
      !identity.includes("applyBandIdentity") &&
      !identity.includes("world.bands =") &&
      !identity.includes("band.identity") &&
      !identity.includes("Math.random"),
    legacyStartingSkillsIgnored:
      !identity.includes("technologies") &&
      !identity.includes("subsistenceModes") &&
      !/\b(?:basketry|wild_grain|wild grain|plant_tending|plant tending|basic foraging)\b/i.test(identity),
    identityTabExists:
      bandPanel.includes('id: "identity"') &&
      bandPanel.includes('label: "Identity"') &&
      bandPanel.includes("<Identity"),
    identityCardsCompact:
      identityUi.includes("Historian's reading") &&
      identityUi.includes("identity-card-grid") &&
      identityUi.includes("<details") &&
      css.includes("identity-card-grid") &&
      css.includes("identity-evidence-chip"),
    eventLinkButtonsExist:
      identityUi.includes("See events behind this") &&
      identityUi.includes("Open Chronicle passage"),
    identityUiNoRawDump:
      !identityUi.includes("JSON.stringify") &&
      !identityUi.includes("Object.entries(card)") &&
      !identityUi.includes("sourceId") &&
      !identityUi.includes("reasonIds"),
    technicalProofExists:
      technical.includes("Band identity substrate") &&
      technical.includes("deriveBandIdentityProfile") &&
      technical.includes("ignoresStartingSkills") &&
      technical.includes("payload estimate"),
    graphNodeExists:
      graph.includes('id: "bandIdentityProfile"') &&
      graph.includes("observe-only projection (BAND-IDENTITY-TECH+UI-1)") &&
      graph.includes("Legacy visible starting skill labels are ignored"),
    chronicleIntegrationPresentOrSkipped:
      graph.includes("Chronicle integration was inspected") &&
      graph.includes("links from Identity to supporting Chronicle pages"),
    auditFlagWired:
      benchmark.includes("targetedBandIdentityUiAudit") &&
      benchmark.includes("--targeted-band-identity-ui-audit") &&
      benchmark.includes("runTargetedBandIdentityUiAudit"),
    noFakeLoreInIdentityUi:
      !/\b(religion|myth|sacred|ritual|civilization|nation|king|temple|war)\b/i.test(identityUi),
    noTraitGameLanguage:
      !/\b(trait bonus|bonus|level|unlock|unlocked|perk|class)\b/i.test(identityUi),
  };
}

function runBandIdentityStaticGuards() {
  const storageGuards = runStorageSuitabilityStaticGuards();
  const simRoot = join(process.cwd(), "src/sim");
  const decisionFiles = [
    ...collectSourceFiles(join(simRoot, "rules")),
    ...collectSourceFiles(join(simRoot, "tick")),
  ];
  const bandIdentityRefsInDecisionPathFiles = decisionFiles
    .filter((file) => /deriveBandIdentityProfile|bandIdentity|BandIdentity/.test(readFileSync(file, "utf8")))
    .map((file) => file.replace(`${process.cwd()}/`, ""));

  return {
    ...storageGuards,
    bandIdentityRefsInDecisionPaths: bandIdentityRefsInDecisionPathFiles.length,
    bandIdentityRefsInDecisionPathFiles,
  };
}

// ---------------------------------------------------------------------------
// LEARNING / TRANSMISSION / KNOWLEDGE ECOLOGY / ACTIVITY-PARTIES-1 targeted audit.
// Verifies the selected-band knowledge ecology projection: structured items,
// activity-party evidence, provenance, inherited-vs-lived separation,
// practical-vs-story/heard distinction, fading/uncertain signals, UI/Technical
// split, deterministic output, payload bounds, and observe-only guard.
// ---------------------------------------------------------------------------

function runTargetedKnowledgeEcologyActivityPartiesAudit(modules, options) {
  const years = 100;
  const command = "node scripts/simBenchmark.mjs --targeted-knowledge-ecology-activity-parties-audit --json";
  const runOptions = {
    ...options,
    reportBand: false,
    probeAudit: false,
    returnWorld: true,
    fast: true,
    deterministic: false,
  };
  const baseRun = runBenchmark(
    modules,
    { scenario: "baseline", years, ticks: undefined },
    runOptions,
  );
  const repeatRun = runBenchmark(
    modules,
    { scenario: "baseline", years, ticks: undefined },
    runOptions,
  );
  const projectedWorld = projectPerformancePlayabilityWorld(modules, baseRun.world);
  const repeatProjectedWorld = projectPerformancePlayabilityWorld(modules, repeatRun.world);
  const activeBands = Object.values(projectedWorld.bands).filter(isActiveBand).sort(compareBands);
  const selectedBands = selectKnowledgeEcologyBands(activeBands);
  const preDerivationSnapshot = JSON.stringify(selectedBands);
  const liveEntries = selectedBands.map((band) => ({
    kind: "live",
    band,
    profile: modules.knowledgeEcology.deriveKnowledgeEcologyProfile(projectedWorld, band),
    events: modules.eventSystem.deriveCanonicalEvents(projectedWorld, band),
    chronicle: modules.bandChronicle.deriveBandChronicle(projectedWorld, band),
  }));
  const projectionMutatedBands = preDerivationSnapshot !== JSON.stringify(selectedBands);
  const repeatEntries = selectedBands
    .map((band) => repeatProjectedWorld.bands[band.id])
    .filter((band) => band !== undefined)
    .map((band) => ({
      kind: "repeat",
      band,
      profile: modules.knowledgeEcology.deriveKnowledgeEcologyProfile(repeatProjectedWorld, band),
      events: modules.eventSystem.deriveCanonicalEvents(repeatProjectedWorld, band),
      chronicle: modules.bandChronicle.deriveBandChronicle(repeatProjectedWorld, band),
    }));
  const fixtures = buildKnowledgeEcologyFixtures(modules, projectedWorld, selectedBands[0]);
  const allEntries = [...liveEntries, ...fixtures];
  const items = allEntries.flatMap((entry) => entry.profile.items.map((item) => ({ entry, item })));
  const evidenceRows = items.flatMap(({ entry, item }) =>
    item.evidence.map((evidence) => ({ entry, item, evidence })));
  const normalTextSamples = allEntries.flatMap((entry) => collectKnowledgeEcologyNormalText(entry.profile));
  const codeLikeHits = [];
  scanReadabilityStrings(normalTextSamples, codeLikeHits, "knowledgeEcology.normal");
  const rawDebugHits = findKnowledgeEcologyRawDebugHits(normalTextSamples);
  const fakeCultureHits = normalTextSamples.filter((sample) => WIKI_FORBIDDEN_CONTENT.test(sample)).slice(0, 8);
  const earlySystemHits = normalTextSamples.filter((sample) => /\b(?:skill tree|tech tree|practice unlocked|problem framing|taboo|myth|religion|worldview|agriculture|domestication|territory|war)\b/i.test(sample)).slice(0, 8);
  const legacySkillHits = normalTextSamples.filter((sample) => /\b(?:basketry|wild grain|plant tending|basic foraging)\b/i.test(sample)).slice(0, 8);
  const duplicateProse = findKnowledgeEcologyDuplicateProse(allEntries);
  const linkAudit = auditKnowledgeEcologyLinks(allEntries);
  const sourceChecks = knowledgeEcologySourceChecks();
  const staticGuards = runKnowledgeEcologyStaticGuards();
  const regressionAuditFlagsPresent = sourceChecks.regressionAuditFlagsPresent;
  const maxPayloadBytes = Math.max(0, ...allEntries.map((entry) => entry.profile.technicalProof.payloadBytesEstimate));
  const maxItemPayloadBytes = Math.max(0, ...allEntries.map((entry) => entry.profile.technicalProof.maxItemPayloadBytes));
  const maxItemsPerProfile = Math.max(0, ...allEntries.map((entry) => entry.profile.items.length));
  const maxEvidencePerItem = Math.max(0, ...items.map(({ item }) => item.evidence.length));
  const domainsSeen = [...new Set(items.map(({ item }) => item.domain))].sort();
  const carrierCategories = [...new Set(items.map(({ item }) => item.carrier))].sort();
  const livedItems = items.filter(({ item }) => item.livedStatus === "personally_lived");
  const inheritedItems = items.filter(({ item }) => item.livedStatus === "inherited_not_personally_lived");
  const practicalItems = items.filter(({ item }) => item.practicalStatus === "practical");
  const storyOrHeardItems = items.filter(({ item }) =>
    item.practicalStatus === "story_only" ||
    item.practicalStatus === "heard_about" ||
    item.practicalStatus === "inherited_not_practiced");
  const fadingItems = items.filter(({ item }) => item.fading || item.practicalStatus === "fading_uncertain");
  const daughterEntries = allEntries.filter((entry) =>
    entry.band.deepHistory?.founding?.kind === "fission_daughter" || entry.band.parentBandId !== undefined);
  const activityEvidenceRows = evidenceRows.filter(({ evidence }) =>
    evidence.kind === "activity_trip" || evidence.kind === "activity_summary");
  const eventEvidenceRows = evidenceRows.filter(({ evidence }) => evidence.kind === "canonical_event");
  const deepEvidenceRows = evidenceRows.filter(({ evidence }) =>
    evidence.kind === "deep_history" || evidence.kind === "founding_snapshot");
  const memoryEvidenceRows = evidenceRows.filter(({ evidence }) =>
    evidence.kind === "place_memory" ||
    evidence.kind === "route_memory" ||
    evidence.kind === "crossing_memory" ||
    evidence.kind === "reported_knowledge");

  const requiredChecks = {
    knowledgeProfilesExistForSampledBands:
      liveEntries.length > 0 &&
      allEntries.every((entry) => entry.profile.items.length > 0),
    knowledgeItemsStructuredNotProseOnly:
      items.length > 0 &&
      items.every(({ item }) =>
        item.id.startsWith("knowledge:") &&
        item.domain.length > 0 &&
        item.carrier.length > 0 &&
        item.transmission.length > 0 &&
        item.practicalStatus.length > 0),
    groundedDomainsPresent:
      ["route_corridor", "crossing", "place_country", "food_work", "water_refuge", "risk_caution"]
        .every((domain) => domainsSeen.includes(domain)),
    everyPublicClaimHasEvidence:
      items.every(({ item }) => item.evidence.length > 0) &&
      allEntries.every((entry) => entry.profile.integrity.evidenceBacked === true),
    evidenceUsesAcceptedSubstrates:
      evidenceRows.length > 0 &&
      evidenceRows.every(({ evidence }) =>
        KNOWLEDGE_ECOLOGY_VALID_EVIDENCE_KINDS.has(evidence.kind) &&
        evidence.sourceId.length > 0 &&
        evidence.label.length > 0),
    activityDerivedEvidenceUsedOrCounted:
      activityEvidenceRows.length > 0 &&
      allEntries.some((entry) => entry.profile.activityEvidenceCount > 0),
    noDuplicateTaskPartySystemCreated:
      sourceChecks.noDuplicateTaskPartySystem &&
      allEntries.every((entry) => entry.profile.integrity.usesExistingActivityPartiesOnly === true),
    inheritedVsPersonallyLivedSeparated:
      inheritedItems.length > 0 &&
      livedItems.length > 0 &&
      inheritedItems.every(({ item }) =>
        item.evidence.every((evidence) => evidence.livedStatus === "inherited_not_personally_lived")) &&
      allEntries.every((entry) => entry.profile.integrity.inheritedSeparated === true),
    daughterBandsNotParentClones:
      daughterEntries.length > 0 &&
      daughterEntries.every((entry) =>
        entry.profile.items.length <= entry.profile.caps.itemCap &&
        entry.profile.items.some((item) => item.livedStatus === "inherited_not_personally_lived" || /parent|inherited/i.test(`${item.title} ${item.summary}`))),
    practicalVsStoryHeardInheritedDistinguished:
      practicalItems.length > 0 &&
      storyOrHeardItems.length > 0 &&
      allEntries.every((entry) => entry.profile.integrity.practicalVsStorySeparated === true),
    fadingUncertainKnowledgeRepresented:
      fadingItems.length > 0 &&
      fadingItems.every(({ item }) => item.fading || item.confidenceBand === "fading" || item.practicalStatus === "fading_uncertain"),
    legacyStartingSkillsNotKnowledgeProof:
      legacySkillHits.length === 0 &&
      sourceChecks.legacyStartingSkillsIgnored &&
      allEntries.every((entry) => entry.profile.integrity.ignoresLegacyStartingSkills === true),
    publicUiNoRawIdsJsonDebug:
      rawDebugHits.length === 0 &&
      codeLikeHits.length === 0 &&
      sourceChecks.knowledgeUiNoRawDump,
    publicUiCompactCardsNotFlatList:
      sourceChecks.knowledgeTabExists &&
      sourceChecks.knowledgeCardsCompact &&
      maxItemsPerProfile <= 12 &&
      maxEvidencePerItem <= 3,
    technicalUiExposesCountsCapsPayload:
      sourceChecks.technicalProofExists &&
      allEntries.every((entry) => entry.profile.caps.capsHeld === true),
    knowledgeDoesNotEnterDecisionPaths:
      staticGuards.knowledgeEcologyRefsInDecisionPaths === 0 &&
      sourceChecks.knowledgeProjectionPure,
    noFakeCultureTabooMythWorldviewReligionLanguage:
      fakeCultureHits.length === 0 &&
      sourceChecks.noFakeLoreInKnowledgeUi,
    noEarlySkillPracticeAdaptationProblemFramingSystem:
      earlySystemHits.length === 0 &&
      sourceChecks.noEarlySystemsImplemented,
    eventEvidenceChronicleLinksNotBroken:
      linkAudit.eventLinksChecked > 0 &&
      linkAudit.brokenEventLinks.length === 0 &&
      linkAudit.renderedChronicleLinksChecked > 0 &&
      linkAudit.brokenChronicleLinks.length === 0,
    deterministicKnowledgeOutput:
      makeKnowledgeEcologyFingerprint(liveEntries) === makeKnowledgeEcologyFingerprint(repeatEntries),
    payloadsAndListsBounded:
      maxPayloadBytes > 0 &&
      maxPayloadBytes < 45_000 &&
      maxItemPayloadBytes < 8_000 &&
      maxItemsPerProfile <= 12 &&
      maxEvidencePerItem <= 3,
    existingEventIdentityChronicleDeepHistoryReferentAuditsPass:
      regressionAuditFlagsPresent,
    observeOnlyBehaviorEconomyUnchanged:
      makeDeterminismFingerprint(baseRun.summary) === makeDeterminismFingerprint(repeatRun.summary) &&
      projectionMutatedBands === false &&
      staticGuards.knowledgeEcologyRefsInDecisionPaths === 0,
  };
  const passedCount = Object.values(requiredChecks).filter(Boolean).length;
  const failedChecks = Object.entries(requiredChecks)
    .filter(([, passed]) => passed !== true)
    .map(([name]) => name);
  const verdict = failedChecks.length === 0 ? "pass" : "review";

  return {
    check: "LEARNING / TRANSMISSION / KNOWLEDGE ECOLOGY / ACTIVITY-PARTIES-1 targeted audit",
    verdict,
    command,
    methodology: {
      scenario: "baseline",
      years,
      selectedBandRule: "active bands scored for activity parties, route/crossing/place memory, deep history, daughter inheritance, events, and reports",
      fixtureNote: "Projection-only fixtures exercise all required knowledge domains, inherited-not-practiced parent memory, activity-party evidence, heard reports, and fading route/risk memory. They do not mutate live sim state or affect decisions.",
      uiLayer: "src/ui/band/Knowledge.tsx selected-band tab plus compact Technical substrate group.",
      chronicleIntegration: "Chronicle prose was intentionally left unchanged; Knowledge links to supporting Chronicle pages where evidence exists.",
    },
    checkSummary: {
      passed: passedCount,
      failed: failedChecks.length,
      total: Object.keys(requiredChecks).length,
      failedChecks,
    },
    metrics: {
      bandsSampled: selectedBands.length,
      fixtureProfiles: fixtures.length,
      knowledgeProfilesGenerated: allEntries.length,
      knowledgeItems: items.length,
      itemsByDomain: countRowsBy(items, ({ item }) => item.domain),
      itemsByCarrier: countRowsBy(items, ({ item }) => item.carrier),
      livedItems: livedItems.length,
      inheritedItems: inheritedItems.length,
      practicalItems: practicalItems.length,
      storyOrHeardItems: storyOrHeardItems.length,
      activityDerivedRefs: activityEvidenceRows.length,
      eventDerivedRefs: eventEvidenceRows.length,
      deepHistoryRefs: deepEvidenceRows.length,
      memoryRefs: memoryEvidenceRows.length,
      fadingOrUncertainItems: fadingItems.length,
      daughterInheritedItems: daughterEntries.reduce(
        (sum, entry) => sum + entry.profile.items.filter((item) => item.livedStatus === "inherited_not_personally_lived").length,
        0,
      ),
      evidenceChips: evidenceRows.length,
      eventLinksChecked: linkAudit.eventLinksChecked,
      brokenEventLinks: linkAudit.brokenEventLinks.length,
      renderedChronicleLinksChecked: linkAudit.renderedChronicleLinksChecked,
      potentialUnresolvedChronicleTargets: linkAudit.potentialUnresolvedChronicleTargets,
      brokenChronicleLinks: linkAudit.brokenChronicleLinks.length,
      rawDebugHits: rawDebugHits.length,
      fakeCultureHits: fakeCultureHits.length,
      earlySystemHits: earlySystemHits.length,
      legacySkillHits: legacySkillHits.length,
      duplicateProseCount: duplicateProse.duplicateCount,
      maxKnowledgePayloadBytes: maxPayloadBytes,
      maxKnowledgePayloadKb: round2(maxPayloadBytes / 1024),
      maxKnowledgeItemPayloadBytes: maxItemPayloadBytes,
      maxKnowledgeItemPayloadKb: round2(maxItemPayloadBytes / 1024),
      maxItemsPerProfile,
      maxEvidencePerItem,
      deterministicProfilesChecked: Math.min(liveEntries.length, repeatEntries.length),
      projectionMutatedBands,
      regressionAuditFlagsPresent,
    },
    samples: {
      profiles: allEntries.slice(0, 5).map((entry) => ({
        kind: entry.kind,
        bandId: String(entry.band.id),
        title: entry.profile.overviewTitle,
        summary: entry.profile.overviewLines,
        items: entry.profile.items.slice(0, 5).map((item) => ({
          domain: item.domain,
          title: item.title,
          carrier: item.carrier,
          transmission: item.transmission,
          practicalStatus: item.practicalStatus,
          confidenceBand: item.confidenceBand,
          evidence: item.evidence.map((evidence) => evidence.label),
        })),
      })),
      rawDebugHits,
      codeLikeHits: codeLikeHits.slice(0, 8),
      fakeCultureHits,
      earlySystemHits,
      legacySkillHits,
      duplicateProseSamples: duplicateProse.samples,
      brokenEventLinks: linkAudit.brokenEventLinks,
      brokenChronicleLinks: linkAudit.brokenChronicleLinks,
    },
    sourceChecks,
    staticGuards,
    regressions: {
      note: "Existing regression audits are not recursively run inside this targeted audit; run the documented verification battery separately.",
      flagsPresent: regressionAuditFlagsPresent,
    },
    requiredChecks,
  };
}

const KNOWLEDGE_ECOLOGY_VALID_EVIDENCE_KINDS = new Set([
  "canonical_event",
  "deep_history",
  "activity_trip",
  "activity_summary",
  "place_memory",
  "route_memory",
  "crossing_memory",
  "reported_knowledge",
  "demography",
  "founding_snapshot",
  "residential_move",
]);

function selectKnowledgeEcologyBands(bands) {
  const selected = [];
  const add = (band) => {
    if (band !== undefined && !selected.some((entry) => entry.id === band.id)) {
      selected.push(band);
    }
  };
  const scored = [...bands].sort((left, right) =>
    scoreKnowledgeEcologyBand(right) - scoreKnowledgeEcologyBand(left) || compareBands(left, right));

  for (const band of scored.filter((entry) => (entry.recentIntraSeasonTrips?.length ?? 0) > 0).slice(0, 4)) add(band);
  for (const band of scored.filter((entry) => entry.deepHistory?.founding.kind === "fission_daughter").slice(0, 3)) add(band);
  for (const band of scored.filter((entry) => Object.keys(entry.travelCorridors).length > 0 || Object.keys(entry.crossingMemories).length > 0).slice(0, 4)) add(band);
  for (const band of scored.filter((entry) => (entry.reportedKnowledge?.reports.length ?? 0) > 0).slice(0, 2)) add(band);
  for (const band of scored) {
    add(band);
    if (selected.length >= 10) {
      break;
    }
  }

  return selected;
}

function scoreKnowledgeEcologyBand(band) {
  return (
    (band.deepHistory === undefined ? 0 : 12) +
    (band.deepHistory?.founding.kind === "fission_daughter" ? 14 : 0) +
    (band.deepHistory?.inheritedEraSummaries.length ?? 0) * 6 +
    (band.deepHistory?.inheritedEpisodes.length ?? 0) * 6 +
    (band.recentIntraSeasonTrips?.length ?? 0) * 4 +
    (band.activityLaborSummary?.activeActivityGroupCount ?? 0) * 3 +
    Object.keys(band.travelCorridors).length * 3 +
    Object.keys(band.crossingMemories).length * 3 +
    Object.keys(band.placeMemory).length * 0.4 +
    (band.reportedKnowledge?.reports.length ?? 0) * 2 +
    (band.recentResidentialMoveEvents?.length ?? 0) * 2
  );
}

function buildKnowledgeEcologyFixtures(modules, world, sourceBand) {
  if (sourceBand === undefined) {
    return [];
  }

  const fixtureBandId = `${String(sourceBand.id)}:knowledge-ecology-fixture`;
  const parentBandId = sourceBand.id;
  const fixtureTick = world.time.tick;
  const oldTime = {
    tick: Math.max(0, Number(fixtureTick) - 96),
    year: Math.max(0, world.time.year - 24),
    season: world.time.season,
  };
  const recentTime = {
    tick: fixtureTick,
    year: world.time.year,
    season: world.time.season,
  };
  const routeId = `route:knowledge-fixture:${String(sourceBand.id)}`;
  const tileA = sourceBand.position;
  const tileB = sourceBand.currentCampTileId ?? sourceBand.position;
  const activityTrip = makeKnowledgeFixtureTrip(sourceBand, world, tileB, "plant_gathering_group", "gathered_plant_food", "successful_observation", "confidence_refreshed");
  const waterTrip = makeKnowledgeFixtureTrip(sourceBand, world, tileA, "water_group", "water_information", "returned_with_information", "water_reliability_refreshed");
  const routeTrip = makeKnowledgeFixtureTrip(sourceBand, world, tileB, "memory_refresh_group", "route_information", "returned_with_information", "route_memory_refreshed");
  const riskTrip = makeKnowledgeFixtureTrip(sourceBand, world, tileA, "memory_refresh_group", "none", "failed_due_to_water_risk", "risk_suspicion_added");
  const inheritedEra = sourceBand.deepHistory?.eras.slice(-1)[0];
  const deepHistory = sourceBand.deepHistory === undefined
    ? undefined
    : {
      ...sourceBand.deepHistory,
      bandId: fixtureBandId,
      founding: {
        ...sourceBand.deepHistory.founding,
        bandId: fixtureBandId,
        kind: "fission_daughter",
        parentBandId,
        foundedAt: { ...sourceBand.deepHistory.founding.foundedAt, year: Math.max(0, world.time.year - 30) },
        parentPopulationBefore: sourceBand.size,
      },
      inheritedEraSummaries: inheritedEra === undefined
        ? [{
          sourceBandId: parentBandId,
          startYear: Math.max(0, world.time.year - 50),
          endYear: Math.max(0, world.time.year - 30),
          headline: "steady_years",
          populationEnd: sourceBand.size,
        }]
        : [{
          sourceBandId: parentBandId,
          startYear: inheritedEra.startYear,
          endYear: inheritedEra.endYear,
          headline: inheritedEra.headline,
          populationEnd: inheritedEra.populationEnd,
        }],
      inheritedEpisodes: (sourceBand.deepHistory?.episodes ?? []).slice(0, 2).map((episode) => ({
        ...episode,
        id: `knowledge-inherited:${episode.id}`,
        provenance: "inherited",
        inheritedFromBandId: parentBandId,
      })),
      ancestryLine: [{
        bandId: parentBandId,
        foundedYear: sourceBand.deepHistory?.founding.foundedAt.year ?? 0,
        kind: sourceBand.deepHistory?.founding.kind ?? "origin",
      }],
    };
  const fixtureBand = {
    ...sourceBand,
    id: fixtureBandId,
    parentBandId,
    deepHistory,
    recentIntraSeasonTrips: [activityTrip, waterTrip, routeTrip, riskTrip],
    activityLaborSummary: {
      ...(sourceBand.activityLaborSummary ?? {}),
      activeActivityGroupCount: 4,
      peopleAwayInActivityGroups: 10,
      peopleAtResidentialCenterEstimate: Math.max(1, Math.round(sourceBand.size) - 10),
      peopleByActivityType: [
        { taskGroupType: "plant_gathering_group", groupCount: 1, assignedPeopleEstimate: 4 },
        { taskGroupType: "water_group", groupCount: 1, assignedPeopleEstimate: 2 },
        { taskGroupType: "memory_refresh_group", groupCount: 2, assignedPeopleEstimate: 4 },
      ],
    },
    activityOutcomeSummary: {
      ...(sourceBand.activityOutcomeSummary ?? {}),
      successCount: 2,
      partialCount: 1,
      failedCount: 1,
      informationCount: 2,
      returnsByResourceKind: [
        { returnedResourceKind: "gathered_plant_food", count: 1, estimatedReturnValueTotal: 0.3 },
        { returnedResourceKind: "water_information", count: 1, estimatedReturnValueTotal: 0 },
        { returnedResourceKind: "route_information", count: 1, estimatedReturnValueTotal: 0 },
      ],
    },
    placeMemory: {
      ...sourceBand.placeMemory,
      [tileA]: {
        tileId: tileA,
        firstObservedAt: oldTime,
        lastObservedAt: recentTime,
        visitCount: 8,
        seasonsObserved: [world.time.season],
        lastKnownFoodEstimate: 0.5,
        lastKnownWaterStress: 0.1,
        lastKnownRiskEstimate: 0.2,
        valences: ["reliable", "return_place", "route_node"],
        attachment: 0.62,
        confidence: 0.68,
        reasonIds: [`knowledge-fixture:place:${String(sourceBand.id)}`],
        repeatedReturnCount: 5,
        isReturnPlace: true,
        lastReturnAt: recentTime,
        seasonalReturnPattern: [world.time.season],
      },
    },
    travelCorridors: {
      ...sourceBand.travelCorridors,
      [routeId]: {
        id: routeId,
        fromTileId: tileA,
        toTileId: tileB,
        useCount: 12,
        lastUsedAt: oldTime,
        intentKinds: ["return_to_known_place"],
        confidence: 0.72,
      },
    },
    crossingMemories: {
      ...sourceBand.crossingMemories,
      [`${String(tileA)}|${String(tileB)}:knowledge-fixture`]: {
        riverId: "knowledge-fixture-river",
        crossingTileA: tileA,
        crossingTileB: tileB,
        crossingClass: "ford_like",
        firstUsedAt: oldTime,
        lastUsedAt: oldTime,
        useCount: 3,
        successConfidence: 0.32,
        seasonalReliability: 0.42,
        riskMemory: 0.72,
        reasonIds: [`knowledge-fixture:crossing:${String(sourceBand.id)}`],
      },
    },
    contactMemories: {
      ...sourceBand.contactMemories,
      [parentBandId]: {
        otherBandId: parentBandId,
        firstContactAt: oldTime,
        lastContactAt: recentTime,
        contactCount: 3,
        peacefulContactCount: 2,
        strainedContactCount: 0,
        sharedUseCount: 1,
        avoidanceCount: 0,
        familiarity: 0.52,
        tension: 0.08,
        trustLikeTolerance: 0.5,
        relation: "parent_daughter",
        reasonIds: [`knowledge-fixture:contact:${String(sourceBand.id)}`],
      },
    },
    reportedKnowledge: {
      ...(sourceBand.reportedKnowledge ?? {}),
      reports: [{
        reportId: `knowledge-fixture-report:${String(sourceBand.id)}`,
        sourceBandId: parentBandId,
        receiverBandId: fixtureBandId,
        tickCreated: fixtureTick,
        tickReceived: fixtureTick,
        topic: "reliable_water",
        targetTileId: tileA,
        confidence: 0.48,
        freshness: 0.6,
        hops: 1,
        distortionLevel: "vague",
        trustBasis: "parent",
        receiverDisposition: "remembered_only",
        confirmationStatus: "unconfirmed",
        evidenceCount: 1,
        contradictionCount: 0,
        noHiddenTruth: true,
        noDirectUnlock: true,
        noGuaranteedTruth: true,
        noLanguageSystem: true,
        reasonIds: [`knowledge-fixture:report:${String(sourceBand.id)}`],
      }],
    },
  };
  const fixtureWorld = {
    ...world,
    bands: {
      ...world.bands,
      [fixtureBandId]: fixtureBand,
    },
  };

  return [{
    kind: "fixture:knowledge-domains",
    band: fixtureBand,
    profile: modules.knowledgeEcology.deriveKnowledgeEcologyProfile(fixtureWorld, fixtureBand),
    events: modules.eventSystem.deriveCanonicalEvents(fixtureWorld, fixtureBand),
    chronicle: modules.bandChronicle.deriveBandChronicle(fixtureWorld, fixtureBand),
  }];
}

function makeKnowledgeFixtureTrip(sourceBand, world, targetTileId, taskGroupType, returnedResourceKind, activityOutcome, memoryEffectType) {
  const reasonId = `knowledge-fixture:${String(sourceBand.id)}:${taskGroupType}:${activityOutcome}`;
  return {
    day: 10,
    tick: world.time.tick,
    season: world.time.season,
    sourceBandId: sourceBand.id,
    originTileId: sourceBand.position,
    targetTileId,
    taskGroupType,
    groupLabel: taskGroupType.replace(/_/g, " "),
    estimatedPeopleCount: 4,
    objective: taskGroupType === "water_group" ? "water_security" : taskGroupType === "memory_refresh_group" ? "memory_refresh" : "local_exploitation",
    objectiveLabel: "knowledge audit fixture",
    startDay: 10,
    endDay: 12,
    activityStatus: "completed_observation",
    distanceTiles: 2,
    estimatedDurationDays: 2,
    cause: taskGroupType === "water_group" ? "water_check" : taskGroupType === "memory_refresh_group" ? "memory_refresh" : "local_resource_use",
    movementType: taskGroupType === "water_group" ? "water_trip" : taskGroupType === "memory_refresh_group" ? "memory_refresh_trip" : "food_patch_trip",
    outcome: "returns_same_day",
    activityResult: activityOutcome,
    activityOutcome,
    activityOutcomeReasonIds: [reasonId],
    activityOutcomeSummary: "Projection fixture for knowledge ecology audit.",
    resourceReturn: {
      returnedResourceKind,
      estimatedReturnValue: 0,
      confidence: 0.5,
      reasonIds: [reasonId],
    },
    shadowSubsistence: {
      sameDayFoodValue: 0,
      delayedFoodValue: 0,
      consumedByEconomy: false,
      sameDayFoodOnly: true,
      delayedNotConsumed: true,
      waterAndInfoNotConsumed: true,
      plantsZeroed: true,
      noYieldCoupling: true,
      noCarryingCapacityMutation: true,
      noHiddenTruth: true,
      reasonIds: [reasonId],
    },
    activityMemoryEffect: {
      sourceBandId: sourceBand.id,
      sourceTripDay: 10,
      tick: world.time.tick,
      season: world.time.season,
      targetTileId,
      activityOutcome,
      effectType: memoryEffectType,
      effectSummary: "Knowledge audit fixture memory effect.",
      confidenceDelta: memoryEffectType === "risk_suspicion_added" ? -0.1 : 0.12,
      reasonIds: [reasonId],
      noHiddenTruth: true,
      targetKnownMemoryOnly: true,
      noNewResourceDiscovery: true,
      noFoodCoupling: true,
      noYieldCoupling: true,
      noCarryingCapacityCoupling: true,
      noPopulationChange: true,
      noStressChange: true,
      noSupportChange: true,
    },
    pathTiles: [sourceBand.position, targetTileId],
    tilesCrossed: 1,
    roundTripTiles: 2,
    activityDaysRepresented: 2,
    resultSummary: "Projection fixture only.",
    reasonIds: [reasonId],
    noResidentialRelocation: true,
    noYieldChange: true,
    noStressChange: true,
    noPopulationChange: true,
    noCarryingCapacityChange: true,
    noSupportChange: true,
    bandKnownTargetOnly: true,
  };
}

function collectKnowledgeEcologyNormalText(profile) {
  return [
    profile.overviewTitle,
    ...profile.overviewLines,
    ...profile.items.flatMap((item) => [
      item.title,
      item.summary,
      item.uncertainty ?? "",
      item.domain.replace(/_/g, " "),
      item.carrier.replace(/_/g, " "),
      item.transmission.replace(/_/g, " "),
      item.practicalStatus.replace(/_/g, " "),
      item.confidenceBand.replace(/_/g, " "),
      ...item.evidence.map((entry) => entry.label),
    ]),
  ].filter((entry) => typeof entry === "string" && entry.length > 0);
}

function findKnowledgeEcologyRawDebugHits(samples) {
  const rawPattern = /\b(?:knowledge|canonical-event|band|tile|reason|decision|stock|patch|event|route|era|episode|founding|activity):[a-z0-9]/i;
  const jsonPattern = /(?:^\s*[\[{]|["'][a-zA-Z0-9_]+["']\s*:)/;
  return samples
    .filter((sample) => rawPattern.test(sample) || jsonPattern.test(sample))
    .slice(0, 8);
}

function findKnowledgeEcologyDuplicateProse(entries) {
  let duplicateCount = 0;
  const samples = [];

  for (const entry of entries) {
    const seen = new Set();
    const lines = entry.profile.items
      .map((item) => `${item.title}: ${item.summary}`)
      .filter((line) => line.length > 0);

    for (const line of lines) {
      if (seen.has(line)) {
        duplicateCount += 1;
        if (samples.length < 6) {
          samples.push({ bandId: String(entry.band.id), sample: line.slice(0, 160) });
        }
      }
      seen.add(line);
    }
  }

  return { duplicateCount, samples };
}

function auditKnowledgeEcologyLinks(entries) {
  let eventLinksChecked = 0;
  let renderedChronicleLinksChecked = 0;
  let potentialUnresolvedChronicleTargets = 0;
  const brokenEventLinks = [];
  const brokenChronicleLinks = [];

  for (const entry of entries) {
    const eventIds = new Set(entry.events.events.map((event) => event.id));
    const pageIds = new Set(entry.chronicle.pages.map((page) => page.id));
    for (const item of entry.profile.items) {
      for (const eventId of item.relatedEventIds) {
        eventLinksChecked += 1;
        if (!eventIds.has(eventId)) {
          brokenEventLinks.push({ bandId: String(entry.band.id), itemId: item.id, eventId });
        }
      }
      for (const pageId of item.relatedChronicleLinkIds) {
        if (pageIds.has(pageId)) {
          renderedChronicleLinksChecked += 1;
        } else {
          potentialUnresolvedChronicleTargets += 1;
        }
      }
    }
  }

  return {
    eventLinksChecked,
    renderedChronicleLinksChecked,
    potentialUnresolvedChronicleTargets,
    brokenEventLinks: brokenEventLinks.slice(0, 8),
    brokenChronicleLinks: brokenChronicleLinks.slice(0, 8),
  };
}

function makeKnowledgeEcologyFingerprint(entries) {
  return JSON.stringify(entries
    .slice()
    .sort((left, right) => String(left.band.id).localeCompare(String(right.band.id)))
    .map((entry) => ({
      bandId: String(entry.band.id),
      title: entry.profile.overviewTitle,
      lines: entry.profile.overviewLines,
      items: entry.profile.items.map((item) => ({
        id: item.id,
        domain: item.domain,
        title: item.title,
        summary: item.summary,
        carrier: item.carrier,
        transmission: item.transmission,
        practicalStatus: item.practicalStatus,
        memoryScope: item.memoryScope,
        livedStatus: item.livedStatus,
        confidenceBand: item.confidenceBand,
        evidence: item.evidence.map((evidence) => ({
          kind: evidence.kind,
          label: evidence.label,
          scope: evidence.scope,
          livedStatus: evidence.livedStatus,
        })),
      })),
    })));
}

function countRowsBy(rows, selectKey) {
  return rows.reduce((counts, row) => {
    const key = selectKey(row);
    counts[key] = (counts[key] ?? 0) + 1;
    return counts;
  }, {});
}

function knowledgeEcologySourceChecks() {
  const knowledge = readFileSync(join(process.cwd(), "src/sim/agents/knowledgeEcology.ts"), "utf8");
  const knowledgeUi = readFileSync(join(process.cwd(), "src/ui/band/Knowledge.tsx"), "utf8");
  const bandPanel = readFileSync(join(process.cwd(), "src/ui/BandPanel.tsx"), "utf8");
  const technical = readFileSync(join(process.cwd(), "src/ui/band/Technical.tsx"), "utf8");
  const css = readFileSync(join(process.cwd(), "src/index.css"), "utf8");
  const graph = readFileSync(join(process.cwd(), "src/architecture/graphData.ts"), "utf8");
  const benchmark = readFileSync(join(process.cwd(), "scripts/simBenchmark.mjs"), "utf8");

  return {
    knowledgeProjectionExists:
      knowledge.includes("export function deriveKnowledgeEcologyProfile") &&
      knowledge.includes("KnowledgeEcologyProfile") &&
      knowledge.includes("KnowledgeEcologyItem") &&
      knowledge.includes("usesExistingActivityPartiesOnly"),
    knowledgeProjectionPure:
      knowledge.includes("deriveKnowledgeEcologyProfile") &&
      !knowledge.includes("applyKnowledgeEcology") &&
      !knowledge.includes("advanceKnowledgeEcology") &&
      !knowledge.includes("world.bands =") &&
      !knowledge.includes("band.knowledgeEcology") &&
      !knowledge.includes("Math.random"),
    legacyStartingSkillsIgnored:
      !knowledge.includes("technologies") &&
      !knowledge.includes("subsistenceModes") &&
      !/\b(?:basketry|wild_grain|wild grain|plant_tending|plant tending|basic foraging)\b/i.test(knowledge),
    noDuplicateTaskPartySystem:
      knowledge.includes("recentIntraSeasonTrips") &&
      knowledge.includes("activityOutcomeSummary") &&
      !knowledge.includes("createActivityParty") &&
      !knowledge.includes("spawnActivityParty"),
    knowledgeTabExists:
      bandPanel.includes('id: "knowledge"') &&
      bandPanel.includes('label: "Knowledge"') &&
      bandPanel.includes("<Knowledge"),
    knowledgeCardsCompact:
      knowledgeUi.includes("Learning record") &&
      knowledgeUi.includes("knowledge-card-grid") &&
      knowledgeUi.includes("<details") &&
      css.includes("knowledge-card-grid") &&
      css.includes("knowledge-evidence-chip"),
    eventChronicleLinkButtonsExist:
      knowledgeUi.includes("See events behind this") &&
      knowledgeUi.includes("Open Chronicle passage"),
    knowledgeUiNoRawDump:
      !knowledgeUi.includes("JSON.stringify") &&
      !knowledgeUi.includes("Object.entries(item)") &&
      !knowledgeUi.includes("sourceId") &&
      !knowledgeUi.includes("reasonIds"),
    technicalProofExists:
      technical.includes("Knowledge ecology substrate") &&
      technical.includes("deriveKnowledgeEcologyProfile") &&
      technical.includes("existingActivityPartiesOnly") &&
      technical.includes("payload estimate"),
    graphNodeExists:
      graph.includes('id: "knowledgeEcology"') &&
      graph.includes("observe-only projection (LEARNING / TRANSMISSION / KNOWLEDGE ECOLOGY / ACTIVITY-PARTIES-1)") &&
      graph.includes("existing activity-party trips"),
    chronicleIntegrationInspected:
      graph.includes("Chronicle integration was inspected; this pass avoids new Chronicle prose"),
    auditFlagWired:
      benchmark.includes("targetedKnowledgeEcologyActivityPartiesAudit") &&
      benchmark.includes("--targeted-knowledge-ecology-activity-parties-audit") &&
      benchmark.includes("runTargetedKnowledgeEcologyActivityPartiesAudit"),
    regressionAuditFlagsPresent:
      benchmark.includes("--targeted-band-identity-ui-audit") &&
      benchmark.includes("--targeted-event-system-ui-audit") &&
      benchmark.includes("--targeted-deep-time-history-audit") &&
      benchmark.includes("--targeted-deep-time-chronicle-ui-audit") &&
      benchmark.includes("--targeted-ui-readability-polish-1c-audit") &&
      benchmark.includes("--targeted-whole-ui-readability-history-fun-audit") &&
      benchmark.includes("--targeted-band-chronicle-foundation-audit") &&
      benchmark.includes("--targeted-band-chronicle-wiki-expansion-audit") &&
      benchmark.includes("--targeted-specific-memory-referents-audit"),
    noFakeLoreInKnowledgeUi:
      !/\b(religion|myth|sacred|ritual|civilization|nation|king|temple|war|taboo|worldview)\b/i.test(knowledgeUi),
    noEarlySystemsImplemented:
      !knowledge.includes("derivePractice") &&
      !knowledge.includes("applyPractice") &&
      !knowledge.includes("problemFraming") &&
      !knowledge.includes("taboo") &&
      !knowledge.includes("worldview") &&
      !knowledge.includes("agriculture") &&
      !knowledge.includes("domestication") &&
      !knowledge.includes("territory"),
  };
}

function runKnowledgeEcologyStaticGuards() {
  const storageGuards = runStorageSuitabilityStaticGuards();
  const simRoot = join(process.cwd(), "src/sim");
  const decisionFiles = [
    ...collectSourceFiles(join(simRoot, "rules")),
    ...collectSourceFiles(join(simRoot, "tick")),
  ];
  const knowledgeEcologyRefsInDecisionPathFiles = decisionFiles
    .filter((file) => /deriveKnowledgeEcologyProfile|knowledgeEcology|KnowledgeEcology/.test(readFileSync(file, "utf8")))
    .map((file) => file.replace(`${process.cwd()}/`, ""));
  const bandIdentityRefsInDecisionPathFiles = decisionFiles
    .filter((file) => /deriveBandIdentityProfile|bandIdentity|BandIdentity/.test(readFileSync(file, "utf8")))
    .map((file) => file.replace(`${process.cwd()}/`, ""));
  const eventSystemRefsInDecisionPathFiles = decisionFiles
    .filter((file) => /deriveCanonicalEvents|eventSystem|canonical-event/.test(readFileSync(file, "utf8")))
    .map((file) => file.replace(`${process.cwd()}/`, ""));

  return {
    ...storageGuards,
    knowledgeEcologyRefsInDecisionPaths: knowledgeEcologyRefsInDecisionPathFiles.length,
    knowledgeEcologyRefsInDecisionPathFiles,
    bandIdentityRefsInDecisionPaths: bandIdentityRefsInDecisionPathFiles.length,
    bandIdentityRefsInDecisionPathFiles,
    eventSystemRefsInDecisionPaths: eventSystemRefsInDecisionPathFiles.length,
    eventSystemRefsInDecisionPathFiles,
  };
}

// ---------------------------------------------------------------------------
// MATERIAL AFFORDANCE + FORAGER ENGINEERING CATALOG-1 targeted audit.
// Verifies a bounded selected-band projection of practical material
// possibilities before problem framing, experimentation, skills, or culture.
// ---------------------------------------------------------------------------

function runTargetedMaterialAffordanceForagerEngineeringAudit(modules, options) {
  const years = 100;
  const command = "node scripts/simBenchmark.mjs --targeted-material-affordance-forager-engineering-audit --json";
  const runOptions = {
    ...options,
    reportBand: false,
    probeAudit: false,
    returnWorld: true,
    fast: true,
    deterministic: false,
  };
  const baseRun = runBenchmark(
    modules,
    { scenario: "baseline", years, ticks: undefined },
    runOptions,
  );
  const repeatRun = runBenchmark(
    modules,
    { scenario: "baseline", years, ticks: undefined },
    runOptions,
  );
  const projectedWorld = projectPerformancePlayabilityWorld(modules, baseRun.world);
  const repeatProjectedWorld = projectPerformancePlayabilityWorld(modules, repeatRun.world);
  const activeBands = Object.values(projectedWorld.bands).filter(isActiveBand).sort(compareBands);
  const selectedBands = selectMaterialAffordanceBands(modules, projectedWorld, activeBands);
  const preDerivationSnapshot = JSON.stringify(selectedBands);
  const liveEntries = selectedBands.map((band) => ({
    kind: "live",
    band,
    profile: modules.materialAffordance.deriveMaterialAffordanceProfile(projectedWorld, band),
    knowledge: modules.knowledgeEcology.deriveKnowledgeEcologyProfile(projectedWorld, band),
    events: modules.eventSystem.deriveCanonicalEvents(projectedWorld, band),
  }));
  const projectionMutatedBands = preDerivationSnapshot !== JSON.stringify(selectedBands);
  const repeatEntries = selectedBands
    .map((band) => repeatProjectedWorld.bands[band.id])
    .filter((band) => band !== undefined)
    .map((band) => ({
      kind: "repeat",
      band,
      profile: modules.materialAffordance.deriveMaterialAffordanceProfile(repeatProjectedWorld, band),
      knowledge: modules.knowledgeEcology.deriveKnowledgeEcologyProfile(repeatProjectedWorld, band),
      events: modules.eventSystem.deriveCanonicalEvents(repeatProjectedWorld, band),
    }));
  const fixtures = buildMaterialAffordanceFixtures(modules, projectedWorld, selectedBands[0]);
  const allEntries = [...liveEntries, ...fixtures];
  const items = allEntries.flatMap((entry) => entry.profile.items.map((item) => ({ entry, item })));
  const evidenceRows = items.flatMap(({ entry, item }) =>
    item.evidence.map((evidence) => ({ entry, item, evidence })));
  const normalTextSamples = allEntries.flatMap((entry) => collectMaterialAffordanceNormalText(entry.profile));
  const rawDebugHits = findMaterialAffordanceRawDebugHits(normalTextSamples);
  const forbiddenLanguageHits = normalTextSamples
    .filter((sample) => /\b(?:unlock|unlocked|tech tree|technology|researched|level|bonus|civilization advancement|tribal tech|invented)\b/i.test(sample))
    .slice(0, 8);
  const fakeSkillHits = normalTextSamples
    .filter((sample) => /\b(?:learned basketry|learned shelter|invented|became engineers|mastery|acquired skill|practice discovered|skill granted|automatic improvement)\b/i.test(sample))
    .slice(0, 8);
  const legacySkillHits = normalTextSamples
    .filter((sample) => /\b(?:basketry|wild grain|plant tending|basic foraging|foraging skill)\b/i.test(sample))
    .slice(0, 8);
  const sourceChecks = materialAffordanceSourceChecks();
  const staticGuards = runMaterialAffordanceStaticGuards();
  const linkAudit = auditMaterialAffordanceLinks(allEntries);
  const familyNames = [
    "carrying_containers_cordage",
    "shelter_camp_structure",
    "fire_hearth_fuel",
    "food_processing",
    "water_edge_trapping",
    "route_crossing_engineering",
    "tool_cutting_scraping_digging",
    "visual_mineral_adhesive",
    "camp_organization_care",
  ];
  const familiesSeen = [...new Set(items.map(({ item }) => item.family))].sort();
  const statusesSeen = [...new Set(items.map(({ item }) => item.status))].sort();
  const strengthsSeen = [...new Set(items.map(({ item }) => item.strength))].sort();
  const materialBasisRefs = evidenceRows.filter(({ evidence }) =>
    evidence.kind === "material" || evidence.kind === "terrain_hydrography");
  const knowledgeRefs = evidenceRows.filter(({ evidence }) => evidence.sourceSystem === "knowledge_ecology");
  const activityRefs = evidenceRows.filter(({ evidence }) =>
    evidence.sourceSystem === "activity_party" || evidence.sourceSystem === "activity_summary");
  const eventRefs = evidenceRows.filter(({ evidence }) => evidence.sourceSystem === "canonical_event");
  const memoryRefs = evidenceRows.filter(({ evidence }) =>
    evidence.sourceSystem === "place_memory" ||
    evidence.sourceSystem === "route_memory" ||
    evidence.sourceSystem === "crossing_memory" ||
    evidence.sourceSystem === "residential_move" ||
    evidence.sourceSystem === "body_camp_logistics" ||
    evidence.sourceSystem === "foraging_adaptation");
  const repetitionRefs = evidenceRows.filter(({ evidence }) => evidence.sourceSystem === "foraging_adaptation");
  const daughterEntries = allEntries.filter((entry) =>
    entry.band.parentBandId !== undefined || entry.band.deepHistory?.founding?.kind === "fission_daughter");
  const inheritedEvidenceRows = evidenceRows.filter(({ evidence }) => evidence.livedBasis === "inherited_not_lived");
  const livedEvidenceRows = evidenceRows.filter(({ evidence }) => evidence.livedBasis === "lived" || evidence.livedBasis === "mixed");
  const constraints = items.flatMap(({ entry, item }) => item.constraints.map((constraint) => ({ entry, item, constraint })));
  const futureHooks = items.flatMap(({ entry, item }) => item.futureHooks.map((hook) => ({ entry, item, hook })));
  const maxProfilePayload = Math.max(0, ...allEntries.map((entry) => entry.profile.technicalProof.payloadBytesEstimate));
  const maxItemsPerProfile = Math.max(0, ...allEntries.map((entry) => entry.profile.items.length));
  const maxEvidencePerItem = Math.max(0, ...items.map(({ item }) => item.evidence.length));
  const maxHooksPerItem = Math.max(0, ...items.map(({ item }) => item.futureHooks.length));
  const maxConstraintsPerItem = Math.max(0, ...items.map(({ item }) => item.constraints.length));
  const maxMaterialBasisPerItem = Math.max(0, ...items.map(({ item }) => item.materialBasis.length));
  const maxKnowledgeBasisPerItem = Math.max(0, ...items.map(({ item }) => item.knowledgeBasis.length));
  const maxActivityEventBasisPerItem = Math.max(0, ...items.map(({ item }) => item.activityEventBasis.length));

  const requiredChecks = {
    affordanceProfilesExistForSampledBands:
      liveEntries.length > 0 &&
      liveEntries.every((entry) => entry.profile.projectionMode === "selected_band_projection" && entry.profile.items.length > 0),
    affordanceItemsStructuredNotProseOnly:
      items.length > 0 &&
      items.every(({ item }) =>
        item.id.startsWith("material-affordance:") &&
        item.family.length > 0 &&
        item.publicLabel.length > 0 &&
        item.meaning.length > 0 &&
        item.possibleOnly === true &&
        item.noPracticeDiscovery === true &&
        item.noSkillGranted === true &&
        item.noDecisionInfluence === true &&
        Array.isArray(item.evidence) &&
        Array.isArray(item.futureHooks) &&
        Array.isArray(item.constraints)),
    requiredFamiliesRepresented:
      familyNames.every((family) => familiesSeen.includes(family)),
    statusStrengthConfidencePresent:
      statusesSeen.length >= 3 &&
      strengthsSeen.includes("weak") &&
      items.every(({ item }) => item.status.length > 0 && item.strength.length > 0 && Number.isFinite(item.confidence)),
    materialBasisWhereSupported:
      materialBasisRefs.length > 0 &&
      liveEntries.some((entry) => entry.profile.materialBasisCount > 0),
    knowledgeActivityEventBasisRepresented:
      knowledgeRefs.length > 0 &&
      activityRefs.length > 0 &&
      eventRefs.length > 0 &&
      liveEntries.every((entry) => entry.profile.activityEvidenceCount >= 0),
    constraintsRepresented:
      constraints.length > 0 &&
      liveEntries.some((entry) => entry.profile.constraintCount > 0),
    futureHooksWithoutPractices:
      futureHooks.length > 0 &&
      items.every(({ item }) => item.futureHooks.every((hook) => /question|later/i.test(hook))) &&
      items.every(({ item }) => item.noPracticeDiscovery === true && item.noSkillGranted === true),
    publicUiSaysPossibleNotLearned:
      sourceChecks.affordanceTabExists &&
      sourceChecks.publicNotLearnedWarning &&
      sourceChecks.publicCardsExist,
    noTechTreeUnlockLanguage:
      forbiddenLanguageHits.length === 0 &&
      sourceChecks.publicUiNoForbiddenLanguage,
    legacyStartingSkillsNotPrimaryProof:
      legacySkillHits.length === 0 &&
      sourceChecks.legacyStartingSkillsIgnored &&
      liveEntries.every((entry) => entry.profile.integrity.ignoresLegacyStartingSkills === true) &&
      liveEntries.every((entry) => entry.profile.technicalProof.legacyStartingSkillProofCount === 0),
    knowledgeEcologyUsedAsSafeSource:
      knowledgeRefs.length > 0 &&
      sourceChecks.knowledgeEcologyImported,
    activityPartyEvidenceUsedOrExplicitlyCounted:
      activityRefs.length > 0 &&
      liveEntries.every((entry) => entry.profile.technicalProof.activityPartyEvidenceCount >= 0),
    eventEvidenceUsedWhereApplicable:
      eventRefs.length > 0 &&
      linkAudit.brokenEventEvidence.length === 0,
    inheritedVsLivedBasisSeparated:
      liveEntries.every((entry) => entry.profile.integrity.inheritedSeparated === true) &&
      livedEvidenceRows.length > 0 &&
      (inheritedEvidenceRows.length > 0 || sourceChecks.inheritedGuardExists),
    daughterBandsDoNotInheritPracticedAffordance:
      liveEntries.every((entry) => entry.profile.integrity.daughterAffordanceIsNotPracticedInheritance === true) &&
      (daughterEntries.length > 0 || sourceChecks.daughterGuardExists),
    publicUiNoRawIdsJsonDebug:
      rawDebugHits.length === 0 &&
      sourceChecks.publicUiNoRawDump,
    technicalUiExposesCountsCapsProvenancePayload:
      sourceChecks.technicalProofExists &&
      liveEntries.every((entry) => entry.profile.caps.capsHeld === true && entry.profile.technicalProof.payloadBytesEstimate > 0),
    chronicleIntegrationInspectedOrIntentionallySkipped:
      liveEntries.every((entry) =>
        entry.profile.chronicleIntegration.mode === "inspected_skipped" &&
        entry.profile.chronicleIntegration.brokenRenderedLinks === 0),
    eventKnowledgeChronicleLinksNotBroken:
      linkAudit.brokenEventEvidence.length === 0 &&
      linkAudit.brokenKnowledgeEvidence.length === 0 &&
      linkAudit.brokenChronicleLinks === 0,
    affordanceDoesNotEnterDecisionPaths:
      staticGuards.materialAffordanceRefsInDecisionPaths === 0 &&
      liveEntries.every((entry) => entry.profile.integrity.noDecisionInfluence === true),
    noEarlyPracticeSkillProblemCultureSystems:
      fakeSkillHits.length === 0 &&
      sourceChecks.noEarlySystemsImplemented &&
      liveEntries.every((entry) =>
        entry.profile.integrity.noPracticeDiscovery === true &&
        entry.profile.integrity.noProblemFraming === true &&
        entry.profile.integrity.noSkillOrAdaptationSystem === true &&
        entry.profile.integrity.noCultureSystem === true),
    deterministicOutput:
      makeMaterialAffordanceFingerprint(liveEntries) === makeMaterialAffordanceFingerprint(repeatEntries),
    payloadsAndListsBounded:
      maxProfilePayload > 0 &&
      maxProfilePayload < 45_000 &&
      maxItemsPerProfile <= 9 &&
      maxEvidencePerItem <= 5 &&
      maxHooksPerItem <= 4 &&
      maxConstraintsPerItem <= 4 &&
      maxMaterialBasisPerItem <= 4 &&
      maxKnowledgeBasisPerItem <= 4 &&
      maxActivityEventBasisPerItem <= 4,
    regressionAuditFlagsPresent:
      sourceChecks.regressionAuditFlagsPresent,
    observeOnlyBehaviorEconomyUnchanged:
      makeDeterminismFingerprint(baseRun.summary) === makeDeterminismFingerprint(repeatRun.summary) &&
      projectionMutatedBands === false &&
      staticGuards.materialAffordanceRefsInDecisionPaths === 0,
  };
  const passedCount = Object.values(requiredChecks).filter(Boolean).length;
  const failedChecks = Object.entries(requiredChecks)
    .filter(([, passed]) => passed !== true)
    .map(([name]) => name);
  const verdict = failedChecks.length === 0 ? "pass" : "review";

  return {
    check: "MATERIAL AFFORDANCE + FORAGER ENGINEERING CATALOG-1 targeted audit",
    verdict,
    command,
    methodology: {
      scenario: "baseline",
      years,
      selectedBandRule: "active bands scored for material/terrain evidence, resource memories, activity parties, canonical events, route/crossing/place memory, body/camp logistics, and repetition signals",
      fixtureNote: "One projection-only fixture exercises existing activity-party and activity-summary evidence when the sampled live snapshot has no current activity-party records.",
      projectionMode: "pure selected-band projection; not stored on Band and not imported by decision paths",
      uiLayer: "src/ui/band/Affordances.tsx selected-band tab plus Technical Material affordance substrate group",
      chronicleIntegration: "Chronicle was inspected and intentionally skipped for new prose; no rendered Chronicle affordance links are created in this pass.",
      regressionNote: "Existing accepted audits are not recursively run inside this audit; run the documented verification battery separately.",
    },
    checkSummary: {
      passed: passedCount,
      failed: failedChecks.length,
      total: Object.keys(requiredChecks).length,
      failedChecks,
    },
    metrics: {
      bandsSampled: selectedBands.length,
      fixtureProfiles: fixtures.length,
      liveAffordanceProfiles: liveEntries.length,
      affordanceProfiles: allEntries.length,
      affordanceItems: items.length,
      itemsByFamily: countRowsBy(items, ({ item }) => item.family),
      itemsByStatus: countRowsBy(items, ({ item }) => item.status),
      itemsByStrength: countRowsBy(items, ({ item }) => item.strength),
      materialBasisRefs: materialBasisRefs.length,
      knowledgeRefs: knowledgeRefs.length,
      activityRefs: activityRefs.length,
      eventRefs: eventRefs.length,
      memoryRefs: memoryRefs.length,
      repetitionRefs: repetitionRefs.length,
      inheritedBasisRefs: inheritedEvidenceRows.length,
      livedBasisRefs: livedEvidenceRows.length,
      daughterProfiles: daughterEntries.length,
      constraints: constraints.length,
      futureHooks: futureHooks.length,
      brokenLinks: linkAudit.brokenEventEvidence.length + linkAudit.brokenKnowledgeEvidence.length + linkAudit.brokenChronicleLinks,
      brokenEventEvidence: linkAudit.brokenEventEvidence.length,
      brokenKnowledgeEvidence: linkAudit.brokenKnowledgeEvidence.length,
      brokenChronicleLinks: linkAudit.brokenChronicleLinks,
      rawDebugHits: rawDebugHits.length,
      fakeSkillHits: fakeSkillHits.length,
      techTreeLanguageHits: forbiddenLanguageHits.length,
      legacySkillHits: legacySkillHits.length,
      maxProfilePayload,
      maxProfilePayloadKb: round2(maxProfilePayload / 1024),
      maxItemsPerProfile,
      maxEvidencePerItem,
      maxHooksPerItem,
      maxConstraintsPerItem,
      maxMaterialBasisPerItem,
      maxKnowledgeBasisPerItem,
      maxActivityEventBasisPerItem,
      decisionPathRefs: staticGuards.materialAffordanceRefsInDecisionPaths,
      projectionMutatedBands,
    },
    samples: {
      profiles: allEntries.slice(0, 5).map((entry) => ({
        kind: entry.kind,
        bandId: String(entry.band.id),
        title: entry.profile.overviewTitle,
        summary: entry.profile.overviewLines,
        items: entry.profile.items.map((item) => ({
          family: item.family,
          label: item.publicLabel,
          status: item.status,
          strength: item.strength,
          evidence: item.evidence.map((evidence) => evidence.label),
          futureHooks: item.futureHooks,
          constraints: item.constraints.map((constraint) => constraint.label),
        })),
      })),
      rawDebugHits,
      forbiddenLanguageHits,
      fakeSkillHits,
      legacySkillHits,
      brokenEventEvidence: linkAudit.brokenEventEvidence,
      brokenKnowledgeEvidence: linkAudit.brokenKnowledgeEvidence,
      materialAffordanceRefsInDecisionPathFiles: staticGuards.materialAffordanceRefsInDecisionPathFiles,
    },
    sourceChecks,
    staticGuards,
    requiredChecks,
  };
}

function buildMaterialAffordanceFixtures(modules, world, sourceBand) {
  if (sourceBand === undefined) {
    return [];
  }

  const fixtureBandId = `${String(sourceBand.id)}:material-affordance-fixture`;
  const fixtureBase = {
    ...sourceBand,
    id: fixtureBandId,
  };
  const targetTileId = sourceBand.currentCampTileId ?? sourceBand.position;
  const trip = makeKnowledgeFixtureTrip(
    fixtureBase,
    world,
    targetTileId,
    "plant_gathering_group",
    "gathered_plant_food",
    "successful_observation",
    "confidence_refreshed",
  );
  const fixtureBand = {
    ...fixtureBase,
    recentIntraSeasonTrips: [trip],
    activityOutcomeSummary: {
      bandId: fixtureBandId,
      day: 10,
      tick: world.time.tick,
      season: world.time.season,
      outcomesByType: [{ outcome: "successful_observation", count: 1 }],
      outcomesByTaskType: [{ taskGroupType: "plant_gathering_group", outcome: "successful_observation", count: 1 }],
      returnsByResourceKind: [{ returnedResourceKind: "gathered_plant_food", count: 1, estimatedReturnValueTotal: 0.24 }],
      successCount: 1,
      partialCount: 0,
      failedCount: 0,
      informationCount: 1,
      noEffectCount: 0,
      maxEstimatedReturnValue: 0.24,
      consumedByEconomy: false,
      noYieldCoupling: true,
      noCarryingCapacityCoupling: true,
      noPopulationChange: true,
      noStressChange: true,
      noSupportChange: true,
    },
    activityLaborSummary: {
      ...(sourceBand.activityLaborSummary ?? {}),
      bandId: fixtureBandId,
      day: 10,
      tick: world.time.tick,
      season: world.time.season,
      totalPeople: sourceBand.size,
      workingAdults: sourceBand.demography.workingAdults,
      activeActivityGroupCount: Math.max(1, sourceBand.activityLaborSummary?.activeActivityGroupCount ?? 0),
      peopleAssignedToActivityGroups: Math.max(2, sourceBand.activityLaborSummary?.peopleAssignedToActivityGroups ?? 0),
      peopleAwayInActivityGroups: Math.max(2, sourceBand.activityLaborSummary?.peopleAwayInActivityGroups ?? 0),
      peopleAtResidentialCenterEstimate: Math.max(1, sourceBand.size - 2),
      peopleByActivityType: [{ taskGroupType: "plant_gathering_group", groupCount: 1, assignedPeopleEstimate: 2 }],
      recentActivityGroupSummaries: [],
      cappedAllocation: false,
      impossibleOverAllocationCount: 0,
      allocationConfidence: "estimated_only",
      noFoodCoupling: true,
      noYieldCoupling: true,
      noCarryingCapacityCoupling: true,
      noPopulationChange: true,
      noStressChange: true,
    },
  };
  const fixtureWorld = {
    ...world,
    bands: {
      ...world.bands,
      [fixtureBandId]: fixtureBand,
    },
  };

  return [{
    kind: "fixture:activity-evidence",
    band: fixtureBand,
    profile: modules.materialAffordance.deriveMaterialAffordanceProfile(fixtureWorld, fixtureBand),
    knowledge: modules.knowledgeEcology.deriveKnowledgeEcologyProfile(fixtureWorld, fixtureBand),
    events: modules.eventSystem.deriveCanonicalEvents(fixtureWorld, fixtureBand),
  }];
}

function selectMaterialAffordanceBands(modules, world, bands) {
  const selected = [];
  const add = (band) => {
    if (band !== undefined && !selected.some((entry) => entry.id === band.id)) {
      selected.push(band);
    }
  };
  const scored = [...bands].sort((left, right) =>
    scoreMaterialAffordanceBand(modules, world, right) - scoreMaterialAffordanceBand(modules, world, left) || compareBands(left, right));

  for (const band of scored.filter((entry) => (entry.recentIntraSeasonTrips?.length ?? 0) > 0).slice(0, 3)) add(band);
  for (const band of scored.filter((entry) => Object.keys(entry.crossingMemories).length > 0 || Object.keys(entry.travelCorridors).length > 0).slice(0, 3)) add(band);
  for (const band of scored.filter((entry) => entry.bodyCampLogistics !== undefined || entry.seasonalSupport !== undefined).slice(0, 2)) add(band);
  for (const band of scored.filter((entry) => entry.parentBandId !== undefined || entry.deepHistory?.founding?.kind === "fission_daughter").slice(0, 2)) add(band);
  for (const band of scored) {
    add(band);
    if (selected.length >= 8) {
      break;
    }
  }

  return selected;
}

function scoreMaterialAffordanceBand(modules, world, band) {
  const events = modules.eventSystem.deriveCanonicalEvents(world, band);
  const resourceMemoryCount = Object.keys(band.resourceMemory?.patches ?? {}).length;
  const observedTileCount = Object.keys(band.knowledge.observedTiles ?? {}).length;
  return (
    resourceMemoryCount * 4 +
    Math.min(observedTileCount, 40) * 0.3 +
    (band.recentIntraSeasonTrips?.length ?? 0) * 4 +
    (band.activityOutcomeSummary?.informationCount ?? 0) * 2 +
    Object.keys(band.placeMemory).length * 1.5 +
    Object.keys(band.travelCorridors).length * 3 +
    Object.keys(band.crossingMemories).length * 4 +
    (band.recentResidentialMoveEvents?.length ?? 0) * 3 +
    events.events.length * 2 +
    (band.bodyCampLogistics === undefined ? 0 : 8) +
    (band.foragingAdaptation?.repetitionAffordances.length ?? 0) * 3 +
    (band.seasonalSupport === undefined ? 0 : 4) +
    (band.parentBandId === undefined ? 0 : 5)
  );
}

function collectMaterialAffordanceNormalText(profile) {
  return [
    profile.overviewTitle,
    ...profile.overviewLines,
    ...profile.items.flatMap((item) => [
      item.publicLabel,
      item.meaning,
      item.status.replace(/_/g, " "),
      item.strength,
      ...item.materialBasis,
      ...item.knowledgeBasis,
      ...item.activityEventBasis,
      ...item.futureHooks,
      ...item.constraints.map((constraint) => constraint.label),
      ...item.evidence.map((evidence) => evidence.label),
    ]),
  ].filter((entry) => typeof entry === "string" && entry.length > 0);
}

function findMaterialAffordanceRawDebugHits(samples) {
  const rawPattern = /\b(?:material-affordance|knowledge:|canonical-event|band|tile|reason|patch|route|event):[a-z0-9]/i;
  const jsonPattern = /(?:^\s*[\[{]|["'][a-zA-Z0-9_]+["']\s*:)/;
  return samples
    .filter((sample) => rawPattern.test(sample) || jsonPattern.test(sample))
    .slice(0, 8);
}

function auditMaterialAffordanceLinks(entries) {
  const brokenEventEvidence = [];
  const brokenKnowledgeEvidence = [];
  let brokenChronicleLinks = 0;

  for (const entry of entries) {
    const eventIds = new Set(entry.events.events.map((event) => event.id));
    const knowledgeIds = new Set(entry.knowledge.items.map((item) => item.id));

    for (const item of entry.profile.items) {
      for (const evidence of item.evidence) {
        if (evidence.sourceSystem === "canonical_event" && !eventIds.has(evidence.sourceId)) {
          brokenEventEvidence.push({ bandId: String(entry.band.id), itemId: item.id, eventId: evidence.sourceId });
        }
        if (evidence.sourceSystem === "knowledge_ecology" && !knowledgeIds.has(evidence.sourceId)) {
          brokenKnowledgeEvidence.push({ bandId: String(entry.band.id), itemId: item.id, knowledgeId: evidence.sourceId });
        }
      }
    }
    brokenChronicleLinks += entry.profile.chronicleIntegration.brokenRenderedLinks;
  }

  return {
    brokenEventEvidence: brokenEventEvidence.slice(0, 8),
    brokenKnowledgeEvidence: brokenKnowledgeEvidence.slice(0, 8),
    brokenChronicleLinks,
  };
}

function makeMaterialAffordanceFingerprint(entries) {
  return JSON.stringify(entries
    .slice()
    .sort((left, right) => String(left.band.id).localeCompare(String(right.band.id)))
    .map((entry) => ({
      bandId: String(entry.band.id),
      title: entry.profile.overviewTitle,
      lines: entry.profile.overviewLines,
      items: entry.profile.items.map((item) => ({
        id: item.id,
        family: item.family,
        label: item.publicLabel,
        status: item.status,
        strength: item.strength,
        confidence: item.confidence,
        materialBasis: item.materialBasis,
        knowledgeBasis: item.knowledgeBasis,
        activityEventBasis: item.activityEventBasis,
        futureHooks: item.futureHooks,
        constraints: item.constraints.map((constraint) => constraint.label),
        evidence: item.evidence.map((evidence) => ({
          kind: evidence.kind,
          sourceSystem: evidence.sourceSystem,
          label: evidence.label,
          livedBasis: evidence.livedBasis,
        })),
      })),
    })));
}

