function chooseKnownOrTripTile(band, trip) {
  const observed = Object.keys(band.knowledge.observedTiles ?? {});
  if (observed.includes(String(trip.targetTileId))) {
    return trip.targetTileId;
  }
  return observed[0] ?? trip.targetTileId ?? band.position;
}

