function buildTargetedPlantUseTestCase(eligibility, testing, name, context, overrides) {
  const memory = makeTargetedPlantEligibilityMemory(name, overrides);
  const candidate = eligibility.derivePlantUseEligibility(memory, context);
  const update = testing.applyPlantUseTestFromEligibility({ patchMemories: [memory], cap: 48 }, {
    bandId: "band:targeted-plant-use-test",
    tick: context.tick,
    season: context.season,
    memory,
    eligibility: candidate,
    foodStress: context.foodStress,
    perCapitaReturn: context.perCapitaReturn,
  });
  const updatedMemory = update.resourceKnowledgeState.patchMemories[0];

  return {
    name,
    context,
    eligibility: formatPlantUseEligibility(candidate),
    event: formatPlantUseTestEvent(update.event),
    memoryAfter: {
      confidence: updatedMemory.confidence,
      learning: updatedMemory.learning,
      plantObservation: updatedMemory.plantObservation === undefined ? undefined : {
        processingNeedSuspected: updatedMemory.plantObservation.suspectedProcessingNeed,
        safetyRiskSuspected: updatedMemory.plantObservation.suspectedSafetyRisk,
        observationCount: updatedMemory.plantObservation.observationCount,
      },
      useHistoryUnchanged: updatedMemory.useHistory.successfulUses === memory.useHistory.successfulUses &&
        updatedMemory.useHistory.lastYieldEstimate === memory.useHistory.lastYieldEstimate,
    },
  };
}

