// 2K.1F-A: distill the per-band/per-bucket probe accumulation into a distribution +
// usefulness + spam report. Benchmark-only.
function summarizeProbeAudit(audit) {
  const bands = Object.entries(audit.byBand).map(([id, b]) => {
    const targetCounts = Object.entries(b.distinctProbeTargets);
    const targets = targetCounts.map(([, n]) => n);
    const maxTargetRepeat = targets.length === 0 ? 0 : Math.max(...targets);
    const topTargetEntry = targetCounts.sort((a, c) => c[1] - a[1])[0];
    // Shannon entropy (bits) of the band's probe-target distribution — higher = more
    // diverse probing, ~0 = always the same target (2K.1G target-diversity metric).
    const total = targets.reduce((s, n) => s + n, 0);
    const entropy = total === 0 ? 0 : -targets.reduce((s, n) => {
      const p = n / total;
      return s + p * Math.log2(p);
    }, 0);
    return {
      id,
      decisions: b.decisions,
      probes: b.probes,
      probeShare: b.decisions === 0 ? 0 : Math.round((b.probes / b.decisions) * 1000) / 1000,
      probesStressed: b.probesStressed,
      probesComfortable: b.probesComfortable,
      probesWithBelief: b.probesWithBelief,
      probesTilesGained: b.probesTilesGained,
      probesZeroGain: b.probesZeroGain,
      gainRate: b.probes === 0 ? null : Math.round((b.probesTilesGained / b.probes) * 1000) / 1000,
      probesRepeatTarget: b.probesRepeatTarget,
      distinctProbeTargets: targetCounts.length,
      maxRepeatOnOneTarget: maxTargetRepeat,
      topProbeTarget: topTargetEntry === undefined ? null : { tile: topTargetEntry[0], count: topTargetEntry[1] },
      probeTargetEntropyBits: Math.round(entropy * 1000) / 1000,
      beliefSource: b.beliefSource,
      avgBestConf: b.probes === 0 ? null : Math.round((b.sumBestConf / b.probes) * 1000) / 1000,
      avgStressProbe: b.probes === 0 ? null : Math.round((b.sumStressProbe / b.probes) * 1000) / 1000,
    };
  }).sort((a, b) => b.probes - a.probes);

  const probeCounts = bands.map((b) => b.probes).sort((a, b) => a - b);
  const totalProbes = probeCounts.reduce((s, n) => s + n, 0);
  const median = probeCounts.length === 0 ? 0
    : probeCounts.length % 2 === 1 ? probeCounts[(probeCounts.length - 1) / 2]
    : (probeCounts[probeCounts.length / 2 - 1] + probeCounts[probeCounts.length / 2]) / 2;
  // How many top bands account for >=80% of all probes (concentration).
  let acc = 0, bandsFor80 = 0;
  for (const b of bands) { if (acc >= totalProbes * 0.8) break; acc += b.probes; bandsFor80 += 1; }
  const totalStressed = bands.reduce((s, b) => s + b.probesStressed, 0);
  const totalComfortable = bands.reduce((s, b) => s + b.probesComfortable, 0);
  const totalGain = bands.reduce((s, b) => s + b.probesTilesGained, 0);
  const totalZero = bands.reduce((s, b) => s + b.probesZeroGain, 0);
  // Bands stuck re-probing one target a lot (>=40 repeats on a single tile) — the
  // perpetual same-target loop the checkpoint targets.
  const sameTargetLoopBands = bands.filter((b) => b.maxRepeatOnOneTarget >= 40).length;
  const maxSameTargetRepeat = bands.reduce((m, b) => Math.max(m, b.maxRepeatOnOneTarget), 0);

  return {
    bandCount: bands.length,
    totalProbes,
    medianProbesPerBand: median,
    maxProbesByOneBand: bands[0]?.probes ?? 0,
    bandsAccountingFor80pct: bandsFor80,
    sameTargetLoopBands,
    maxSameTargetRepeat,
    probesStressed: totalStressed,
    probesComfortable: totalComfortable,
    stressedShare: totalProbes === 0 ? 0 : Math.round((totalStressed / totalProbes) * 1000) / 1000,
    probesTilesGained: totalGain,
    probesZeroGain: totalZero,
    overallGainRate: totalProbes === 0 ? null : Math.round((totalGain / totalProbes) * 1000) / 1000,
    perBucket: audit.byBucket,
    topBands: bands.slice(0, 6),
  };
}

function getTicksRequested(request) {
  if (request.ticks !== undefined && Number.isFinite(request.ticks)) {
    return Math.max(0, Math.floor(request.ticks));
  }

  return Math.max(0, Math.floor((request.years ?? 0) * 4));
}

function runTargetedTimeScaleCheck(modules) {
  const worlds = [
    { label: "map1", init: { kind: "map1" } },
    { label: "map2", init: { kind: "map2" } },
  ];
  const horizons = [
    {
      label: "1_season",
      modes: [
        { mode: "daily", steps: 90, elapsedDays: 90 },
        { mode: "weekly", steps: 13, elapsedDays: 91 },
        { mode: "monthly", steps: 3, elapsedDays: 90 },
        { mode: "seasonal", steps: 1, elapsedDays: 90 },
      ],
    },
    {
      label: "10_seasons",
      modes: [
        { mode: "daily", steps: 900, elapsedDays: 900 },
        { mode: "weekly", steps: 129, elapsedDays: 903 },
        { mode: "monthly", steps: 30, elapsedDays: 900 },
        { mode: "seasonal", steps: 10, elapsedDays: 900 },
      ],
    },
  ];
  const cases = [];

  for (const worldCase of worlds) {
    for (const horizon of horizons) {
      const seasonalBehavior = runTimeScaleCase(modules, worldCase.init, "seasonal", horizon.modes.find((mode) => mode.mode === "seasonal").steps);
      const modeResults = [];

      for (const modeCase of horizon.modes) {
        const first = runTimeScaleCase(modules, worldCase.init, modeCase.mode, modeCase.steps);
        const repeat = runTimeScaleCase(modules, worldCase.init, modeCase.mode, modeCase.steps);
        const deterministic = first.timeFingerprint === repeat.timeFingerprint;
        const behaviorMatchesSeasonal = first.behaviorFingerprint === seasonalBehavior.behaviorFingerprint;

        modeResults.push({
          mode: modeCase.mode,
          steps: modeCase.steps,
          elapsedDays: modeCase.elapsedDays,
          deterministic,
          behaviorMatchesSeasonal,
          runtimeMs: round2(first.runtimeMs),
          summary: first.summary,
          movementAudit: first.movementAudit,
          tripAudit: first.tripAudit,
        });
      }

      cases.push({
        world: worldCase.label,
        horizon: horizon.label,
        seasonalReference: seasonalBehavior.summary,
        modes: modeResults,
      });
    }
  }

  const deterministic = cases.every((entry) => entry.modes.every((mode) => mode.deterministic));
  const compatibilityMatches = cases.every((entry) => entry.modes.every((mode) => mode.behaviorMatchesSeasonal));

  return {
    check: "TIME-1C targeted time-scale/trip compatibility check",
    verdict: deterministic && compatibilityMatches ? "pass" : "fail",
    notes: [
      "daily/weekly/monthly advance calendar days; seasonal compatibility systems execute only when a season boundary is crossed",
      "TIME-1B added deterministic non-relocating intra-season trip records; seasonal mode aggregates the same records without UI/render updates",
      "TIME-1C runs those trips through the common DailyAction registry and enriches each record with source band, task group type, daily objective, tile-by-tile breadcrumb path (no teleport), a return/overnight/continues outcome, and movement taxonomy; band.position is still never moved by the daily layer",
      "TIME-1C-VIS marker glide/render-only layer is reverted; ACTIVITY-VIS reads real trip records through capped UI overlays, while this check audits the sim ledger and labor accounting",
      "weekly cases intentionally advance 91/903 days, so calendar day differs while behavior remains equal to the seasonal boundary state",
      "this remains a narrow trip-layer spike; daily residential decisions and resource/economy effects remain deferred (memory-refresh coupling gated behind an anti-omniscience audit)",
    ],
    deterministic,
    compatibilityMatches,
    cases,
  };
}

function runTimeScaleCase(modules, init, mode, steps) {
  const start = performance.now();
  const world = modules.stepSim(modules.initSimWorld(init), steps, mode);
  const runtimeMs = performance.now() - start;
  const summary = summarizeTimeScaleWorld(world);
  const movementAudit = summarizeTimeScaleMovement(world);
  const tripAudit = summarizeTimeScaleTrips(world);
  const behaviorFingerprint = makeTimeScaleBehaviorFingerprint(world);
  const timeFingerprint = JSON.stringify({
    time: {
      tick: Number(world.time.tick),
      day: Number(world.time.day ?? Number(world.time.tick) * 90),
      year: world.time.year,
      season: world.time.season,
      dayOfSeason: world.time.dayOfSeason ?? 0,
    },
    behavior: behaviorFingerprint,
  });

  return {
    world,
    runtimeMs,
    summary,
    movementAudit,
    tripAudit,
    behaviorFingerprint,
    timeFingerprint,
  };
}

function summarizeTimeScaleWorld(world) {
  const bands = Object.values(world.bands).sort(compareBands);
  const activeBands = bands.filter(isActiveBand);
  const fissionEvents = getUniqueFissionEvents(bands);

  return {
    tick: Number(world.time.tick),
    day: Number(world.time.day ?? Number(world.time.tick) * 90),
    year: world.time.year,
    season: world.time.season,
    dayOfSeason: world.time.dayOfSeason ?? 0,
    activeBands: activeBands.length,
    totalBands: bands.length,
    totalPopulation: toPopulationCount(getTotalPopulation(world)),
    fissions: fissionEvents.length,
    absorbedBands: bands.filter((band) => band.viability?.status === "absorbed").length,
    extinctBands: bands.filter((band) => band.viability?.status === "extinct").length,
    totalDecisions: world.decisionArchive.totalDecisions,
    totalMoveDecisions: world.decisionArchive.totalMoveDecisions,
    totalProbeDecisions: world.decisionArchive.totalProbeDecisions ?? 0,
    totalResourceScoutDecisions: world.decisionArchive.totalResourceScoutDecisions ?? 0,
  };
}

function summarizeTimeScaleMovement(world) {
  const bands = Object.values(world.bands).filter(isActiveBand);
  const seasonTicks = Math.max(1, Number(world.time.tick));
  let residentialMoves = 0;
  let totalTileDistance = 0;
  let maxTileDistance = 0;
  let oneTileMoves = 0;
  let multiTileMoves = 0;
  const causeKinds = new Set();
  const multiTileMoveSamples = [];

  for (const band of bands) {
    for (const move of band.movementHistory ?? []) {
      const distance = getTileDistance(world, move.fromTileId, move.toTileId) ?? 0;
      residentialMoves += 1;
      totalTileDistance += distance;
      maxTileDistance = Math.max(maxTileDistance, distance);

      if (distance === 1) {
        oneTileMoves += 1;
      } else if (distance > 1) {
        multiTileMoves += 1;
        if (multiTileMoveSamples.length < 5) {
          multiTileMoveSamples.push({
            bandId: String(band.id),
            tick: Number(move.tick),
            from: String(move.fromTileId),
            to: String(move.toTileId),
            distance,
            action: move.action.type,
            intentKind: move.intentKind,
            primaryReasonId: String(move.primaryReasonId),
          });
        }
      }

      if (move.intentKind !== undefined) {
        causeKinds.add(move.intentKind);
      } else {
        causeKinds.add(move.action.type);
      }
    }
  }

  return {
    activeBands: bands.length,
    bandsWithNoRecentResidentialMoves: bands.filter((band) => (band.movementHistory?.length ?? 0) === 0).length,
    residentialMoves,
    averageMovesPerBand: round4(residentialMoves / Math.max(1, bands.length)),
    averageTileDistancePerMove: round4(totalTileDistance / Math.max(1, residentialMoves)),
    averageTileDistancePerSeason: round4(totalTileDistance / seasonTicks),
    maxTileDistance,
    oneTileMoves,
    multiTileMoves,
    multiTileMoveSamples,
    causeKinds: [...causeKinds].sort(),
  };
}

function summarizeTimeScaleTrips(world) {
  const activeBands = Object.values(world.bands).filter(isActiveBand);
  const trips = activeBands.flatMap((band) =>
    (band.recentIntraSeasonTrips ?? []).map((trip) => ({
      bandId: String(band.id),
      day: Number(trip.day),
      tick: Number(trip.tick),
      season: trip.season,
      sourceBandId: String(trip.sourceBandId ?? band.id),
      from: String(trip.originTileId),
      to: String(trip.targetTileId),
      taskGroupType: trip.taskGroupType,
      groupLabel: trip.groupLabel,
      estimatedPeopleCount: trip.estimatedPeopleCount,
      objective: trip.objective,
      objectiveLabel: trip.objectiveLabel,
      startDay: Number(trip.startDay ?? trip.day),
      endDay: Number(trip.endDay ?? trip.day),
      activityStatus: trip.activityStatus,
      distanceTiles: trip.distanceTiles,
      estimatedDurationDays: trip.estimatedDurationDays,
      cause: trip.cause,
      movementType: trip.movementType,
      outcome: trip.outcome,
      activityResult: trip.activityResult,
      activityOutcome: trip.activityOutcome,
      activityOutcomeReasonIds: (trip.activityOutcomeReasonIds ?? []).map(String),
      activityOutcomeSummary: trip.activityOutcomeSummary,
      resourceReturn: trip.resourceReturn === undefined
        ? undefined
        : {
            returnedResourceKind: trip.resourceReturn.returnedResourceKind,
            estimatedReturnValue: trip.resourceReturn.estimatedReturnValue,
            returnConfidence: trip.resourceReturn.returnConfidence,
            consumedByEconomy: trip.resourceReturn.consumedByEconomy,
            noYieldCoupling: trip.resourceReturn.noYieldCoupling,
            noCarryingCapacityCoupling: trip.resourceReturn.noCarryingCapacityCoupling,
            noPopulationChange: trip.resourceReturn.noPopulationChange,
            noStressChange: trip.resourceReturn.noStressChange,
            noSupportChange: trip.resourceReturn.noSupportChange,
            reasonIds: (trip.resourceReturn.reasonIds ?? []).map(String),
          },
      activityMemoryEffect: trip.activityMemoryEffect === undefined
        ? undefined
        : serializeActivityMemoryEffect(trip.activityMemoryEffect),
      tilesCrossed: trip.tilesCrossed,
      roundTripTiles: trip.roundTripTiles,
      activityDaysRepresented: trip.activityDaysRepresented ?? 1,
      routeLength: (trip.pathTiles ?? []).length,
      pathContiguous: isContiguousPath(world, trip.pathTiles ?? []),
      resourceClassId: trip.resourceClassId,
      resultSummary: trip.resultSummary,
      reasonIds: trip.reasonIds.map(String),
      noResidentialRelocation: trip.noResidentialRelocation,
      noYieldChange: trip.noYieldChange,
      noStressChange: trip.noStressChange,
      noPopulationChange: trip.noPopulationChange,
      noCarryingCapacityChange: trip.noCarryingCapacityChange,
      noSupportChange: trip.noSupportChange,
      bandKnownTargetOnly: trip.bandKnownTargetOnly,
    })),
  );
  const causeCounts = {};
  const movementTypeCounts = {};
  const taskGroupTypeCounts = {};
  const objectiveCounts = {};
  const outcomeCounts = { returns_same_day: 0, overnight: 0, continues: 0 };
  const activityResultCounts = {};
  const activityOutcomeCounts = {};
  const activityOutcomeCountsByTaskType = {};
  const returnedResourceKindCounts = {};
  const activityMemoryEffectCounts = {};
  const activityMemoryTouchedPatchIds = new Set();
  const activityStatusCounts = {};
  let maxEstimatedReturnValue = 0;
  let resourceReturnConsumedByEconomyCount = 0;
  let resourceReturnGuardFailureCount = 0;
  let activityMemoryGuardFailureCount = 0;
  let activityMemoryHiddenTruthFailureCount = 0;
  let minActivityMemoryConfidenceDelta = 0;
  let maxActivityMemoryConfidenceDelta = 0;
  let sawActivityMemoryDelta = false;
  let totalDistanceTiles = 0;
  let totalEstimatedPeople = 0;
  let maxEstimatedPeople = 0;
  let totalTilesCrossed = 0;
  let totalRoundTripTiles = 0;
  let totalDailyTileDistance = 0;
  let maxDistanceTiles = 0;
  let maxRoundTripTiles = 0;
  let maxDailyTileDistance = 0;
  let maxDurationDays = 0;
  let maxRouteLength = 0;

  for (const trip of trips) {
    causeCounts[trip.cause] = (causeCounts[trip.cause] ?? 0) + 1;
    movementTypeCounts[trip.movementType] = (movementTypeCounts[trip.movementType] ?? 0) + 1;
    taskGroupTypeCounts[trip.taskGroupType] = (taskGroupTypeCounts[trip.taskGroupType] ?? 0) + 1;
    objectiveCounts[trip.objective] = (objectiveCounts[trip.objective] ?? 0) + 1;
    outcomeCounts[trip.outcome] = (outcomeCounts[trip.outcome] ?? 0) + 1;
    activityResultCounts[trip.activityResult] = (activityResultCounts[trip.activityResult] ?? 0) + 1;
    activityOutcomeCounts[trip.activityOutcome] = (activityOutcomeCounts[trip.activityOutcome] ?? 0) + 1;
    const taskOutcomeKey = `${trip.taskGroupType}:${trip.activityOutcome}`;
    activityOutcomeCountsByTaskType[taskOutcomeKey] = (activityOutcomeCountsByTaskType[taskOutcomeKey] ?? 0) + 1;
    activityStatusCounts[trip.activityStatus] = (activityStatusCounts[trip.activityStatus] ?? 0) + 1;
    const resourceReturn = trip.resourceReturn;
    if (resourceReturn !== undefined) {
      returnedResourceKindCounts[resourceReturn.returnedResourceKind] =
        (returnedResourceKindCounts[resourceReturn.returnedResourceKind] ?? 0) + 1;
      maxEstimatedReturnValue = Math.max(maxEstimatedReturnValue, resourceReturn.estimatedReturnValue ?? 0);
      resourceReturnConsumedByEconomyCount += resourceReturn.consumedByEconomy === true ? 1 : 0;
      resourceReturnGuardFailureCount += resourceReturn.consumedByEconomy === false &&
        resourceReturn.noYieldCoupling === true &&
        resourceReturn.noCarryingCapacityCoupling === true &&
        resourceReturn.noPopulationChange === true &&
        resourceReturn.noStressChange === true &&
        resourceReturn.noSupportChange === true
        ? 0
        : 1;
    }
    const activityMemoryEffect = trip.activityMemoryEffect;
    if (activityMemoryEffect !== undefined) {
      activityMemoryEffectCounts[activityMemoryEffect.effectType] =
        (activityMemoryEffectCounts[activityMemoryEffect.effectType] ?? 0) + 1;

      if (activityMemoryEffect.effectType !== "none" && activityMemoryEffect.patchId !== undefined) {
        activityMemoryTouchedPatchIds.add(activityMemoryEffect.patchId);
      }

      activityMemoryGuardFailureCount += isActivityMemoryEffectGuardClean(activityMemoryEffect) ? 0 : 1;
      activityMemoryHiddenTruthFailureCount += activityMemoryEffect.noHiddenTruth === true &&
        activityMemoryEffect.targetKnownMemoryOnly === true &&
        activityMemoryEffect.noNewResourceDiscovery === true
        ? 0
        : 1;

      if (!sawActivityMemoryDelta || activityMemoryEffect.confidenceDelta < minActivityMemoryConfidenceDelta) {
        minActivityMemoryConfidenceDelta = activityMemoryEffect.confidenceDelta;
      }

      if (!sawActivityMemoryDelta || activityMemoryEffect.confidenceDelta > maxActivityMemoryConfidenceDelta) {
        maxActivityMemoryConfidenceDelta = activityMemoryEffect.confidenceDelta;
      }

      sawActivityMemoryDelta = true;
    }
    const dailyTileDistance = trip.roundTripTiles / Math.max(1, trip.estimatedDurationDays);
    totalEstimatedPeople += trip.estimatedPeopleCount ?? 0;
    maxEstimatedPeople = Math.max(maxEstimatedPeople, trip.estimatedPeopleCount ?? 0);
    totalDistanceTiles += trip.distanceTiles;
    totalTilesCrossed += trip.tilesCrossed;
    totalRoundTripTiles += trip.roundTripTiles;
    totalDailyTileDistance += dailyTileDistance;
    maxDistanceTiles = Math.max(maxDistanceTiles, trip.distanceTiles);
    maxRoundTripTiles = Math.max(maxRoundTripTiles, trip.roundTripTiles);
    maxDailyTileDistance = Math.max(maxDailyTileDistance, dailyTileDistance);
    maxDurationDays = Math.max(maxDurationDays, trip.estimatedDurationDays);
    maxRouteLength = Math.max(maxRouteLength, trip.routeLength);
  }

  // TIME-1C academic-range cross-check at the declared ~1.25 km/tile scale.
  // Day-return foraging reach is ~2-5 tiles one-way (roughly 5-12.5 km round
  // trip at this scale); overnight/continues forays may range further while the
  // camp stays fixed; residential relocation is a SEPARATE seasonal process.
  const KM_PER_TILE = 1.25;
  const elapsedDays = Math.max(1, Number(world.time.day ?? Number(world.time.tick) * 90));
  const elapsedSeasons = Math.max(1, Number(world.time.tick));
  const maxRecentTripsPerBand = activeBands.reduce(
    (max, band) => Math.max(max, band.recentIntraSeasonTrips?.length ?? 0),
    0,
  );

  return {
    totalTrips: trips.length,
    bandsWithTrips: new Set(trips.map((trip) => trip.bandId)).size,
    averageTripsPerCalendarDay: round4(trips.length / elapsedDays),
    averageTripsPerSeason: round4(trips.length / elapsedSeasons),
    averageDistanceTiles: round4(totalDistanceTiles / Math.max(1, trips.length)),
    maxDistanceTiles,
    averageRoundTripTiles: round4(totalRoundTripTiles / Math.max(1, trips.length)),
    maxRoundTripTiles,
    averageDailyTileDistance: round4(totalDailyTileDistance / Math.max(1, trips.length)),
    maxDailyTileDistance: round4(maxDailyTileDistance),
    maxDurationDays,
    averageTilesCrossed: round4(totalTilesCrossed / Math.max(1, trips.length)),
    maxRouteLength,
    causeCounts,
    movementTypeCounts,
    taskGroupTypeCounts,
    objectiveCounts,
    outcomeCounts,
    activityResultCounts,
    activityOutcomeCounts,
    activityOutcomeCountsByTaskType,
    activityStatusCounts,
    returnedResourceKindCounts,
    activityMemoryEffectCounts,
    activityMemoryTouchedMemoryCount: activityMemoryTouchedPatchIds.size,
    minActivityMemoryConfidenceDelta: round4(minActivityMemoryConfidenceDelta),
    maxActivityMemoryConfidenceDelta: round4(maxActivityMemoryConfidenceDelta),
    activityMemoryGuardFailureCount,
    activityMemoryHiddenTruthFailureCount,
    maxEstimatedReturnValue: round4(maxEstimatedReturnValue),
    resourceReturnConsumedByEconomyCount,
    resourceReturnGuardFailureCount,
    averageEstimatedPeopleCount: round4(totalEstimatedPeople / Math.max(1, trips.length)),
    maxEstimatedPeopleCount: maxEstimatedPeople,
    returnedSameDayCount: outcomeCounts.returns_same_day,
    overnightCount: outcomeCounts.overnight,
    continueCount: outcomeCounts.continues,
    maxRecentTripsPerBand,
    overcrowdingGuard: {
      recentTripRecordCapPerBand: 24,
      maxRecentTripsPerBand,
      visualLayerActive: true,
      note: "ACTIVITY-VIS renders only real ledger records with capped selected/all-band UI overlays; benchmark remains a sim audit and creates no renderer-only trips.",
    },
    academicComparison: {
      kmPerTile: KM_PER_TILE,
      maxOneWayKm: round2(maxDistanceTiles * KM_PER_TILE),
      maxDailyKm: round2(maxDailyTileDistance * KM_PER_TILE),
      dayReturnReachTilesRef: "2-5 one-way tiles; ~5-12.5 km round trip at 1.25 km/tile",
      tripsWithinDayReturnReach: trips.filter((trip) => trip.distanceTiles <= 5).length,
      note: "daily trips never move band.position; residential relocation is the separate seasonal process in movementAudit",
    },
    allPathsContiguousNoTeleport: trips.every((trip) => trip.pathContiguous === true),
    movementHasCauses: trips.every((trip) => trip.cause !== undefined && trip.reasonIds.length > 0),
    noResidentialRelocation: trips.every((trip) => trip.noResidentialRelocation === true),
    noYieldStressPopulationChange: trips.every(
      (trip) => trip.noYieldChange === true && trip.noStressChange === true && trip.noPopulationChange === true,
    ),
    noCarryingCapacityChange: trips.every((trip) => trip.noCarryingCapacityChange === true),
    noSupportChange: trips.every((trip) => trip.noSupportChange === true),
    noResourceReturnEconomyCoupling: trips.every(
      (trip) =>
        trip.resourceReturn?.consumedByEconomy === false &&
        trip.resourceReturn?.noYieldCoupling === true &&
        trip.resourceReturn?.noCarryingCapacityCoupling === true &&
        trip.resourceReturn?.noPopulationChange === true &&
        trip.resourceReturn?.noStressChange === true &&
        trip.resourceReturn?.noSupportChange === true,
    ),
    noActivityMemoryEconomyCoupling: trips.every((trip) =>
      trip.activityMemoryEffect === undefined || isActivityMemoryEffectGuardClean(trip.activityMemoryEffect),
    ),
    noActivityMemoryHiddenTruth: trips.every(
      (trip) =>
        trip.activityMemoryEffect === undefined ||
        (
          trip.activityMemoryEffect.noHiddenTruth === true &&
          trip.activityMemoryEffect.targetKnownMemoryOnly === true &&
          trip.activityMemoryEffect.noNewResourceDiscovery === true
        ),
    ),
    bandKnownTargetsOnly: trips.every((trip) => trip.bandKnownTargetOnly === true),
    laborAudit: summarizeActivityLaborAudit(world),
    activityMemoryAudit: summarizeActivityMemoryAudit(world),
    samples: trips
      .sort((left, right) => left.day - right.day || left.bandId.localeCompare(right.bandId) || left.to.localeCompare(right.to))
      .slice(0, 8),
  };
}

function summarizeActivityLaborAudit(world) {
  const activeBands = Object.values(world.bands).filter(isActiveBand);
  const summaries = activeBands
    .map((band) => band.activityLaborSummary)
    .filter((summary) => summary !== undefined);
  const groupCountsByType = {};
  const peopleByGroupType = {};
  const statusCounts = {};
  const outcomeCounts = {};
  const activityOutcomeCounts = {};
  const returnedResourceKindCounts = {};
  let maxPeopleAway = 0;
  let maxPeopleAssigned = 0;
  let maxShareOfWorkingAdultsAway = 0;
  let maxShareOfWorkingAdultsAssigned = 0;
  let impossibleOverAllocationCount = 0;
  let cappedBandSnapshotCount = 0;
  let totalAssigned = 0;
  let totalBase = 0;
  let recordCount = 0;
  let sameDayReturnedGroups = 0;
  let overnightGroups = 0;
  let continuingGroups = 0;
  let delayedGroups = 0;
  let maxEstimatedReturnValue = 0;
  let resourceReturnGuardFailureCount = 0;

  for (const summary of summaries) {
    const workingAdults = Math.max(1, summary.workingAdults ?? 0);
    maxPeopleAway = Math.max(maxPeopleAway, summary.peopleAwayInActivityGroups ?? 0);
    maxPeopleAssigned = Math.max(maxPeopleAssigned, summary.peopleAssignedToActivityGroups ?? 0);
    maxShareOfWorkingAdultsAway = Math.max(
      maxShareOfWorkingAdultsAway,
      (summary.peopleAwayInActivityGroups ?? 0) / workingAdults,
    );
    maxShareOfWorkingAdultsAssigned = Math.max(
      maxShareOfWorkingAdultsAssigned,
      (summary.peopleAssignedToActivityGroups ?? 0) / workingAdults,
    );
    impossibleOverAllocationCount += summary.impossibleOverAllocationCount ?? 0;
    cappedBandSnapshotCount += summary.cappedAllocation === true ? 1 : 0;
    totalAssigned += summary.peopleAssignedToActivityGroups ?? 0;
    totalBase += summary.peopleAtResidentialCenterEstimate ?? 0;

    for (const entry of summary.peopleByActivityType ?? []) {
      groupCountsByType[entry.taskGroupType] = (groupCountsByType[entry.taskGroupType] ?? 0) + entry.groupCount;
      peopleByGroupType[entry.taskGroupType] = (peopleByGroupType[entry.taskGroupType] ?? 0) + entry.assignedPeopleEstimate;
    }

    for (const record of summary.recentActivityGroupSummaries ?? []) {
      recordCount += 1;
      statusCounts[record.status] = (statusCounts[record.status] ?? 0) + 1;
      outcomeCounts[record.outcome] = (outcomeCounts[record.outcome] ?? 0) + 1;
      activityOutcomeCounts[record.activityOutcome] = (activityOutcomeCounts[record.activityOutcome] ?? 0) + 1;
      returnedResourceKindCounts[record.resourceReturn.returnedResourceKind] =
        (returnedResourceKindCounts[record.resourceReturn.returnedResourceKind] ?? 0) + 1;
      maxEstimatedReturnValue = Math.max(maxEstimatedReturnValue, record.resourceReturn.estimatedReturnValue ?? 0);
      resourceReturnGuardFailureCount += record.resourceReturn.consumedByEconomy === false &&
        record.resourceReturn.noYieldCoupling === true &&
        record.resourceReturn.noCarryingCapacityCoupling === true &&
        record.resourceReturn.noPopulationChange === true &&
        record.resourceReturn.noStressChange === true &&
        record.resourceReturn.noSupportChange === true
        ? 0
        : 1;

      if (record.status === "returned" && record.outcome === "returns_same_day") {
        sameDayReturnedGroups += 1;
      } else if (record.status === "overnight") {
        overnightGroups += 1;
      } else if (record.status === "continuing") {
        continuingGroups += 1;
      } else if (record.status === "delayed") {
        delayedGroups += 1;
      }
    }
  }

  return {
    bandsWithLaborSnapshots: summaries.length,
    totalLaborRecordsInSnapshots: recordCount,
    maxPeopleAway,
    maxPeopleAssigned,
    maxShareOfWorkingAdultsAway: round4(maxShareOfWorkingAdultsAway),
    maxShareOfWorkingAdultsAssigned: round4(maxShareOfWorkingAdultsAssigned),
    impossibleOverAllocationCount,
    cappedBandSnapshotCount,
    averageAssignedPeoplePerSnapshot: round4(totalAssigned / Math.max(1, summaries.length)),
    averageAtResidentialCenterPerSnapshot: round4(totalBase / Math.max(1, summaries.length)),
    groupCountsByType,
    peopleByGroupType,
    statusCounts,
    outcomeCounts,
    activityOutcomeCounts,
    returnedResourceKindCounts,
    sameDayReturnedGroups,
    overnightGroups,
    continuingGroups,
    delayedGroups,
    maxEstimatedReturnValue: round4(maxEstimatedReturnValue),
    resourceReturnGuardFailureCount,
    noYieldStressPopulationCarryingCapacityCoupling: summaries.every(
      (summary) =>
        summary.noFoodCoupling === true &&
        summary.noYieldCoupling === true &&
        summary.noCarryingCapacityCoupling === true &&
        summary.noPopulationChange === true &&
        summary.noStressChange === true,
    ),
    noReturnEconomyCoupling: resourceReturnGuardFailureCount === 0,
  };
}

function summarizeActivityMemoryAudit(world) {
  const activeBands = Object.values(world.bands).filter(isActiveBand);
  const summaries = activeBands
    .map((band) => band.activityMemoryUpdateSummary)
    .filter((summary) => summary !== undefined);
  const effectCounts = {};
  const touchedPatchIds = new Set();
  let totalRecentEffects = 0;
  let totalConfidenceIncrease = 0;
  let totalConfidenceDecrease = 0;
  let minConfidenceDelta = 0;
  let maxConfidenceDelta = 0;
  let sawDelta = false;
  let guardFailureCount = 0;
  let hiddenTruthFailureCount = 0;
  const examples = [];

  for (const summary of summaries) {
    totalConfidenceIncrease += summary.confidenceIncreaseTotal ?? 0;
    totalConfidenceDecrease += summary.confidenceDecreaseTotal ?? 0;

    for (const entry of summary.effectCounts ?? []) {
      effectCounts[entry.effectType] = (effectCounts[entry.effectType] ?? 0) + entry.count;
    }

    for (const effect of summary.recentMemoryEffects ?? []) {
      totalRecentEffects += 1;
      if (effect.patchId !== undefined) {
        touchedPatchIds.add(String(effect.patchId));
      }

      guardFailureCount += isActivityMemoryEffectGuardClean(effect) ? 0 : 1;
      hiddenTruthFailureCount += effect.noHiddenTruth === true &&
        effect.targetKnownMemoryOnly === true &&
        effect.noNewResourceDiscovery === true
        ? 0
        : 1;

      if (!sawDelta || effect.confidenceDelta < minConfidenceDelta) {
        minConfidenceDelta = effect.confidenceDelta;
      }

      if (!sawDelta || effect.confidenceDelta > maxConfidenceDelta) {
        maxConfidenceDelta = effect.confidenceDelta;
      }

      sawDelta = true;

      if (examples.length < 8) {
        examples.push(serializeActivityMemoryEffect(effect));
      }
    }
  }

  return {
    bandsWithActivityMemorySummaries: summaries.length,
    totalRecentMemoryEffects: totalRecentEffects,
    touchedMemoryCount: touchedPatchIds.size,
    effectCounts,
    confidenceIncreaseTotal: round4(totalConfidenceIncrease),
    confidenceDecreaseTotal: round4(totalConfidenceDecrease),
    minConfidenceDelta: round4(minConfidenceDelta),
    maxConfidenceDelta: round4(maxConfidenceDelta),
    guardFailureCount,
    hiddenTruthFailureCount,
    noEconomyCoupling: guardFailureCount === 0,
    noHiddenTruth: hiddenTruthFailureCount === 0,
    examples,
  };
}

function serializeActivityMemoryEffect(effect) {
  return {
    sourceBandId: String(effect.sourceBandId),
    sourceTripDay: Number(effect.sourceTripDay),
    tick: Number(effect.tick),
    season: effect.season,
    targetTileId: String(effect.targetTileId),
    patchId: effect.patchId === undefined ? undefined : String(effect.patchId),
    resourceClassId: effect.resourceClassId,
    activityOutcome: effect.activityOutcome,
    effectType: effect.effectType,
    effectSummary: effect.effectSummary,
    mainConfidenceChannel: effect.mainConfidenceChannel,
    confidenceDelta: effect.confidenceDelta,
    confidenceBefore: effect.confidenceBefore,
    confidenceAfter: effect.confidenceAfter,
    reasonIds: (effect.reasonIds ?? []).map(String),
    noHiddenTruth: effect.noHiddenTruth,
    targetKnownMemoryOnly: effect.targetKnownMemoryOnly,
    noNewResourceDiscovery: effect.noNewResourceDiscovery,
    noFoodCoupling: effect.noFoodCoupling,
    noYieldCoupling: effect.noYieldCoupling,
    noCarryingCapacityCoupling: effect.noCarryingCapacityCoupling,
    noPopulationChange: effect.noPopulationChange,
    noStressChange: effect.noStressChange,
    noSupportChange: effect.noSupportChange,
  };
}

function isActivityMemoryEffectGuardClean(effect) {
  return effect.noHiddenTruth === true &&
    effect.targetKnownMemoryOnly === true &&
    effect.noNewResourceDiscovery === true &&
    effect.noFoodCoupling === true &&
    effect.noYieldCoupling === true &&
    effect.noCarryingCapacityCoupling === true &&
    effect.noPopulationChange === true &&
    effect.noStressChange === true &&
    effect.noSupportChange === true;
}

function runTargetedActivityMemorySensitivityCheck(modules, options) {
  const scenarios = [
    { label: "map1", scenario: "baseline" },
    { label: "map2", scenario: "map2_varied_migration" },
  ];
  const years = (options.activityMemorySensitivityYears?.length ?? 0) > 0
    ? [...new Set(options.activityMemorySensitivityYears)].sort((left, right) => left - right)
    : [20, 50, 100];
  const cases = [];
  let deterministicRepeat = undefined;

  for (const scenario of scenarios) {
    for (const yearCount of years) {
      const onRun = runActivityMemorySensitivityRun(modules, scenario.scenario, yearCount, false);
      const offRun = runActivityMemorySensitivityRun(modules, scenario.scenario, yearCount, true);
      const comparison = compareActivityMemorySensitivityRuns(onRun, offRun);

      if (deterministicRepeat === undefined) {
        const onRepeat = runActivityMemorySensitivityRun(modules, scenario.scenario, yearCount, false);
        const offRepeat = runActivityMemorySensitivityRun(modules, scenario.scenario, yearCount, true);
        deterministicRepeat = {
          scenario: scenario.scenario,
          years: yearCount,
          onMatched: makeActivityMemorySensitivityFingerprint(onRun) === makeActivityMemorySensitivityFingerprint(onRepeat),
          offMatched: makeActivityMemorySensitivityFingerprint(offRun) === makeActivityMemorySensitivityFingerprint(offRepeat),
        };
      }

      cases.push({
        map: scenario.label,
        scenario: scenario.scenario,
        years: yearCount,
        mode: "runner seasonal stepSim path; daily actions execute through advanceWorldByDays",
        on: summarizeActivityMemorySensitivityRun(onRun),
        off: summarizeActivityMemorySensitivityRun(offRun),
        comparison,
      });
    }
  }

  const allComparisons = cases.map((entry) => entry.comparison);
  // REALISM-2B rebaseline. First-season reconnaissance (the TIME/MOVEMENT-REALISM-2
  // starting-local bridge) lets bands use already-observed local knowledge from day 6
  // instead of being frozen for 90 days. The first-season audit shows year-1 macro is
  // identical ON/OFF on both maps; the divergence is a LONG-RUN, deterministic,
  // bounded drift that flows through resource_scout target selection -> position ->
  // the PRE-EXISTING 2K.9 learned-support reader (no NEW economy reader, returns never
  // consumed, no hidden discovery). So we split the macro check:
  //   - macro STRUCTURE (active bands / fissions / extinctions) must stay invariant; and
  //   - population MAGNITUDE may drift within a bounded relative cap (the realistic cost
  //     of early local knowledge informing decisions; measured worst case ~+9/336 ≈ 2.7%
  //     on Map 2 at 100y, 0 at 20y, Map 1 fully inert).
  // The HARD safety proofs below (no economy reader, no returns consumed, no guard
  // failures, no hidden truth, determinism) remain strict and unchanged.
  const POSITION_SENSITIVITY_CAP = 4;
  const macroStructureInvariant = allComparisons.every((entry) =>
    Math.abs(entry.macroDeltas.activeBands) <= 1 &&
    Math.abs(entry.macroDeltas.fissions) <= 1 &&
    Math.abs(entry.macroDeltas.extinctBands) <= 1,
  );
  const populationSensitivityBounded = cases.every((entry) => {
    const populationCap = Math.max(3, Math.ceil(0.05 * entry.on.totalPopulation));
    return (
      Math.abs(entry.comparison.macroDeltas.totalPopulation) <= populationCap &&
      entry.comparison.finalBandPositionChangedCount <= POSITION_SENSITIVITY_CAP
    );
  });
  const observedMaxPopulationDelta = Math.max(
    0,
    ...allComparisons.map((entry) => Math.abs(entry.macroDeltas.totalPopulation)),
  );
  const noLargeMacroDivergence = macroStructureInvariant && populationSensitivityBounded;
  const noDecisionPathDelta = allComparisons.every((entry) => entry.changedDecisionArchiveFields.length === 0);
  const noEconomyDirectRead = buildActivityMemoryStaticReaderInventory()
    .every((entry) => entry.readsActivityReturnOrEffectRecordsInEconomy !== true);
  const noReturnConsumed = cases.every((entry) =>
    entry.on.tripAudit.resourceReturnConsumedByEconomyCount === 0 &&
    entry.off.tripAudit.resourceReturnConsumedByEconomyCount === 0 &&
    entry.on.tripAudit.resourceReturnGuardFailureCount === 0 &&
    entry.off.tripAudit.resourceReturnGuardFailureCount === 0,
  );
  const noActivityEffectGuardFailures = cases.every((entry) =>
    entry.on.activityMemoryAudit.guardFailureCount === 0 &&
    entry.off.activityMemoryAudit.guardFailureCount === 0,
  );
  const noHiddenTruth = cases.every((entry) =>
    entry.on.activityMemoryAudit.hiddenTruthFailureCount === 0 &&
    entry.off.activityMemoryAudit.hiddenTruthFailureCount === 0,
  );

  return {
    check: "ACTIVITY-GROUPS-6 targeted activity-memory sensitivity audit",
    verdict: noEconomyDirectRead && noReturnConsumed && noActivityEffectGuardFailures && noHiddenTruth && noLargeMacroDivergence
      ? "pass"
      : "review",
    notes: [
      "ON uses normal ACTIVITY-GROUPS-4 memory writes; OFF keeps the same daily action schedule but disables memory writes through WorldState.auditOptions.activityMemoryCouplingDisabled.",
      "This is an audit-only benchmark path. It does not change normal sim behavior, resource returns, support, yield, carrying capacity, stress, population, relocation, fission, or plant safety.",
      "Dynamic reader exposure counts current activity-touched memories still present in bounded band memory. It is conservative and does not claim exact function-call tracing.",
      "Important caveat: ResourcePatchMemory already has a pre-existing 2K.9 learned-support reader in carryingCapacity/socialContext when exploitationSkill matches. Activity return/effect records are not directly consumed by economy, but changed patch confidence can theoretically influence that existing learned-support path.",
      "REALISM-2B rebaseline: with first-season reconnaissance, activity memory influences resource_scout target selection from tick 1, so the long-run ON/OFF divergence grew (Map 2 ~+9 population / 336 at 100y; 0 at 20y; Map 1 inert). Macro STRUCTURE (active bands / fissions / extinctions) stays invariant and the divergence flows only through the pre-existing 2K.9 learned-support path; the bounded population magnitude is accepted as the realistic cost of early local knowledge. Hard economy/hidden-truth/determinism proofs remain strict.",
    ],
    years,
    readerInventory: buildActivityMemoryStaticReaderInventory(),
    noDecisionPathDelta,
    noLargeMacroDivergence,
    macroStructureInvariant,
    populationSensitivityBounded,
    observedMaxPopulationDelta,
    populationSensitivityCapPolicy: "per-case |popDelta| <= max(3, ceil(0.05 * onPopulation)); finalBandPositionChangedCount <= 4",
    noEconomyCouplingProof: {
      noDirectActivityReturnOrEffectEconomyReaders: noEconomyDirectRead,
      resourceReturnConsumedByEconomyCount: sumCases(cases, (entry) =>
        entry.on.tripAudit.resourceReturnConsumedByEconomyCount + entry.off.tripAudit.resourceReturnConsumedByEconomyCount,
      ),
      resourceReturnGuardFailureCount: sumCases(cases, (entry) =>
        entry.on.tripAudit.resourceReturnGuardFailureCount + entry.off.tripAudit.resourceReturnGuardFailureCount,
      ),
      activityMemoryGuardFailureCount: sumCases(cases, (entry) =>
        entry.on.activityMemoryAudit.guardFailureCount + entry.off.activityMemoryAudit.guardFailureCount,
      ),
      existingPatchMemoryEconomyReader: "2K.9 learned support in carryingCapacity.ts/socialContext.ts reads ResourcePatchMemory via deriveTileLearnedSupport when matching exploitationSkill exists; not a direct read of activityMemoryEffect/resourceReturn.",
    },
    antiOmniscienceProof: {
      activityMemoryHiddenTruthFailureCount: sumCases(cases, (entry) =>
        entry.on.activityMemoryAudit.hiddenTruthFailureCount + entry.off.activityMemoryAudit.hiddenTruthFailureCount,
      ),
      bandKnownTargetsOnly: cases.every((entry) =>
        entry.on.tripAudit.bandKnownTargetsOnly === true && entry.off.tripAudit.bandKnownTargetsOnly === true,
      ),
      noNewResourceDiscoveryGuard: "activity memory effects report targetKnownMemoryOnly=true and noNewResourceDiscovery=true; OFF-side memory effects are all none.",
    },
    deterministicRepeat,
    cases,
  };
}

function runActivityMemorySensitivityRun(modules, scenario, years, memoryDisabled) {
  const ticks = years * 4;
  const init = scenario === "map2_varied_migration" ? { kind: "map2" } : { kind: "map1" };
  const start = performance.now();
  const initialWorld = applyBenchmarkAuditOptions(modules.initSimWorld(init), {
    activityMemoryCouplingDisabledForAudit: memoryDisabled,
  });
  const world = modules.stepSim(initialWorld, ticks, "seasonal");
  const runtimeMs = performance.now() - start;
  const timeScaleSummary = summarizeTimeScaleWorld(world);
  const knownTileRecordsTotal = Object.values(world.bands)
    .reduce((sum, band) => sum + Object.keys(band.knowledge.observedTiles).length, 0);
  const summary = {
    completed: true,
    tick: timeScaleSummary.tick,
    year: timeScaleSummary.year,
    ticksRequested: ticks,
    ticksSimulated: ticks,
    totalRuntimeMs: round2(runtimeMs),
    averageMsPerTick: round4(runtimeMs / Math.max(1, ticks)),
    maxMsPerTick: undefined,
    activeBands: timeScaleSummary.activeBands,
    totalBands: timeScaleSummary.totalBands,
    absorbedBands: timeScaleSummary.absorbedBands,
    extinctBands: timeScaleSummary.extinctBands,
    totalPopulation: timeScaleSummary.totalPopulation,
    knownTileRecordsTotal,
    movementDecisionsEvaluated: timeScaleSummary.totalDecisions,
    decisionArchive: {
      totalDecisions: timeScaleSummary.totalDecisions,
      totalStayDecisions: world.decisionArchive.totalStayDecisions,
      totalMoveDecisions: timeScaleSummary.totalMoveDecisions,
      totalExploreDecisions: world.decisionArchive.totalExploreDecisions,
      totalNoOpDecisions: world.decisionArchive.totalNoOpDecisions,
      totalProbeDecisions: timeScaleSummary.totalProbeDecisions,
      totalResourceScoutDecisions: timeScaleSummary.totalResourceScoutDecisions,
      totalFrontierMoves: world.decisionArchive.totalFrontierMoves,
      recentDecisionLimit: world.decisionArchive.recentDecisionLimit,
      recentDecisionIdsRetained: world.decisionArchive.recentDecisionIds.length,
    },
    fissions: timeScaleSummary.fissions,
  };

  return {
    scenario,
    years,
    memoryDisabled,
    result: { summary },
    world,
    tripAudit: summarizeTimeScaleTrips(world),
    activityMemoryAudit: summarizeActivityMemoryAudit(world),
    readerExposure: summarizeActivityMemoryReaderExposure(world, modules),
  };
}

function summarizeActivityMemorySensitivityRun(run) {
  return {
    completed: run.result.summary.completed,
    tick: run.result.summary.tick,
    year: run.result.summary.year,
    totalPopulation: run.result.summary.totalPopulation,
    activeBands: run.result.summary.activeBands,
    totalBands: run.result.summary.totalBands,
    fissions: run.result.summary.fissions,
    extinctBands: run.result.summary.extinctBands,
    absorbedBands: run.result.summary.absorbedBands,
    decisionArchive: run.result.summary.decisionArchive,
    movementDecisionsEvaluated: run.result.summary.movementDecisionsEvaluated,
    knownTileRecordsTotal: run.result.summary.knownTileRecordsTotal,
    averageMsPerTick: run.result.summary.averageMsPerTick,
    maxMsPerTick: run.result.summary.maxMsPerTick,
    tripAudit: {
      totalTrips: run.tripAudit.totalTrips,
      activityOutcomeCounts: run.tripAudit.activityOutcomeCounts,
      returnedResourceKindCounts: run.tripAudit.returnedResourceKindCounts,
      activityMemoryEffectCounts: run.tripAudit.activityMemoryEffectCounts,
      minActivityMemoryConfidenceDelta: run.tripAudit.minActivityMemoryConfidenceDelta,
      maxActivityMemoryConfidenceDelta: run.tripAudit.maxActivityMemoryConfidenceDelta,
      resourceReturnConsumedByEconomyCount: run.tripAudit.resourceReturnConsumedByEconomyCount,
      resourceReturnGuardFailureCount: run.tripAudit.resourceReturnGuardFailureCount,
      noResourceReturnEconomyCoupling: run.tripAudit.noResourceReturnEconomyCoupling,
      noActivityMemoryEconomyCoupling: run.tripAudit.noActivityMemoryEconomyCoupling,
      noActivityMemoryHiddenTruth: run.tripAudit.noActivityMemoryHiddenTruth,
      bandKnownTargetsOnly: run.tripAudit.bandKnownTargetsOnly,
    },
    activityMemoryAudit: run.activityMemoryAudit,
    readerExposure: run.readerExposure,
  };
}

function compareActivityMemorySensitivityRuns(onRun, offRun) {
  const onSummary = onRun.result.summary;
  const offSummary = offRun.result.summary;
  const macroDeltas = {
    totalPopulation: onSummary.totalPopulation - offSummary.totalPopulation,
    activeBands: onSummary.activeBands - offSummary.activeBands,
    totalBands: onSummary.totalBands - offSummary.totalBands,
    fissions: onSummary.fissions - offSummary.fissions,
    extinctBands: onSummary.extinctBands - offSummary.extinctBands,
    absorbedBands: onSummary.absorbedBands - offSummary.absorbedBands,
    knownTileRecordsTotal: onSummary.knownTileRecordsTotal - offSummary.knownTileRecordsTotal,
  };
  const decisionDeltas = diffNumberRecord(onSummary.decisionArchive, offSummary.decisionArchive);
  const changedDecisionArchiveFields = Object.entries(decisionDeltas)
    .filter(([, delta]) => delta !== 0)
    .map(([field, delta]) => ({ field, delta }));
  const finalBandDelta = compareFinalBands(onRun.world, offRun.world);

  return {
    macroDeltas,
    decisionDeltas,
    changedDecisionArchiveFields,
    finalBandPositionChangedCount: finalBandDelta.positionChangedCount,
    finalBandPopulationChangedCount: finalBandDelta.populationChangedCount,
    finalBandStatusChangedCount: finalBandDelta.statusChangedCount,
    finalBandChangedSamples: finalBandDelta.samples,
    onOffTripCountDelta: onRun.tripAudit.totalTrips - offRun.tripAudit.totalTrips,
    onOffTouchedMemoryDelta:
      onRun.activityMemoryAudit.touchedMemoryCount - offRun.activityMemoryAudit.touchedMemoryCount,
    onOffReaderExposureDelta: diffNumberRecord(onRun.readerExposure.potentialReaderExposure, offRun.readerExposure.potentialReaderExposure),
    interpretation: finalBandDelta.positionChangedCount === 0 && changedDecisionArchiveFields.length === 0
      ? "inert at macro/decision-path level for this horizon; activity memory still changes bounded patch confidence records"
      : "bounded behavior sensitivity detected; inspect changed fields and band samples",
  };
}

function compareFinalBands(onWorld, offWorld) {
  const onBands = Object.fromEntries(Object.values(onWorld.bands).map((band) => [String(band.id), band]));
  const offBands = Object.fromEntries(Object.values(offWorld.bands).map((band) => [String(band.id), band]));
  const ids = [...new Set([...Object.keys(onBands), ...Object.keys(offBands)])].sort();
  let positionChangedCount = 0;
  let populationChangedCount = 0;
  let statusChangedCount = 0;
  const samples = [];

  for (const id of ids) {
    const onBand = onBands[id];
    const offBand = offBands[id];
    if (onBand === undefined || offBand === undefined) {
      statusChangedCount += 1;
      if (samples.length < 6) {
        samples.push({
          bandId: id,
          onStatus: onBand?.status ?? onBand?.viability?.status,
          offStatus: offBand?.status ?? offBand?.viability?.status,
          kind: "presence_changed",
        });
      }
      continue;
    }

    const onPopulation = toPopulationCount(onBand.demography.population);
    const offPopulation = toPopulationCount(offBand.demography.population);
    const positionChanged = String(onBand.position) !== String(offBand.position);
    const populationChanged = onPopulation !== offPopulation;
    const statusChanged = onBand.status !== offBand.status || onBand.viability?.status !== offBand.viability?.status;
    positionChangedCount += positionChanged ? 1 : 0;
    populationChangedCount += populationChanged ? 1 : 0;
    statusChangedCount += statusChanged ? 1 : 0;

    if ((positionChanged || populationChanged || statusChanged) && samples.length < 6) {
      samples.push({
        bandId: id,
        onPosition: String(onBand.position),
        offPosition: String(offBand.position),
        onPopulation,
        offPopulation,
        onStatus: onBand.viability?.status ?? onBand.status,
        offStatus: offBand.viability?.status ?? offBand.status,
      });
    }
  }

  return {
    positionChangedCount,
    populationChangedCount,
    statusChangedCount,
    samples,
  };
}

function summarizeActivityMemoryReaderExposure(world, modules) {
  const currentTick = Number(world.time.tick);
  const activeBands = Object.values(world.bands).filter(isActiveBand);
  const effectCounts = {};
  const resourceClassCounts = {};
  const sourceCounts = {};
  const potentialReaderExposure = {
    movementResourceBeliefOpportunity: 0,
    resourceScoutCandidateSelection: 0,
    plantUseEligibility: 0,
    patchReturnView: 0,
    learnedSupportProjection: 0,
    carryingCapacityCurrentFootprintLearnedSupport: 0,
    riskAwareReaders: 0,
    seasonalityAwareReaders: 0,
    stalenessAwareReaders: 0,
  };
  let touchedMemoryCount = 0;
  let bandsWithTouchedMemories = 0;
  const examples = [];

  for (const band of activeBands) {
    const recentTouchedPatchIds = getRecentActivityTouchedPatchIds(band);
    let bandTouched = 0;

    for (const memory of band.resourceKnowledgeState?.patchMemories ?? []) {
      const touch = getActivityMemoryTouch(memory, recentTouchedPatchIds);
      if (touch === undefined) {
        continue;
      }

      touchedMemoryCount += 1;
      bandTouched += 1;
      effectCounts[touch.effectType] = (effectCounts[touch.effectType] ?? 0) + 1;
      resourceClassCounts[memory.resourceClassId] = (resourceClassCounts[memory.resourceClassId] ?? 0) + 1;
      sourceCounts[memory.source] = (sourceCounts[memory.source] ?? 0) + 1;

      const effective = modules.resourceKnowledge.effectiveResourceConfidence(memory, currentTick);
      const strength = Math.max(effective.effectivePresenceConfidence, effective.effectiveYieldConfidence);
      const distance = getTileDistance(world, band.position, memory.approximateTile);

      if (memory.approximateTile !== band.position && strength >= 0.1) {
        potentialReaderExposure.movementResourceBeliefOpportunity += 1;
      }

      if (distance !== undefined && distance > 0 && distance <= 10 && effective.effectivePresenceConfidence >= 0.08) {
        potentialReaderExposure.resourceScoutCandidateSelection += 1;
      }

      if (modules.plantUseEligibility.isPlantUseCandidateMemory(memory)) {
        potentialReaderExposure.plantUseEligibility += 1;
      }

      potentialReaderExposure.patchReturnView += 1;

      if (band.exploitationSkill !== undefined) {
        const learned = modules.patchExploitationKnowledge.deriveTileLearnedSupport(
          memory.approximateTile,
          band.resourceKnowledgeState?.patchMemories ?? [],
          {
            currentTick: world.time.tick,
            recentPlantUseTests: band.recentPlantUseTests,
            recentCauseSpecificEvents: band.recentCauseSpecificEvents,
            exploitationSkill: band.exploitationSkill,
          },
        );
        if (learned.matchedPatchCount > 0) {
          potentialReaderExposure.learnedSupportProjection += 1;
          if (memory.approximateTile === band.position) {
            potentialReaderExposure.carryingCapacityCurrentFootprintLearnedSupport += 1;
          }
        }
      }

      if (memory.risk.badWater || memory.risk.poisoningOrBadReaction || memory.risk.predatorOrAnimalRisk > 0) {
        potentialReaderExposure.riskAwareReaders += 1;
      }

      if (memory.seasonality.bestSeasons.length > 0 || memory.seasonality.badSeasons.length > 0) {
        potentialReaderExposure.seasonalityAwareReaders += 1;
      }

      if (effective.isStale || effective.isDormant) {
        potentialReaderExposure.stalenessAwareReaders += 1;
      }

      if (examples.length < 8) {
        examples.push({
          bandId: String(band.id),
          patchId: String(memory.patchId),
          tileId: String(memory.approximateTile),
          resourceClassId: memory.resourceClassId,
          effectType: touch.effectType,
          source: memory.source,
          state: memory.state,
          distance,
          effectivePresenceConfidence: effective.effectivePresenceConfidence,
          effectiveYieldConfidence: effective.effectiveYieldConfidence,
          stalenessLabel: effective.label,
          reasonIds: memory.reasonIds.filter(isActivityMemoryReason).map(String).slice(-3),
        });
      }
    }

    if (bandTouched > 0) {
      bandsWithTouchedMemories += 1;
    }
  }

  return {
    touchedMemoryCount,
    bandsWithTouchedMemories,
    effectCounts,
    resourceClassCounts,
    sourceCounts,
    potentialReaderExposure,
    examples,
    notes: [
      "Counts are current-world exposure for activity-touched patch memories, not exhaustive historical call tracing.",
      "recent activity-memory summaries are included so a freshly touched patch still counts even if the memory's bounded reasonIds ring rotated.",
    ],
  };
}

function getRecentActivityTouchedPatchIds(band) {
  const patchIds = new Set();
  for (const effect of band.activityMemoryUpdateSummary?.recentMemoryEffects ?? []) {
    if (effect.patchId !== undefined && effect.effectType !== "none") {
      patchIds.add(String(effect.patchId));
    }
  }

  for (const trip of band.recentIntraSeasonTrips ?? []) {
    const effect = trip.activityMemoryEffect;
    if (effect !== undefined && effect.patchId !== undefined && effect.effectType !== "none") {
      patchIds.add(String(effect.patchId));
    }
  }

  return patchIds;
}

function getActivityMemoryTouch(memory, recentTouchedPatchIds) {
  const reasonId = memory.reasonIds.find(isActivityMemoryReason);
  const effectType = reasonId === undefined ? undefined : getActivityMemoryEffectTypeFromReason(reasonId);

  if (effectType !== undefined) {
    return { effectType };
  }

  if (recentTouchedPatchIds.has(String(memory.patchId))) {
    return { effectType: "recent_summary_reference" };
  }

  return undefined;
}

function isActivityMemoryReason(reasonId) {
  return String(reasonId).includes("reason:activity-memory:");
}

function getActivityMemoryEffectTypeFromReason(reasonId) {
  const text = String(reasonId);
  const effectTypes = [
    "confidence_refreshed",
    "confidence_lowered",
    "seasonality_hint_added",
    "risk_suspicion_added",
    "water_reliability_refreshed",
    "plant_caution_refreshed",
    "route_memory_refreshed",
    "repeated_use_counter_incremented_placeholder",
  ];
  return effectTypes.find((effectType) => text.includes(`:${effectType}:`));
}

function buildActivityMemoryStaticReaderInventory() {
  return [
    {
      system: "daily task trip selection/outcome",
      files: ["src/sim/agents/intraSeasonTrips.ts"],
      reads: ["ResourcePatchMemory confidence/status/seasonality/risk/staleness through effectiveResourceConfidence"],
      sensitivity: "can select different future daily task targets or classify deterministic outcomes differently",
      decisionClass: "daily activity ledger",
      economy: false,
      readsActivityReturnOrEffectRecordsInEconomy: false,
    },
    {
      system: "resource belief opportunity",
      files: ["src/sim/agents/resourceKnowledge.ts", "src/sim/rules/bandDecision.ts", "src/sim/agents/socialContext.ts"],
      reads: ["effective confidence", "source", "resource class", "risk discount", "staleness"],
      sensitivity: "can change probe pressure / known-opportunity explanation used by movement scoring and context",
      decisionClass: "movement/probe scoring",
      economy: false,
      readsActivityReturnOrEffectRecordsInEconomy: false,
    },
    {
      system: "resource scout target selection",
      files: ["src/sim/agents/resourceScout.ts", "src/sim/rules/bandDecision.ts"],
      reads: ["effective confidence", "season match", "risk/cause rings", "access confidence", "learning/readiness"],
      sensitivity: "can reorder or gate resource_scout targets among already-known patch memories",
      decisionClass: "scouting",
      economy: false,
      readsActivityReturnOrEffectRecordsInEconomy: false,
    },
    {
      system: "plant use eligibility",
      files: ["src/sim/agents/plantUseEligibility.ts"],
      reads: ["plantObservation", "seasonality badSeasons", "risk suspicion", "effective confidence", "learning contradiction counters"],
      sensitivity: "can change future cautious plant follow-up/test readiness for known plant-bearing memories",
      decisionClass: "plant follow-up/testing",
      economy: false,
      readsActivityReturnOrEffectRecordsInEconomy: false,
    },
    {
      system: "observed patch return view",
      files: ["src/sim/agents/patchExploitationKnowledge.ts", "src/sim/agents/resourceScout.ts", "src/sim/agents/socialContext.ts"],
      reads: ["effective confidence", "plant caution", "risk", "seasonality", "useHistory", "learning", "exploitationSkill"],
      sensitivity: "can change patch-return debug/readiness and scout selection bias; projected support stays decision-side unless occupied",
      decisionClass: "scouting/opportunity",
      economy: false,
      readsActivityReturnOrEffectRecordsInEconomy: false,
    },
    {
      system: "learned support / carrying capacity",
      files: ["src/sim/agents/carryingCapacity.ts", "src/sim/agents/socialContext.ts"],
      reads: ["ResourcePatchMemory via deriveTileLearnedSupport when exploitationSkill exists"],
      sensitivity: "pre-existing 2K.9 coupling can alter band-specific learned usable support for occupied footprint or projected known opportunity",
      decisionClass: "existing learned-support economy/context",
      economy: true,
      readsActivityReturnOrEffectRecordsInEconomy: false,
      caveat: "This reads patch memory, not activityMemoryEffect/resourceReturn. Activity memory changes can theoretically reach it indirectly through patch confidence/status.",
    },
    {
      system: "fission / daughter inheritance",
      files: ["src/sim/agents/resourceKnowledge.ts", "src/sim/agents/demography.ts"],
      reads: ["resourcePatchRetentionScore", "effective confidence", "risk salience", "source/staleness"],
      sensitivity: "can affect which known patch memories a daughter inherits if fission occurs after activity updates",
      decisionClass: "daughter knowledge inheritance",
      economy: false,
      readsActivityReturnOrEffectRecordsInEconomy: false,
    },
  ];
}

function diffNumberRecord(left, right) {
  const keys = [...new Set([...Object.keys(left ?? {}), ...Object.keys(right ?? {})])].sort();
  const result = {};

  for (const key of keys) {
    const leftValue = typeof left?.[key] === "number" ? left[key] : 0;
    const rightValue = typeof right?.[key] === "number" ? right[key] : 0;
    result[key] = leftValue - rightValue;
  }

  return result;
}

function sumCases(cases, getValue) {
  return cases.reduce((sum, entry) => sum + getValue(entry), 0);
}

function makeActivityMemorySensitivityFingerprint(run) {
  return JSON.stringify({
    summary: {
      tick: run.result.summary.tick,
      totalPopulation: run.result.summary.totalPopulation,
      activeBands: run.result.summary.activeBands,
      totalBands: run.result.summary.totalBands,
      fissions: run.result.summary.fissions,
      extinctBands: run.result.summary.extinctBands,
      decisionArchive: run.result.summary.decisionArchive,
    },
    activityMemoryAudit: run.activityMemoryAudit,
    readerExposure: run.readerExposure,
    bands: Object.values(run.world.bands)
      .sort(compareBands)
      .map((band) => ({
        id: String(band.id),
        position: String(band.position),
        status: band.status,
        viability: band.viability?.status,
        population: toPopulationCount(band.demography.population),
        patchReasonIds: (band.resourceKnowledgeState?.patchMemories ?? [])
          .map((memory) => ({
            patchId: String(memory.patchId),
            confidence: memory.confidence,
            state: memory.state,
            reasonIds: memory.reasonIds.map(String),
          })),
      })),
  });
}

function runTargetedActivityMemoryReaderCausalCheck(modules, options) {
  const years = Number.isFinite(options.activityMemoryReaderYears) && options.activityMemoryReaderYears > 0
    ? Math.floor(options.activityMemoryReaderYears)
    : 100;
  const ticks = years * 4;
  const checkpointTicks = new Map([20, 50, 100]
    .filter((year) => year <= years)
    .map((year) => [year * 4, year]));
  let onWorld = modules.initSimWorld({ kind: "map2" });
  let offWorld = applyBenchmarkAuditOptions(modules.initSimWorld({ kind: "map2" }), {
    activityMemoryCouplingDisabledForAudit: true,
  });
  const firstDivergences = {
    activityMemoryWrite: undefined,
    dailyTripRetargeting: undefined,
    resourceScoutTargetSelection: undefined,
    resourceBeliefOpportunity: undefined,
    movementKnownOpportunity: undefined,
    learnedSupportProjection: undefined,
    fissionInheritance: undefined,
    decisionMix: undefined,
    finalBandState: undefined,
  };
  const checkpoints = [];
  let firstDecisionDivergenceContext;

  for (let tick = 1; tick <= ticks; tick += 1) {
    onWorld = modules.stepSim(onWorld, 1, "seasonal");
    offWorld = modules.stepSim(offWorld, 1, "seasonal");

    const snapshot = summarizeActivityMemoryReaderCausalSnapshot(onWorld, offWorld, modules);
    recordFirstActivityMemoryReaderDivergences(firstDivergences, snapshot);
    if (
      firstDecisionDivergenceContext === undefined &&
      firstDivergences.decisionMix !== undefined &&
      firstDivergences.decisionMix.tick === tick
    ) {
      firstDecisionDivergenceContext = summarizeActivityMemoryReaderCausalCheckpoint(snapshot);
    }

    const checkpointYear = checkpointTicks.get(tick);
    if (checkpointYear !== undefined) {
      checkpoints.push({
        year: checkpointYear,
        tick,
        summary: summarizeActivityMemoryReaderCausalCheckpoint(snapshot),
      });
    }
  }

  const finalSnapshot = summarizeActivityMemoryReaderCausalSnapshot(onWorld, offWorld, modules);
  const noEconomyCoupling =
    finalSnapshot.noEconomyCouplingProof.resourceReturnConsumedByEconomyCount === 0 &&
    finalSnapshot.noEconomyCouplingProof.resourceReturnGuardFailureCount === 0 &&
    finalSnapshot.noEconomyCouplingProof.activityMemoryGuardFailureCount === 0;
  const noHiddenTruth =
    finalSnapshot.antiOmniscienceProof.activityMemoryHiddenTruthFailureCount === 0 &&
    finalSnapshot.antiOmniscienceProof.bandKnownTargetsOnly === true;
  const likelyCause = inferActivityMemoryReaderLikelyCause(
    firstDivergences,
    finalSnapshot,
    firstDecisionDivergenceContext,
  );

  return {
    check: "ACTIVITY-GROUPS-7 targeted activity-memory reader causal audit",
    verdict: noEconomyCoupling && noHiddenTruth ? "pass" : "review",
    scenario: "map2_varied_migration",
    years,
    notes: [
      "ON/OFF worlds advance in lockstep through stepSim(..., seasonal), so daily trips and seasonal decisions both execute.",
      "The audit observes reader outputs; it does not tune scores, add movement bonuses, create resources, or feed economy.",
      "Reader score/target deltas are benchmark-only comparisons of current ON/OFF band-private memory state.",
    ],
    likelyCause,
    firstDivergences,
    firstDecisionDivergenceContext,
    checkpoints,
    final: finalSnapshot,
    readerConclusions: buildActivityMemoryReaderConclusions(firstDivergences, finalSnapshot),
  };
}

function recordFirstActivityMemoryReaderDivergences(firstDivergences, snapshot) {
  const readers = snapshot.readers;

  if (firstDivergences.activityMemoryWrite === undefined && snapshot.activityMemoryWrite.onNonNoneEffects > 0) {
    firstDivergences.activityMemoryWrite = makeFirstReaderDivergenceRecord(snapshot, {
      changedCount: snapshot.activityMemoryWrite.onNonNoneEffects,
      sample: snapshot.activityMemoryWrite.effectCountsOn,
    });
  }

  for (const [key, metric] of [
    ["dailyTripRetargeting", readers.dailyTripRetargeting],
    ["resourceScoutTargetSelection", readers.resourceScoutTargetSelection],
    ["resourceBeliefOpportunity", readers.resourceBeliefOpportunity],
    ["movementKnownOpportunity", readers.movementKnownOpportunity],
    ["learnedSupportProjection", readers.learnedSupportProjection],
    ["fissionInheritance", readers.fissionInheritance],
  ]) {
    if (firstDivergences[key] === undefined && metric.changedCount > 0) {
      firstDivergences[key] = makeFirstReaderDivergenceRecord(snapshot, metric);
    }
  }

  if (
    firstDivergences.decisionMix === undefined &&
    snapshot.decisionDeltas.changedDecisionArchiveFields.length > 0
  ) {
    firstDivergences.decisionMix = makeFirstReaderDivergenceRecord(snapshot, {
      changedCount: snapshot.decisionDeltas.changedDecisionArchiveFields.length,
      sample: snapshot.decisionDeltas.changedDecisionArchiveFields,
    });
  }

  if (
    firstDivergences.finalBandState === undefined &&
    (
      snapshot.finalBandDelta.positionChangedCount > 0 ||
      snapshot.finalBandDelta.populationChangedCount > 0 ||
      snapshot.finalBandDelta.statusChangedCount > 0
    )
  ) {
    firstDivergences.finalBandState = makeFirstReaderDivergenceRecord(snapshot, {
      changedCount:
        snapshot.finalBandDelta.positionChangedCount +
        snapshot.finalBandDelta.populationChangedCount +
        snapshot.finalBandDelta.statusChangedCount,
      sample: snapshot.finalBandDelta.samples,
    });
  }
}

function makeFirstReaderDivergenceRecord(snapshot, metric) {
  return {
    tick: snapshot.tick,
    year: snapshot.year,
    season: snapshot.season,
    day: snapshot.day,
    changedCount: metric.changedCount,
    sample: metric.sample,
  };
}

function summarizeActivityMemoryReaderCausalSnapshot(onWorld, offWorld, modules) {
  const onTripAudit = summarizeTimeScaleTrips(onWorld);
  const offTripAudit = summarizeTimeScaleTrips(offWorld);
  const onMemoryAudit = summarizeActivityMemoryAudit(onWorld);
  const offMemoryAudit = summarizeActivityMemoryAudit(offWorld);
  const onExposure = summarizeActivityMemoryReaderExposure(onWorld, modules);
  const offExposure = summarizeActivityMemoryReaderExposure(offWorld, modules);
  const onSummary = summarizeTimeScaleWorld(onWorld);
  const offSummary = summarizeTimeScaleWorld(offWorld);
  const decisionDeltas = diffNumberRecord(onSummary, offSummary);
  const archiveDeltas = diffNumberRecord(onWorld.decisionArchive, offWorld.decisionArchive);
  const changedDecisionArchiveFields = Object.entries(archiveDeltas)
    .filter(([, delta]) => delta !== 0)
    .map(([field, delta]) => ({ field, delta }));
  const finalBandDelta = compareFinalBands(onWorld, offWorld);
  const readers = summarizeActivityMemoryReaderDeltas(onWorld, offWorld, modules);

  return {
    tick: onSummary.tick,
    day: onSummary.day,
    year: onSummary.year,
    season: onSummary.season,
    activityMemoryWrite: {
      onTrips: onTripAudit.totalTrips,
      offTrips: offTripAudit.totalTrips,
      onNonNoneEffects: Object.entries(onMemoryAudit.effectCounts)
        .filter(([effectType]) => effectType !== "none")
        .reduce((sum, [, count]) => sum + count, 0),
      offNonNoneEffects: Object.entries(offMemoryAudit.effectCounts)
        .filter(([effectType]) => effectType !== "none")
        .reduce((sum, [, count]) => sum + count, 0),
      effectCountsOn: onMemoryAudit.effectCounts,
      effectCountsOff: offMemoryAudit.effectCounts,
      touchedMemoryCountOn: onMemoryAudit.touchedMemoryCount,
      touchedMemoryCountOff: offMemoryAudit.touchedMemoryCount,
    },
    readers,
    readerExposure: {
      on: onExposure.potentialReaderExposure,
      off: offExposure.potentialReaderExposure,
      delta: diffNumberRecord(onExposure.potentialReaderExposure, offExposure.potentialReaderExposure),
    },
    macroDeltas: {
      totalPopulation: onSummary.totalPopulation - offSummary.totalPopulation,
      activeBands: onSummary.activeBands - offSummary.activeBands,
      totalBands: onSummary.totalBands - offSummary.totalBands,
      fissions: onSummary.fissions - offSummary.fissions,
      extinctBands: onSummary.extinctBands - offSummary.extinctBands,
      absorbedBands: onSummary.absorbedBands - offSummary.absorbedBands,
      knownTileRecordsTotal: countKnownTileRecords(onWorld) - countKnownTileRecords(offWorld),
    },
    decisionDeltas: {
      summaryFieldDeltas: decisionDeltas,
      archiveDeltas,
      changedDecisionArchiveFields,
    },
    finalBandDelta,
    noEconomyCouplingProof: {
      resourceReturnConsumedByEconomyCount:
        onTripAudit.resourceReturnConsumedByEconomyCount + offTripAudit.resourceReturnConsumedByEconomyCount,
      resourceReturnGuardFailureCount:
        onTripAudit.resourceReturnGuardFailureCount + offTripAudit.resourceReturnGuardFailureCount,
      activityMemoryGuardFailureCount:
        onMemoryAudit.guardFailureCount + offMemoryAudit.guardFailureCount,
      noDirectActivityReturnOrEffectEconomyReaders: true,
      existingPatchMemoryEconomyReader:
        "2K.9 learned support reads ResourcePatchMemory through deriveTileLearnedSupport; this audit measures its projection deltas separately.",
    },
    antiOmniscienceProof: {
      activityMemoryHiddenTruthFailureCount:
        onMemoryAudit.hiddenTruthFailureCount + offMemoryAudit.hiddenTruthFailureCount,
      bandKnownTargetsOnly: onTripAudit.bandKnownTargetsOnly === true && offTripAudit.bandKnownTargetsOnly === true,
      noNewResourceDiscoveryGuard: true,
    },
  };
}

function summarizeActivityMemoryReaderDeltas(onWorld, offWorld, modules) {
  const tripRetarget = compareRecentTripReaders(onWorld, offWorld);
  const scoutTarget = compareResourceScoutTargetReaders(onWorld, offWorld, modules);
  const belief = compareResourceBeliefReaders(onWorld, offWorld, modules);
  const knownOpportunity = compareMovementKnownOpportunityReaders(onWorld, offWorld);
  const learnedSupport = compareLearnedSupportReaders(onWorld, offWorld);
  const fissionInheritance = compareFissionInheritanceReaders(onWorld, offWorld);

  return {
    dailyTripRetargeting: tripRetarget,
    resourceScoutTargetSelection: scoutTarget,
    resourceBeliefOpportunity: belief,
    movementKnownOpportunity: knownOpportunity,
    learnedSupportProjection: learnedSupport,
    fissionInheritance,
  };
}

function compareRecentTripReaders(onWorld, offWorld) {
  const samples = [];
  let changedTargetCount = 0;
  let changedOutcomeCount = 0;
  let changedTaskTypeCount = 0;
  let changedCount = 0;
  let consumedActivityUpdatedMemoryCount = 0;

  for (const { onBand, offBand } of iterateCommonActiveBands(onWorld, offWorld)) {
    const offTripsByDay = new Map((offBand.recentIntraSeasonTrips ?? []).map((trip) => [Number(trip.day), trip]));

    for (const onTrip of onBand.recentIntraSeasonTrips ?? []) {
      const offTrip = offTripsByDay.get(Number(onTrip.day));
      if (offTrip === undefined) {
        continue;
      }

      const targetChanged = String(onTrip.targetTileId) !== String(offTrip.targetTileId);
      const outcomeChanged = onTrip.activityOutcome !== offTrip.activityOutcome || onTrip.outcome !== offTrip.outcome;
      const taskTypeChanged = onTrip.taskGroupType !== offTrip.taskGroupType;
      if (!targetChanged && !outcomeChanged && !taskTypeChanged) {
        continue;
      }

      changedCount += 1;
      changedTargetCount += targetChanged ? 1 : 0;
      changedOutcomeCount += outcomeChanged ? 1 : 0;
      changedTaskTypeCount += taskTypeChanged ? 1 : 0;
      consumedActivityUpdatedMemoryCount += hasActivityTouchedMemoryForTile(onBand, onTrip.targetTileId) ? 1 : 0;

      if (samples.length < 6) {
        samples.push({
          bandId: String(onBand.id),
          day: Number(onTrip.day),
          onTarget: String(onTrip.targetTileId),
          offTarget: String(offTrip.targetTileId),
          onTaskType: onTrip.taskGroupType,
          offTaskType: offTrip.taskGroupType,
          onOutcome: onTrip.activityOutcome,
          offOutcome: offTrip.activityOutcome,
        });
      }
    }
  }

  return {
    reader: "daily trip retargeting",
    changedCount,
    changedTargetCount,
    changedOutcomeCount,
    changedTaskTypeCount,
    consumedActivityUpdatedMemoryCount,
    touchesEconomyPath: false,
    readsHiddenTruth: false,
    sample: samples,
  };
}

function compareResourceScoutTargetReaders(onWorld, offWorld, modules) {
  const samples = [];
  let changedTargetCount = 0;
  let changedScoreCount = 0;
  let changedGuidanceCount = 0;
  let consumedActivityUpdatedMemoryCount = 0;

  for (const { onBand, offBand } of iterateCommonActiveBands(onWorld, offWorld)) {
    const onCandidate = modules.selectResourceScoutTargetForAudit(onWorld, onBand);
    const offCandidate = modules.selectResourceScoutTargetForAudit(offWorld, offBand);
    const targetChanged = String(onCandidate?.targetTileId) !== String(offCandidate?.targetTileId);
    const scoreDelta = round4((onCandidate?.voiScore ?? 0) - (offCandidate?.voiScore ?? 0));
    const selectionDelta = round4(getScoutSelectionKey(onCandidate) - getScoutSelectionKey(offCandidate));
    const scoreChanged = Math.abs(scoreDelta) > 0.0001 || Math.abs(selectionDelta) > 0.0001;
    const guidanceChanged =
      onCandidate?.patchReturnGuidance?.guidanceReason !== offCandidate?.patchReturnGuidance?.guidanceReason ||
      (onCandidate?.patchReturnGuidance?.selectionBias ?? 0) !== (offCandidate?.patchReturnGuidance?.selectionBias ?? 0);

    if (!targetChanged && !scoreChanged && !guidanceChanged) {
      continue;
    }

    changedTargetCount += targetChanged ? 1 : 0;
    changedScoreCount += scoreChanged ? 1 : 0;
    changedGuidanceCount += guidanceChanged ? 1 : 0;
    const consumed = onCandidate !== undefined &&
      hasActivityTouchedMemoryForTile(onBand, onCandidate.targetTileId, onCandidate.targetResourceClass);
    consumedActivityUpdatedMemoryCount += consumed ? 1 : 0;

    if (samples.length < 6) {
      samples.push({
        bandId: String(onBand.id),
        onTarget: onCandidate === undefined ? undefined : String(onCandidate.targetTileId),
        offTarget: offCandidate === undefined ? undefined : String(offCandidate.targetTileId),
        onClass: onCandidate?.targetResourceClass,
        offClass: offCandidate?.targetResourceClass,
        onVoiScore: onCandidate?.voiScore,
        offVoiScore: offCandidate?.voiScore,
        scoreDelta,
        onSelectionKey: round4(getScoutSelectionKey(onCandidate)),
        offSelectionKey: round4(getScoutSelectionKey(offCandidate)),
        selectionDelta,
        onGuidance: summarizeScoutGuidance(onCandidate),
        offGuidance: summarizeScoutGuidance(offCandidate),
        consumedActivityUpdatedMemory: consumed,
      });
    }
  }

  return {
    reader: "resource scout target selection",
    changedCount: changedTargetCount + changedScoreCount + changedGuidanceCount,
    changedTargetCount,
    changedScoreCount,
    changedGuidanceCount,
    consumedActivityUpdatedMemoryCount,
    touchesEconomyPath: false,
    readsHiddenTruth: false,
    sample: samples,
  };
}

function getScoutSelectionKey(candidate) {
  if (candidate === undefined) {
    return 0;
  }

  return round4((candidate.voiScore ?? 0) + (candidate.patchReturnGuidance?.selectionBias ?? 0));
}

function summarizeScoutGuidance(candidate) {
  if (candidate === undefined) {
    return undefined;
  }

  return {
    reason: candidate.patchReturnGuidance.guidanceReason,
    bias: candidate.patchReturnGuidance.selectionBias,
    learnedRankDelta: candidate.patchReturnGuidance.learnedRankDelta,
    readiness: candidate.patchReturnGuidance.readiness,
    riskState: candidate.patchReturnGuidance.riskState,
  };
}

function compareResourceBeliefReaders(onWorld, offWorld, modules) {
  const samples = [];
  let changedBestTileCount = 0;
  let changedScoreCount = 0;
  let consumedActivityUpdatedMemoryCount = 0;

  for (const { onBand, offBand } of iterateCommonActiveBands(onWorld, offWorld)) {
    const onBelief = deriveBandResourceBeliefForAudit(onWorld, onBand, modules);
    const offBelief = deriveBandResourceBeliefForAudit(offWorld, offBand, modules);
    const bestChanged = String(onBelief.bestBeliefTile ?? "") !== String(offBelief.bestBeliefTile ?? "");
    const scoreDelta = round4((onBelief.beliefOpportunityScore ?? 0) - (offBelief.beliefOpportunityScore ?? 0));
    const scoreChanged = Math.abs(scoreDelta) > 0.0001;

    if (!bestChanged && !scoreChanged) {
      continue;
    }

    changedBestTileCount += bestChanged ? 1 : 0;
    changedScoreCount += scoreChanged ? 1 : 0;
    const consumed = onBelief.bestBeliefTile !== undefined &&
      hasActivityTouchedMemoryForTile(onBand, onBelief.bestBeliefTile, onBelief.bestBeliefClass);
    consumedActivityUpdatedMemoryCount += consumed ? 1 : 0;

    if (samples.length < 6) {
      samples.push({
        bandId: String(onBand.id),
        onBestTile: onBelief.bestBeliefTile === undefined ? undefined : String(onBelief.bestBeliefTile),
        offBestTile: offBelief.bestBeliefTile === undefined ? undefined : String(offBelief.bestBeliefTile),
        onBestClass: onBelief.bestBeliefClass,
        offBestClass: offBelief.bestBeliefClass,
        onScore: onBelief.beliefOpportunityScore,
        offScore: offBelief.beliefOpportunityScore,
        scoreDelta,
        consumedActivityUpdatedMemory: consumed,
      });
    }
  }

  return {
    reader: "resource belief opportunity",
    changedCount: changedBestTileCount + changedScoreCount,
    changedBestTileCount,
    changedScoreCount,
    consumedActivityUpdatedMemoryCount,
    touchesEconomyPath: false,
    readsHiddenTruth: false,
    sample: samples,
  };
}

function deriveBandResourceBeliefForAudit(world, band, modules) {
  return modules.deriveResourceBeliefOpportunity(band.resourceKnowledgeState, {
    currentTileId: band.position,
    currentTick: Number(world.time.tick),
    waterStress: band.pressureState?.waterStress ?? 0,
    perCapitaReturn:
      band.carryingCapacity?.perCapitaReturn?.perCapitaReturn ??
      band.perCapitaReturn?.perCapitaReturn ??
      0.5,
    chronicDecline: band.returnTrend?.chronicDecline === true,
  });
}

function compareMovementKnownOpportunityReaders(onWorld, offWorld) {
  const samples = [];
  let changedNearbyOpportunityCount = 0;
  let changedKnownUnusedHabitatCount = 0;
  let changedExhaustedRangeCount = 0;
  let consumedActivityUpdatedMemoryCount = 0;

  for (const { onBand, offBand } of iterateCommonActiveBands(onWorld, offWorld)) {
    const onNearby = summarizeNearbyOpportunityForCausalAudit(onBand.nearbyOpportunity);
    const offNearby = summarizeNearbyOpportunityForCausalAudit(offBand.nearbyOpportunity);
    const onKnown = summarizeKnownUnusedForCausalAudit(onBand.carryingCapacity?.knownUnusedHabitat);
    const offKnown = summarizeKnownUnusedForCausalAudit(offBand.carryingCapacity?.knownUnusedHabitat);
    const onExhausted = summarizeExhaustedForCausalAudit(onBand.exhaustedRangeAudit);
    const offExhausted = summarizeExhaustedForCausalAudit(offBand.exhaustedRangeAudit);
    const nearbyChanged = JSON.stringify(onNearby) !== JSON.stringify(offNearby);
    const knownChanged = JSON.stringify(onKnown) !== JSON.stringify(offKnown);
    const exhaustedChanged = JSON.stringify(onExhausted) !== JSON.stringify(offExhausted);

    if (!nearbyChanged && !knownChanged && !exhaustedChanged) {
      continue;
    }

    changedNearbyOpportunityCount += nearbyChanged ? 1 : 0;
    changedKnownUnusedHabitatCount += knownChanged ? 1 : 0;
    changedExhaustedRangeCount += exhaustedChanged ? 1 : 0;
    const consumed = (
      (onNearby.bestKnownOpportunityTileId !== undefined &&
        hasActivityTouchedMemoryForTile(onBand, onNearby.bestKnownOpportunityTileId)) ||
      (onKnown.candidateTileId !== undefined && hasActivityTouchedMemoryForTile(onBand, onKnown.candidateTileId))
    );
    consumedActivityUpdatedMemoryCount += consumed ? 1 : 0;

    if (samples.length < 6) {
      samples.push({
        bandId: String(onBand.id),
        onNearby,
        offNearby,
        onKnownUnused: onKnown,
        offKnownUnused: offKnown,
        onExhausted,
        offExhausted,
        consumedActivityUpdatedMemory: consumed,
      });
    }
  }

  return {
    reader: "movement / known opportunity scoring",
    changedCount: changedNearbyOpportunityCount + changedKnownUnusedHabitatCount + changedExhaustedRangeCount,
    changedNearbyOpportunityCount,
    changedKnownUnusedHabitatCount,
    changedExhaustedRangeCount,
    consumedActivityUpdatedMemoryCount,
    touchesEconomyPath: false,
    readsHiddenTruth: false,
    sample: samples,
  };
}

function summarizeNearbyOpportunityForCausalAudit(value) {
  return {
    bestKnownOpportunityTileId: value?.bestKnownOpportunityTileId === undefined
      ? undefined
      : String(value.bestKnownOpportunityTileId),
    opportunityStrength: round4(value?.opportunityStrength ?? 0),
    passabilityConfidence: round4(value?.passabilityConfidence ?? 0),
    learnedSupportGate: round4(value?.learnedSupportGate ?? 0),
    currentLearnedSupport: round4(value?.currentLearnedSupport ?? 0),
    bestCandidateLearnedSupport: round4(value?.bestCandidateLearnedSupport ?? 0),
    candidatesWithLearnedSupport: value?.candidatesWithLearnedSupport ?? 0,
  };
}

function summarizeKnownUnusedForCausalAudit(value) {
  return {
    candidateTileId: value?.candidateTileId === undefined ? undefined : String(value.candidateTileId),
    opportunityKind: value?.opportunityKind,
    expectedPerCapitaReturn: round4(value?.expectedPerCapitaReturn ?? 0),
    confidence: round4(value?.confidence ?? 0),
    consideredAsTarget: value?.consideredAsTarget ?? false,
    rejectionReason: value?.rejectionReason,
  };
}

function summarizeExhaustedForCausalAudit(value) {
  return {
    knownUnusedOpportunity: round4(value?.knownUnusedOpportunity ?? 0),
    hasViableKnownTarget: value?.hasViableKnownTarget ?? false,
    probeSuggestedBeforeRelocation: value?.probeSuggestedBeforeRelocation ?? false,
    beliefOpportunityScore: round4(value?.beliefOpportunityScore ?? 0),
    onlyInferredOpportunity: value?.onlyInferredOpportunity ?? false,
  };
}

function compareLearnedSupportReaders(onWorld, offWorld) {
  const samples = [];
  let changedProjectionCount = 0;
  let changedCurrentFootprintCount = 0;
  let consumedActivityUpdatedMemoryCount = 0;

  for (const { onBand, offBand } of iterateCommonActiveBands(onWorld, offWorld)) {
    const onLearned = summarizeBandLearnedSupportForCausalAudit(onBand);
    const offLearned = summarizeBandLearnedSupportForCausalAudit(offBand);
    const projectionChanged =
      Math.abs(onLearned.candidateProjectedLearnedSupportDelta - offLearned.candidateProjectedLearnedSupportDelta) > 0.0001 ||
      Math.abs(onLearned.bestCandidateLearnedSupport - offLearned.bestCandidateLearnedSupport) > 0.0001;
    const currentChanged =
      Math.abs(onLearned.realizedLearnedSupportDelta - offLearned.realizedLearnedSupportDelta) > 0.0001 ||
      Math.abs(onLearned.currentLearnedSupport - offLearned.currentLearnedSupport) > 0.0001;

    if (!projectionChanged && !currentChanged) {
      continue;
    }

    changedProjectionCount += projectionChanged ? 1 : 0;
    changedCurrentFootprintCount += currentChanged ? 1 : 0;
    const consumed = onLearned.activityTouchedMatchedPatchCount > 0;
    consumedActivityUpdatedMemoryCount += consumed ? 1 : 0;

    if (samples.length < 6) {
      samples.push({
        bandId: String(onBand.id),
        on: onLearned,
        off: offLearned,
        consumedActivityUpdatedMemory: consumed,
      });
    }
  }

  return {
    reader: "learned support / 2K.9 projection",
    changedCount: changedProjectionCount + changedCurrentFootprintCount,
    changedProjectionCount,
    changedCurrentFootprintCount,
    consumedActivityUpdatedMemoryCount,
    touchesEconomyPath: true,
    readsHiddenTruth: false,
    sample: samples,
  };
}

function summarizeBandLearnedSupportForCausalAudit(band) {
  const supportDebug = band.carryingCapacity?.perCapitaReturn?.supportDebug;

  return {
    realizedLearnedSupportDelta: round4(supportDebug?.realizedLearnedSupportDelta ?? 0),
    candidateProjectedLearnedSupportDelta: round4(supportDebug?.candidateProjectedLearnedSupportDelta ?? 0),
    currentLearnedSupport: round4(band.nearbyOpportunity?.currentLearnedSupport ?? 0),
    bestCandidateLearnedSupport: round4(band.nearbyOpportunity?.bestCandidateLearnedSupport ?? 0),
    learnedSupportGate: round4(band.nearbyOpportunity?.learnedSupportGate ?? 0),
    candidatesWithLearnedSupport: band.nearbyOpportunity?.candidatesWithLearnedSupport ?? 0,
    sourceClasses: supportDebug?.realizedLearnedSupportSourceClasses ?? [],
    blockedReasons: supportDebug?.realizedLearnedSupportBlockedReasons ?? [],
    activityTouchedMatchedPatchCount: (band.resourceKnowledgeState?.patchMemories ?? []).filter((memory) =>
      getActivityMemoryTouch(memory, getRecentActivityTouchedPatchIds(band)) !== undefined &&
      memory.approximateTile === band.position,
    ).length,
  };
}

function compareFissionInheritanceReaders(onWorld, offWorld) {
  const onFissions = getUniqueFissionEvents(Object.values(onWorld.bands));
  const offFissions = getUniqueFissionEvents(Object.values(offWorld.bands));
  const samples = [];
  let daughterMemoryDiffCount = 0;

  for (const { onBand, offBand } of iterateCommonActiveBands(onWorld, offWorld)) {
    if (onBand.parentBandId === undefined && offBand.parentBandId === undefined) {
      continue;
    }

    const onMemoryCount = onBand.resourceKnowledgeState?.patchMemories.length ?? 0;
    const offMemoryCount = offBand.resourceKnowledgeState?.patchMemories.length ?? 0;
    if (onMemoryCount === offMemoryCount) {
      continue;
    }

    daughterMemoryDiffCount += 1;
    if (samples.length < 6) {
      samples.push({
        bandId: String(onBand.id),
        parentBandId: String(onBand.parentBandId ?? offBand.parentBandId),
        onMemoryCount,
        offMemoryCount,
      });
    }
  }

  return {
    reader: "daughter/fission memory inheritance",
    changedCount: Math.abs(onFissions.length - offFissions.length) + daughterMemoryDiffCount,
    fissionCountDelta: onFissions.length - offFissions.length,
    daughterMemoryDiffCount,
    consumedActivityUpdatedMemoryCount: 0,
    touchesEconomyPath: false,
    readsHiddenTruth: false,
    sample: samples,
  };
}

function iterateCommonActiveBands(onWorld, offWorld) {
  const pairs = [];
  for (const onBand of Object.values(onWorld.bands).filter(isActiveBand).sort(compareBands)) {
    const offBand = offWorld.bands[onBand.id];
    if (offBand !== undefined && isActiveBand(offBand)) {
      pairs.push({ onBand, offBand });
    }
  }

  return pairs;
}

function hasActivityTouchedMemoryForTile(band, tileId, resourceClassId) {
  const recentPatchIds = getRecentActivityTouchedPatchIds(band);
  return (band.resourceKnowledgeState?.patchMemories ?? []).some((memory) =>
    memory.approximateTile === tileId &&
    (resourceClassId === undefined || memory.resourceClassId === resourceClassId) &&
    getActivityMemoryTouch(memory, recentPatchIds) !== undefined
  );
}

function countKnownTileRecords(world) {
  return Object.values(world.bands)
    .reduce((sum, band) => sum + Object.keys(band.knowledge.observedTiles).length, 0);
}

function summarizeActivityMemoryReaderCausalCheckpoint(snapshot) {
  return {
    macroDeltas: snapshot.macroDeltas,
    decisionChanges: snapshot.decisionDeltas.changedDecisionArchiveFields,
    finalBandDelta: snapshot.finalBandDelta,
    activityMemoryWrite: snapshot.activityMemoryWrite,
    readers: Object.fromEntries(Object.entries(snapshot.readers).map(([key, value]) => [
      key,
      {
        changedCount: value.changedCount,
        consumedActivityUpdatedMemoryCount: value.consumedActivityUpdatedMemoryCount,
        touchesEconomyPath: value.touchesEconomyPath,
        sample: value.sample.slice(0, 2),
      },
    ])),
  };
}

function inferActivityMemoryReaderLikelyCause(firstDivergences, finalSnapshot, firstDecisionDivergenceContext) {
  if (firstDivergences.decisionMix === undefined) {
    return {
      reader: "none",
      confidence: "high",
      reason: "No decision-mix divergence occurred inside the audited horizon.",
    };
  }

  const decisionTick = firstDivergences.decisionMix.tick;
  const readerCandidates = Object.entries(firstDivergences)
    .filter(([key, value]) =>
      value !== undefined &&
      key !== "activityMemoryWrite" &&
      key !== "decisionMix" &&
      key !== "finalBandState" &&
      value.tick <= decisionTick,
    )
    .map(([reader, value]) => ({ reader, tick: value.tick, changedCount: value.changedCount }));
  const sameTick = readerCandidates.filter((entry) => entry.tick === decisionTick);
  const directDecisionReaders = Object.entries(firstDecisionDivergenceContext?.readers ?? {})
    .filter(([, value]) => value.changedCount > 0)
    .map(([reader, value]) => ({
      reader,
      changedCount: value.changedCount,
      consumedActivityUpdatedMemoryCount: value.consumedActivityUpdatedMemoryCount,
      touchesEconomyPath: value.touchesEconomyPath,
      sample: value.sample,
    }));
  const directLikely = directDecisionReaders.find((entry) => entry.reader === "movementKnownOpportunity") ??
    directDecisionReaders.find((entry) => entry.reader === "resourceScoutTargetSelection") ??
    directDecisionReaders.find((entry) => entry.reader === "resourceBeliefOpportunity") ??
    directDecisionReaders[0];
  const likely = directLikely ??
    sameTick.find((entry) => entry.reader === "movementKnownOpportunity") ??
    sameTick.find((entry) => entry.reader === "resourceScoutTargetSelection") ??
    sameTick.find((entry) => entry.reader === "resourceBeliefOpportunity") ??
    readerCandidates.find((entry) => entry.reader === "movementKnownOpportunity") ??
    readerCandidates.find((entry) => entry.reader === "resourceScoutTargetSelection") ??
    readerCandidates[0];

  return {
    reader: likely?.reader ?? "unknown",
    confidence: likely === undefined ? "low" : directDecisionReaders.length > 1 ? "medium" : "medium_high",
    firstDecisionDivergenceTick: decisionTick,
    supportingReaderDivergencesBeforeOrAtDecision: readerCandidates,
    directDecisionReaderDeltas: directDecisionReaders,
    finalDecisionChanges: finalSnapshot.decisionDeltas.changedDecisionArchiveFields,
    reason: "Causal attribution prioritizes reader deltas present at the first decision-archive divergence, with earlier reader deltas reported as upstream contributors.",
  };
}

function buildActivityMemoryReaderConclusions(firstDivergences, finalSnapshot) {
  const entries = {};
  for (const [key, metric] of Object.entries(finalSnapshot.readers)) {
    entries[key] = {
      changedCount: metric.changedCount,
      consumedActivityUpdatedMemoryCount: metric.consumedActivityUpdatedMemoryCount,
      firstDivergence: firstDivergences[key],
      touchesEconomyPath: metric.touchesEconomyPath,
      readsHiddenTruth: metric.readsHiddenTruth,
      assessment: metric.changedCount === 0
        ? "no observed ON/OFF reader output delta at final horizon"
        : metric.touchesEconomyPath
          ? "existing learned-support path is sensitive to patch memory; no new activity-return economy read was added"
          : "reader output differs through existing band-known memory path",
    };
  }

  return entries;
}

function runTargetedActivityMemoryReaderFixtureCheck(modules) {
  const checks = [];
  const push = (name, passed) => checks.push({ name, passed });

  const threshold = buildAg8MovementThresholdFixtures(modules);
  const belief = buildAg8BeliefMemoryFixtures(modules);
  const movement = buildAg8ActivityMemoryMovementGateFixtures(modules);
  const learned = buildAg8LearnedSupportFixtures(modules);
  const knownSensitivityCase = {
    scenario: "map2_varied_migration",
    validationCommand: "node scripts/simBenchmark.mjs --targeted-activity-memory-reader-causal --activity-memory-reader-years 100 --json",
    expectedDirectReader: "movementKnownOpportunity",
    expectedFirstDecisionTick: 212,
    expectedFinalDecisionDeltas: {
      totalFrontierMoves: 26,
      totalMoveDecisions: 26,
      totalProbeDecisions: -2,
      totalResourceScoutDecisions: -24,
    },
    note: "AG8 keeps fixtures fast; the full known-case replay is run as the separate AG7 causal audit in validation.",
  };

  push("M1_below_threshold_not_viable", threshold.below.hasViableKnownTarget === false);
  push("M2_at_threshold_still_not_viable_strict_greater_than", threshold.at.hasViableKnownTarget === false);
  push("M3_above_threshold_viable", threshold.above.hasViableKnownTarget === true);
  push("M4_threshold_margin_small", threshold.above.thresholdMargin > 0 && threshold.above.thresholdMargin <= 0.03);

  push("B1_refresh_can_cross_belief_threshold",
    belief.refreshCrosses.before.hasBelievableOpportunity === false &&
      belief.refreshCrosses.after.hasBelievableOpportunity === true);
  push("B2_refresh_can_remain_same_branch_when_already_believable",
    belief.refreshNoFlip.before.hasBelievableOpportunity === true &&
      belief.refreshNoFlip.after.hasBelievableOpportunity === true &&
      belief.refreshNoFlip.before.readerBranch === belief.refreshNoFlip.after.readerBranch);
  push("B3_lowering_can_remove_believable_patch",
    belief.loweringPrevents.before.hasBelievableOpportunity === true &&
      belief.loweringPrevents.after.hasBelievableOpportunity === false);
  push("B4_seasonality_hint_is_recorded_but_not_a_strong_current_reader",
    belief.seasonalityHint.after.badSeasons.includes(belief.seasonalityHint.season) &&
      Math.abs(belief.seasonalityHint.after.score - belief.seasonalityHint.before.score) <= 0.02);

  push("G1_activity_refresh_can_unlock_movement_known_target",
    movement.refreshUnlocks.before.hasViableKnownTarget === false &&
      movement.refreshUnlocks.after.hasViableKnownTarget === true);
  push("G2_activity_lowering_can_lock_movement_known_target",
    movement.loweringLocks.before.hasViableKnownTarget === true &&
      movement.loweringLocks.after.hasViableKnownTarget === false);
  push("G3_activity_movement_delta_bounded",
    Math.abs(movement.refreshUnlocks.scoreDelta) <= 0.08 &&
      Math.abs(movement.loweringLocks.scoreDelta) <= 0.08);

  push("L1_weak_confidence_not_certain_support",
    learned.weakConfidence.observedConfidence === "weak" &&
      learned.weakConfidence.support <= 0.06 &&
      learned.weakConfidence.matchedPatchCount <= 1);
  push("L2_activity_refresh_can_cross_learned_support_actionability",
    learned.refreshProjection.before.tileSupport === 0 &&
      learned.refreshProjection.after.tileSupport > 0);
  push("L3_projected_support_bounded",
    learned.refreshProjection.after.candidateProjectedLearnedSupportDelta > 0 &&
      learned.refreshProjection.after.candidateProjectedLearnedSupportDelta <= 0.3);
  push("L4_lowering_can_remove_learned_support_without_negative_economy",
    learned.loweringProjection.before.tileSupport > 0 &&
      learned.loweringProjection.after.tileSupport === 0 &&
      learned.loweringProjection.after.realizedLearnedSupportDelta === 0);

  return {
    suite: "targeted_activity_memory_reader_fixture",
    checkpoint: "ACTIVITY-GROUPS-8",
    passed: checks.every((entry) => entry.passed),
    assertions: checks,
    readersFixtureTested: [
      "movementKnownOpportunity / nearbyOpportunity > 0.12 gate",
      "resource belief opportunity >= 0.1 gate",
      "activity memory confidence refresh/lower/seasonality effects",
      "2K.8 decision-side learned support in deriveNearbyOpportunityGradient",
      "2K.9 realized/projected learned support in deriveCarryingCapacity",
      "AG7 Map2 100y ON/OFF causal replay",
    ],
    movementKnownOpportunity: {
      threshold,
      belief,
      movement,
      interpretation:
        "Sensitivity is real at explicit thresholds: >0.12 for nearbyOpportunity viability and >=0.1 for belief opportunity. Activity memory deltas are small, but can cross those thresholds when the reader is already near the margin.",
    },
    learnedSupportProjection: {
      ...learned,
      interpretation:
        "2K.9 can read activity-updated ResourcePatchMemory indirectly, but support is gated by matching skill, actionability, footprint/projection rules, and bounded support caps. Weak confidence remains weak and does not become certain support.",
    },
    knownSensitivityCase,
    constraints: {
      simBehaviorChanged: false,
      noFoodCouplingAdded: true,
      noYieldOrSupportFormulaChanged: true,
      noPopulationStressMortalityChange: true,
      noFissionRelocationTuning: true,
      noHiddenDiscovery: true,
      deterministic: true,
    },
    recommendation:
      "Do not tune yet. Before real resource returns feed economy, add a focused AG9 decision fixture around full evaluateBandDecision for the dry-corridor band at the tick-212 branch, or damp activity-memory effects only if that fixture proves outsized branch flips away from near-threshold cases.",
  };
}

// ===========================================================================
// ACTIVITY-GROUPS-9 — full evaluateBandDecision divergence fixture.
//
// AG7 found the first Map 2 100y activity-memory ON/OFF decision divergence at
// tick 212 / year 53 spring (ON +1 frontier/move, -1 resource_scout, one
// dry-corridor band one tile apart). AG8 fixtured the isolated readers and their
// thresholds. AG9 reproduces the FULL real decision at the divergence point: it
// finds the first per-band decision divergence deterministically (not hardcoded),
// then captures the complete ON/OFF evaluateBandDecision context for the divergent
// dry-corridor band — memory inputs, movementKnownOpportunity gate + margin,
// resource-scout target/score, belief, probe score, learned-support projection,
// candidate scores, and final reasonIds — and identifies exactly which gate flips.
//
// AUDIT/FIXTURE ONLY. No threshold tuning, no economy/food/support/yield/CC
// coupling, no population/stress/mortality/fission/relocation change, no hidden
// discovery. It only OBSERVES the in-situ decision through the behavior-neutral
// AG9 `decisionObserver` hook on the real stepSim/advanceWorldByDays path.
// ===========================================================================

const AG9_VIABILITY_THRESHOLD = 0.12; // movementKnownOpportunity hasViableKnownTarget gate (strict >)
const AG9_BELIEF_THRESHOLD = 0.1; // ResourceBeliefOpportunity hasBelievableOpportunity gate

function runTargetedActivityDecisionDivergenceCheck(modules) {
  const maxYears = 60; // 240 ticks — comfortably past both the historical and rebaselined cases
  const maxTicks = maxYears * 4;
  // REALISM-2B rebaseline: first-season reconnaissance lets activity memory retarget
  // resource_scout from tick 1, so the FIRST ON/OFF decision divergence is now early by
  // design (was the AG7 tick-212 near-threshold case). The verdict still depends only on
  // the safety proofs (no economy coupling, no hidden truth, deterministic) — the tick is
  // descriptive. Both values are reported so the shift is explicit, not hidden.
  const ag7HistoricalFirstDecisionTick = 212;
  const realism2bExpectedFirstDecisionTick = 1;

  // Pass 1 — deterministic first-divergence scan (cheap per-band decision signatures).
  const scan = scanForFirstDecisionDivergence(modules, maxTicks);

  if (scan.firstDivergence === undefined) {
    return {
      check: "ACTIVITY-GROUPS-9 full decision divergence fixture",
      verdict: "review",
      scenario: "map2_varied_migration",
      command: "node scripts/simBenchmark.mjs --targeted-activity-decision-divergence --json",
      note: `No per-band decision divergence found within ${maxTicks} ticks (${maxYears}y).`,
      ticksScanned: scan.ticksScanned,
    };
  }

  const divergenceTick = scan.firstDivergence.tick;

  // Pass 2 — heavy in-situ capture of the exact divergent tick (full ON/OFF context).
  const capture = captureDecisionDivergenceDetail(
    modules,
    divergenceTick,
    scan.firstDivergence.divergentBandIds,
  );

  // Pass 3 — independent determinism re-scan (re-finds the same divergence).
  const repeatScan = scanForFirstDecisionDivergence(modules, divergenceTick);
  const deterministicRepeat =
    repeatScan.firstDivergence !== undefined &&
    repeatScan.firstDivergence.tick === divergenceTick &&
    JSON.stringify([...repeatScan.firstDivergence.divergentBandIds].sort()) ===
      JSON.stringify([...scan.firstDivergence.divergentBandIds].sort());

  const onTrips = summarizeTimeScaleTrips(capture.onWorld);
  const offTrips = summarizeTimeScaleTrips(capture.offWorld);
  const onMem = summarizeActivityMemoryAudit(capture.onWorld);
  const offMem = summarizeActivityMemoryAudit(capture.offWorld);

  const noEconomyCouplingProof = {
    resourceReturnConsumedByEconomyCount:
      onTrips.resourceReturnConsumedByEconomyCount + offTrips.resourceReturnConsumedByEconomyCount,
    resourceReturnGuardFailureCount:
      onTrips.resourceReturnGuardFailureCount + offTrips.resourceReturnGuardFailureCount,
    activityMemoryGuardFailureCount: onMem.guardFailureCount + offMem.guardFailureCount,
    noNewActivityReturnEconomyReader: true,
    existingPatchMemoryEconomyReader:
      "2K.9 learned support reads ResourcePatchMemory through deriveTileLearnedSupport; AG9 only observes its projection, it adds no new consumption.",
  };
  const antiOmniscienceProof = {
    activityMemoryHiddenTruthFailureCount: onMem.hiddenTruthFailureCount + offMem.hiddenTruthFailureCount,
    bandKnownTargetsOnly: onTrips.bandKnownTargetsOnly === true && offTrips.bandKnownTargetsOnly === true,
    noNewResourceDiscoveryGuard: true,
  };

  const macroBounded =
    scan.firstDivergence.macroDeltas.totalPopulation === 0 &&
    scan.firstDivergence.macroDeltas.activeBands === 0 &&
    scan.firstDivergence.macroDeltas.fissions === 0 &&
    scan.firstDivergence.macroDeltas.extinctBands === 0;

  const proofsClean =
    noEconomyCouplingProof.resourceReturnConsumedByEconomyCount === 0 &&
    noEconomyCouplingProof.resourceReturnGuardFailureCount === 0 &&
    noEconomyCouplingProof.activityMemoryGuardFailureCount === 0 &&
    antiOmniscienceProof.activityMemoryHiddenTruthFailureCount === 0 &&
    antiOmniscienceProof.bandKnownTargetsOnly === true;

  const assessment = assessDecisionDivergenceSensitivity(capture.divergentBands, macroBounded);

  return {
    check: "ACTIVITY-GROUPS-9 full decision divergence fixture",
    verdict: proofsClean && deterministicRepeat ? "pass" : "review",
    scenario: "map2_varied_migration",
    command: "node scripts/simBenchmark.mjs --targeted-activity-decision-divergence --json",
    notes: [
      "ON/OFF Map 2 worlds advance in lockstep through the real stepSim(..., 'seasonal') daily-action path; OFF disables activity-memory coupling via auditOptions.",
      "The divergence tick is FOUND by comparing per-band decision signatures, not hardcoded. REALISM-2B rebaseline: first-season reconnaissance moves the first divergence to tick 1 (was the AG7 tick-212 fixture), reported via realism2bExpectedFirstDecisionTick; the verdict depends only on the safety proofs, not the tick.",
      "State is captured in-situ at the exact pre-decision world via the behavior-neutral AG9 decisionObserver; evaluateBandDecision is observed, never re-scored or tuned.",
      "Candidate scores come straight from Decision.alternativesConsidered; the movementKnownOpportunity gate margin is opportunityStrength - 0.12 (strict >).",
    ],
    firstDivergence: {
      tick: divergenceTick,
      year: scan.firstDivergence.year,
      season: scan.firstDivergence.season,
      divergentBandIds: scan.firstDivergence.divergentBandIds,
      ag7HistoricalFirstDecisionTick,
      realism2bExpectedFirstDecisionTick,
      matchesRealism2bRebaseline: divergenceTick === realism2bExpectedFirstDecisionTick,
      supersedesAg7Tick212Fixture: true,
      decisionArchiveDeltas: scan.firstDivergence.archiveDeltas,
      macroDeltas: scan.firstDivergence.macroDeltas,
      macroBounded,
    },
    deterministicRepeat,
    divergentBands: capture.divergentBands,
    noEconomyCouplingProof,
    antiOmniscienceProof,
    learnedSupportInvolvement: assessment.learnedSupportInvolvement,
    seasonalityAssessment: assessment.seasonalityAssessment,
    sensitivityAssessment: assessment.sensitivityAssessment,
    constraints: {
      thresholdsTuned: false,
      simBehaviorChanged: false,
      noFoodCouplingAdded: true,
      noYieldOrSupportFormulaChanged: true,
      noCarryingCapacityChange: true,
      noPopulationStressMortalityChange: true,
      noFissionRelocationChange: true,
      noHiddenDiscovery: true,
      deterministic: deterministicRepeat,
    },
    recommendation: assessment.recommendation,
  };
}

// Step ON/OFF in lockstep, comparing each band's decision signature per tick, and
// stop at the first tick where any common band's decision differs. Deterministic.
function scanForFirstDecisionDivergence(modules, maxTicks) {
  let onWorld = modules.initSimWorld({ kind: "map2" });
  let offWorld = applyBenchmarkAuditOptions(modules.initSimWorld({ kind: "map2" }), {
    activityMemoryCouplingDisabledForAudit: true,
  });
  let firstDivergence;
  let tick = 0;

  for (tick = 1; tick <= maxTicks; tick += 1) {
    const onSignatures = new Map();
    const offSignatures = new Map();
    onWorld = modules.stepSim(onWorld, 1, "seasonal", makeDecisionSignatureObserver(onSignatures));
    offWorld = modules.stepSim(offWorld, 1, "seasonal", makeDecisionSignatureObserver(offSignatures));

    const divergentBandIds = diffDecisionSignatures(onSignatures, offSignatures);
    if (divergentBandIds.length > 0) {
      const onSummary = summarizeTimeScaleWorld(onWorld);
      const offSummary = summarizeTimeScaleWorld(offWorld);
      firstDivergence = {
        tick,
        year: onSummary.year,
        season: onSummary.season,
        divergentBandIds,
        archiveDeltas: filterNonZeroNumberRecord(diffNumberRecord(onWorld.decisionArchive, offWorld.decisionArchive)),
        macroDeltas: {
          totalPopulation: onSummary.totalPopulation - offSummary.totalPopulation,
          activeBands: onSummary.activeBands - offSummary.activeBands,
          totalBands: onSummary.totalBands - offSummary.totalBands,
          fissions: onSummary.fissions - offSummary.fissions,
          extinctBands: onSummary.extinctBands - offSummary.extinctBands,
        },
      };
      break;
    }
  }

  return { ticksScanned: tick, firstDivergence };
}

function makeDecisionSignatureObserver(sink) {
  return (observation) => {
    sink.set(String(observation.band.id), decisionSignature(observation.decision));
  };
}

function decisionSignature(decision) {
  return [
    decision.action?.type ?? "none",
    getDecisionActionTargetTile(decision.action) ?? "-",
    decision.primaryReason?.type ?? "none",
  ].join("|");
}

function diffDecisionSignatures(onSignatures, offSignatures) {
  const ids = [...new Set([...onSignatures.keys(), ...offSignatures.keys()])].sort();
  const divergent = [];
  for (const id of ids) {
    if (onSignatures.get(id) !== offSignatures.get(id)) {
      divergent.push(id);
    }
  }
  return divergent;
}

function getDecisionActionTargetTile(action) {
  if (action === undefined || action === null) {
    return undefined;
  }
  if (action.targetTileId !== undefined) {
    return String(action.targetTileId);
  }
  if (action.tileId !== undefined) {
    return String(action.tileId);
  }
  return undefined;
}

function filterNonZeroNumberRecord(record) {
  const out = {};
  for (const [key, value] of Object.entries(record)) {
    if (value !== 0) {
      out[key] = value;
    }
  }
  return out;
}

// Re-run from scratch to (divergenceTick - 1) with no observer, then capture the
// divergence tick in-situ with a heavy per-band observer. At divergenceTick-1 both
// worlds share identical positions (the first decision divergence is THIS tick), so
// the captured ON/OFF records compare like-for-like: same tile, divergent memory.
function captureDecisionDivergenceDetail(modules, divergenceTick, divergentBandIds) {
  let onWorld = modules.initSimWorld({ kind: "map2" });
  let offWorld = applyBenchmarkAuditOptions(modules.initSimWorld({ kind: "map2" }), {
    activityMemoryCouplingDisabledForAudit: true,
  });
  if (divergenceTick > 1) {
    onWorld = modules.stepSim(onWorld, divergenceTick - 1, "seasonal");
    offWorld = modules.stepSim(offWorld, divergenceTick - 1, "seasonal");
  }

  const onRecords = new Map();
  const offRecords = new Map();
  onWorld = modules.stepSim(onWorld, 1, "seasonal", makeDecisionRecordObserver(modules, onRecords));
  offWorld = modules.stepSim(offWorld, 1, "seasonal", makeDecisionRecordObserver(modules, offRecords));

  const divergentBands = divergentBandIds.map((id) =>
    buildDivergentBandComparison(id, onRecords.get(id), offRecords.get(id)),
  );

  return { onWorld, offWorld, divergentBands };
}

function makeDecisionRecordObserver(modules, sink) {
  return (observation) => {
    sink.set(String(observation.band.id), buildBandDecisionRecord(modules, observation));
  };
}

// Full in-situ decision record for one band at the divergence tick. Everything here
// is read from the pre-decision band snapshot + the Decision the band actually made.
function buildBandDecisionRecord(modules, observation) {
  const { world, band, updatedBand, decision } = observation;
  const nearby = band.nearbyOpportunity;
  const opportunityStrength = round4(nearby?.opportunityStrength ?? 0);
  const bestKnownTile =
    nearby?.bestKnownOpportunityTileId === undefined ? undefined : String(nearby.bestKnownOpportunityTileId);
  const scout = safeSelectScoutTarget(modules, world, band);
  const belief = deriveBandResourceBeliefForAudit(world, band, modules);
  const beliefScore = round4(belief.beliefOpportunityScore ?? 0);

  return {
    bandId: String(band.id),
    tile: String(band.position),
    decision: {
      signature: decisionSignature(decision),
      actionType: decision.action?.type,
      actionTargetTile: getDecisionActionTargetTile(decision.action),
      movedTo: String(updatedBand.position),
      moved: String(updatedBand.position) !== String(band.position),
      mobilityIntentKind: decision.mobilityIntent?.kind,
      intentStatus: decision.intentStatus,
      primaryReasonType: decision.primaryReason?.type,
      primaryReasonId: decision.primaryReason?.id === undefined ? undefined : String(decision.primaryReason.id),
      reasonIds: collectDecisionReasonIds(decision),
    },
    movementKnownOpportunity: {
      bestKnownOpportunityTileId: bestKnownTile,
      opportunityStrength,
      viabilityThreshold: AG9_VIABILITY_THRESHOLD,
      thresholdMargin: round4(opportunityStrength - AG9_VIABILITY_THRESHOLD),
      passesViabilityGate: bestKnownTile !== undefined && opportunityStrength > AG9_VIABILITY_THRESHOLD,
      learnedSupportGate: round4(nearby?.learnedSupportGate ?? 0),
      currentLearnedSupport: round4(nearby?.currentLearnedSupport ?? 0),
      bestCandidateLearnedSupport: round4(nearby?.bestCandidateLearnedSupport ?? 0),
      candidatesWithLearnedSupport: nearby?.candidatesWithLearnedSupport ?? 0,
    },
    exhaustedRange: summarizeExhaustedForCausalAudit(band.exhaustedRangeAudit),
    knownUnusedHabitat: summarizeKnownUnusedForCausalAudit(band.carryingCapacity?.knownUnusedHabitat),
    resourceScout:
      scout === undefined
        ? undefined
        : {
            targetTile: String(scout.targetTileId),
            resourceClass: scout.targetResourceClass,
            voiScore: round4(scout.voiScore ?? 0),
            selectionKey: round4(getScoutSelectionKey(scout)),
            guidance: summarizeScoutGuidance(scout),
          },
    resourceBelief: {
      bestBeliefTile: belief.bestBeliefTile === undefined ? undefined : String(belief.bestBeliefTile),
      bestBeliefClass: belief.bestBeliefClass,
      beliefOpportunityScore: beliefScore,
      beliefThreshold: AG9_BELIEF_THRESHOLD,
      hasBelievableOpportunity: belief.hasBelievableOpportunity ?? beliefScore >= AG9_BELIEF_THRESHOLD,
      bestBeliefConfidence: round4(belief.bestBeliefConfidence ?? 0),
      onlyInferred: belief.onlyInferred ?? false,
    },
    learnedSupportProjection: summarizeBandLearnedSupportForCausalAudit(band),
    candidateScores: summarizeDecisionCandidates(decision),
    activityTouchedMemories: summarizeDecisionRelevantMemories(modules, world, band, {
      bestKnownTile,
      scoutTile: scout === undefined ? undefined : String(scout.targetTileId),
      beliefTile: belief.bestBeliefTile === undefined ? undefined : String(belief.bestBeliefTile),
    }),
  };
}

function safeSelectScoutTarget(modules, world, band) {
  try {
    return modules.selectResourceScoutTargetForAudit(world, band);
  } catch {
    return undefined;
  }
}

function collectDecisionReasonIds(decision) {
  const ids = [];
  if (decision.primaryReason?.id !== undefined) {
    ids.push(String(decision.primaryReason.id));
  }
  for (const reason of decision.secondaryReasons ?? []) {
    if (reason?.id !== undefined) {
      ids.push(String(reason.id));
    }
  }
  return ids;
}

function summarizeDecisionCandidates(decision) {
  return (decision.alternativesConsidered ?? []).map((alternative, index) => ({
    rank: index,
    chosen: index === 0,
    actionType: alternative.action?.type,
    targetTile: getDecisionActionTargetTile(alternative.action),
    score: round4(alternative.score ?? 0),
    scoutValue: round4(alternative.scoreBreakdown?.scoutValue ?? 0),
    moveValue: round4(alternative.scoreBreakdown?.moveValue ?? 0),
    frontierProbeValue: round4(alternative.scoreBreakdown?.frontierProbeValue ?? 0),
    knownOpportunityPull: round4(alternative.scoreBreakdown?.knownOpportunityPull ?? 0),
    logisticalProbeValue: round4(alternative.scoreBreakdown?.logisticalProbeValue ?? 0),
    localSurvivalValue: round4(alternative.scoreBreakdown?.localSurvivalValue ?? 0),
    rejectionReasonType: alternative.rejectionReason?.type,
  }));
}

// Patch memories that actually feed this band's decision-relevant tiles, with their
// effective confidence and any activity-memory touch — this is the ON/OFF input diff.
function summarizeDecisionRelevantMemories(modules, world, band, tiles) {
  const currentTick = Number(world.time.tick);
  const recentTouchedPatchIds = getRecentActivityTouchedPatchIds(band);
  const relevantTiles = new Set(
    [String(band.position), tiles.bestKnownTile, tiles.scoutTile, tiles.beliefTile].filter((value) => value !== undefined),
  );
  const memories = [];

  for (const memory of band.resourceKnowledgeState?.patchMemories ?? []) {
    const touch = getActivityMemoryTouch(memory, recentTouchedPatchIds);
    const tileId = String(memory.approximateTile);
    const isRelevant = relevantTiles.has(tileId);
    if (touch === undefined && !isRelevant) {
      continue;
    }

    const effective = modules.resourceKnowledge.effectiveResourceConfidence(memory, currentTick);
    memories.push({
      patchId: String(memory.patchId),
      tileId,
      resourceClassId: memory.resourceClassId,
      source: memory.source,
      state: memory.state,
      decisionRelevantTile: isRelevant,
      activityTouchEffect: touch?.effectType,
      effectivePresenceConfidence: round4(effective.effectivePresenceConfidence),
      effectiveYieldConfidence: round4(effective.effectiveYieldConfidence),
      stalenessLabel: effective.label,
      reasonIds: memory.reasonIds.filter(isActivityMemoryReason).map(String).slice(-3),
    });

    if (memories.length >= 10) {
      break;
    }
  }

  return memories;
}

// Identify exactly which gate flipped and quantify the score/threshold deltas.
function buildDivergentBandComparison(bandId, onRecord, offRecord) {
  if (onRecord === undefined || offRecord === undefined) {
    return { bandId, incomplete: true, on: onRecord, off: offRecord };
  }

  const gateFlips = [];
  if (onRecord.movementKnownOpportunity.passesViabilityGate !== offRecord.movementKnownOpportunity.passesViabilityGate) {
    gateFlips.push({
      gate: "movementKnownOpportunity.hasViableKnownTarget (opportunityStrength > 0.12, strict)",
      on: {
        opportunityStrength: onRecord.movementKnownOpportunity.opportunityStrength,
        thresholdMargin: onRecord.movementKnownOpportunity.thresholdMargin,
        passes: onRecord.movementKnownOpportunity.passesViabilityGate,
      },
      off: {
        opportunityStrength: offRecord.movementKnownOpportunity.opportunityStrength,
        thresholdMargin: offRecord.movementKnownOpportunity.thresholdMargin,
        passes: offRecord.movementKnownOpportunity.passesViabilityGate,
      },
    });
  }
  if (onRecord.exhaustedRange.hasViableKnownTarget !== offRecord.exhaustedRange.hasViableKnownTarget) {
    gateFlips.push({
      gate: "exhaustedRange.hasViableKnownTarget",
      on: { value: onRecord.exhaustedRange.hasViableKnownTarget, status: onRecord.exhaustedRange.status },
      off: { value: offRecord.exhaustedRange.hasViableKnownTarget, status: offRecord.exhaustedRange.status },
    });
  }
  if (onRecord.resourceBelief.hasBelievableOpportunity !== offRecord.resourceBelief.hasBelievableOpportunity) {
    gateFlips.push({
      gate: "resourceBelief.hasBelievableOpportunity (beliefOpportunityScore >= 0.1)",
      on: { score: onRecord.resourceBelief.beliefOpportunityScore, has: onRecord.resourceBelief.hasBelievableOpportunity },
      off: { score: offRecord.resourceBelief.beliefOpportunityScore, has: offRecord.resourceBelief.hasBelievableOpportunity },
    });
  }
  if (
    (onRecord.knownUnusedHabitat.consideredAsTarget ?? false) !==
    (offRecord.knownUnusedHabitat.consideredAsTarget ?? false)
  ) {
    gateFlips.push({
      gate: "knownUnusedHabitat.consideredAsTarget",
      on: {
        considered: onRecord.knownUnusedHabitat.consideredAsTarget,
        rejectionReason: onRecord.knownUnusedHabitat.rejectionReason,
      },
      off: {
        considered: offRecord.knownUnusedHabitat.consideredAsTarget,
        rejectionReason: offRecord.knownUnusedHabitat.rejectionReason,
      },
    });
  }

  const onCompetition = computeCandidateCompetition(onRecord);
  const offCompetition = computeCandidateCompetition(offRecord);
  const scoutTargetChanged = String(onRecord.resourceScout?.targetTile) !== String(offRecord.resourceScout?.targetTile);
  const scoutGuidanceChanged =
    onRecord.resourceScout?.guidance?.reason !== offRecord.resourceScout?.guidance?.reason ||
    (onRecord.resourceScout?.guidance?.bias ?? 0) !== (offRecord.resourceScout?.guidance?.bias ?? 0);
  const beliefChanged =
    Math.abs(onRecord.resourceBelief.beliefOpportunityScore - offRecord.resourceBelief.beliefOpportunityScore) > 0.0001 ||
    Math.abs(onRecord.resourceBelief.bestBeliefConfidence - offRecord.resourceBelief.bestBeliefConfidence) > 0.0001 ||
    String(onRecord.resourceBelief.bestBeliefTile) !== String(offRecord.resourceBelief.bestBeliefTile);

  let operativeReader;
  if (gateFlips.length > 0) {
    operativeReader = gateFlips[0].gate;
  } else if (scoutTargetChanged || scoutGuidanceChanged) {
    operativeReader = "resource_scout target selection (activity-memory patchReturnGuidance redirects which patch is scouted)";
  } else if (beliefChanged) {
    operativeReader = "resource belief opportunity";
  } else {
    operativeReader = "candidate scoring competition (no single boolean threshold gate flipped)";
  }

  return {
    bandId,
    isDryCorridorBand: bandId.includes("dry-corridor"),
    tile: onRecord.tile,
    sameTileBeforeDecision: onRecord.tile === offRecord.tile,
    operativeReader,
    minWinningMargin: round4(Math.min(onCompetition.margin, offCompetition.margin)),
    decisionFlip: {
      onActionType: onRecord.decision.actionType,
      offActionType: offRecord.decision.actionType,
      onMovedTo: onRecord.decision.movedTo,
      offMovedTo: offRecord.decision.movedTo,
      onPrimaryReasonType: onRecord.decision.primaryReasonType,
      offPrimaryReasonType: offRecord.decision.primaryReasonType,
      onPrimaryReasonId: onRecord.decision.primaryReasonId,
      offPrimaryReasonId: offRecord.decision.primaryReasonId,
    },
    candidateCompetition: {
      on: onCompetition,
      off: offCompetition,
      note: "winnerScore - runnerUpScore is the deliberation margin; a small ON margin means the activity-memory-driven scout retarget only needed to nudge the scout candidate below the (identical) move candidate to flip the branch.",
    },
    readerInputDeltas: {
      scoutTargetChanged,
      onScoutTarget: onRecord.resourceScout?.targetTile,
      offScoutTarget: offRecord.resourceScout?.targetTile,
      onScoutGuidance: onRecord.resourceScout?.guidance?.reason,
      offScoutGuidance: offRecord.resourceScout?.guidance?.reason,
      beliefChanged,
      onBestBeliefConfidence: onRecord.resourceBelief.bestBeliefConfidence,
      offBestBeliefConfidence: offRecord.resourceBelief.bestBeliefConfidence,
    },
    scoreDeltas: {
      opportunityStrength: round4(
        onRecord.movementKnownOpportunity.opportunityStrength - offRecord.movementKnownOpportunity.opportunityStrength,
      ),
      currentLearnedSupport: round4(
        onRecord.movementKnownOpportunity.currentLearnedSupport - offRecord.movementKnownOpportunity.currentLearnedSupport,
      ),
      bestCandidateLearnedSupport: round4(
        onRecord.movementKnownOpportunity.bestCandidateLearnedSupport -
          offRecord.movementKnownOpportunity.bestCandidateLearnedSupport,
      ),
      beliefOpportunityScore: round4(
        onRecord.resourceBelief.beliefOpportunityScore - offRecord.resourceBelief.beliefOpportunityScore,
      ),
      scoutVoiScore: round4((onRecord.resourceScout?.voiScore ?? 0) - (offRecord.resourceScout?.voiScore ?? 0)),
      projectedLearnedSupport: round4(
        (onRecord.learnedSupportProjection?.candidateProjectedLearnedSupportDelta ?? 0) -
          (offRecord.learnedSupportProjection?.candidateProjectedLearnedSupportDelta ?? 0),
      ),
    },
    gateFlips,
    on: onRecord,
    off: offRecord,
  };
}

function computeCandidateCompetition(record) {
  const candidates = record.candidateScores ?? [];
  const winner = candidates[0];
  const runnerUp = candidates[1];
  const bestScout = candidates.find((candidate) => candidate.actionType === "resource_scout");
  const bestMove = candidates.find((candidate) => candidate.actionType === "move_to_tile");

  return {
    winnerActionType: winner?.actionType,
    winnerTargetTile: winner?.targetTile,
    winnerScore: round4(winner?.score ?? 0),
    runnerUpActionType: runnerUp?.actionType,
    runnerUpTargetTile: runnerUp?.targetTile,
    runnerUpScore: round4(runnerUp?.score ?? 0),
    margin: round4((winner?.score ?? 0) - (runnerUp?.score ?? 0)),
    bestScoutScore: bestScout === undefined ? undefined : round4(bestScout.score ?? 0),
    bestScoutTile: bestScout?.targetTile,
    bestMoveScore: bestMove === undefined ? undefined : round4(bestMove.score ?? 0),
    bestMoveTile: bestMove?.targetTile,
  };
}

function assessDecisionDivergenceSensitivity(divergentBands, macroBounded) {
  const completeBands = divergentBands.filter((band) => !band.incomplete);
  const operativeReaders = [...new Set(completeBands.map((band) => band.operativeReader))];
  const flippedGates = [...new Set(completeBands.flatMap((band) => band.gateFlips.map((flip) => flip.gate)))];
  let maxOpportunityDelta = 0;
  let learnedSupportContributed = false;
  let minWinningMargin = Number.POSITIVE_INFINITY;

  for (const band of completeBands) {
    maxOpportunityDelta = Math.max(maxOpportunityDelta, Math.abs(band.scoreDeltas.opportunityStrength));
    minWinningMargin = Math.min(minWinningMargin, band.minWinningMargin ?? Number.POSITIVE_INFINITY);
    if (
      Math.abs(band.scoreDeltas.currentLearnedSupport) > 0.0001 ||
      Math.abs(band.scoreDeltas.bestCandidateLearnedSupport) > 0.0001
    ) {
      learnedSupportContributed = true;
    }
  }
  if (!Number.isFinite(minWinningMargin)) {
    minWinningMargin = 0;
  }

  const usedMovementGate = operativeReaders.some((reader) => reader.startsWith("movementKnownOpportunity"));
  const nearThreshold = minWinningMargin <= 0.1;
  const tooStrong = !macroBounded || completeBands.length > 1 || maxOpportunityDelta > 0.12;
  const sensitivityClass = tooStrong
    ? "too_strong"
    : nearThreshold
      ? "healthy_near_threshold_sensitivity"
      : "expected_learning";

  return {
    learnedSupportInvolvement: {
      contributesToMovementGate: learnedSupportContributed && usedMovementGate,
      appearedAsSideSignalOnly: !(learnedSupportContributed && usedMovementGate),
      note:
        learnedSupportContributed && usedMovementGate
          ? "Activity-refreshed patch memory changed deriveTileLearnedSupport, added symmetrically into opportunityStrength, and crossed the strict 0.12 hasViableKnownTarget gate — so learned-support projection is a real contributor at this divergence."
          : "Learned-support projection is a SIDE SIGNAL at this divergence: the movementKnownOpportunity opportunityStrength term is inert here (no qualifying skill-matched candidate; opportunityStrength 0, ON/OFF delta 0). The flip is driven by " +
            operativeReaders.join(" / ") +
            ".",
    },
    seasonalityAssessment: {
      note: "Consistent with AG8: seasonality hints are recorded in patch memory (badSeasons) and lower season/yield confidence, but they remain a weak DIRECT dampener — recency can offset the confidence drop, so seasonality did not by itself prevent the near-threshold flip. Revisit only if activity returns later feed food/support.",
      strongDirectDampener: false,
    },
    sensitivityAssessment: {
      class: sensitivityClass,
      operativeReaders,
      flippedBooleanGates: flippedGates,
      minWinningMargin: round4(minWinningMargin),
      maxOpportunityStrengthDelta: round4(maxOpportunityDelta),
      macroBounded,
      nearThreshold,
      verdict:
        sensitivityClass === "too_strong"
          ? "Sensitivity is too strong: the activity-memory delta perturbed macro state, flipped multiple bands, or moved a decision far past a threshold — damping should be considered."
          : "Sensitivity is healthy/expected: a single dry-corridor band swaps one branch (move/frontier vs resource_scout) because activity memory retargets which patch it scouts, and in the ON world the chosen move only edges out the scout candidate by a razor-thin deliberation margin. No boolean gate is manufactured, no macro state diverges — realistic near-threshold learning, not a twitch.",
    },
    recommendation:
      "REALISM-2B: first-season reconnaissance moves the first ON/OFF divergence to tick 1 and lets several bands retarget their early resource_scout from already-observed local knowledge — so this is now an early, sometimes multi-band branch swap rather than the historical AG7 tick-212 near-threshold single-band case. It remains driven only by resource_scout retargeting, with macro STRUCTURE invariant, no economy coupling, and no hidden discovery; accepted as bounded learning. Do not tune resource_scout/seasonality dampening here — re-evaluate only once activity returns are allowed to feed the support/food economy directly, when these flips could compound.",
  };
}

// ===========================================================================
// ACTIVITY-GROUPS-10 — shadow subsistence audit.
//
// Reads the per-trip shadowSubsistence records and band-level
// activityShadowSubsistenceSummary that AG10 now derives (shadow-only), aggregates
// them across Map 1 + Map 2, compares the shadow estimate to the existing ABSTRACT
// per-capita support, and proves (a) macro outcomes are unchanged vs the established
// baselines and (b) shadow values are not consumed by economy. It answers the AG10
// design questions about frequency, magnitude, dominant task types, distance, season,
// hunting/fishing representation, and coupling risk.
// ===========================================================================

const AG10_RELIABILITY_BUCKETS = ["0.0-0.2", "0.2-0.4", "0.4-0.6", "0.6-0.8", "0.8-1.0"];

function reliabilityBucket(value) {
  if (value < 0.2) return AG10_RELIABILITY_BUCKETS[0];
  if (value < 0.4) return AG10_RELIABILITY_BUCKETS[1];
  if (value < 0.6) return AG10_RELIABILITY_BUCKETS[2];
  if (value < 0.8) return AG10_RELIABILITY_BUCKETS[3];
  return AG10_RELIABILITY_BUCKETS[4];
}

function auditShadowScenario(modules, kind, scenarioLabel, years, expectedMacro) {
  const ticks = years * 4;
  const world = modules.stepSim(modules.initSimWorld({ kind }), ticks, "seasonal");
  const macroSummary = summarizeTimeScaleWorld(world);
  const bands = Object.values(world.bands).filter(isActiveBand);

  let totalTrips = 0;
  let totalGross = 0;
  let totalNet = 0;
  let totalFoodNet = 0;
  let totalWaterNet = 0;
  let totalTravelCost = 0;
  let foodTripCount = 0;
  let waterTripCount = 0;
  let infoTripCount = 0;
  let noContributionTripCount = 0;
  let seasonMismatchTripCount = 0;
  let sameDayTripCount = 0;
  let delayedTripCount = 0;
  let huntedShadowCount = 0;
  let fishShadowCount = 0;
  let gatheredShadowCount = 0;
  let plantUncertainCount = 0;
  let shadowConsumedByEconomyCount = 0;
  let noEconomyCouplingFailCount = 0;
  let foodReliabilitySum = 0;
  const byTaskType = {};
  const byReturnKind = {};
  const reliabilityDistribution = Object.fromEntries(AG10_RELIABILITY_BUCKETS.map((b) => [b, 0]));
  const distanceCost = {};
  const bandRatios = [];
  const tooHighCases = [];
  const tooLowCases = [];
  let bandsWithShadowSummary = 0;

  for (const band of bands) {
    const summary = band.activityShadowSubsistenceSummary;
    if (summary !== undefined) {
      bandsWithShadowSummary += 1;
      if (summary.shadowConsumedByEconomy !== false) noEconomyCouplingFailCount += 1;
      if (summary.noEconomyCoupling !== true) noEconomyCouplingFailCount += 1;
      if (summary.shadowSupportComparable) {
        bandRatios.push(summary.shadowVsCurrentSupportRatio);
        const sample = {
          bandId: String(band.id),
          shadowVsCurrentSupportRatio: summary.shadowVsCurrentSupportRatio,
          meanFoodTripShadowNet: summary.meanFoodTripShadowNet,
          currentAbstractPerCapitaReturn: summary.currentAbstractPerCapitaReturn,
          foodBearingTripCount: summary.foodBearingTripCount,
        };
        if (summary.shadowVsCurrentSupportRatio > 2 && tooHighCases.length < 6) tooHighCases.push(sample);
        if (summary.shadowVsCurrentSupportRatio < 0.25 && tooLowCases.length < 6) tooLowCases.push(sample);
      }
    }

    for (const trip of band.recentIntraSeasonTrips ?? []) {
      const shadow = trip.shadowSubsistence;
      totalTrips += 1;
      totalGross += shadow.shadowGrossValue;
      totalNet += shadow.shadowNetValue;
      totalTravelCost += shadow.shadowTravelCost;
      if (shadow.shadowConsumedByEconomy !== false) shadowConsumedByEconomyCount += 1;
      if (shadow.noEconomyCoupling !== true) noEconomyCouplingFailCount += 1;

      if (shadow.shadowSupportDomain === "food") {
        totalFoodNet += shadow.shadowNetValue;
        if (shadow.shadowNetValue > 0) {
          foodTripCount += 1;
          foodReliabilitySum += shadow.shadowReliability;
          reliabilityDistribution[reliabilityBucket(shadow.shadowReliability)] += 1;
        }
      } else if (shadow.shadowSupportDomain === "water_support") {
        totalWaterNet += shadow.shadowNetValue;
        if (shadow.shadowNetValue > 0) waterTripCount += 1;
      }

      if (shadow.shadowReturnKind === "information_only") infoTripCount += 1;
      if (shadow.shadowReturnKind === "none") noContributionTripCount += 1;
      if (shadow.shadowReturnKind === "hunted_food_shadow") huntedShadowCount += 1;
      if (shadow.shadowReturnKind === "fish_shadow") fishShadowCount += 1;
      if (shadow.shadowReturnKind === "gathered_food_shadow") gatheredShadowCount += 1;
      if (shadow.shadowReturnKind === "plant_food_shadow_uncertain") plantUncertainCount += 1;
      if (trip.activityOutcome === "failed_due_to_season_mismatch") seasonMismatchTripCount += 1;
      if (shadow.contributesAtBaseSameDay) sameDayTripCount += 1;
      else delayedTripCount += 1;

      const task = byTaskType[trip.taskGroupType] ?? { count: 0, gross: 0, net: 0 };
      task.count += 1;
      task.gross = round4(task.gross + shadow.shadowGrossValue);
      task.net = round4(task.net + shadow.shadowNetValue);
      byTaskType[trip.taskGroupType] = task;

      const rk = byReturnKind[shadow.shadowReturnKind] ?? { count: 0, net: 0 };
      rk.count += 1;
      rk.net = round4(rk.net + shadow.shadowNetValue);
      byReturnKind[shadow.shadowReturnKind] = rk;

      const dKey = String(trip.distanceTiles);
      const d = distanceCost[dKey] ?? { distanceTiles: trip.distanceTiles, tripCount: 0, travelCostTotal: 0, grossTotal: 0 };
      d.tripCount += 1;
      d.travelCostTotal = round4(d.travelCostTotal + shadow.shadowTravelCost);
      d.grossTotal = round4(d.grossTotal + shadow.shadowGrossValue);
      distanceCost[dKey] = d;
    }
  }

  const meanBandRatio = bandRatios.length > 0 ? round4(bandRatios.reduce((a, b) => a + b, 0) / bandRatios.length) : 0;
  const macroMatchesBaseline =
    expectedMacro === undefined ||
    (macroSummary.totalPopulation === expectedMacro.totalPopulation &&
      macroSummary.activeBands === expectedMacro.activeBands &&
      macroSummary.fissions === expectedMacro.fissions);

  return {
    scenario: scenarioLabel,
    years,
    macro: {
      tick: macroSummary.tick,
      totalPopulation: macroSummary.totalPopulation,
      activeBands: macroSummary.activeBands,
      fissions: macroSummary.fissions,
      extinctBands: macroSummary.extinctBands,
    },
    expectedMacroBaseline: expectedMacro,
    macroMatchesBaseline,
    sampledTripCount: totalTrips,
    bandsWithShadowSummary,
    tripsPerActiveBand: bands.length > 0 ? round4(totalTrips / bands.length) : 0,
    shadowTotals: {
      totalShadowGross: round4(totalGross),
      totalShadowNet: round4(totalNet),
      totalFoodShadowNet: round4(totalFoodNet),
      totalWaterSupportShadowNet: round4(totalWaterNet),
      totalShadowTravelCost: round4(totalTravelCost),
      travelCostShareOfGross: totalGross > 0 ? round4(totalTravelCost / totalGross) : 0,
      meanNetPerTrip: totalTrips > 0 ? round4(totalNet / totalTrips) : 0,
      meanFoodNetPerFoodTrip: foodTripCount > 0 ? round4(totalFoodNet / foodTripCount) : 0,
      meanFoodReliability: foodTripCount > 0 ? round4(foodReliabilitySum / foodTripCount) : 0,
    },
    tripComposition: {
      foodTripCount,
      waterTripCount,
      informationOnlyTripCount: infoTripCount,
      noContributionTripCount,
      seasonMismatchTripCount,
      sameDayTripCount,
      delayedTripCount,
      seasonMismatchShare: totalTrips > 0 ? round4(seasonMismatchTripCount / totalTrips) : 0,
      delayedShare: totalTrips > 0 ? round4(delayedTripCount / totalTrips) : 0,
    },
    huntingFishingRepresentation: {
      huntedShadowCount,
      fishShadowCount,
      gatheredShadowCount,
      plantUncertainCount,
      huntedFishingRepresented: huntedShadowCount + fishShadowCount > 0,
    },
    shadowByTaskType: Object.fromEntries(
      Object.entries(byTaskType).sort(([a], [b]) => a.localeCompare(b)),
    ),
    shadowByReturnKind: Object.fromEntries(
      Object.entries(byReturnKind).sort(([a], [b]) => a.localeCompare(b)),
    ),
    reliabilityDistribution,
    distanceCostDistribution: Object.values(distanceCost).sort((a, b) => a.distanceTiles - b.distanceTiles),
    shadowVsCurrentAbstractSupport: {
      comparableBandCount: bandRatios.length,
      meanShadowVsCurrentSupportRatio: meanBandRatio,
      tooHighCases,
      tooLowCases,
      note: "ratio = mean food-trip shadow net / current abstract per-capita return; both are normalized per-capita-like magnitudes. A typical successful activity-group return is this fraction of the abstract per-capita support the economy currently assumes.",
    },
    noEconomyCouplingProof: {
      shadowConsumedByEconomyCount,
      noEconomyCouplingFailCount,
      allShadowRecordsFlaggedShadowOnly: shadowConsumedByEconomyCount === 0 && noEconomyCouplingFailCount === 0,
    },
  };
}

function runTargetedActivityShadowSubsistenceCheck(modules, options) {
  const years =
    Number.isFinite(options.activityShadowYears) && options.activityShadowYears > 0
      ? Math.floor(options.activityShadowYears)
      : 20;
  // Established deterministic baselines used for the macro-unchanged proof (only valid
  // at 20y, the standard smoke horizon). Shadow data is pure-derived, so macro must match.
  const map1Baseline = years === 20 ? { totalPopulation: 179, activeBands: 5, fissions: 0 } : undefined;
  const map2Baseline = years === 20 ? { totalPopulation: 264, activeBands: 9, fissions: 0 } : undefined;

  const map1 = auditShadowScenario(modules, "map1", "baseline", years, map1Baseline);
  const map2 = auditShadowScenario(modules, "map2", "map2_varied_migration", years, map2Baseline);

  const determinismRepeat = auditShadowScenario(modules, "map2", "map2_varied_migration", years, map2Baseline);
  const deterministic =
    JSON.stringify(determinismRepeat.shadowTotals) === JSON.stringify(map2.shadowTotals) &&
    JSON.stringify(determinismRepeat.shadowByTaskType) === JSON.stringify(map2.shadowByTaskType);

  const macroUnchanged =
    map1.macroMatchesBaseline && map2.macroMatchesBaseline;
  const noEconomyCoupling =
    map1.noEconomyCouplingProof.allShadowRecordsFlaggedShadowOnly &&
    map2.noEconomyCouplingProof.allShadowRecordsFlaggedShadowOnly;

  // Use Map 2 (richer migration scenario) as the primary basis for the design answers.
  const primary = map2;
  const dominantTaskOf = (scenario) =>
    Object.entries(scenario.shadowByTaskType).sort((a, b) => b[1].net - a[1].net)[0];
  const dominantTask = dominantTaskOf(primary);
  const map1Dominant = dominantTaskOf(map1);

  return {
    check: "ACTIVITY-GROUPS-10 shadow subsistence audit",
    verdict: macroUnchanged && noEconomyCoupling && deterministic ? "pass" : "review",
    command: "node scripts/simBenchmark.mjs --targeted-activity-shadow-subsistence --json",
    years,
    notes: [
      "Shadow subsistence is a normalized, support-LIKE estimate (same 0..~1 scale as per-capita return), NOT calories.",
      "It is derived from band-known info only (patch memory effective confidence, remembered risk/seasonality, distance, group size, task type, deterministic outcome). No hidden truth, no randomness.",
      "The abstract economy still drives ALL real behaviour; shadow values are never read by yield/support/carrying-capacity/population/stress/fission/relocation.",
    ],
    scenarios: { map1, map2 },
    deterministic,
    macroUnchangedProof: {
      map1: { matchesBaseline: map1.macroMatchesBaseline, macro: map1.macro, baseline: map1.expectedMacroBaseline },
      map2: { matchesBaseline: map2.macroMatchesBaseline, macro: map2.macro, baseline: map2.expectedMacroBaseline },
      macroUnchanged,
      note: "Shadow is pure-derived; at 20y the deterministic macro must equal the established Map 1 (179/5/0) and Map 2 (264/9/0) baselines.",
    },
    noEconomyCouplingProof: {
      map1: map1.noEconomyCouplingProof,
      map2: map2.noEconomyCouplingProof,
      noEconomyCoupling,
      staticGuardCommand:
        "grep proof that no support/yield/carrying-capacity/pressure/demography/rules module reads shadowSubsistence/shadowNetValue/activityShadowSubsistenceSummary is run in AG10 validation.",
    },
    designQuestions: {
      q1_frequency_plausible: {
        tripsPerActiveBand: primary.tripsPerActiveBand,
        sampledTripCount: primary.sampledTripCount,
        answer:
          "Activity groups fire regularly (the recent-trip window holds ~" +
          primary.tripsPerActiveBand +
          " trips/active band), so they are frequent enough to be a plausible subsistence channel — but many trips are information/season-failures, so usable food trips are a subset.",
      },
      q2_magnitude_vs_abstract: {
        meanShadowVsCurrentSupportRatio: primary.shadowVsCurrentAbstractSupport.meanShadowVsCurrentSupportRatio,
        tooHighCount: primary.shadowVsCurrentAbstractSupport.tooHighCases.length,
        tooLowCount: primary.shadowVsCurrentAbstractSupport.tooLowCases.length,
        answer:
          "A typical successful food trip's shadow net is ~" +
          primary.shadowVsCurrentAbstractSupport.meanShadowVsCurrentSupportRatio +
          "× the abstract per-capita return. This is intentionally a per-trip increment, not a full per-capita ration, so it reads LOW vs whole-band abstract support — many trips would need to sum to feed the band.",
      },
      q3_dominant_task: {
        map2DominantTaskType: dominantTask?.[0],
        map2DominantTaskNet: dominantTask?.[1]?.net,
        map1DominantTaskType: map1Dominant?.[0],
        map1DominantTaskNet: map1Dominant?.[1]?.net,
        map2ShadowByReturnKind: primary.shadowByReturnKind,
        answer:
          "Dominant shadow subsistence is SCENARIO-DEPENDENT and follows the local resource classes the daily ledger targets: Map 2 (varied/aquatic migration) is led by " +
          (dominantTask?.[0] ?? "n/a") +
          " then fishing, while Map 1 (baseline) is led by " +
          (map1Dominant?.[0] ?? "n/a") +
          " (gathering). Hunting/fishing produce the largest per-success net but at low reliability; gathering/local foraging are the reliable staple. No single task type is hardcoded to dominate — it tracks the band's known patches.",
      },
      q4_distance_cost_matters: {
        travelCostShareOfGross: primary.shadowTotals.travelCostShareOfGross,
        distanceCostDistribution: primary.distanceCostDistribution,
        answer:
          "Travel cost consumes ~" +
          round4((primary.shadowTotals.travelCostShareOfGross ?? 0) * 100) +
          "% of gross shadow at current short trip distances; central-place cost is present and scales with distance, but daily trips are near-camp so it is a modest (non-dominant) penalty today.",
      },
      q5_season_matters: {
        seasonMismatchShare: primary.tripComposition.seasonMismatchShare,
        answer:
          "Seasonality matters: ~" +
          round4((primary.tripComposition.seasonMismatchShare ?? 0) * 100) +
          "% of trips hit a known season mismatch (zero food) and in-season confidence further scales gross, so season is a real determinant of shadow yield.",
      },
      q6_hunting_fishing_represented: {
        ...primary.huntingFishingRepresentation,
        answer:
          primary.huntingFishingRepresentation.huntedFishingRepresented
            ? "Hunting and/or fishing are represented as distinct high-variance, low-reliability shadow returns (hunting reliability 0.32 vs gathering 0.82), so a successful hunt brings food but is never guaranteed."
            : "Hunting/fishing shadow returns did not appear in this sample (task groups were gathering/water/plant dominated); the model supports them but the daily ledger rarely emitted them here.",
      },
      q7_coupling_risks: {
        answer:
          "Partial coupling risk: shadow net is per-trip and currently LOW relative to whole-band abstract support, so naively replacing abstract support would starve bands. Season-failure and information trips contribute 0, creating gaps. Hunting variance must stay discounted. Distance cost and delayed (overnight) returns must be timed correctly. Any coupling must be a small, capped supplement first, never a replacement.",
      },
      q8_recommended_ag11_strategy: {
        recommendation: "capped_supplement_then_compared_split",
        answer:
          "AG11 should NOT replace abstract support. Start with a tiny capped SUPPLEMENT: let same-day food shadow net add a small bounded fraction on top of abstract support (cap << abstract), keep abstract support as the floor, and keep a per-band shadow/real split audit. Only after the shadow magnitude is calibrated against abstract support across maps/horizons should a gradual replacement be considered.",
      },
    },
    constraints: {
      simBehaviorChanged: false,
      shadowOnly: true,
      noActualCaloriesConsumed: true,
      noSupportYieldCarryingCapacityChange: true,
      noPopulationStressMortalityChange: true,
      noFissionRelocationChange: true,
      noHiddenResourceTruth: true,
      noPlantInstantlySafe: true,
      noHuntingGuaranteed: true,
      deterministic,
    },
  };
}

// ===========================================================================
// ACTIVITY-GROUPS-11 — Tiny flag-gated activity subsistence supplement.
// ===========================================================================

function runActivitySupplementScenario(modules, kind, scenarioLabel, years, enabled) {
  const ticks = years * 4;
  const initialWorld = applyBenchmarkAuditOptions(modules.initSimWorld({ kind }), {
    activitySubsistenceSupplementEnabledForAudit: enabled,
  });
  const start = performance.now();
  const world = modules.stepSim(initialWorld, ticks, "seasonal");
  const runtimeMs = performance.now() - start;
  const macro = summarizeTimeScaleWorld(world);

  return {
    scenario: scenarioLabel,
    kind,
    years,
    enabled,
    runtimeMs: round2(runtimeMs),
    macro: {
      tick: macro.tick,
      year: macro.year,
      totalPopulation: macro.totalPopulation,
      activeBands: macro.activeBands,
      totalBands: macro.totalBands,
      fissions: macro.fissions,
      extinctBands: macro.extinctBands,
      absorbedBands: macro.absorbedBands,
      movementDecisions: macro.totalDecisions,
      moveDecisions: macro.totalMoveDecisions,
      scoutDecisions: macro.totalResourceScoutDecisions,
      probeDecisions: macro.totalProbeDecisions,
    },
    supplement: summarizeActivitySupplementAudit(world),
    tripAudit: summarizeTimeScaleTrips(world),
    activityMemoryAudit: summarizeActivityMemoryAudit(world),
  };
}

function summarizeActivitySupplementAudit(world) {
  let bandsWithSupplementField = 0;
  let consumedTotal = 0;
  let capHitCount = 0;
  let eligibleShadow = 0;
  let delayedTracked = 0;
  let finalSupportTotal = 0;
  let abstractSupportFloorTotal = 0;
  let guardFailureCount = 0;
  const byTaskType = {};
  const byKind = { gathering: 0, hunting: 0, fishing: 0, plants: 0 };

  for (const band of Object.values(world.bands)) {
    const supplement = band.carryingCapacity?.perCapitaReturn?.supportDebug?.activitySubsistenceSupplement;

    if (supplement === undefined) {
      continue;
    }

    bandsWithSupplementField += 1;
    const consumed = Math.max(0, supplement.finalSupportWithSupplement - supplement.abstractSupportFloor);
    consumedTotal += consumed;
    eligibleShadow += supplement.activityShadowSameDayFoodEligible;
    delayedTracked += supplement.activityShadowDelayedFoodTracked;
    finalSupportTotal += supplement.finalSupportWithSupplement;
    abstractSupportFloorTotal += supplement.abstractSupportFloor;
    if (supplement.supplementCapApplied) capHitCount += 1;
    byKind.gathering += supplement.supplementFromGathering;
    byKind.hunting += supplement.supplementFromHunting;
    byKind.fishing += supplement.supplementFromFishing;
    byKind.plants += supplement.supplementFromPlants;

    if (
      supplement.supplementConsumedByEconomy !== true ||
      supplement.sameDayFoodOnly !== true ||
      supplement.delayedNotConsumed !== true ||
      supplement.waterAndInfoNotConsumed !== true ||
      supplement.plantsZeroed !== true ||
      supplement.noYieldCoupling !== true ||
      supplement.noCarryingCapacityMutation !== true ||
      supplement.noHiddenTruth !== true
    ) {
      guardFailureCount += 1;
    }

    for (const entry of supplement.byTaskType) {
      const current = byTaskType[entry.taskGroupType] ?? { shadowNetEligible: 0, consumedSupport: 0 };
      current.shadowNetEligible = round4(current.shadowNetEligible + entry.shadowNetEligible);
      current.consumedSupport = round4(current.consumedSupport + entry.consumedSupport);
      byTaskType[entry.taskGroupType] = current;
    }
  }

  return {
    bandsWithSupplementField,
    consumedSupportTotal: round4(consumedTotal),
    abstractSupportFloorTotal: round4(abstractSupportFloorTotal),
    finalSupportTotal: round4(finalSupportTotal),
    supplementShareOfFinalSupport: finalSupportTotal > 0 ? round4(consumedTotal / finalSupportTotal) : 0,
    sameDayFoodEligibleShadowNet: round4(eligibleShadow),
    delayedFoodTrackedNotConsumed: round4(delayedTracked),
    capHitCount,
    guardFailureCount,
    byKind: Object.fromEntries(Object.entries(byKind).map(([key, value]) => [key, round4(value)])),
    byTaskType: Object.fromEntries(Object.entries(byTaskType).sort(([a], [b]) => a.localeCompare(b))),
  };
}

function compareActivitySupplementRuns(offRun, onRun) {
  return {
    populationDelta: onRun.macro.totalPopulation - offRun.macro.totalPopulation,
    activeBandDelta: onRun.macro.activeBands - offRun.macro.activeBands,
    totalBandDelta: onRun.macro.totalBands - offRun.macro.totalBands,
    fissionDelta: onRun.macro.fissions - offRun.macro.fissions,
    extinctionDelta: onRun.macro.extinctBands - offRun.macro.extinctBands,
    absorbedDelta: onRun.macro.absorbedBands - offRun.macro.absorbedBands,
    movementDecisionDelta: onRun.macro.movementDecisions - offRun.macro.movementDecisions,
    moveDecisionDelta: onRun.macro.moveDecisions - offRun.macro.moveDecisions,
    scoutDecisionDelta: onRun.macro.scoutDecisions - offRun.macro.scoutDecisions,
    probeDecisionDelta: onRun.macro.probeDecisions - offRun.macro.probeDecisions,
    consumedSupportTotal: onRun.supplement.consumedSupportTotal,
    supplementShareOfFinalSupport: onRun.supplement.supplementShareOfFinalSupport,
    capHitCount: onRun.supplement.capHitCount,
    guardFailureCount: onRun.supplement.guardFailureCount,
  };
}

function runTargetedActivitySubsistenceSupplementCheck(modules, options) {
  const years = (options.activitySupplementYears?.length ?? 0) > 0
    ? [...new Set(options.activitySupplementYears)].sort((left, right) => left - right)
    : [20, 50];
  const cases = [];

  for (const year of years) {
    for (const [kind, label] of [["map1", "baseline"], ["map2", "map2_varied_migration"]]) {
      const offRun = runActivitySupplementScenario(modules, kind, label, year, false);
      const offRepeat = runActivitySupplementScenario(modules, kind, label, year, false);
      const onRun = runActivitySupplementScenario(modules, kind, label, year, true);
      const offSignature = JSON.stringify({
        macro: offRun.macro,
        tripAudit: offRun.tripAudit,
        activityMemoryAudit: offRun.activityMemoryAudit,
      });
      const offRepeatSignature = JSON.stringify({
        macro: offRepeat.macro,
        tripAudit: offRepeat.tripAudit,
        activityMemoryAudit: offRepeat.activityMemoryAudit,
      });

      cases.push({
        scenario: label,
        years: year,
        off: {
          macro: offRun.macro,
          supplement: offRun.supplement,
        },
        on: {
          macro: onRun.macro,
          supplement: onRun.supplement,
        },
        offByteIdenticalRepeat: offSignature === offRepeatSignature,
        delta: compareActivitySupplementRuns(offRun, onRun),
      });
    }
  }

  const anyOffSupplementConsumed = cases.some((entry) => entry.off.supplement.consumedSupportTotal !== 0);
  const guardFailures = cases.reduce((sum, entry) => sum + entry.on.supplement.guardFailureCount, 0);
  const runawayCases = cases.filter(
    (entry) =>
      Math.abs(entry.delta.populationDelta) > 20 ||
      Math.abs(entry.delta.fissionDelta) > 2 ||
      entry.delta.supplementShareOfFinalSupport > 0.04,
  );
  const offByteIdentical = cases.every((entry) => entry.offByteIdenticalRepeat && entry.off.supplement.bandsWithSupplementField === 0);
  const onSmallAndCapped = runawayCases.length === 0 && guardFailures === 0;

  return {
    check: "ACTIVITY-GROUPS-11 tiny activity subsistence supplement audit",
    verdict: offByteIdentical && onSmallAndCapped && !anyOffSupplementConsumed ? "pass_optional_experimental" : "review",
    command: "node scripts/simBenchmark.mjs --targeted-activity-subsistence-supplement --json",
    years,
    featureFlag: {
      field: "world.auditOptions.activitySubsistenceSupplementEnabled",
      default: false,
      normalWorldsEnabled: false,
    },
    formula: {
      fraction: 0.06,
      cap: "min(0.75 adult-equivalent support, 0.03 * adultEquivalentDemand)",
      consumed: "same-day returned food shadow net only, reliability-weighted; hunting further discounted; plants/water/info/delayed returns not consumed",
      abstractSupportFloor: "sharedReachableSupport + realizedLearnedSupportDelta",
    },
    cases,
    offBaselineProof: {
      offByteIdenticalRepeat: cases.every((entry) => entry.offByteIdenticalRepeat),
      offSupplementFieldsAbsent: cases.every((entry) => entry.off.supplement.bandsWithSupplementField === 0),
      anyOffSupplementConsumed,
    },
    onRiskSummary: {
      guardFailures,
      runawayCases,
      maxPopulationDelta: cases.reduce((max, entry) => Math.max(max, Math.abs(entry.delta.populationDelta)), 0),
      maxSupplementShareOfFinalSupport: cases.reduce(
        (max, entry) => Math.max(max, entry.delta.supplementShareOfFinalSupport),
        0,
      ),
    },
    recommendation:
      offByteIdentical && onSmallAndCapped
        ? "Keep disabled by default; expose as optional experimental flag for continued calibration."
        : "Do not enable beyond audit; tune or revert before AG12.",
  };
}

// ===========================================================================
// Band Life Readability — raw activity label collapse vs grounded display variety.
// ===========================================================================

function readableActivityCategory(trip) {
  if (trip.taskGroupType !== "local_foraging_group") {
    switch (trip.taskGroupType) {
      case "hunting_group":
        return "hunting";
      case "fishing_group":
        return "fishing";
      case "plant_gathering_group":
        return "gathering";
      case "water_group":
        return "water";
      case "plant_followup_group":
        return "plant_check";
      case "memory_refresh_group":
        return "scouting_or_memory";
      default:
        return "other";
    }
  }

  switch (trip.resourceClassId) {
    case "aquatic_food":
      return "near_camp_fishing";
    case "animal_food":
      return "near_camp_hunting";
    case "generic_plant_food":
    case "fallback_food":
      return "near_camp_gathering";
    default:
      return "near_camp_foraging";
  }
}

function incrementCount(object, key, amount = 1) {
  object[key] = (object[key] ?? 0) + amount;
}

function topCount(counts) {
  const entries = Object.entries(counts).sort((left, right) =>
    right[1] === left[1] ? left[0].localeCompare(right[0]) : right[1] - left[1],
  );

  return entries[0] ?? ["none", 0];
}

function auditBandLifeScenario(modules, kind, label, years) {
  const world = modules.stepSim(modules.initSimWorld({ kind }), years * 4, "seasonal");
  const bands = Object.values(world.bands).filter(isActiveBand);
  const macro = summarizeTimeScaleWorld(world);
  const rawTaskTypeCounts = {};
  const rawGroupLabelCounts = {};
  const readableCategoryCounts = {};
  const localForagingResourceClasses = {};
  const returnKindCounts = {};
  const seasonCounts = {};
  const examples = [];
  const nineOfNineRawLocalExamples = [];
  let totalTrips = 0;
  let totalBandsWithTrips = 0;
  let bandsWithAllRawSame = 0;
  let bandsWithAllReadableSame = 0;
  let bandsWhereReadableAddsVariety = 0;
  let bandsWhereReadableStillMonotone = 0;
  let richBandsWithTrips = 0;
  let richBandsAllRawLocal = 0;
  let richBandsReadableStillMonotone = 0;
  let maxRawTopShare = 0;
  let maxReadableTopShare = 0;
  let shadowRecords = 0;
  let shadowEconomyConsumed = 0;
  let resourceReturnsEconomyConsumed = 0;
  let ag11SupplementFields = 0;

  for (const band of bands) {
    const trips = [...(band.recentIntraSeasonTrips ?? [])].sort((left, right) => Number(right.day) - Number(left.day));
    const rawCounts = {};
    const readableCounts = {};
    const recentNine = trips.slice(0, 9);
    const perCapitaReturn =
      band.carryingCapacity?.perCapitaReturn?.perCapitaReturn ??
      band.perCapitaReturn?.perCapitaReturn ??
      0;
    const isRichBand = perCapitaReturn >= 0.62;

    if (trips.length > 0) {
      totalBandsWithTrips += 1;
      if (isRichBand) {
        richBandsWithTrips += 1;
      }
    }

    for (const trip of trips) {
      totalTrips += 1;
      incrementCount(rawTaskTypeCounts, trip.taskGroupType);
      incrementCount(rawGroupLabelCounts, trip.groupLabel);
      incrementCount(returnKindCounts, trip.resourceReturn.returnedResourceKind);
      incrementCount(seasonCounts, trip.season);

      const readable = readableActivityCategory(trip);
      incrementCount(readableCategoryCounts, readable);
      incrementCount(rawCounts, trip.groupLabel);
      incrementCount(readableCounts, readable);

      if (trip.taskGroupType === "local_foraging_group") {
        incrementCount(localForagingResourceClasses, trip.resourceClassId ?? "unknown");
      }
      if (trip.shadowSubsistence !== undefined) {
        shadowRecords += 1;
        if (trip.shadowSubsistence.shadowConsumedByEconomy !== false) {
          shadowEconomyConsumed += 1;
        }
      }
      if (trip.resourceReturn.consumedByEconomy !== false) {
        resourceReturnsEconomyConsumed += 1;
      }
    }

    const [rawTopLabel, rawTop] = topCount(rawCounts);
    const [readableTopLabel, readableTop] = topCount(readableCounts);
    const rawTopShare = trips.length > 0 ? rawTop / trips.length : 0;
    const readableTopShare = trips.length > 0 ? readableTop / trips.length : 0;
    maxRawTopShare = Math.max(maxRawTopShare, rawTopShare);
    maxReadableTopShare = Math.max(maxReadableTopShare, readableTopShare);

    if (trips.length > 0 && rawTop === trips.length) {
      bandsWithAllRawSame += 1;
      if (readableTop < trips.length) {
        bandsWhereReadableAddsVariety += 1;
      }
    }
    if (trips.length > 0 && readableTop === trips.length) {
      bandsWithAllReadableSame += 1;
      bandsWhereReadableStillMonotone += 1;
    }
    if (isRichBand && trips.length > 0 && rawTopLabel === "Local foraging group" && rawTop === trips.length) {
      richBandsAllRawLocal += 1;
      if (readableTop === trips.length) {
        richBandsReadableStillMonotone += 1;
      }
    }

    if (
      recentNine.length >= 9 &&
      recentNine.every((trip) => trip.taskGroupType === "local_foraging_group")
    ) {
      const resourceClasses = {};
      const readableNine = {};
      for (const trip of recentNine) {
        incrementCount(resourceClasses, trip.resourceClassId ?? "unknown");
        incrementCount(readableNine, readableActivityCategory(trip));
      }
      if (nineOfNineRawLocalExamples.length < 6) {
        nineOfNineRawLocalExamples.push({
          bandId: String(band.id),
          bandName: band.name,
          perCapitaReturn: round4(perCapitaReturn),
          resourceClasses,
          readableCategories: readableNine,
          stillDisplayMonotone: Object.keys(readableNine).length === 1,
        });
      }
    }

    if (examples.length < 8 && trips.length > 0) {
      examples.push({
        bandId: String(band.id),
        bandName: band.name,
        tripCount: trips.length,
        perCapitaReturn: round4(perCapitaReturn),
        rawTopLabel,
        rawTopShare: round4(rawTopShare),
        readableTopLabel,
        readableTopShare: round4(readableTopShare),
        firstTrip: {
          taskGroupType: trips[0].taskGroupType,
          resourceClassId: trips[0].resourceClassId,
          readableCategory: readableActivityCategory(trips[0]),
          returnKind: trips[0].resourceReturn.returnedResourceKind,
          outcome: trips[0].activityOutcome,
        },
      });
    }

    const supplement = band.carryingCapacity?.perCapitaReturn?.supportDebug?.activitySubsistenceSupplement;
    if (supplement !== undefined) {
      ag11SupplementFields += 1;
    }
  }

  const [topRawTaskType, topRawTaskCount] = topCount(rawTaskTypeCounts);
  const [topReadableCategory, topReadableCount] = topCount(readableCategoryCounts);

  return {
    scenario: label,
    kind,
    years,
    macro: {
      tick: macro.tick,
      year: macro.year,
      totalPopulation: macro.totalPopulation,
      activeBands: macro.activeBands,
      fissions: macro.fissions,
    },
    activeBands: bands.length,
    totalTrips,
    totalBandsWithTrips,
    tripsPerBandWithTrips: totalBandsWithTrips > 0 ? round4(totalTrips / totalBandsWithTrips) : 0,
    rawTaskTypeCounts,
    rawGroupLabelCounts,
    readableCategoryCounts,
    localForagingResourceClasses,
    returnKindCounts,
    seasonCounts,
    topShares: {
      topRawTaskType,
      topRawTaskShare: totalTrips > 0 ? round4(topRawTaskCount / totalTrips) : 0,
      topReadableCategory,
      topReadableShare: totalTrips > 0 ? round4(topReadableCount / totalTrips) : 0,
      maxBandRawTopShare: round4(maxRawTopShare),
      maxBandReadableTopShare: round4(maxReadableTopShare),
    },
    repetition: {
      bandsWithAllRawSame,
      bandsWithAllReadableSame,
      bandsWhereReadableAddsVariety,
      bandsWhereReadableStillMonotone,
      nineOfNineRawLocalExamples,
    },
    richBandReadability: {
      richBandsWithTrips,
      richBandsAllRawLocal,
      richBandsReadableStillMonotone,
      note: "rich = current per-capita return >= 0.62; this is an audit lens only, not a behavior rule",
    },
    coupling: {
      shadowRecords,
      shadowEconomyConsumed,
      resourceReturnsEconomyConsumed,
      ag11SupplementFields,
      ag10ShadowOnly: shadowRecords > 0 && shadowEconomyConsumed === 0 && resourceReturnsEconomyConsumed === 0,
      ag11NormalPath: ag11SupplementFields === 0 ? "off_by_default_no_supplement_fields" : "enabled_or_unexpected_fields_present",
    },
    examples,
  };
}

function runTargetedBandLifeReadabilityAudit(modules, options) {
  const years =
    Number.isFinite(options.activityReadabilityYears) && options.activityReadabilityYears > 0
      ? Math.floor(options.activityReadabilityYears)
      : 20;
  const map1 = auditBandLifeScenario(modules, "map1", "baseline", years);
  const map2 = auditBandLifeScenario(modules, "map2", "map2_varied_migration", years);
  const deterministicRepeat = auditBandLifeScenario(modules, "map2", "map2_varied_migration", years);
  const deterministic =
    JSON.stringify(map2.rawTaskTypeCounts) === JSON.stringify(deterministicRepeat.rawTaskTypeCounts) &&
    JSON.stringify(map2.readableCategoryCounts) === JSON.stringify(deterministicRepeat.readableCategoryCounts) &&
    JSON.stringify(map2.repetition) === JSON.stringify(deterministicRepeat.repetition);
  const ag10ShadowOnly = map1.coupling.ag10ShadowOnly && map2.coupling.ag10ShadowOnly;
  const ag11Off = map1.coupling.ag11NormalPath === "off_by_default_no_supplement_fields" &&
    map2.coupling.ag11NormalPath === "off_by_default_no_supplement_fields";

  return {
    check: "Band life readability / activity variety audit",
    verdict: deterministic && ag10ShadowOnly && ag11Off ? "pass" : "review",
    command: "node scripts/simBenchmark.mjs --targeted-band-life-readability-audit --json",
    years,
    notes: [
      "Raw task labels can collapse resource-specific local activity into Local foraging group; the new display breaks that out using existing taskGroupType + resourceClassId + return/outcome metadata.",
      "A band can still be genuinely monotonous when recent trips are all the same local resource class; the audit reports those separately from display-only collapse.",
      "AG10 shadow subsistence is present and shadow-only; AG11 remains off by default in normal worlds.",
    ],
    scenarios: { map1, map2 },
    summary: {
      rawNineOfNineStillPossible:
        map1.repetition.nineOfNineRawLocalExamples.length + map2.repetition.nineOfNineRawLocalExamples.length > 0,
      readableAddsVarietyBands: map1.repetition.bandsWhereReadableAddsVariety + map2.repetition.bandsWhereReadableAddsVariety,
      readableStillMonotoneBands: map1.repetition.bandsWhereReadableStillMonotone + map2.repetition.bandsWhereReadableStillMonotone,
      dominantRawTaskMap2: map2.topShares.topRawTaskType,
      dominantReadableCategoryMap2: map2.topShares.topReadableCategory,
      ag10ShadowOnly,
      ag11Off,
      deterministic,
    },
  };
}

// ===========================================================================
// Activity Composition / Camp Life v0 — visible activity mix, support status,
// monotony classes, and the grounded residential-center labor remainder.
// ===========================================================================

function detailedActivityLabel(trip) {
  if (trip.taskGroupType === "water_group") {
    return trip.distanceTiles <= 2 ? "near_camp_water_work" : "water_check";
  }
  if (trip.taskGroupType === "memory_refresh_group") {
    return trip.outcome === "returns_same_day" ? "known_place_recheck" : "route_memory_trip";
  }
  if (trip.taskGroupType === "plant_followup_group") {
    return "plant_safety_check";
  }
  if (trip.taskGroupType === "hunting_group") {
    return trip.outcome === "returns_same_day" ? "known_patch_hunting" : "wide_hunting_foray";
  }
  if (trip.taskGroupType === "fishing_group") {
    return trip.outcome === "returns_same_day" ? "known_shore_fishing" : "wide_fishing_foray";
  }
  if (trip.taskGroupType === "plant_gathering_group") {
    return trip.outcome === "returns_same_day" ? "known_patch_gathering" : "wide_gathering_foray";
  }

  switch (trip.resourceClassId) {
    case "aquatic_food":
      return trip.distanceTiles <= 2 ? "near_camp_fishing" : "shore_fishing";
    case "animal_food":
      return trip.distanceTiles <= 2 ? "near_camp_hunting" : "local_hunting";
    case "generic_plant_food":
      return trip.distanceTiles <= 2 ? "near_camp_gathering" : "patch_gathering";
    case "fallback_food":
      return "fallback_gathering";
    default:
      return "local_foraging";
  }
}

function broadActivityCategory(trip) {
  if (trip.taskGroupType === "water_group") {
    return "water";
  }
  if (trip.taskGroupType === "memory_refresh_group") {
    return trip.outcome === "returns_same_day" ? "scout" : "route";
  }
  if (trip.taskGroupType === "plant_followup_group") {
    return "scout";
  }
  if (trip.outcome !== "returns_same_day") {
    return trip.resourceClassId === "animal_food" ? "food_hunt" : "route";
  }
  if (trip.resourceClassId === "animal_food") {
    return "food_hunt";
  }
  if (trip.resourceClassId === "aquatic_food") {
    return "food_fish";
  }
  if (trip.resourceClassId === "generic_plant_food" || trip.resourceClassId === "fallback_food") {
    return "food_gather";
  }
  return "food_local";
}

function isFoodTrip(trip) {
  return broadActivityCategory(trip).startsWith("food");
}

function knownFoodMemoryCounts(band) {
  const counts = {
    animal_food: 0,
    aquatic_food: 0,
    generic_plant_food: 0,
    fallback_food: 0,
    totalFood: 0,
    highConfidenceAnimalFood: 0,
  };

  for (const memory of band.resourceKnowledgeState?.patchMemories ?? []) {
    if (
      memory.resourceClassId !== "animal_food" &&
      memory.resourceClassId !== "aquatic_food" &&
      memory.resourceClassId !== "generic_plant_food" &&
      memory.resourceClassId !== "fallback_food"
    ) {
      continue;
    }

    counts.totalFood += 1;
    counts[memory.resourceClassId] += 1;
    if (
      memory.resourceClassId === "animal_food" &&
      memory.confidence.presenceConfidence >= 0.45 &&
      memory.confidence.yieldConfidence >= 0.28
    ) {
      counts.highConfidenceAnimalFood += 1;
    }
  }

  return counts;
}

function isHungerPressureBand(band) {
  const foodStress = band.pressureState?.foodStress ?? 0;
  const perCapitaReturn =
    band.carryingCapacity?.perCapitaReturn?.perCapitaReturn ??
    band.perCapitaReturn?.perCapitaReturn ??
    0.5;

  return foodStress >= 0.35 || perCapitaReturn < 0.55 || band.returnTrend?.chronicDecline === true;
}

function isWaterAnchoredOrAquaticBand(band, trips) {
  const name = String(band.name ?? "").toLowerCase();
  const nameLooksWaterAnchored =
    name.includes("river") ||
    name.includes("lake") ||
    name.includes("shore") ||
    name.includes("estuary") ||
    name.includes("delta") ||
    name.includes("marsh") ||
    name.includes("basin") ||
    name.includes("creek");
  const aquaticTrips = trips.filter((trip) => trip.resourceClassId === "aquatic_food").length;
  const waterTrips = trips.filter((trip) => trip.taskGroupType === "water_group").length;

  return nameLooksWaterAnchored || aquaticTrips + waterTrips >= Math.max(2, Math.ceil(trips.length * 0.35));
}

function hasContiguousActivityBreadcrumb(world, trip) {
  const path = trip.pathTiles ?? [];

  if (path.length <= 1) {
    return true;
  }
  if (path[0] !== trip.originTileId) {
    return false;
  }

  for (let index = 1; index < path.length; index += 1) {
    const previous = world.tiles[path[index - 1]];

    if (previous === undefined || !previous.neighbors.includes(path[index])) {
      return false;
    }
  }

  return trip.tilesCrossed === path.length - 1;
}

function classifyBandMonotony(band, trips, rawTop, readableTop, detailedTop) {
  const labor = band.activityLaborSummary;
  const rawAllSame = trips.length > 0 && rawTop[1] === trips.length;
  const readableAllSame = trips.length > 0 && readableTop[1] === trips.length;
  const detailedAllSame = trips.length > 0 && detailedTop[1] === trips.length;
  const waterAnchored = isWaterAnchoredOrAquaticBand(band, trips);
  const localFoodDominant =
    trips.length > 0 &&
    trips.filter((trip) => trip.cause === "local_resource_use" && isFoodTrip(trip)).length / trips.length >= 0.75;
  const campRemainder =
    labor !== undefined && (labor.peopleAtResidentialCenterEstimate > 0 || band.demography.dependents + band.demography.elders > 0);

  return {
    trueMonotony: detailedAllSame,
    labelMonotony: rawAllSame && !detailedAllSame,
    ecologicalMonotony: detailedAllSame && waterAnchored && localFoodDominant,
    missingRoleMonotony: detailedAllSame && campRemainder,
    waterAnchoredOrAquatic: waterAnchored,
    localFoodDominant,
    campRemainder,
  };
}

function summarizeBandActivityComposition(band) {
  const trips = [...(band.recentIntraSeasonTrips ?? [])].sort((left, right) => Number(right.day) - Number(left.day));
  const rawCounts = {};
  const readableCounts = {};
  const detailedCounts = {};
  const broadCounts = {};
  const resourceClassCounts = {};
  const returnKindCounts = {};
  const causeCounts = {};

  for (const trip of trips) {
    incrementCount(rawCounts, trip.taskGroupType);
    incrementCount(readableCounts, readableActivityCategory(trip));
    incrementCount(detailedCounts, detailedActivityLabel(trip));
    incrementCount(broadCounts, broadActivityCategory(trip));
    incrementCount(resourceClassCounts, trip.resourceClassId ?? "none");
    incrementCount(returnKindCounts, trip.resourceReturn.returnedResourceKind);
    incrementCount(causeCounts, trip.cause);
  }

  const rawTop = topCount(rawCounts);
  const readableTop = topCount(readableCounts);
  const detailedTop = topCount(detailedCounts);
  const broadTop = topCount(broadCounts);
  const monotony = classifyBandMonotony(band, trips, rawTop, readableTop, detailedTop);
  const labor = band.activityLaborSummary;
  const foodMemories = knownFoodMemoryCounts(band);
  const hungry = isHungerPressureBand(band);
  const huntingTripCount = trips.filter((trip) => trip.taskGroupType === "hunting_group" || trip.resourceClassId === "animal_food").length;
  const foodTripCount = trips.filter(isFoodTrip).length;
  const perCapitaReturn =
    band.carryingCapacity?.perCapitaReturn?.perCapitaReturn ??
    band.perCapitaReturn?.perCapitaReturn ??
    0;

  return {
    bandId: String(band.id),
    bandName: band.name,
    tripCount: trips.length,
    rawCounts,
    readableCounts,
    detailedCounts,
    broadCounts,
    resourceClassCounts,
    returnKindCounts,
    causeCounts,
    topShares: {
      raw: { label: rawTop[0], share: trips.length > 0 ? round4(rawTop[1] / trips.length) : 0 },
      readable: { label: readableTop[0], share: trips.length > 0 ? round4(readableTop[1] / trips.length) : 0 },
      detailed: { label: detailedTop[0], share: trips.length > 0 ? round4(detailedTop[1] / trips.length) : 0 },
      broad: { label: broadTop[0], share: trips.length > 0 ? round4(broadTop[1] / trips.length) : 0 },
    },
    monotony,
    labor:
      labor === undefined
        ? undefined
        : {
            activeActivityGroupCount: labor.activeActivityGroupCount,
            workingAdults: labor.workingAdults,
            assignedPeople: labor.peopleAssignedToActivityGroups,
            awayPeople: labor.peopleAwayInActivityGroups,
            atCampPeople: labor.peopleAtResidentialCenterEstimate,
            dependents: band.demography.dependents,
            elders: band.demography.elders,
          },
    hungerAndHunting: {
      hungry,
      foodStress: round4(band.pressureState?.foodStress ?? 0),
      perCapitaReturn: round4(perCapitaReturn),
      chronicDecline: band.returnTrend?.chronicDecline === true,
      foodMemories,
      foodTripCount,
      huntingTripCount,
      huntingShareOfFoodTrips: foodTripCount > 0 ? round4(huntingTripCount / foodTripCount) : 0,
      interpretation:
        hungry && foodMemories.animal_food > 0 && huntingTripCount === 0
          ? "hungry_with_animal_memory_but_no_hunting_recently"
          : hungry && huntingTripCount > 0
            ? "hungry_and_hunting_present"
            : hungry
              ? "hungry_but_no_known_animal_memory_or_other_food_won"
              : "not_food_stressed",
    },
  };
}

function auditActivityCompositionScenario(modules, kind, label, years) {
  const world = modules.stepSim(modules.initSimWorld({ kind }), years * 4, "seasonal");
  const bands = Object.values(world.bands).filter(isActiveBand);
  const macro = summarizeTimeScaleWorld(world);
  const rawActionTypeDistribution = {};
  const readableLabelDistribution = {};
  const detailedLabelDistribution = {};
  const resourceClassDistribution = {};
  const broadCategoryDistribution = {};
  const returnKindDistribution = {};
  const seasonDistribution = {};
  const pressureBuckets = {};
  const waterReliabilityBuckets = {};
  const rangeContextDistribution = {};
  const topShareBands = [];
  const monotonyCounts = {
    trueMonotony: 0,
    labelMonotony: 0,
    ecologicalMonotony: 0,
    missingRoleMonotony: 0,
    waterAnchoredOrAquatic: 0,
  };
  const sameCategoryRunCounts = {
    sixOfSix: 0,
    eightOfEight: 0,
    nineOfNine: 0,
  };
  const hungerAndHunting = {
    hungryBandsWithTrips: 0,
    hungryBandsWithAnimalMemory: 0,
    hungryBandsWithHighConfidenceAnimalMemory: 0,
    hungryBandsWithHuntingTrips: 0,
    hungryBandsWithAnimalMemoryButNoHunting: 0,
    huntingTripCountInHungryBands: 0,
    foodTripCountInHungryBands: 0,
    examples: [],
  };
  const campLife = {
    bandsWithLaborSummary: 0,
    bandsWithCampRemainder: 0,
    totalWorkingAdultsAtCamp: 0,
    totalDependentsAndElders: 0,
    bandsWhereTripsLookAllSameButCampRemainderExists: 0,
  };
  const examples = [];
  let totalTrips = 0;
  let bandsWithTrips = 0;
  let shadowRecords = 0;
  let shadowEconomyConsumed = 0;
  let resourceReturnsEconomyConsumed = 0;
  let ag11SupplementFields = 0;
  let pathTeleportViolations = 0;
  let unknownTargetViolations = 0;

  for (const band of bands.sort(compareBands)) {
    const summary = summarizeBandActivityComposition(band);
    const trips = [...(band.recentIntraSeasonTrips ?? [])].sort((left, right) => Number(right.day) - Number(left.day));

    if (trips.length > 0) {
      bandsWithTrips += 1;
      topShareBands.push({
        bandId: summary.bandId,
        bandName: summary.bandName,
        trips: trips.length,
        topDetailedLabel: summary.topShares.detailed.label,
        topDetailedShare: summary.topShares.detailed.share,
        topBroadLabel: summary.topShares.broad.label,
        topBroadShare: summary.topShares.broad.share,
      });
    }

    for (const trip of trips) {
      totalTrips += 1;
      incrementCount(rawActionTypeDistribution, trip.taskGroupType);
      incrementCount(readableLabelDistribution, readableActivityCategory(trip));
      incrementCount(detailedLabelDistribution, detailedActivityLabel(trip));
      incrementCount(resourceClassDistribution, trip.resourceClassId ?? "none");
      incrementCount(broadCategoryDistribution, broadActivityCategory(trip));
      incrementCount(returnKindDistribution, trip.resourceReturn.returnedResourceKind);
      incrementCount(seasonDistribution, trip.season);
      if (trip.shadowSubsistence !== undefined) {
        shadowRecords += 1;
        if (trip.shadowSubsistence.shadowConsumedByEconomy !== false) {
          shadowEconomyConsumed += 1;
        }
      }
      if (trip.resourceReturn.consumedByEconomy !== false) {
        resourceReturnsEconomyConsumed += 1;
      }
      if (!hasContiguousActivityBreadcrumb(world, trip)) {
        pathTeleportViolations += 1;
      }
      const knownTarget = (band.resourceKnowledgeState?.patchMemories ?? []).some((memory) => memory.approximateTile === trip.targetTileId);
      if (trip.bandKnownTargetOnly !== true || !knownTarget) {
        unknownTargetViolations += 1;
      }
    }

    for (const key of Object.keys(monotonyCounts)) {
      if (summary.monotony[key] === true) {
        monotonyCounts[key] += 1;
      }
    }

    const recentNine = trips.slice(0, 9);
    for (const [count, key] of [[6, "sixOfSix"], [8, "eightOfEight"], [9, "nineOfNine"]]) {
      const recent = recentNine.slice(0, count);
      if (recent.length === count) {
        const categories = {};
        for (const trip of recent) {
          incrementCount(categories, broadActivityCategory(trip));
        }
        if (topCount(categories)[1] === count) {
          sameCategoryRunCounts[key] += 1;
        }
      }
    }

    const pressureKey =
      (band.pressureState?.foodStress ?? 0) >= 0.35
        ? "food_pressure"
        : (band.pressureState?.waterStress ?? 0) >= 0.32
          ? "water_pressure"
          : "low_pressure";
    incrementCount(pressureBuckets, pressureKey);

    const waterKey =
      (band.activityShadowSubsistenceSummary?.waterSupportTripCount ?? 0) > 0
        ? "water_trips_recent"
        : (band.pressureState?.waterStress ?? 0) >= 0.32
          ? "water_stressed_no_recent_water_trip"
          : "water_stable_or_not_triggered";
    incrementCount(waterReliabilityBuckets, waterKey);

    const familiar = modules.familiarCountry.deriveFamiliarCountry(band, world.time.tick);
    const rangeContext = modules.familiarCountry.classifyMovementContext(band, familiar, world.time.tick);
    incrementCount(rangeContextDistribution, rangeContext);

    const labor = band.activityLaborSummary;
    if (labor !== undefined) {
      campLife.bandsWithLaborSummary += 1;
      campLife.totalWorkingAdultsAtCamp += labor.peopleAtResidentialCenterEstimate;
      campLife.totalDependentsAndElders += band.demography.dependents + band.demography.elders;
      if (summary.monotony.campRemainder) {
        campLife.bandsWithCampRemainder += 1;
      }
      if (summary.monotony.missingRoleMonotony) {
        campLife.bandsWhereTripsLookAllSameButCampRemainderExists += 1;
      }
    }

    if (summary.hungerAndHunting.hungry && trips.length > 0) {
      hungerAndHunting.hungryBandsWithTrips += 1;
      hungerAndHunting.foodTripCountInHungryBands += summary.hungerAndHunting.foodTripCount;
      hungerAndHunting.huntingTripCountInHungryBands += summary.hungerAndHunting.huntingTripCount;
      if (summary.hungerAndHunting.foodMemories.animal_food > 0) {
        hungerAndHunting.hungryBandsWithAnimalMemory += 1;
      }
      if (summary.hungerAndHunting.foodMemories.highConfidenceAnimalFood > 0) {
        hungerAndHunting.hungryBandsWithHighConfidenceAnimalMemory += 1;
      }
      if (summary.hungerAndHunting.huntingTripCount > 0) {
        hungerAndHunting.hungryBandsWithHuntingTrips += 1;
      }
      if (summary.hungerAndHunting.interpretation === "hungry_with_animal_memory_but_no_hunting_recently") {
        hungerAndHunting.hungryBandsWithAnimalMemoryButNoHunting += 1;
      }
      if (hungerAndHunting.examples.length < 6) {
        hungerAndHunting.examples.push({
          bandId: summary.bandId,
          bandName: summary.bandName,
          foodStress: summary.hungerAndHunting.foodStress,
          perCapitaReturn: summary.hungerAndHunting.perCapitaReturn,
          foodMemories: summary.hungerAndHunting.foodMemories,
          foodTripCount: summary.hungerAndHunting.foodTripCount,
          huntingTripCount: summary.hungerAndHunting.huntingTripCount,
          topDetailed: summary.topShares.detailed,
          interpretation: summary.hungerAndHunting.interpretation,
        });
      }
    }

    const supplement = band.carryingCapacity?.perCapitaReturn?.supportDebug?.activitySubsistenceSupplement;
    if (supplement !== undefined) {
      ag11SupplementFields += 1;
    }

    if (examples.length < 8 && (summary.monotony.trueMonotony || summary.monotony.labelMonotony || summary.hungerAndHunting.hungry)) {
      examples.push({
        bandId: summary.bandId,
        bandName: summary.bandName,
        tripCount: summary.tripCount,
        topShares: summary.topShares,
        resourceClassCounts: summary.resourceClassCounts,
        broadCounts: summary.broadCounts,
        monotony: summary.monotony,
        labor: summary.labor,
        hungerAndHunting: summary.hungerAndHunting,
      });
    }
  }

  topShareBands.sort((left, right) =>
    right.topDetailedShare === left.topDetailedShare
      ? left.bandName.localeCompare(right.bandName)
      : right.topDetailedShare - left.topDetailedShare,
  );

  return {
    scenario: label,
    kind,
    years,
    macro: {
      tick: macro.tick,
      year: macro.year,
      totalPopulation: macro.totalPopulation,
      activeBands: macro.activeBands,
      fissions: macro.fissions,
    },
    activeBands: bands.length,
    bandsWithTrips,
    totalTrips,
    groupsPerBandWithTrips: bandsWithTrips > 0 ? round4(totalTrips / bandsWithTrips) : 0,
    distributions: {
      rawActionTypeDistribution,
      readableLabelDistribution,
      detailedLabelDistribution,
      resourceClassDistribution,
      broadCategoryDistribution,
      returnKindDistribution,
      seasonDistribution,
      pressureBuckets,
      waterReliabilityBuckets,
      rangeContextDistribution,
    },
    repetition: {
      monotonyCounts,
      sameCategoryRunCounts,
      topShareBands: topShareBands.slice(0, 8),
    },
    hungerAndHunting: {
      ...hungerAndHunting,
      huntingShareOfHungryFoodTrips:
        hungerAndHunting.foodTripCountInHungryBands > 0
          ? round4(hungerAndHunting.huntingTripCountInHungryBands / hungerAndHunting.foodTripCountInHungryBands)
          : 0,
      note:
        "Hunger makes known food memories eligible as food_resource_check; hunting appears when animal_food memories win the deterministic selector.",
    },
    campLife: {
      ...campLife,
      averageWorkingAdultsAtCamp:
        campLife.bandsWithLaborSummary > 0 ? round4(campLife.totalWorkingAdultsAtCamp / campLife.bandsWithLaborSummary) : 0,
      averageDependentsAndElders:
        campLife.bandsWithLaborSummary > 0 ? round4(campLife.totalDependentsAndElders / campLife.bandsWithLaborSummary) : 0,
      displayModel:
        "read-only camp-life card from activityLaborSummary.peopleAtResidentialCenterEstimate + demographic dependents/elders; no food/support generated",
    },
    couplingAndSafety: {
      shadowRecords,
      shadowEconomyConsumed,
      resourceReturnsEconomyConsumed,
      ag11SupplementFields,
      ag10ShadowOnly: shadowRecords > 0 && shadowEconomyConsumed === 0 && resourceReturnsEconomyConsumed === 0,
      ag11Off: ag11SupplementFields === 0,
      unknownTargetViolations,
      pathTeleportViolations,
      noEconomySupportPopulationStressCoupling:
        shadowEconomyConsumed === 0 &&
        resourceReturnsEconomyConsumed === 0 &&
        ag11SupplementFields === 0,
    },
    examples,
  };
}

function runTargetedActivityCompositionAudit(modules, options) {
  const years =
    Number.isFinite(options.activityCompositionYears) && options.activityCompositionYears > 0
      ? Math.floor(options.activityCompositionYears)
      : 20;
  const map1 = auditActivityCompositionScenario(modules, "map1", "baseline", years);
  const map2 = auditActivityCompositionScenario(modules, "map2", "map2_varied_migration", years);
  const deterministicRepeat = auditActivityCompositionScenario(modules, "map2", "map2_varied_migration", years);
  const deterministic =
    JSON.stringify(map2.distributions) === JSON.stringify(deterministicRepeat.distributions) &&
    JSON.stringify(map2.repetition) === JSON.stringify(deterministicRepeat.repetition) &&
    JSON.stringify(map2.hungerAndHunting) === JSON.stringify(deterministicRepeat.hungerAndHunting);
  const ag10ShadowOnly = map1.couplingAndSafety.ag10ShadowOnly && map2.couplingAndSafety.ag10ShadowOnly;
  const ag11Off = map1.couplingAndSafety.ag11Off && map2.couplingAndSafety.ag11Off;
  const noHiddenOrTeleport =
    map1.couplingAndSafety.unknownTargetViolations === 0 &&
    map2.couplingAndSafety.unknownTargetViolations === 0 &&
    map1.couplingAndSafety.pathTeleportViolations === 0 &&
    map2.couplingAndSafety.pathTeleportViolations === 0;

  return {
    check: "Activity composition / camp life v0 audit",
    verdict: deterministic && ag10ShadowOnly && ag11Off && noHiddenOrTeleport ? "pass" : "review",
    command: "node scripts/simBenchmark.mjs --targeted-activity-composition-audit --json",
    years,
    scenarios: { map1, map2 },
    summary: {
      deterministic,
      ag10ShadowOnly,
      ag11Off,
      noHiddenOrTeleport,
      map2DominantBroadCategory: topCount(map2.distributions.broadCategoryDistribution)[0],
      map2TrueMonotoneBands: map2.repetition.monotonyCounts.trueMonotony,
      map2LabelMonotoneBands: map2.repetition.monotonyCounts.labelMonotony,
      map2MissingRoleMonotoneBands: map2.repetition.monotonyCounts.missingRoleMonotony,
      map2HungryBandsWithAnimalMemoryButNoHunting:
        map2.hungerAndHunting.hungryBandsWithAnimalMemoryButNoHunting,
      campLifeDisplayGroundedBands:
        map1.campLife.bandsWithCampRemainder + map2.campLife.bandsWithCampRemainder,
    },
    notes: [
      "Visible trips are real non-relocating activity records; AG10 shadow support is report-only and AG11 remains off.",
      "Camp-life visibility is grounded in existing labor remainder and demographic cohorts, not new support or fake tasks.",
      "Starvation currently increases food-resource checks, not hunting specifically; hunting requires known animal-food memory to win selection.",
    ],
  };
}

function runTargetedStuckBandAudit(modules, options) {
  const years =
    Number.isFinite(options.stuckBandYears) && options.stuckBandYears > 0
      ? Math.floor(options.stuckBandYears)
      : 80;
  const map1 = auditStuckBandScenario(modules, "baseline", "map1", years, options);
  const map2 = auditStuckBandScenario(modules, "map2_varied_migration", "map2", years, options);
  const map2Repeat = auditStuckBandScenario(modules, "map2_varied_migration", "map2", years, options);
  const singleOriginYears =
    Number.isFinite(options.stuckSingleOriginYears) && options.stuckSingleOriginYears > 0
      ? Math.floor(options.stuckSingleOriginYears)
      : undefined;
  const singleOrigin =
    singleOriginYears === undefined
      ? undefined
      : summarizeStuckWorld(
          computeSingleOriginTalkWorld(modules, singleOriginYears),
          "single-origin-map2",
          "single_origin_map2",
          singleOriginYears,
        );
  const deterministic =
    JSON.stringify(map2.counts) === JSON.stringify(map2Repeat.counts) &&
    JSON.stringify(map2.samples) === JSON.stringify(map2Repeat.samples) &&
    JSON.stringify(map2.actionDistribution) === JSON.stringify(map2Repeat.actionDistribution);
  const scenarios = singleOrigin === undefined ? { map1, map2 } : { map1, map2, singleOrigin };
  const allScenarioSummaries = Object.values(scenarios);
  const noFrozenBadTileBands = allScenarioSummaries.every((scenario) => scenario.counts.frozenBadTileBands === 0);

  return {
    check: "Stuck/frozen band audit",
    verdict: deterministic && noFrozenBadTileBands ? "pass" : "review",
    command:
      singleOriginYears === undefined
        ? "node scripts/simBenchmark.mjs --targeted-stuck-band-audit --json"
        : `node scripts/simBenchmark.mjs --targeted-stuck-band-audit --stuck-single-origin-years ${singleOriginYears} --json`,
    years,
    singleOriginYears,
    scenarios,
    summary: {
      deterministic,
      noFrozenBadTileBands,
      map1FrozenBadTileBands: map1.counts.frozenBadTileBands,
      map2FrozenBadTileBands: map2.counts.frozenBadTileBands,
      singleOriginFrozenBadTileBands: singleOrigin?.counts.frozenBadTileBands ?? null,
      map1LongStressedDwellBands: map1.counts.longStressedDwellBands,
      map2LongStressedDwellBands: map2.counts.longStressedDwellBands,
      singleOriginLongStressedDwellBands: singleOrigin?.counts.longStressedDwellBands ?? null,
      map1DepletionEntries: map1.depletion.entries,
      map2DepletionEntries: map2.depletion.entries,
      singleOriginDepletionEntries: singleOrigin?.depletion.entries ?? null,
    },
    notes: [
      "A harsh-place stay is only flagged when same-tile dwell is long and the band's own pressure/last-decision score says the site is bad.",
      "The freeze fix weakens residence-unchanged choices after repeated bad-site dwell; it does not create forced movement or hidden target selection.",
      "Dormant depletion remains sparse: current/near-band tiles use normal ecology; far abandoned entries use cheap scalar recovery and drop below floor.",
    ],
  };
}

function auditStuckBandScenario(modules, scenario, label, years, options) {
  const result = runBenchmark(
    modules,
    { scenario, years },
    { ...options, fast: true, returnWorld: true, reportBand: false, probeAudit: false },
  );
  return summarizeStuckWorld(result.world, label, scenario, years, result.summary);
}

function summarizeStuckWorld(world, label, scenario, years, summary = undefined) {
  const activeBands = Object.values(world.bands).filter(isActiveBand).sort(compareBands);
  const samples = [];
  const actionDistribution = {};
  const primaryReasonDistribution = {};
  const counts = {
    activeBands: activeBands.length,
    longDwellBands: 0,
    longStressedDwellBands: 0,
    residenceUnchangedUnderPressure: 0,
    frozenBadTileBands: 0,
    stressedBandsWithNonStayAlternative: 0,
    stressedBandsWithoutNonStayAlternative: 0,
  };
  let maxConsecutiveSeasonsOnTile = 0;
  let totalConsecutiveSeasonsOnTile = 0;

  for (const band of activeBands) {
    const dwell = band.consecutiveSeasonsOnTile ?? 0;
    maxConsecutiveSeasonsOnTile = Math.max(maxConsecutiveSeasonsOnTile, dwell);
    totalConsecutiveSeasonsOnTile += dwell;

    if (dwell >= 16) {
      counts.longDwellBands += 1;
    }

    const latestDecisionId = band.decisionHistory[band.decisionHistory.length - 1];
    const latestDecision = latestDecisionId === undefined ? undefined : world.decisions[latestDecisionId];
    const actionType = latestDecision?.action?.type ?? "none";
    const primaryReason = latestDecision?.primaryReason?.type ?? "none";
    incrementCount(actionDistribution, actionType);
    incrementCount(primaryReasonDistribution, primaryReason);

    const stayAlternative = (latestDecision?.alternativesConsidered ?? []).find((alternative) =>
      alternative.action?.type === "stay",
    );
    const bestNonStayAlternative = (latestDecision?.alternativesConsidered ?? []).find((alternative) =>
      alternative.action?.type !== "stay",
    );
    const badSitePressure = estimateBadSitePressureForAudit(band, stayAlternative?.scoreBreakdown);
    const stressed =
      badSitePressure >= 0.42 ||
      (band.pressureState?.foodStress ?? 0) >= 0.55 ||
      (band.pressureState?.waterStress ?? 0) >= 0.55 ||
      (band.pressureState?.mobilityPressure ?? 0) >= 0.62;
    const residenceUnchanged =
      actionType === "stay" ||
      actionType === "logistical_probe" ||
      actionType === "resource_scout" ||
      actionType === "no_op" ||
      actionType === "none";

    if (dwell >= 16 && stressed) {
      counts.longStressedDwellBands += 1;

      if (bestNonStayAlternative === undefined) {
        counts.stressedBandsWithoutNonStayAlternative += 1;
      } else {
        counts.stressedBandsWithNonStayAlternative += 1;
      }
    }

    if (dwell >= 16 && stressed && residenceUnchanged) {
      counts.residenceUnchangedUnderPressure += 1;
    }

    if (dwell >= 24 && stressed && (actionType === "stay" || actionType === "no_op")) {
      counts.frozenBadTileBands += 1;
    }

    if (samples.length < 10 && dwell >= 12 && stressed) {
      samples.push({
        bandId: String(band.id),
        tileId: String(band.position),
        dwellSeasons: dwell,
        dwellYears: round2(dwell / 4),
        badSitePressure: round4(badSitePressure),
        pressure: {
          food: round4(band.pressureState?.foodStress ?? 0),
          water: round4(band.pressureState?.waterStress ?? 0),
          mobility: round4(band.pressureState?.mobilityPressure ?? 0),
          risk: round4(band.pressureState?.riskPressure ?? 0),
        },
        latestDecision: {
          action: actionType,
          primaryReason,
          movedRecently: (band.movementHistory?.length ?? 0) > 0,
        },
        alternatives: summarizeStuckDecisionAlternatives(stayAlternative, bestNonStayAlternative),
      });
    }
  }

  const depletionValues = Object.values(world.tileDepletion ?? {});
  const depletionMean =
    depletionValues.length === 0
      ? 0
      : depletionValues.reduce((sum, value) => sum + value, 0) / depletionValues.length;

  return {
    label,
    scenario,
    years,
    completed: summary?.completed ?? true,
    tick: summary?.tick ?? Number(world.time?.tick ?? 0),
    totalRuntimeMs: summary?.totalRuntimeMs ?? null,
    averageMsPerTick: summary?.averageMsPerTick ?? null,
    depletionPhase: summary?.phaseSummary?.depletionAdvance,
    actionDistribution,
    primaryReasonDistribution,
    counts: {
      ...counts,
      maxConsecutiveSeasonsOnTile,
      averageConsecutiveSeasonsOnTile: round2(totalConsecutiveSeasonsOnTile / Math.max(1, activeBands.length)),
    },
    depletion: {
      entries: depletionValues.length,
      mean: round4(depletionMean),
      max: round4(Math.max(0, ...depletionValues)),
      dormantOptimization: "far abandoned sparse depletion entries skip tile-profile regeneration and decay by scalar recovery",
      noFullMapScan: true,
    },
    samples,
  };
}

function estimateBadSitePressureForAudit(band, scoreBreakdown) {
  if (scoreBreakdown !== undefined) {
    return clamp01(
      (1 - (scoreBreakdown.localSurvivalValue ?? 0)) * 0.34 +
        (scoreBreakdown.foodStress ?? 0) * 0.24 +
        (scoreBreakdown.waterStress ?? 0) * 0.22 +
        (scoreBreakdown.mobilityPressure ?? 0) * 0.16 +
        (scoreBreakdown.nearbyBandPressure ?? 0) * 0.16 +
        (scoreBreakdown.rangeSaturation ?? 0) * 0.14 +
        (scoreBreakdown.crowdingPenalty ?? 0) * 0.14 +
        (scoreBreakdown.socialAccessRisk ?? 0) * 0.08 +
        (scoreBreakdown.depletionPenalty ?? 0) * 0.18 +
        (scoreBreakdown.biomeMismatchPenalty ?? 0) * 0.12 +
        (scoreBreakdown.riskCost ?? 0) * 0.08 -
        (scoreBreakdown.waterRefugeSecurity ?? 0) * 0.12 -
        (scoreBreakdown.rememberedReliability ?? 0) * 0.08,
    );
  }

  return clamp01(
      (band.pressureState?.foodStress ?? band.hungerPressure ?? 0) * 0.32 +
      (band.pressureState?.waterStress ?? 0) * 0.28 +
      (band.pressureState?.mobilityPressure ?? 0) * 0.22 +
      (band.pressureState?.nearbyBandPressure ?? 0) * 0.18 +
      (band.rangeSaturation?.saturationPressure ?? 0) * 0.16 +
      (band.pressureState?.riskPressure ?? 0) * 0.12 +
      (band.viability?.viabilityPressure ?? 0) * 0.12,
  );
}

function summarizeStuckDecisionAlternatives(stayAlternative, bestNonStayAlternative) {
  return {
    stayScore: stayAlternative === undefined ? null : round4(stayAlternative.score ?? 0),
    stayLocalSurvival: stayAlternative === undefined
      ? null
      : round4(stayAlternative.scoreBreakdown?.localSurvivalValue ?? 0),
    stayDepletionPenalty: stayAlternative === undefined
      ? null
      : round4(stayAlternative.scoreBreakdown?.depletionPenalty ?? 0),
    bestNonStayAction: bestNonStayAlternative?.action?.type ?? null,
    bestNonStayTarget: bestNonStayAlternative === undefined
      ? null
      : getDecisionActionTargetTile(bestNonStayAlternative.action) ?? null,
    bestNonStayScore: bestNonStayAlternative === undefined ? null : round4(bestNonStayAlternative.score ?? 0),
    stayMinusBestNonStay: stayAlternative === undefined || bestNonStayAlternative === undefined
      ? null
      : round4((stayAlternative.score ?? 0) - (bestNonStayAlternative.score ?? 0)),
  };
}

