// ---------------------------------------------------------------------------
// Carrying-capacity / effective-yield / daughter-colonization scenarios (2J).
//
// These only set INITIAL conditions: where a lineage stands, the ecology of the
// tiles it can SEE, what it knows/remembers, and the use/crowding/stress it
// carries. Every per-capita / yield / opportunity comparison still runs off the
// band's OWN observed records (anti-omniscience preserved); no hidden tile truth
// is read and no global best tile is injected.
// ---------------------------------------------------------------------------

function buildCrowdedDeltaSaturation(modules, baseWorld) {
  // Rich aquatic/coastal core (high base potential, strong recovery/diversity),
  // but heavily used and crowded by several daughters. Base richness stays high
  // while effective per-capita return falls under use + local population. A known
  // underused floodplain corridor inland gives crowded daughters a probe target.
  let world = reshapeDryMarginBand(modules, baseWorld, {
    bandId: "band:delta-coastal-foragers",
    position: { x: 39, y: 58 },
    currentTilePatch: { terrainKind: "coast", isCoastal: true, isFloodplain: true, droughtRisk: 0.06, waterAccess: 0.84, aquaticPotential: 0.84 },
    currentRecord: { source: "personally_observed", confidence: 1, waterAccess: 0.84, richness: 0.72, aquatic: 0.84, reliability: 0.82, risk: 0.12, visits: 14, isReturnPlace: true, attachment: 0.72 },
    knownTiles: [
      // Rich, heavily-foraged core ring (high potential, high local use pressure).
      { x: 39, y: 57, source: "personally_observed", confidence: 0.86, isCoastal: true, droughtRisk: 0.06, waterAccess: 0.82, aquaticPotential: 0.82, richness: 0.7, reliability: 0.8 },
      { x: 40, y: 58, source: "personally_observed", confidence: 0.86, isCoastal: true, droughtRisk: 0.06, waterAccess: 0.8, aquaticPotential: 0.8, richness: 0.68, reliability: 0.8 },
      { x: 38, y: 58, source: "personally_observed", confidence: 0.84, isCoastal: true, droughtRisk: 0.06, waterAccess: 0.78, aquaticPotential: 0.78, richness: 0.66, reliability: 0.78 },
      { x: 39, y: 59, source: "personally_observed", confidence: 0.84, isCoastal: true, droughtRisk: 0.06, waterAccess: 0.8, aquaticPotential: 0.8, richness: 0.68, reliability: 0.79 },
      // Underused floodplain corridor 4-5 tiles inland: viable, low use, a probe target.
      { x: 36, y: 55, source: "personally_observed", confidence: 0.58, isFloodplain: true, droughtRisk: 0.12, waterAccess: 0.6, richness: 0.55, reliability: 0.64, peakSeasons: ["spring", "summer"] },
      { x: 35, y: 54, source: "inherited_memory", confidence: 0.42, isFloodplain: true, droughtRisk: 0.14, waterAccess: 0.58, richness: 0.52, reliability: 0.62, peakSeasons: ["spring", "summer"] },
    ],
    stress: { foodStress: 0.42, waterStress: 0.2, riskPressure: 0.22, fatiguePressure: 0.32, usePressure: 0.8, placeAttachmentPull: 0.46 },
    population: 30,
  });

  for (let index = 1; index <= 4; index += 1) {
    world = addScenarioDaughter(world, {
      parentBandId: "band:delta-coastal-foragers",
      daughterBandId: `band:delta-coastal-foragers:delta-crowd:${index}`,
      population: 24,
      tileOffset: index,
      stress: { foodStress: 0.44, waterStress: 0.22, riskPressure: 0.26, mortalityPressure: 0.24, usePressure: 0.72 },
    });
  }

  return {
    world,
    notes: [
      "rich delta/coast core stays high in BASE potential but is heavily used + crowded",
      "expect effective yield / per-capita return to fall and saturation to rise",
      "some daughters should probe/disperse toward the known inland floodplain corridor",
      "recovery/high-rank persistence should keep the core from being fully abandoned",
    ],
  };
}

