        topPromising: view.summary.topPromising.map(formatObservedPatchReturn),
        topRiskyOrUncertain: view.summary.topRiskyOrUncertain.map(formatObservedPatchReturn),
        knowledgeOnly: view.summary.knowledgeOnly,
        futureExploitationHook: view.summary.futureExploitationHook,
